#include <cuda_runtime.h>
#include <float.h>
#include <utility>

/*
 * Highly optimized brute-force k-NN for 2D points (float2) on modern NVIDIA GPUs.
 *
 * Algorithm (per query point):
 *  - Process the data set in fixed-size chunks (CHUNK_SIZE points per chunk).
 *  - For each chunk:
 *      * All threads in the block compute squared Euclidean distances to the query.
 *      * Distances and indices for the whole chunk are stored in shared memory.
 *      * A parallel bitonic sort is executed on the chunk in shared memory
 *        to sort all distances in ascending order.
 *      * The best local_k = min(k, chunk_size) neighbors from this chunk
 *        (i.e., the first local_k entries after sort) are merged with the
 *        current global top-k list for this query, which is stored in shared
 *        memory and kept sorted.
 *  - After all chunks are processed, the global top-k for each query is written
 *    to the result array in ascending order of distance.
 *
 * Properties:
 *  - No dynamic device memory allocation is performed.
 *  - All heavy work (distance computation and per-chunk selection) is parallelized.
 *  - Merging partial results between chunks is O(k) and done by a single thread.
 *  - k is supported up to MAX_K (1024) and can vary at runtime (power of two in [32,1024]).
 *  - Data layout:
 *      query:  float2[query_count]
 *      data:   float2[data_count]
 *      result: std::pair<int,float>[query_count * k]
 */

constexpr int BLOCK_SIZE  = 256;   // Threads per block; tuned for modern GPUs
constexpr int MAX_K       = 1024;  // Maximum supported k (assumed by problem)
constexpr int CHUNK_SIZE  = 2048;  // Number of data points processed per chunk (power of two)

static_assert((CHUNK_SIZE & (CHUNK_SIZE - 1)) == 0,
              "CHUNK_SIZE must be a power of two for bitonic sort.");

/*
 * In-place bitonic sort on shared memory arrays of length N (power-of-two).
 *
 * - dist: array of distances to sort (ascending).
 * - idx:  parallel array of indices to permute along with dist.
 * - N:    compile-time constant equal to CHUNK_SIZE.
 *
 * The implementation is the standard bitonic sort network, parallelized over
 * blockDim.x threads. Each thread processes multiple indices (stride blockDim.x).
 */
template <int N>
__device__ __forceinline__ void bitonic_sort_shared(float *dist, int *idx)
{
    // Outer loop: size of subsequences being merged (k)
    for (int k = 2; k <= N; k <<= 1) {
        // Inner loop: distance between elements to compare (j)
        for (int j = k >> 1; j > 0; j >>= 1) {
            // Each thread handles multiple indices: tid, tid + blockDim.x, ...
            for (int tid = threadIdx.x; tid < N; tid += blockDim.x) {
                int ixj = tid ^ j;  // Partner index for comparison
                if (ixj > tid) {
                    float di = dist[tid];
                    float dj = dist[ixj];
                    int   ii = idx[tid];
                    int   ij = idx[ixj];

                    bool ascending = ((tid & k) == 0);
                    // For ascending sequences, keep smaller at lower index.
                    // For descending sequences, keep larger at lower index.
                    bool do_swap = ascending ? (di > dj) : (di < dj);

                    if (do_swap) {
                        dist[tid] = dj;
                        dist[ixj] = di;
                        idx[tid]  = ij;
                        idx[ixj]  = ii;
                    }
                }
            }
            __syncthreads();
        }
    }
}

/*
 * Kernel: compute k nearest neighbors for 2D points.
 *
 * Mapping:
 *  - One block handles one query point.
 *  - All threads within the block cooperate on scanning the full data set,
 *    chunk by chunk.
 */
__global__ void knn_kernel(const float2 * __restrict__ query,
                           int query_count,
                           const float2 * __restrict__ data,
                           int data_count,
                           int k,
                           std::pair<int, float> * __restrict__ result)
{
    int qid = blockIdx.x;
    if (qid >= query_count) {
        return;
    }

    // Shared memory for per-block (per-query) computations.
    __shared__ float  s_dist[CHUNK_SIZE];   // Distances for current chunk
    __shared__ int    s_idx[CHUNK_SIZE];    // Corresponding data indices

    __shared__ float  topk_dist[MAX_K];     // Global top-k distances for this query (sorted)
    __shared__ int    topk_idx[MAX_K];      // Global top-k indices for this query (sorted)

    __shared__ float  temp_dist[MAX_K];     // Temporary buffer for merging
    __shared__ int    temp_idx[MAX_K];      // Temporary buffer for merging

    __shared__ int    s_current_k;          // Current number of valid entries in topk arrays
    __shared__ float2 s_query;              // Query point for this block

    // Initialize query and current_k once per block
    if (threadIdx.x == 0) {
        s_query     = query[qid];
        s_current_k = 0;
    }
    __syncthreads();

    float qx = s_query.x;
    float qy = s_query.y;

    int num_chunks = (data_count + CHUNK_SIZE - 1) / CHUNK_SIZE;

    // Process data in chunks
    for (int chunk = 0; chunk < num_chunks; ++chunk) {
        int base = chunk * CHUNK_SIZE;
        int chunk_size = data_count - base;
        if (chunk_size > CHUNK_SIZE) {
            chunk_size = CHUNK_SIZE;
        }

        // Compute distances for this chunk in parallel
        for (int offset = threadIdx.x; offset < CHUNK_SIZE; offset += blockDim.x) {
            int idx_global = base + offset;
            if (idx_global < data_count) {
                float2 p = data[idx_global];
                float dx = p.x - qx;
                float dy = p.y - qy;
                s_dist[offset] = dx * dx + dy * dy;  // squared Euclidean distance
                s_idx[offset]  = idx_global;
            } else {
                // Out-of-range entries are filled with +INF so they sort to the end
                s_dist[offset] = FLT_MAX;
                s_idx[offset]  = -1;
            }
        }
        __syncthreads();

        // Sort the entire chunk (CHUNK_SIZE elements) by distance ascending
        bitonic_sort_shared<CHUNK_SIZE>(s_dist, s_idx);
        __syncthreads();

        // Thread 0 merges this chunk's best local_k neighbors with the global top-k
        if (threadIdx.x == 0) {
            int cur_k   = s_current_k;
            int local_k = k;
            if (local_k > chunk_size) {
                local_k = chunk_size;
            }

            // Merge two sorted lists:
            //  - topk_dist[0..cur_k)
            //  - s_dist[0..local_k)
            // into temp_dist[0..new_k), keeping at most k elements.
            int i = 0;      // index in global top-k
            int j = 0;      // index in chunk best
            int t = 0;      // index in temp

            // Merge until one list is exhausted or we have k elements
            while (t < k && i < cur_k && j < local_k) {
                if (topk_dist[i] <= s_dist[j]) {
                    temp_dist[t] = topk_dist[i];
                    temp_idx[t]  = topk_idx[i];
                    ++i;
                } else {
                    temp_dist[t] = s_dist[j];
                    temp_idx[t]  = s_idx[j];
                    ++j;
                }
                ++t;
            }

            // Copy any remaining elements from global top-k
            while (t < k && i < cur_k) {
                temp_dist[t] = topk_dist[i];
                temp_idx[t]  = topk_idx[i];
                ++i;
                ++t;
            }

            // Copy any remaining elements from chunk's best
            while (t < k && j < local_k) {
                temp_dist[t] = s_dist[j];
                temp_idx[t]  = s_idx[j];
                ++j;
                ++t;
            }

            // t is the new current_k (never exceeds k)
            s_current_k = t;

            // Copy merged result back into topk arrays
            for (int m = 0; m < t; ++m) {
                topk_dist[m] = temp_dist[m];
                topk_idx[m]  = temp_idx[m];
            }
        }
        __syncthreads();
    }

    // Write final top-k results for this query to global memory.
    // topk_dist/topk_idx are sorted ascending by distance.
    int final_k = s_current_k;  // Should be exactly k since data_count >= k
    for (int j = threadIdx.x; j < k; j += blockDim.x) {
        int out_idx = qid * k + j;
        if (j < final_k) {
            result[out_idx].first  = topk_idx[j];
            result[out_idx].second = topk_dist[j];
        } else {
            // Safety fallback; should not occur when data_count >= k.
            result[out_idx].first  = -1;
            result[out_idx].second = FLT_MAX;
        }
    }
}

/*
 * Host entry point.
 *
 * Parameters:
 *  - query:       device pointer to array of query_count float2 points
 *  - query_count: number of queries
 *  - data:        device pointer to array of data_count float2 points
 *  - data_count:  number of data points
 *  - result:      device pointer to array of size query_count * k of std::pair<int,float>
 *  - k:           number of nearest neighbors to find (power of two in [32,1024])
 *
 * Assumptions:
 *  - All pointers are device pointers allocated with cudaMalloc.
 *  - data_count >= k.
 *  - query_count, data_count are large enough to benefit from GPU parallelism.
 */
void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    // Clamp k to supported maximum; per problem statement, this should never trigger.
    if (k > MAX_K) {
        k = MAX_K;
    }

    dim3 block(BLOCK_SIZE);
    dim3 grid(query_count);  // One block per query

    knn_kernel<<<grid, block>>>(query, query_count, data, data_count, k, result);

    // Synchronize to ensure results are ready when run_knn returns.
    // For maximum performance in more complex applications, the caller
    // may choose to remove this synchronize and manage streams explicitly.
    cudaDeviceSynchronize();
}

#include <cuda_runtime.h>
#include <utility>

// This implementation assigns one GPU thread to each query point.
// Each thread scans all data points and maintains a per-thread fixed-size
// max-heap of size K containing the K nearest neighbors found so far.
//
// Rationale:
//   - The number of queries is on the order of thousands, which provides
//     enough parallelism (thousands of threads) to keep modern GPUs busy.
//   - Each thread independently processes its query, avoiding inter-thread
//     synchronization and shared-memory complexity.
//   - A max-heap gives O(log K) insertion per candidate, which is important
//     for large K (up to 1024) and large data_count (millions).
//   - We compute squared Euclidean distance (no sqrt) to minimize ALU cost.
//
// Notes:
//   - K is known at compile time via template parameter, enabling the
//     compiler to optimize loops around heap operations.
//   - For K=1024, the per-thread heap arrays reside in local memory (backed
//     by global memory). This is unavoidable because K is large enough that
//     storing all values in registers or shared memory per thread would
//     severely limit occupancy. However, the dominating cost remains the
//     O(query_count * data_count) distance computations and global loads,
//     so this is an acceptable tradeoff.
//   - The final result for each query is sorted by increasing distance
//     (result[i * K + 0] is the nearest neighbor).

namespace {

// Max-heap helper: sift element at index `idx` upward to restore heap property.
template <int K>
__device__ __forceinline__
void heap_sift_up(float* __restrict__ heap_dist,
                  int*   __restrict__ heap_idx,
                  int idx)
{
    // Max-heap: parent index for current node.
    while (idx > 0) {
        int parent = (idx - 1) >> 1;
        if (heap_dist[parent] >= heap_dist[idx])
            break;
        // Swap parent and current.
        float tmpd = heap_dist[parent];
        heap_dist[parent] = heap_dist[idx];
        heap_dist[idx] = tmpd;

        int tmpi = heap_idx[parent];
        heap_idx[parent] = heap_idx[idx];
        heap_idx[idx] = tmpi;

        idx = parent;
    }
}

// Max-heap helper: sift element at index `idx` downward to restore heap property.
template <int K>
__device__ __forceinline__
void heap_sift_down(float* __restrict__ heap_dist,
                    int*   __restrict__ heap_idx,
                    int    heap_size,
                    int    idx)
{
    while (true) {
        int left  = (idx << 1) + 1;
        int right = left + 1;
        int largest = idx;

        if (left < heap_size && heap_dist[left] > heap_dist[largest]) {
            largest = left;
        }
        if (right < heap_size && heap_dist[right] > heap_dist[largest]) {
            largest = right;
        }
        if (largest == idx) {
            break;
        }

        // Swap current and largest child.
        float tmpd = heap_dist[largest];
        heap_dist[largest] = heap_dist[idx];
        heap_dist[idx] = tmpd;

        int tmpi = heap_idx[largest];
        heap_idx[largest] = heap_idx[idx];
        heap_idx[idx] = tmpi;

        idx = largest;
    }
}

// Max-heap helper: insert a new (distance, index) into the heap.
// If heap is not full, grows the heap. If full, replaces the root if the
// new distance is smaller than the current maximum.
template <int K>
__device__ __forceinline__
void heap_insert(float d,
                 int   idx_val,
                 float* __restrict__ heap_dist,
                 int*   __restrict__ heap_idx,
                 int&   heap_size)
{
    if (heap_size < K) {
        // Insert at end and sift up.
        int pos = heap_size;
        heap_dist[pos] = d;
        heap_idx[pos]  = idx_val;
        heap_sift_up<K>(heap_dist, heap_idx, pos);
        ++heap_size;
    } else {
        // Heap is full: only insert if new distance is smaller than current max.
        if (d < heap_dist[0]) {
            heap_dist[0] = d;
            heap_idx[0]  = idx_val;
            heap_sift_down<K>(heap_dist, heap_idx, heap_size, 0);
        }
    }
}

// Pop the maximum element from the heap (root) and shrink heap_size by 1.
// Returns (distance, index) through references.
template <int K>
__device__ __forceinline__
void heap_pop_max(float* __restrict__ heap_dist,
                  int*   __restrict__ heap_idx,
                  int&   heap_size,
                  float& out_dist,
                  int&   out_idx)
{
    out_dist = heap_dist[0];
    out_idx  = heap_idx[0];

    int last = heap_size - 1;
    heap_dist[0] = heap_dist[last];
    heap_idx[0]  = heap_idx[last];
    --heap_size;

    if (heap_size > 0) {
        heap_sift_down<K>(heap_dist, heap_idx, heap_size, 0);
    }
}

// Kernel: one thread per query. Each thread builds a max-heap of size K
// containing the K nearest neighbors for its query.
template <int K>
__global__
void knn_kernel(const float2* __restrict__ query,
                int                     query_count,
                const float2* __restrict__ data,
                int                     data_count,
                std::pair<int, float>* __restrict__ result)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid >= query_count) {
        return;
    }

    // Load query point into registers.
    float2 q = query[tid];
    float qx = q.x;
    float qy = q.y;

    // Per-thread max-heap for top-K nearest neighbors.
    // For large K these arrays reside in local memory (backed by global),
    // which is acceptable given that distance computations dominate runtime.
    float heap_dist[K];
    int   heap_idx[K];
    int   heap_size = 0;

    // Scan all data points.
    for (int j = 0; j < data_count; ++j) {
        float2 p = data[j];
        float dx = qx - p.x;
        float dy = qy - p.y;
        float d2 = dx * dx + dy * dy;  // squared Euclidean distance

        heap_insert<K>(d2, j, heap_dist, heap_idx, heap_size);
    }

    // At this point, heap_size == K (because data_count >= K).
    // We now extract elements from the max-heap into the result array
    // in ascending order of distance:
    //   - Popping from a max-heap gives elements in descending order.
    //   - We fill the output from the end to the beginning so that
    //     result[0] is the nearest (smallest distance).
    int base = tid * K;
    for (int out_pos = heap_size - 1; out_pos >= 0; --out_pos) {
        float d;
        int   idx_val;
        heap_pop_max<K>(heap_dist, heap_idx, heap_size, d, idx_val);

        std::pair<int, float>& r = result[base + out_pos];
        r.first  = idx_val;
        r.second = d;
    }
}

} // anonymous namespace

// Host-side launcher.
// query   : device pointer to array of query_count float2 points.
// data    : device pointer to array of data_count float2 points.
// result  : device pointer to array of query_count * k std::pair<int,float>.
// k       : power of two between 32 and 1024 inclusive.
//
// The function launches a CUDA kernel specialized for the given k.
// No additional device memory is allocated here; all buffers are
// expected to be allocated by the caller using cudaMalloc.
void run_knn(const float2* query,
             int           query_count,
             const float2* data,
             int           data_count,
             std::pair<int, float>* result,
             int           k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    // Tune threads per block for modern NVIDIA GPUs.
    // 256 threads per block is a reasonable default balancing occupancy
    // and per-thread resource usage.
    const int block_size = 256;
    int grid_size = (query_count + block_size - 1) / block_size;

    switch (k) {
        case 32:
            knn_kernel<32><<<grid_size, block_size>>>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_kernel<64><<<grid_size, block_size>>>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_kernel<128><<<grid_size, block_size>>>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_kernel<256><<<grid_size, block_size>>>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_kernel<512><<<grid_size, block_size>>>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_kernel<1024><<<grid_size, block_size>>>(query, query_count, data, data_count, result);
            break;
        default:
            // According to the problem statement, k is always a power of two
            // between 32 and 1024 inclusive, so we should never get here.
            // If we do, fall back to the nearest larger supported K by
            // clamping to [32, 1024] and rounding up to power of two.
            {
                int kk = k;
                if (kk < 32) kk = 32;
                if (kk > 1024) kk = 1024;

                // Round up to next power of two within [32, 1024].
                int pow2 = 32;
                while (pow2 < kk && pow2 < 1024) {
                    pow2 <<= 1;
                }

                switch (pow2) {
                    case 32:
                        knn_kernel<32><<<grid_size, block_size>>>(query, query_count, data, data_count, result);
                        break;
                    case 64:
                        knn_kernel<64><<<grid_size, block_size>>>(query, query_count, data, data_count, result);
                        break;
                    case 128:
                        knn_kernel<128><<<grid_size, block_size>>>(query, query_count, data, data_count, result);
                        break;
                    case 256:
                        knn_kernel<256><<<grid_size, block_size>>>(query, query_count, data, data_count, result);
                        break;
                    case 512:
                        knn_kernel<512><<<grid_size, block_size>>>(query, query_count, data, data_count, result);
                        break;
                    case 1024:
                    default:
                        knn_kernel<1024><<<grid_size, block_size>>>(query, query_count, data, data_count, result);
                        break;
                }
            }
            break;
    }

    // The caller can choose whether to synchronize and check for errors.
    // cudaDeviceSynchronize() and error handling are intentionally omitted
    // to keep this function as a pure launcher.
}

