#include <cuda_runtime.h>
#include <utility>

// ============================================================================
// Optimized k-NN (k-nearest neighbors) for 2D points using CUDA
// Target hardware: modern NVIDIA data-center GPUs (e.g., A100, H100)
// ============================================================================
//
// High-level algorithm overview (per query):
// -----------------------------------------
// 1. Each query is processed by a single thread block.
// 2. The block is split into several warps; each warp processes a disjoint
//    subset of the data points in a strided manner.
// 3. For each warp, lane threads compute distances to their assigned data
//    points. The distances and indices from all lanes in a warp are collected
//    into per-warp shared memory buffers.
// 4. Lane 0 of each warp maintains a max-heap (of size k) in shared memory
//    containing the k best candidates (smallest distances) seen by that warp.
//    The heap insertion is O(log k).
// 5. After all data points are processed, thread 0 of the block merges all
//    per-warp heaps into a final block-level max-heap of size k.
// 6. The final heap is heap-sorted in-place to obtain the k nearest neighbors
//    in ascending order of distance.
// 7. The results (indices and distances) are written to the output array.
//
// Data layout assumptions:
// ------------------------
// - query:  query_count elements of float2 (x, y)
// - data:   data_count elements of float2 (x, y)
// - result: query_count * k elements of std::pair<int, float>
//   For query i, result[i * k + j] holds the j-th nearest neighbor
//   data index and squared distance.
//
// Performance considerations:
// ---------------------------
// - One block per query ensures good parallelism for thousands of queries.
// - Each block uses WARPS_PER_BLOCK warps; each warp scans a ~1/W subset
//   of the data.
// - Heap sizes per warp and for the final heap are exactly k, where
//   k ∈ [32, 1024] and is a power of two.
// - Shared memory is used for per-warp heaps and staging buffers; no
//   additional global memory allocations are performed.
// - The number of threads per block and the amount of shared memory are
//   chosen so that the kernel runs within the default dynamic shared memory
//   limit on A100/H100 without requiring cudaFuncSetAttribute.
//
// ============================================================================

constexpr int KNN_WARP_SIZE        = 32;
constexpr int KNN_WARPS_PER_BLOCK  = 4;   // 4 warps * 32 threads = 128 threads per block

// ============================================================================
// Device-side heap utilities (max-heap) for distances
// ----------------------------------------------------------------------------
// We maintain a max-heap of size up to 'capacity'. The root (index 0)
// holds the largest distance among the elements in the heap. This allows
// efficient maintenance of the k smallest distances: new candidates are
// inserted only if they are better (smaller) than the current worst
// candidate at the root.
// ============================================================================

__device__ __forceinline__ void max_heap_sift_up(float* heap_dist, int* heap_idx, int index)
{
    // Standard max-heap "bubble up" operation to restore heap property
    while (index > 0)
    {
        int parent = (index - 1) >> 1;
        if (heap_dist[parent] >= heap_dist[index])
            break;

        // Swap parent and current
        float tmp_dist = heap_dist[parent];
        heap_dist[parent] = heap_dist[index];
        heap_dist[index] = tmp_dist;

        int tmp_idx = heap_idx[parent];
        heap_idx[parent] = heap_idx[index];
        heap_idx[index] = tmp_idx;

        index = parent;
    }
}

__device__ __forceinline__ void max_heap_sift_down(float* heap_dist, int* heap_idx, int index, int size)
{
    // Standard max-heap "sift down" operation to restore heap property
    while (true)
    {
        int left  = (index << 1) + 1;
        if (left >= size)
            break;  // No children

        int right = left + 1;
        int largest = left;

        if (right < size && heap_dist[right] > heap_dist[left])
            largest = right;

        if (heap_dist[index] >= heap_dist[largest])
            break;

        // Swap current with largest child
        float tmp_dist = heap_dist[index];
        heap_dist[index] = heap_dist[largest];
        heap_dist[largest] = tmp_dist;

        int tmp_idx = heap_idx[index];
        heap_idx[index] = heap_idx[largest];
        heap_idx[largest] = tmp_idx;

        index = largest;
    }
}

__device__ __forceinline__ void max_heap_insert(
    float* __restrict__ heap_dist,
    int*   __restrict__ heap_idx,
    int&   size,
    int    capacity,
    float  new_dist,
    int    new_idx)
{
    // Insert a new (distance, index) into a fixed-capacity max-heap.
    // Only distances smaller than the current maximum (heap root) are kept
    // once the heap is full.

    if (capacity <= 0)
        return;

    if (size < capacity)
    {
        // Heap not full: append new element and sift up
        int pos = size;
        heap_dist[pos] = new_dist;
        heap_idx[pos]  = new_idx;
        ++size;
        max_heap_sift_up(heap_dist, heap_idx, pos);
    }
    else
    {
        // Heap full: only insert if better (smaller distance) than current max
        if (new_dist >= heap_dist[0])
            return;

        heap_dist[0] = new_dist;
        heap_idx[0]  = new_idx;
        max_heap_sift_down(heap_dist, heap_idx, 0, size);
    }
}

__device__ __forceinline__ void max_heap_sort(float* heap_dist, int* heap_idx, int size)
{
    // In-place heap sort for a max-heap:
    // After this, heap_dist[0..size-1] are in ascending order, and heap_idx
    // is permuted correspondingly.

    for (int i = size - 1; i > 0; --i)
    {
        // Swap root (largest) with the last element in current heap range
        float tmp_dist = heap_dist[0];
        heap_dist[0] = heap_dist[i];
        heap_dist[i] = tmp_dist;

        int tmp_idx = heap_idx[0];
        heap_idx[0] = heap_idx[i];
        heap_idx[i] = tmp_idx;

        // Restore heap property on the reduced heap [0..i-1]
        max_heap_sift_down(heap_dist, heap_idx, 0, i);
    }
}

// ============================================================================
// CUDA kernel: k-NN for 2D points (squared Euclidean distance)
// ============================================================================

__global__ void knn_kernel(
    const float2* __restrict__ query,
    int                         query_count,
    const float2* __restrict__ data,
    int                         data_count,
    std::pair<int, float>* __restrict__ result,
    int                         k)
{
    const int query_idx = blockIdx.x;
    if (query_idx >= query_count)
        return;

    // Load the query point into registers (shared across all threads of the block)
    const float2 q = query[query_idx];
    const float  qx = q.x;
    const float  qy = q.y;

    // ------------------------------------------------------------------------
    // Shared memory layout (dynamic shared memory):
    //
    // - warp_heap_dist  : [KNN_WARPS_PER_BLOCK][k]    (float)
    // - warp_heap_idx   : [KNN_WARPS_PER_BLOCK][k]    (int)
    // - final_heap_dist : [k]                         (float)
    // - final_heap_idx  : [k]                         (int)
    // - warp_input_dist : [KNN_WARPS_PER_BLOCK][32]   (float)
    // - warp_input_idx  : [KNN_WARPS_PER_BLOCK][32]   (int)
    // - warp_heap_sizes : [KNN_WARPS_PER_BLOCK]       (int)
    //
    // All arrays reside in a single contiguous dynamic shared memory block.
    // ------------------------------------------------------------------------

    extern __shared__ unsigned char shared_raw[];
    unsigned char* ptr = shared_raw;

    // Per-warp heaps (distances and indices)
    float* warp_heap_dist = reinterpret_cast<float*>(ptr);
    ptr += sizeof(float) * k * KNN_WARPS_PER_BLOCK;

    int* warp_heap_idx = reinterpret_cast<int*>(ptr);
    ptr += sizeof(int) * k * KNN_WARPS_PER_BLOCK;

    // Final block-level heap
    float* final_heap_dist = reinterpret_cast<float*>(ptr);
    ptr += sizeof(float) * k;

    int* final_heap_idx = reinterpret_cast<int*>(ptr);
    ptr += sizeof(int) * k;

    // Per-warp input staging buffers (one distance/index per lane)
    float* warp_input_dist = reinterpret_cast<float*>(ptr);
    ptr += sizeof(float) * KNN_WARP_SIZE * KNN_WARPS_PER_BLOCK;

    int* warp_input_idx = reinterpret_cast<int*>(ptr);
    ptr += sizeof(int) * KNN_WARP_SIZE * KNN_WARPS_PER_BLOCK;

    // Per-warp heap sizes (number of valid elements in each warp heap)
    int* warp_heap_sizes = reinterpret_cast<int*>(ptr);
    // ptr += sizeof(int) * KNN_WARPS_PER_BLOCK; // Not needed further

    const int tid     = threadIdx.x;
    const int warp_id = tid / KNN_WARP_SIZE;  // warp index within block
    const int lane_id = tid % KNN_WARP_SIZE;  // lane index within warp

    const int warps_per_block = KNN_WARPS_PER_BLOCK;
    const int warp_stride     = warps_per_block * KNN_WARP_SIZE; // stride over data for each warp

    // Per-warp views into shared memory
    float* heap_dist_w = warp_heap_dist + warp_id * k;
    int*   heap_idx_w  = warp_heap_idx  + warp_id * k;

    float* input_dist_w = warp_input_dist + warp_id * KNN_WARP_SIZE;
    int*   input_idx_w  = warp_input_idx  + warp_id * KNN_WARP_SIZE;

    int local_heap_size = 0; // Only meaningful for lane 0 of each warp

    // ------------------------------------------------------------------------
    // Main distance computation loop:
    // Each warp processes a disjoint subset of data points:
    //   For base = warp_id * 32; base < data_count; base += warp_stride
    //     lane i processes index (base + i) if within range.
    // Distances and indices are stored in per-warp shared buffers;
    // lane 0 of each warp then feeds them into a per-warp heap.
    // ------------------------------------------------------------------------

    for (int base = warp_id * KNN_WARP_SIZE; base < data_count; base += warp_stride)
    {
        int data_idx = base + lane_id;

        float dist = 0.0f;
        int   idx  = -1;  // -1 marks "no valid point" in this lane for this iteration

        if (data_idx < data_count)
        {
            float2 p = data[data_idx];
            float dx = p.x - qx;
            float dy = p.y - qy;
            dist = dx * dx + dy * dy;
            idx  = data_idx;
        }

        // Store to per-warp input buffers
        input_dist_w[lane_id] = dist;
        input_idx_w[lane_id]  = idx;

        // Synchronize lanes within the warp to ensure buffers are ready
        __syncwarp();

        if (lane_id == 0)
        {
            // Lane 0 consumes all 32 buffered candidates for this warp
            #pragma unroll
            for (int i = 0; i < KNN_WARP_SIZE; ++i)
            {
                int cand_idx = input_idx_w[i];
                if (cand_idx < 0)
                    continue;  // invalid entry (out-of-range data index)

                float cand_dist = input_dist_w[i];
                max_heap_insert(heap_dist_w, heap_idx_w, local_heap_size, k, cand_dist, cand_idx);
            }
        }

        // Ensure lane 0 has finished using the buffers before they are overwritten
        __syncwarp();
    }

    // Store per-warp heap sizes (only lane 0 of each warp has valid local_heap_size)
    if (lane_id == 0)
    {
        warp_heap_sizes[warp_id] = local_heap_size;
    }

    // Synchronize all threads in the block before merging heaps
    __syncthreads();

    // ------------------------------------------------------------------------
    // Merge per-warp heaps into a single block-level heap and output results.
    // Only thread 0 performs the merge and final sorting.
    // ------------------------------------------------------------------------
    if (tid == 0)
    {
        int final_heap_size = 0;

        // Merge all warp heaps into final heap
        for (int w = 0; w < warps_per_block; ++w)
        {
            int w_size = warp_heap_sizes[w];
            float* hd = warp_heap_dist + w * k;
            int*   hi = warp_heap_idx  + w * k;

            for (int i = 0; i < w_size; ++i)
            {
                max_heap_insert(final_heap_dist, final_heap_idx, final_heap_size, k, hd[i], hi[i]);
            }
        }

        // At this point, final_heap_dist/final_heap_idx form a max-heap containing
        // the k nearest neighbors (or fewer if data_count < k). Given the problem
        // constraints (data_count >= k), final_heap_size will be exactly k.

        max_heap_sort(final_heap_dist, final_heap_idx, final_heap_size);

        // Write sorted results for this query to global memory
        const int out_base = query_idx * k;
        for (int i = 0; i < k; ++i)
        {
            result[out_base + i].first  = final_heap_idx[i];
            result[out_base + i].second = final_heap_dist[i];
        }
    }
}

// ============================================================================
// Host-side wrapper: run_knn
// ============================================================================

void run_knn(
    const float2*              query,
    int                        query_count,
    const float2*              data,
    int                        data_count,
    std::pair<int, float>*     result,
    int                        k)
{
    // Basic sanity check (parameters are assumed valid as per problem statement)
    if (query_count <= 0 || data_count <= 0 || k <= 0)
        return;

    dim3 block_dim(KNN_WARP_SIZE * KNN_WARPS_PER_BLOCK);  // 128 threads per block
    dim3 grid_dim(query_count);                           // one block per query

    // Compute required dynamic shared memory size
    size_t shared_bytes = 0;
    shared_bytes += sizeof(float) * k * KNN_WARPS_PER_BLOCK;            // warp_heap_dist
    shared_bytes += sizeof(int)   * k * KNN_WARPS_PER_BLOCK;            // warp_heap_idx
    shared_bytes += sizeof(float) * k;                                  // final_heap_dist
    shared_bytes += sizeof(int)   * k;                                  // final_heap_idx
    shared_bytes += sizeof(float) * KNN_WARP_SIZE * KNN_WARPS_PER_BLOCK; // warp_input_dist
    shared_bytes += sizeof(int)   * KNN_WARP_SIZE * KNN_WARPS_PER_BLOCK; // warp_input_idx
    shared_bytes += sizeof(int)   * KNN_WARPS_PER_BLOCK;                // warp_heap_sizes

    // Launch kernel (asynchronous)
    knn_kernel<<<grid_dim, block_dim, shared_bytes>>>(query,
                                                      query_count,
                                                      data,
                                                      data_count,
                                                      result,
                                                      k);
}

#include <cuda_runtime.h>
#include <utility>

/*
 * Optimized k-NN CUDA implementation for 2D points.
 *
 * Key design choices:
 * - Each CUDA thread processes one query point.
 * - Data points are processed in tiles stored in shared memory to maximize
 *   reuse across threads in a block and minimize global memory traffic.
 * - Each thread maintains its own top-k structure using a max-heap
 *   (represented by two parallel arrays: distances and indices).
 * - The heap size k is a compile-time template parameter, and run_knn()
 *   dispatches to the appropriate kernel instantiation for each supported k.
 * - The final heap is converted to a sorted array (ascending distance)
 *   using heapsort, and written to the output array.
 *
 * Constraints honored:
 * - No additional device memory allocations (no cudaMalloc in device code).
 * - k is a power of two in [32, 1024], inclusive.
 * - data_count >= k is guaranteed.
 */

/********************* Device-side helper utilities ************************/

// Tile size for loading data points into shared memory.
// 1024 points * sizeof(float2) = 8 KB of shared memory per block.
constexpr int DATA_TILE_SIZE = 1024;

/*
 * Sift-down operation for a max-heap stored in parallel arrays dist / idx.
 * Template parameter K is the maximum heap capacity; heapSize is the current
 * active size (can be <= K, e.g., during heapsort).
 *
 * This function assumes:
 * - dist[0..heapSize-1], idx[0..heapSize-1] contain a valid heap except
 *   possibly at position 'start'.
 * - After return, the max-heap property is restored for the range [0, heapSize).
 */
template <int K>
__device__ __forceinline__ void siftDown(float *dist, int *idx, int start, int heapSize)
{
    int root = start;
    float rootDist = dist[root];
    int rootIdx = idx[root];

    int child = (root << 1) + 1;  // left child index

    while (child < heapSize)
    {
        int right = child + 1;
        int swapIdx = child;
        float swapDist = dist[child];

        if (right < heapSize)
        {
            float rightDist = dist[right];
            if (rightDist > swapDist)
            {
                swapIdx = right;
                swapDist = rightDist;
            }
        }

        if (rootDist >= swapDist)
        {
            // Root is larger than both children; heap property satisfied.
            break;
        }

        // Move larger child up.
        dist[root] = swapDist;
        idx[root] = idx[swapIdx];

        root = swapIdx;
        child = (root << 1) + 1;
    }

    dist[root] = rootDist;
    idx[root] = rootIdx;
}

/*
 * Build a max-heap in-place from an unsorted array of size K.
 * Uses bottom-up heap construction (O(K)).
 */
template <int K>
__device__ __forceinline__ void buildMaxHeap(float *dist, int *idx)
{
    // Start from the last parent node and sift down to restore heap property.
    for (int i = (K >> 1) - 1; i >= 0; --i)
    {
        siftDown<K>(dist, idx, i, K);
    }
}

/*
 * Convert a max-heap to a sorted array in ascending order using heapsort.
 * Precondition: dist / idx represent a valid max-heap of size K.
 * Postcondition: dist / idx are sorted so that dist[0] <= dist[1] <= ... <= dist[K-1].
 */
template <int K>
__device__ __forceinline__ void heapSortAscending(float *dist, int *idx)
{
    for (int end = K - 1; end > 0; --end)
    {
        // Move current maximum (root) to the end of the active range.
        float tmpDist = dist[0];
        dist[0] = dist[end];
        dist[end] = tmpDist;

        int tmpIdx = idx[0];
        idx[0] = idx[end];
        idx[end] = tmpIdx;

        // Restore heap property in the reduced range [0, end).
        siftDown<K>(dist, idx, 0, end);
    }
}

/***************************** CUDA kernel **********************************/

/*
 * Templated k-NN kernel for 2D points.
 *
 * Template parameter K is the number of nearest neighbors to find.
 *
 * Each thread:
 * - Loads one query point.
 * - Iterates over all data points in tiles loaded into shared memory.
 * - Maintains a per-thread max-heap of size K with the best candidates.
 * - After processing all data, sorts the heap and writes the k nearest
 *   neighbors (index + distance) to the output array.
 *
 * Grid/block layout:
 * - blockDim.x = number of threads per block (chosen in run_knn()).
 * - gridDim.x  = ceil(query_count / blockDim.x).
 */
template <int K>
__global__ void knn_kernel_2d(const float2 *__restrict__ query,
                              int query_count,
                              const float2 *__restrict__ data,
                              int data_count,
                              std::pair<int, float> *__restrict__ result)
{
    __shared__ float2 dataTile[DATA_TILE_SIZE];

    const int tid = threadIdx.x;
    const int globalQueryIdx = blockIdx.x * blockDim.x + tid;

    const bool active = (globalQueryIdx < query_count);

    // Per-thread k-NN heap storage: distances and indices.
    // K is a compile-time constant, and data_count >= K (as per problem spec).
    float heapDist[K];
    int   heapIdx[K];

    int count = 0;  // Number of data points processed so far by this thread.

    // Load query point into register for active threads.
    float2 q;
    if (active)
    {
        q = query[globalQueryIdx];
    }

    // Loop over data in tiles.
    for (int base = 0; base < data_count; base += DATA_TILE_SIZE)
    {
        int tileSize = DATA_TILE_SIZE;
        if (base + tileSize > data_count)
        {
            tileSize = data_count - base;
        }

        // Load tile of data points into shared memory (all threads cooperate).
        for (int t = tid; t < tileSize; t += blockDim.x)
        {
            dataTile[t] = data[base + t];
        }

        __syncthreads();

        if (active)
        {
            // Process this tile for the current query point.
            for (int j = 0; j < tileSize; ++j)
            {
                const float2 p = dataTile[j];

                const float dx = p.x - q.x;
                const float dy = p.y - q.y;

                // Squared Euclidean distance (no sqrt needed).
                const float dist = fmaf(dx, dx, dy * dy);
                const int   idx  = base + j;

                if (count < K)
                {
                    // Fill initial buffer until we have K elements.
                    heapDist[count] = dist;
                    heapIdx[count]  = idx;
                    ++count;

                    // Once we reach K elements, build the initial max-heap.
                    if (count == K)
                    {
                        buildMaxHeap<K>(heapDist, heapIdx);
                    }
                }
                else
                {
                    // Heap is full: keep only if better than current worst.
                    if (dist < heapDist[0])
                    {
                        heapDist[0] = dist;
                        heapIdx[0]  = idx;
                        siftDown<K>(heapDist, heapIdx, 0, K);
                    }
                }
            }
        }

        __syncthreads();
    }

    if (active)
    {
        // At this point, data_count >= K ensures count >= K.
        // heapDist / heapIdx represent a max-heap of size K.

        // Sort heap in ascending order of distance.
        heapSortAscending<K>(heapDist, heapIdx);

        // Write results for this query: result[query * K + j] = j-th nearest neighbor.
        const int outBase = globalQueryIdx * K;
        for (int j = 0; j < K; ++j)
        {
            result[outBase + j].first  = heapIdx[j];
            result[outBase + j].second = heapDist[j];
        }
    }
}

/***************************** Host interface *******************************/

/*
 * Host function to launch the appropriate k-NN kernel specialization.
 *
 * Parameters:
 * - query:  device pointer to array of float2 (queries), size query_count.
 * - query_count: number of query points.
 * - data:   device pointer to array of float2 (data points), size data_count.
 * - data_count: number of data points.
 * - result: device pointer to array of std::pair<int,float>, size query_count * k.
 * - k:      number of nearest neighbors to find; power of two in [32, 1024].
 */
void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    // Reasonable default block size for modern data center GPUs.
    // 128 threads per block balances occupancy and per-block workload.
    constexpr int BLOCK_SIZE = 128;

    dim3 block(BLOCK_SIZE);
    dim3 grid((query_count + BLOCK_SIZE - 1) / BLOCK_SIZE);

    // Dispatch to a kernel instantiation with compile-time K.
    switch (k)
    {
        case 32:
            knn_kernel_2d<32><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_kernel_2d<64><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_kernel_2d<128><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_kernel_2d<256><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_kernel_2d<512><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_kernel_2d<1024><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
        default:
            // The problem guarantees k is one of {32, 64, 128, 256, 512, 1024},
            // so this path should not be hit. For robustness, we fall back to
            // the largest supported K (1024) and only use the first k results.
            knn_kernel_2d<1024><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
    }

    // Synchronize to ensure completion before returning to the host.
    cudaDeviceSynchronize();
}

#include <cuda_runtime.h>
#include <utility>
#include <cfloat>

// -------------------------------------------------------------------------------------------------
// Optimized brute-force k-NN for 2D points on modern NVIDIA GPUs (A100 / H100).
//
// - Each CUDA thread processes one query point.
// - All threads in a block cooperatively load tiles of the data points into shared memory.
// - Each thread scans all data points, computing distances to its query.
// - For each query, a per-thread max-heap of size K (K = k) is maintained in local memory,
//   holding the current k nearest neighbors (smallest distances).
// - To insert a candidate distance d:
//     * If we haven't filled the heap yet, we append it.
//     * Once we have K elements, we build an initial max-heap.
//     * Afterwards, for each new distance d, if d < heap[0] (the current worst among the k best),
//       we replace the root and sift-down to restore max-heap property.
// - After scanning all data points, we perform an in-place heap sort on the per-thread heap,
//   which converts the max-heap into an array sorted by ascending distance.
// - The sorted (index, distance) pairs are written to the result array as std::pair<int,float>.
//
// Design notes:
//   * Complexity per query: O(N log K) distance candidates with extremely cheap log K (~10) for K<=1024.
//   * k is a power of two between 32 and 1024 inclusive; we use template specialization on K
//     for best performance and to allow fixed-size arrays.
//   * We only allocate shared memory for a tile of data points; no extra global memory is allocated.
//   * Local thread heaps are stored in thread-local memory (which may spill to global and be cached).
//   * Block size and tile size are chosen to provide good occupancy and memory reuse.
// -------------------------------------------------------------------------------------------------

// Tune these for the target GPU if needed.
#ifndef KNN_BLOCK_DIM
#define KNN_BLOCK_DIM 128    // threads per block (queries processed per block)
#endif

#ifndef KNN_TILE_DATA
#define KNN_TILE_DATA 256    // number of data points loaded per tile into shared memory
#endif

// -------------------------------------------------------------------------------------------------
// Device helper: sift-down operation for a max-heap stored in flat arrays.
//
// heap_dist, heap_idx : arrays of length >= heap_size
// idx                 : index to start sifting down from (usually 0)
// heap_size           : number of elements in the heap [0, heap_size)
// -------------------------------------------------------------------------------------------------
template<int K>
__device__ __forceinline__
void heap_sift_down(float (&heap_dist)[K], int (&heap_idx)[K], int idx, int heap_size)
{
    while (true) {
        int left  = (idx << 1) + 1;  // left child
        if (left >= heap_size) {
            break; // no children
        }
        int right = left + 1;        // right child

        int   largest    = idx;
        float largestVal = heap_dist[idx];

        float leftVal = heap_dist[left];
        if (leftVal > largestVal) {
            largest    = left;
            largestVal = leftVal;
        }

        if (right < heap_size) {
            float rightVal = heap_dist[right];
            if (rightVal > largestVal) {
                largest    = right;
                largestVal = rightVal;
            }
        }

        if (largest == idx) {
            break; // heap property satisfied
        }

        // Swap current node with the largest child
        float tmpd          = heap_dist[idx];
        heap_dist[idx]      = heap_dist[largest];
        heap_dist[largest]  = tmpd;

        int tmpi            = heap_idx[idx];
        heap_idx[idx]       = heap_idx[largest];
        heap_idx[largest]   = tmpi;

        idx = largest;
    }
}

// -------------------------------------------------------------------------------------------------
// Device kernel: brute-force k-NN for 2D points with per-thread max-heap.
// Template parameters:
//   K    : number of neighbors to keep (k)
//   TILE : tile size for shared-memory loads of data points
//
// Each thread processes a single query point.
// -------------------------------------------------------------------------------------------------
template<int K, int TILE>
__global__
void knn_kernel_2d(const float2* __restrict__ query,
                   int                 query_count,
                   const float2* __restrict__ data,
                   int                 data_count,
                   std::pair<int, float>* __restrict__ result)
{
    // Shared memory tile for data points
    __shared__ float2 sh_data[TILE];

    const int tid       = threadIdx.x;
    const int q_global  = blockIdx.x * blockDim.x + tid;
    const bool valid    = (q_global < query_count);

    // Load query point into a register for faster access
    float2 q;
    if (valid) {
        q = query[q_global];
    }

    // Per-thread heap storage: distances and corresponding data indices.
    // We maintain a max-heap of size K.
    float heap_dist[K];
    int   heap_idx[K];
    int   filled = 0;          // number of elements currently in heap (up to K)
    bool  heap_built = false;  // whether we've built the initial max-heap

    // Loop over data points in tiles
    for (int base = 0; base < data_count; base += TILE) {
        int tile_size = data_count - base;
        if (tile_size > TILE) tile_size = TILE;

        // Cooperative load of data tile into shared memory.
        for (int i = tid; i < tile_size; i += blockDim.x) {
            sh_data[i] = data[base + i];
        }

        __syncthreads();

        if (valid) {
            // Process this tile for the current query
            for (int i = 0; i < tile_size; ++i) {
                int global_idx = base + i;

                float dx = q.x - sh_data[i].x;
                float dy = q.y - sh_data[i].y;
                float dist = dx * dx + dy * dy;  // squared Euclidean distance

                if (filled < K) {
                    // Still filling initial buffer; no heap property needed yet.
                    heap_dist[filled] = dist;
                    heap_idx[filled]  = global_idx;
                    ++filled;

                    // Once we have K elements, build the initial max-heap.
                    if (filled == K) {
                        for (int j = (K / 2) - 1; j >= 0; --j) {
                            heap_sift_down<K>(heap_dist, heap_idx, j, K);
                        }
                        heap_built = true;
                    }
                } else {
                    // Heap already built and full: potential replacement of max element.
                    // For a max-heap, root (index 0) holds the current worst (largest distance)
                    // among the K best; only replace it if this candidate is better (smaller).
                    if (dist < heap_dist[0]) {
                        heap_dist[0] = dist;
                        heap_idx[0]  = global_idx;
                        heap_sift_down<K>(heap_dist, heap_idx, 0, K);
                    }
                }
            }
        }

        __syncthreads();
    }

    if (!valid) {
        return;
    }

    // At this point, we must have at least K elements (data_count >= K by assumption).
    // If for some reason heap_built is still false (e.g., data_count == K),
    // we build the heap now.
    if (!heap_built) {
        // filled should equal K here, but we guard against pathological cases.
        int heap_size = (filled < K) ? filled : K;
        for (int j = (heap_size / 2) - 1; j >= 0; --j) {
            heap_sift_down<K>(heap_dist, heap_idx, j, heap_size);
        }
        heap_built = true;
    }

    // In-place heap sort of the max-heap.
    // After this, heap_dist/heap_idx will be sorted in ascending order of distance.
    for (int end = K - 1; end > 0; --end) {
        // Swap root (largest) with last element in current heap
        float tmpd         = heap_dist[0];
        heap_dist[0]       = heap_dist[end];
        heap_dist[end]     = tmpd;

        int tmpi           = heap_idx[0];
        heap_idx[0]        = heap_idx[end];
        heap_idx[end]      = tmpi;

        // Restore heap property on the reduced heap [0, end)
        heap_sift_down<K>(heap_dist, heap_idx, 0, end);
    }

    // Write out sorted results for this query.
    // result[q * K + j] = j-th nearest neighbor for this query.
    int result_base = q_global * K;
    for (int i = 0; i < K; ++i) {
        result[result_base + i].first  = heap_idx[i];
        result[result_base + i].second = heap_dist[i];
    }
}

// -------------------------------------------------------------------------------------------------
// Host interface:
//
// void run_knn(const float2 *query, int query_count,
//              const float2 *data,  int data_count,
//              std::pair<int, float> *result, int k);
//
// query, data, result are device pointers allocated via cudaMalloc.
// k is a power of two between 32 and 1024 inclusive.
// -------------------------------------------------------------------------------------------------
void run_knn(const float2 *query,
             int           query_count,
             const float2 *data,
             int           data_count,
             std::pair<int, float> *result,
             int           k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    const int block_dim = KNN_BLOCK_DIM;
    dim3 block(block_dim);
    dim3 grid((query_count + block_dim - 1) / block_dim);

    // Dispatch to a specialized kernel based on k.
    // k is guaranteed to be a power of two between 32 and 1024 inclusive.
    switch (k) {
        case 32:
            knn_kernel_2d<32, KNN_TILE_DATA><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_kernel_2d<64, KNN_TILE_DATA><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_kernel_2d<128, KNN_TILE_DATA><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_kernel_2d<256, KNN_TILE_DATA><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_kernel_2d<512, KNN_TILE_DATA><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_kernel_2d<1024, KNN_TILE_DATA><<<grid, block>>>(query, query_count, data, data_count, result);
            break;
        default:
            // k is assumed valid by problem constraints; no fallback implemented.
            break;
    }

    // Optionally, the caller can synchronize and check for errors here:
    // cudaDeviceSynchronize();
    // cudaGetLastError();
}

#include <cuda_runtime.h>
#include <utility>

/*
 * Optimized CUDA k-NN (k-nearest neighbors) for 2D points and squared Euclidean distance.
 *
 * Design overview (see individual comments for details):
 *  - One warp (32 threads) processes one query point.
 *  - Multiple warps per block (WARPS_PER_BLOCK) improve occupancy.
 *  - All 32 lanes in a warp cooperatively load and compute distances to data points in a coalesced fashion.
 *  - Lane 0 in each warp maintains a max-heap of size K (K = k) in shared memory to track the K nearest neighbors.
 *  - New candidate distances from all 32 lanes are sequentially fed to lane 0 via warp shuffles and inserted into the heap.
 *  - After processing all data points, lane 0 heap-sorts the K neighbors and writes them to the result array in ascending order.
 *
 *  This approach:
 *    - Achieves coalesced global memory access for data points.
 *    - Avoids per-thread large local arrays by using shared memory per warp.
 *    - Uses the GPU mainly for massive parallel distance computation; the inherently sequential top-k maintenance is localized to one lane per warp.
 */

static constexpr int WARP_SIZE        = 32;
static constexpr int WARPS_PER_BLOCK  = 4;                      // 4 warps per block -> 128 threads per block
static constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * WARP_SIZE;

/* ========================= Heap utilities (max-heap, K smallest elements) ========================= */

template <int K>
__device__ __forceinline__
void heap_sift_up(float *dist, int *idx, int pos)
{
    // Standard max-heap sift-up operation
    int parent = (pos - 1) >> 1;
    while (pos > 0 && dist[parent] < dist[pos]) {
        float td = dist[parent];
        dist[parent] = dist[pos];
        dist[pos] = td;

        int ti = idx[parent];
        idx[parent] = idx[pos];
        idx[pos] = ti;

        pos = parent;
        parent = (pos - 1) >> 1;
    }
}

template <int K>
__device__ __forceinline__
void heap_sift_down(float *dist, int *idx, int heap_size, int pos)
{
    // Standard max-heap sift-down operation
    while (true) {
        int left   = (pos << 1) + 1;
        int right  = left + 1;
        int largest = pos;

        if (left < heap_size && dist[left] > dist[largest]) {
            largest = left;
        }
        if (right < heap_size && dist[right] > dist[largest]) {
            largest = right;
        }
        if (largest == pos) {
            break;
        }

        float td = dist[pos];
        dist[pos] = dist[largest];
        dist[largest] = td;

        int ti = idx[pos];
        idx[pos] = idx[largest];
        idx[largest] = ti;

        pos = largest;
    }
}

template <int K>
__device__ __forceinline__
void heap_insert(float *dist, int *idx, int &heap_size, float d, int i)
{
    // Maintain a max-heap of up to K elements containing the K smallest distances seen so far.
    if (heap_size < K) {
        // Heap not full yet: insert new element and sift up.
        int pos = heap_size++;
        dist[pos] = d;
        idx[pos]  = i;
        heap_sift_up<K>(dist, idx, pos);
    } else if (d < dist[0]) {
        // New distance is better (smaller) than the current worst (root of max-heap).
        dist[0] = d;
        idx[0]  = i;
        heap_sift_down<K>(dist, idx, heap_size, 0);
    }
}

template <int K>
__device__
void heap_sort(float *dist, int *idx, int heap_size)
{
    // Heapsort to produce ascending order of distances.
    // The heap is a max-heap in dist[0 .. heap_size-1].
    for (int i = heap_size - 1; i > 0; --i) {
        // Move current largest to the end.
        float td = dist[0];
        dist[0] = dist[i];
        dist[i] = td;

        int ti = idx[0];
        idx[0] = idx[i];
        idx[i] = ti;

        // Restore heap property in reduced heap [0 .. i-1].
        heap_sift_down<K>(dist, idx, i, 0);
    }
}

/* ========================= k-NN kernel (templated by K = k) ========================= */

template <int K>
__global__
void knn_kernel_2d(const float2 * __restrict__ query,
                   int query_count,
                   const float2 * __restrict__ data,
                   int data_count,
                   std::pair<int, float> * __restrict__ result)
{
    // Shared memory heaps: one heap (size K) per warp in the block.
    __shared__ float s_heap_dist[WARPS_PER_BLOCK][K];
    __shared__ int   s_heap_idx [WARPS_PER_BLOCK][K];

    const int thread_id       = threadIdx.x;
    const int warp_id_in_block = thread_id / WARP_SIZE;              // warp index within this block [0, WARPS_PER_BLOCK)
    const int lane_id         = thread_id & (WARP_SIZE - 1);         // lane index within warp [0, 31]
    const int warp_global_id  = blockIdx.x * WARPS_PER_BLOCK + warp_id_in_block;

    // Each warp processes one query; extra warps (if any) exit.
    if (warp_global_id >= query_count) {
        return;
    }

    // Load query point. Only lane 0 does the global memory load; then broadcast to all lanes.
    float qx = 0.0f, qy = 0.0f;
    if (lane_id == 0) {
        float2 q = query[warp_global_id];
        qx = q.x;
        qy = q.y;
    }
    const unsigned full_mask = 0xFFFFFFFFu;
    qx = __shfl_sync(full_mask, qx, 0);
    qy = __shfl_sync(full_mask, qy, 0);

    // Pointers to this warp's heap in shared memory.
    float *heap_dist = s_heap_dist[warp_id_in_block];
    int   *heap_idx  = s_heap_idx[warp_id_in_block];

    // Only lane 0 will manipulate the heap, but all lanes share the underlying shared memory.
    int heap_size = 0;

    // Loop over data points in tiles of WARP_SIZE.
    // Each lane loads one data point per iteration; together the warp processes 32 points in parallel.
    for (int base = 0; base < data_count; base += WARP_SIZE) {
        const int idx_global = base + lane_id;

        // Compute squared distance for this lane's data point (if in range).
        float d = 0.0f;
        if (idx_global < data_count) {
            float2 p = data[idx_global];
            float dx = p.x - qx;
            float dy = p.y - qy;
            d = dx * dx + dy * dy;
        }

        // Feed all 32 candidates from the warp to lane 0 sequentially via warp shuffles.
        // This preserves correctness while still doing the distance computations in parallel.
        for (int s = 0; s < WARP_SIZE; ++s) {
            float cand_d   = __shfl_sync(full_mask, d, s);
            int   cand_idx = base + s;
            if (lane_id == 0 && cand_idx < data_count) {
                heap_insert<K>(heap_dist, heap_idx, heap_size, cand_d, cand_idx);
            }
        }
    }

    // After processing all data points, lane 0 sorts the heap and writes out the K nearest neighbors.
    if (lane_id == 0) {
        // Given the problem guarantee data_count >= K, heap_size should be K.
        // For robustness, use heap_size in heapsort; it will be min(K, data_count).
        heap_sort<K>(heap_dist, heap_idx, heap_size);

        const int out_base = warp_global_id * K;
        for (int i = 0; i < K; ++i) {
            result[out_base + i].first  = heap_idx[i];
            result[out_base + i].second = heap_dist[i];
        }
    }
}

/* ========================= Host-side dispatch function ========================= */

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    if (query_count <= 0 || data_count <= 0) {
        return;
    }

    dim3 block_dim(THREADS_PER_BLOCK);
    // Each block contains WARPS_PER_BLOCK warps; each warp processes one query.
    dim3 grid_dim((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    // Dispatch to a kernel instance specialized for the given power-of-two k.
    switch (k) {
        case 32:
            knn_kernel_2d<32><<<grid_dim, block_dim>>>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_kernel_2d<64><<<grid_dim, block_dim>>>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_kernel_2d<128><<<grid_dim, block_dim>>>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_kernel_2d<256><<<grid_dim, block_dim>>>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_kernel_2d<512><<<grid_dim, block_dim>>>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_kernel_2d<1024><<<grid_dim, block_dim>>>(query, query_count, data, data_count, result);
            break;
        default:
            // The problem guarantees k is a power of two between 32 and 1024 inclusive.
            // If an unsupported k is provided, do nothing.
            return;
    }

    // Synchronize to ensure completion before the host continues.
    cudaDeviceSynchronize();
}

#include <cuda_runtime.h>
#include <float.h>
#include <utility>

/*
 * Optimized brute-force k-NN for 2D points on modern NVIDIA GPUs (e.g., A100/H100).
 *
 * Algorithm overview (per query point):
 *   - Maintain the current k nearest neighbors in shared memory.
 *   - Process the entire dataset in tiles of size k (CHUNK = k).
 *   - For each tile:
 *       * Compute distances for up to k new data points and place them in the
 *         second half of a shared array of size 2*k.
 *       * Run an in-place bitonic sort on the 2*k candidate neighbors
 *         (k previous best + k new ones).
 *       * Keep only the first k entries (smallest distances) as the new top-k.
 *   - After all tiles are processed, write the final top-k list for the query
 *     into the output array.
 *
 * Notes:
 *   - k is guaranteed to be a power of two between 32 and 1024 (inclusive),
 *     and data_count >= k.
 *   - Distance measure is squared Euclidean distance in 2D.
 *   - No extra device memory is allocated; only shared memory and registers are used.
 *   - The kernel is launched with one block per query; the number of threads per
 *     block is min(256, k), which balances parallelism and shared-memory usage.
 */

constexpr int MAX_K = 1024;  // Maximum allowed k as per problem statement

// In-place bitonic sort of (distance, index) pairs in ascending order by distance.
// 'count' must be a power of two and <= 2 * MAX_K.
//
// This implementation is block-wide: all threads in the block cooperate.
// Each thread processes multiple elements with stride blockDim.x.
__device__ inline void bitonic_sort_pairs(float *dist, int *idx, int count)
{
    // Standard bitonic sort network
    for (int k = 2; k <= count; k <<= 1) {
        // Merge bitonic sequences of length 'k'
        for (int j = k >> 1; j > 0; j >>= 1) {
            __syncthreads();  // ensure previous stage's writes are visible

            for (int i = threadIdx.x; i < count; i += blockDim.x) {
                int ixj = i ^ j;
                if (ixj > i && ixj < count) {
                    // Determine whether this subsequence is sorted ascending or descending
                    bool ascending = ((i & k) == 0);

                    float di = dist[i];
                    float dj = dist[ixj];
                    int   idi = idx[i];
                    int   idj = idx[ixj];

                    // Swap if out of order for the current direction
                    bool do_swap = ascending ? (di > dj) : (di < dj);
                    if (do_swap) {
                        dist[i]  = dj;
                        dist[ixj] = di;
                        idx[i]   = idj;
                        idx[ixj] = idi;
                    }
                }
            }
        }
    }
    __syncthreads();  // final synchronization before returning
}

// Kernel: computes k nearest neighbors for each query point.
__global__ void knn_kernel_2d(
    const float2 *__restrict__ query,
    int query_count,
    const float2 *__restrict__ data,
    int data_count,
    std::pair<int, float> *__restrict__ result,
    int k)
{
    // Shared memory arrays for candidate neighbors:
    // We allocate space for up to 2 * MAX_K pairs (distance, index).
    __shared__ float s_dist[2 * MAX_K];
    __shared__ int   s_idx [2 * MAX_K];

    const int q_idx = blockIdx.x;
    if (q_idx >= query_count || k <= 0 || k > MAX_K) {
        return;
    }

    const int pair_count = 2 * k;  // number of elements actually used in shared arrays

    // Load the query point for this block
    const float2 q = query[q_idx];

    // Initialize shared arrays: set all distances in [0, 2*k) to a large value (infinity)
    // and indices to -1.
    const float INF = FLT_MAX;
    for (int i = threadIdx.x; i < pair_count; i += blockDim.x) {
        s_dist[i] = INF;
        s_idx[i]  = -1;
    }
    __syncthreads();

    // Process the data points in tiles of size 'chunk' = k.
    const int chunk = k;

    for (int base = 0; base < data_count; base += chunk) {
        int tile_count = data_count - base;
        if (tile_count > chunk) {
            tile_count = chunk;
        }

        // Compute distances for this tile and store them into the second half
        // of shared arrays: indices [k, k + tile_count).
        // Remaining entries up to [k, 2*k) are set to INF.
        for (int i = threadIdx.x; i < chunk; i += blockDim.x) {
            int slot = k + i;  // position in shared arrays for new candidates
            if (i < tile_count) {
                int data_idx = base + i;
                float2 p = data[data_idx];

                float dx = p.x - q.x;
                float dy = p.y - q.y;
                float dist = dx * dx + dy * dy;

                s_dist[slot] = dist;
                s_idx[slot]  = data_idx;
            } else if (slot < pair_count) {
                // Fill unused slots (for incomplete tiles) with INF
                s_dist[slot] = INF;
                s_idx[slot]  = -1;
            }
        }
        __syncthreads();

        // Merge the previous top-k (stored in s_dist[0..k-1]) with the new
        // tile's candidates (stored in s_dist[k..k+tile_count-1]) into a new
        // top-k set. We do this by sorting the first 2*k elements using a
        // bitonic sort; the k smallest distances end up in positions [0..k-1].
        bitonic_sort_pairs(s_dist, s_idx, pair_count);

        // After the sort, the first k entries represent the updated global top-k.
        // The second half [k..2k) will be overwritten by the next tile.
    }

    // Write the final top-k neighbors for this query out to global memory.
    const int out_base = q_idx * k;
    for (int i = threadIdx.x; i < k; i += blockDim.x) {
        int out_idx = out_base + i;
        result[out_idx].first  = s_idx[i];
        result[out_idx].second = s_dist[i];
    }
    // No need for further synchronization; each block writes to a disjoint
    // region of the result array.
}

// Host interface: launches the kernel.
// All pointers (query, data, result) are assumed to reside in device memory.
void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0 || k > MAX_K) {
        return;
    }

    // Choose the number of threads per block.
    // k is a power of two between 32 and 1024, inclusive.
    // Use up to 256 threads per block; for small k, use k threads so that
    // each candidate in a tile can be handled in parallel.
    int threads_per_block = (k < 256) ? k : 256;

    dim3 block_dim(threads_per_block, 1, 1);
    dim3 grid_dim(query_count, 1, 1);  // one block per query

    knn_kernel_2d<<<grid_dim, block_dim>>>(query, query_count, data, data_count, result, k);

    // Optional: synchronize for correctness in simple usage patterns.
    // In performance-critical code, consider exposing async behavior to the caller.
    cudaDeviceSynchronize();
}

#include <cuda_runtime.h>
#include <utility>
#include <cfloat>

/*
 * Optimized k-NN (k-nearest neighbors) for 2D points on modern NVIDIA GPUs.
 *
 * Design overview:
 * ----------------
 * - Each CUDA block processes exactly one query point.
 * - Threads in the block cooperatively compute squared Euclidean distances from
 *   that query to all data points.
 * - Distances are processed in tiles and stored in shared memory.
 * - A single thread (thread 0) in each block maintains a max-heap of size k
 *   (stored in shared memory) containing the current k nearest neighbors.
 *   This guarantees O(N log k) work per query, where N = data_count.
 * - After all data points are processed, the heap is converted into a sorted
 *   list (ascending by distance) and written to the result array.
 *
 * Parallelism:
 * ------------
 * - Distance computation is fully parallel within each tile: all threads in the
 *   block compute distances for different data points.
 * - Heap maintenance is done by a single thread per query (thread 0), but since
 *   there are many queries (thousands) and each query is assigned to a
 *   different block, the GPU executes many such heaps in parallel.
 *
 * Memory usage:
 * -------------
 * Shared memory per block:
 *   - TILE_SIZE distances (float) + indices (int)
 *   - K_MAX best distances (float) + indices (int)
 *   Total = TILE_SIZE * 8 bytes + K_MAX * 8 bytes
 *         = 4096 * 8 + 1024 * 8 = 40,960 bytes (< 48 KB default per-block limit)
 *
 * Constraints:
 * ------------
 * - k is a power of two in [32, 1024].
 * - data_count >= k.
 * - No additional device memory allocations (cudaMalloc) are performed.
 */

#ifndef KNN_K_MAX
#define KNN_K_MAX 1024
#endif

#ifndef KNN_TILE_SIZE
#define KNN_TILE_SIZE 4096
#endif

#ifndef KNN_THREADS_PER_BLOCK
#define KNN_THREADS_PER_BLOCK 256
#endif

// Device function to insert a candidate into a max-heap of size up to k.
// The heap is stored in two parallel arrays: best_dist and best_idx.
// Heap invariant: best_dist[0] is the largest distance in the heap.
// Only thread 0 of each block calls this function, so no synchronization is needed here.
__device__ __forceinline__
void heap_insert_max(float *best_dist, int *best_idx,
                     int &heap_size, const int k,
                     float dist, int idx)
{
    // If heap is not full yet, insert new element and heapify up.
    if (heap_size < k)
    {
        int i = heap_size;
        heap_size++;

        // Heapify up to maintain max-heap property.
        while (i > 0)
        {
            int parent = (i - 1) >> 1;
            if (best_dist[parent] >= dist)
                break;

            best_dist[i] = best_dist[parent];
            best_idx[i] = best_idx[parent];
            i = parent;
        }
        best_dist[i] = dist;
        best_idx[i] = idx;
    }
    // If heap is full and this candidate is better than the current worst,
    // replace the root and heapify down.
    else if (dist < best_dist[0])
    {
        int i = 0;

        // We use "dist" and "idx" as the new value to sink down the heap.
        while (true)
        {
            int left  = (i << 1) + 1;
            if (left >= heap_size)
                break;

            int right = left + 1;
            int largest = left;

            if (right < heap_size && best_dist[right] > best_dist[left])
                largest = right;

            if (best_dist[largest] <= dist)
                break;

            best_dist[i] = best_dist[largest];
            best_idx[i] = best_idx[largest];
            i = largest;
        }

        best_dist[i] = dist;
        best_idx[i] = idx;
    }
}

// Kernel implementing k-NN for 2D points using squared Euclidean distance.
__global__
void knn2d_kernel(const float2 * __restrict__ query,
                  int query_count,
                  const float2 * __restrict__ data,
                  int data_count,
                  std::pair<int, float> * __restrict__ result,
                  int k)
{
    // Shared memory buffers:
    // - s_tile_dist / s_tile_idx store a tile of distances and corresponding indices.
    // - s_best_dist / s_best_idx store the current max-heap of k best neighbors.
    __shared__ float s_tile_dist[KNN_TILE_SIZE];
    __shared__ int   s_tile_idx[KNN_TILE_SIZE];
    __shared__ float s_best_dist[KNN_K_MAX];
    __shared__ int   s_best_idx[KNN_K_MAX];

    const int qid = blockIdx.x;
    if (qid >= query_count)
        return;

    // Load the query point for this block.
    const float2 q = query[qid];

    // Local heap size for this block's query.
    // Only thread 0 uses and updates this variable.
    int heap_size = 0;

    // Process the data in tiles.
    for (int tile_start = 0; tile_start < data_count; tile_start += KNN_TILE_SIZE)
    {
        int remaining = data_count - tile_start;
        int tile_elems = (remaining > KNN_TILE_SIZE) ? KNN_TILE_SIZE : remaining;

        // Each thread computes distances for a subset of points in this tile.
        for (int i = threadIdx.x; i < tile_elems; i += blockDim.x)
        {
            int idx = tile_start + i;
            float2 p = data[idx];

            float dx = p.x - q.x;
            float dy = p.y - q.y;
            float dist = dx * dx + dy * dy;  // squared Euclidean distance

            s_tile_dist[i] = dist;
            s_tile_idx[i] = idx;
        }

        // Ensure all distances for this tile are computed before using them.
        __syncthreads();

        // Thread 0 updates the heap with all candidates from this tile.
        if (threadIdx.x == 0)
        {
            for (int i = 0; i < tile_elems; ++i)
            {
                float dist = s_tile_dist[i];
                int idx = s_tile_idx[i];
                heap_insert_max(s_best_dist, s_best_idx, heap_size, k, dist, idx);
            }
        }

        // Ensure thread 0 is done with this tile before reusing shared memory.
        __syncthreads();
    }

    // After processing all data points, the heap in s_best_* contains the k nearest
    // neighbors for this query, but arranged as a max-heap (largest distance at root).
    // We now extract them into the result array in ascending order of distance.
    if (threadIdx.x == 0)
    {
        // heap_size should be exactly k since data_count >= k.
        int hsize = heap_size;
        std::pair<int, float> *row = result + qid * k;

        // Perform an in-place heap sort on the heap arrays, writing into 'row'.
        // We repeatedly remove the maximum (root) and place it at position i;
        // by filling from the end to the beginning, we obtain ascending order.
        for (int i = hsize - 1; i >= 0; --i)
        {
            // Extract root (current maximum distance).
            int   best_index = s_best_idx[0];
            float best_dist  = s_best_dist[0];

            row[i].first  = best_index;
            row[i].second = best_dist;

            // Move the last element to the root and reduce heap size.
            float last_dist = s_best_dist[hsize - 1];
            int   last_idx  = s_best_idx[hsize - 1];
            hsize--;

            int current = 0;

            // Heapify down.
            while (true)
            {
                int left  = (current << 1) + 1;
                if (left >= hsize)
                    break;

                int right = left + 1;
                int largest = left;

                if (right < hsize && s_best_dist[right] > s_best_dist[left])
                    largest = right;

                if (s_best_dist[largest] <= last_dist)
                    break;

                s_best_dist[current] = s_best_dist[largest];
                s_best_idx[current]  = s_best_idx[largest];
                current = largest;
            }

            if (hsize > 0)
            {
                s_best_dist[current] = last_dist;
                s_best_idx[current]  = last_idx;
            }
        }
    }
}

// Host function interface as requested.
void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    // Assumptions from the problem statement:
    // - query, data, and result are already allocated on the device using cudaMalloc.
    // - data_count >= k.
    // - k is a power of two between 32 and 1024 inclusive.

    // Guard against k exceeding compile-time maximum.
    if (k > KNN_K_MAX || k <= 0 || query_count <= 0 || data_count <= 0)
        return;

    dim3 block_dim(KNN_THREADS_PER_BLOCK);
    dim3 grid_dim(query_count);

    knn2d_kernel<<<grid_dim, block_dim>>>(query,
                                          query_count,
                                          data,
                                          data_count,
                                          result,
                                          k);

    // No explicit cudaDeviceSynchronize() here to allow asynchronous execution.
    // The caller can synchronize or perform a blocking cudaMemcpy from 'result'
    // to the host to ensure completion.
}

#include <cuda_runtime.h>
#include <utility>
#include <cfloat>

/*
    Optimized brute-force k-NN for 2D points on modern NVIDIA GPUs (e.g., A100/H100).

    Design overview (see kernel and helper functions below):

    - Each GPU thread is responsible for computing the k nearest neighbors for a single query point.
    - A thread block handles multiple queries concurrently (one query per thread).
    - The data set is traversed in tiles. Each tile of data points is loaded once into shared memory
      and reused by all threads in the block to reduce global memory bandwidth.
    - For each query, the thread maintains a max-heap of size k (stored in thread-local memory) containing
      the current k nearest neighbors (by squared Euclidean distance).
        * The heap is a standard binary max-heap, keyed by distance.
        * For each new data point, if the heap is not yet full, it is appended.
        * Once full, the heap root (current worst neighbor) is replaced when a closer point is found,
          followed by a heapify-down operation (O(log k)).
    - After all data points are processed, a heap sort is applied to each thread's max-heap to obtain
      the final neighbors sorted in ascending order of distance.
    - Result layout: for query i, its neighbors are written into result[i * k + j], where .first is the
      data index and .second is the squared distance.

    Constraints/assumptions (from the problem statement):
      * k is a power of two between 32 and 1024 inclusive.
      * data_count >= k.
      * query, data, and result are device pointers allocated with cudaMalloc.
      * Distances are squared Euclidean distances in 2D: (dx^2 + dy^2).
*/

namespace {

constexpr int MAX_K = 1024;              // Maximum supported k
constexpr int THREADS_PER_BLOCK = 128;   // Threads per block (each handles one query)
                                         // Must be a multiple of 32 for warp efficiency

// Max-heap helper: sift-down operation starting from 'root' index.
// The heap is stored in parallel arrays: dists (keys) and idxs (payload).
// heap_size is the number of elements in the heap.
//
// This maintains the max-heap property: parent distance >= children distances.
__device__ __forceinline__
void heapify_down(float *dists, int *idxs, int heap_size, int root)
{
    int current = root;
    while (true) {
        int left  = (current << 1) + 1;  // left child
        if (left >= heap_size) {
            break; // no children
        }
        int right = left + 1;           // right child
        int largest = current;

        if (dists[left] > dists[largest]) {
            largest = left;
        }
        if (right < heap_size && dists[right] > dists[largest]) {
            largest = right;
        }
        if (largest == current) {
            break; // heap property satisfied
        }

        // Swap current and largest child
        float tmpd = dists[current];
        dists[current] = dists[largest];
        dists[largest] = tmpd;

        int tmpi = idxs[current];
        idxs[current] = idxs[largest];
        idxs[largest] = tmpi;

        current = largest;
    }
}

// Build a max-heap in-place from an unsorted array of length heap_size.
// Complexity: O(heap_size)
__device__ __forceinline__
void build_max_heap(float *dists, int *idxs, int heap_size)
{
    // Start from last internal node and heapify down to the root
    for (int start = (heap_size - 2) >> 1; start >= 0; --start) {
        heapify_down(dists, idxs, heap_size, start);
    }
}

// In-place heap sort on a max-heap to produce ascending order by distance.
// After calling this, dists[0..heap_size-1] and idxs[0..heap_size-1] are sorted
// in ascending order of distance.
__device__ __forceinline__
void heap_sort_ascending(float *dists, int *idxs, int heap_size)
{
    // Standard heapsort from a max-heap:
    // Repeatedly move the max element to the end, reduce heap size, and heapify.
    for (int end = heap_size - 1; end > 0; --end) {
        // Swap root (max) with dists[end]
        float tmpd = dists[0];
        dists[0] = dists[end];
        dists[end] = tmpd;

        int tmpi = idxs[0];
        idxs[0] = idxs[end];
        idxs[end] = tmpi;

        // Restore heap property on the reduced heap [0, end)
        heapify_down(dists, idxs, end, 0);
    }
}

// CUDA kernel performing k-NN search for 2D points.
// Each thread processes one query point and computes its k nearest neighbors.
__global__
void knn_kernel(const float2 *__restrict__ query,
                int query_count,
                const float2 *__restrict__ data,
                int data_count,
                std::pair<int, float> *__restrict__ result,
                int k)
{
    // Shared-memory tile for data points.
    // All threads in the block cooperatively load a tile of data points into sdata,
    // then each thread scans that tile for its own query.
    __shared__ float2 sdata[THREADS_PER_BLOCK];

    const int tid = threadIdx.x;
    const int global_qid = blockIdx.x * blockDim.x + tid;

    // Early exit for threads with no corresponding query
    if (global_qid >= query_count) {
        return;
    }

    // Load this thread's query point
    const float2 q = query[global_qid];

    // Per-thread max-heap for the k nearest neighbors of this query.
    // Stored in thread-local memory; size is fixed at MAX_K, but only the first 'k' entries are used.
    float heap_dists[MAX_K];
    int   heap_idxs[MAX_K];

    int   heap_size = 0;      // number of elements currently in the heap
    float current_max = 0.0f; // distance at heap root (largest among k best)

    // Iterate over data in tiles of size THREADS_PER_BLOCK
    for (int base = 0; base < data_count; base += THREADS_PER_BLOCK) {
        const int data_idx = base + tid;

        // Load one data point per thread into shared memory (if within bounds)
        if (data_idx < data_count) {
            sdata[tid] = data[data_idx];
        }
        __syncthreads();

        // Number of valid elements in this tile
        const int tile_count = min(THREADS_PER_BLOCK, data_count - base);

        // Scan all data points in this tile for this query
        // Use a simple loop; compiler can unroll this for small tile sizes.
        for (int i = 0; i < tile_count; ++i) {
            const float2 p = sdata[i];

            const float dx = p.x - q.x;
            const float dy = p.y - q.y;
            const float dist = dx * dx + dy * dy;
            const int   idx  = base + i;

            if (heap_size < k) {
                // Heap not full yet: just append
                heap_dists[heap_size] = dist;
                heap_idxs[heap_size]  = idx;
                ++heap_size;

                // Once we have exactly k elements, build a max-heap
                if (heap_size == k) {
                    build_max_heap(heap_dists, heap_idxs, heap_size);
                    current_max = heap_dists[0]; // root of max-heap
                }
            } else {
                // Heap is full: keep only if this point is closer than current worst
                if (dist < current_max) {
                    heap_dists[0] = dist;
                    heap_idxs[0]  = idx;
                    heapify_down(heap_dists, heap_idxs, k, 0);
                    current_max = heap_dists[0];
                }
            }
        }

        __syncthreads();
    }

    // At this point, heap_dists/heap_idxs contain up to k best neighbors in a max-heap.
    // data_count >= k by problem statement, so heap_size should be exactly k here.
    const int out_count = heap_size; // should equal k, but use heap_size for safety

    // Convert max-heap into ascending order (nearest first)
    if (out_count > 1) {
        heap_sort_ascending(heap_dists, heap_idxs, out_count);
    }

    // Write results to output array in row-major order:
    // For query global_qid, neighbors occupy result[global_qid * k + 0..k-1].
    const int out_base = global_qid * k;

    // Write the found neighbors
    for (int i = 0; i < out_count; ++i) {
        result[out_base + i].first  = heap_idxs[i];
        result[out_base + i].second = heap_dists[i];
    }

    // In the unlikely case where data_count < k (though problem says data_count >= k),
    // fill remaining entries with sentinel values.
    for (int i = out_count; i < k; ++i) {
        result[out_base + i].first  = -1;
        result[out_base + i].second = FLT_MAX;
    }
}

} // anonymous namespace

// Host-side interface as specified in the problem statement.
//
// query:       device pointer to array of query_count float2 points.
// query_count: number of query points.
// data:        device pointer to array of data_count float2 points.
// data_count:  number of data points.
// result:      device pointer to array of size query_count * k of std::pair<int,float>.
// k:           number of nearest neighbors to return for each query.
//
// This function launches the CUDA kernel; it assumes that 'query', 'data', and 'result'
// have been allocated with cudaMalloc and contain/point to device memory.
void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0 || k > MAX_K) {
        return; // invalid parameters; no work
    }

    // Choose grid size so that each thread handles one query.
    const dim3 blockDim(THREADS_PER_BLOCK);
    const dim3 gridDim((query_count + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK);

    // Launch the kernel.
    knn_kernel<<<gridDim, blockDim>>>(query, query_count, data, data_count, result, k);

    // Optionally, synchronize or check for errors here if desired by the caller.
    // cudaDeviceSynchronize();
    // cudaError_t err = cudaGetLastError();
    // (error handling omitted as per problem statement)
}

#include <cuda_runtime.h>
#include <utility>

// -----------------------------------------------------------------------------
// Configuration constants
// -----------------------------------------------------------------------------

// One warp (32 threads) processes a single query.
static constexpr int WARP_SIZE         = 32;
static constexpr int WARPS_PER_BLOCK   = 4;                      // 4 warps per block => 128 threads
static constexpr int THREADS_PER_BLOCK = WARP_SIZE * WARPS_PER_BLOCK;
static constexpr int TILE_SIZE         = 2048;                   // Number of data points cached in shared memory per tile

// -----------------------------------------------------------------------------
// CUDA kernel implementing k-NN for 2D points.
// Each query is processed by a single warp (32 threads).
//
// Algorithm (per query / warp):
//  1. A warp loads its query point.
//  2. The block iterates over the data set in tiles of TILE_SIZE points.
//     Each tile is loaded into shared memory cooperatively by all threads.
//  3. For each tile, the warp processes its points in chunks of 32:
//       - Each lane computes distance to one data point from the tile.
//       - Lane 0 gathers all 32 distances via warp shuffles and updates a
//         shared-memory top-k list for the query using a streaming selection:
//            * Until k elements are filled, all candidates are inserted.
//            * Once filled, only candidates better than the current worst
//              are inserted, and the new worst is recomputed by scanning k.
//  4. After all data points have been processed, the warp's unsorted top-k
//     list (distance + index) is sorted in ascending order using an in-place
//     bitonic sort in shared memory driven by 32 threads in the warp.
//  5. The sorted neighbors are written to the result array for that query.
// -----------------------------------------------------------------------------

__global__ void knn_kernel_2d(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    std::pair<int, float>* __restrict__ result,
    int k)
{
    extern __shared__ unsigned char shared_raw[];

    // Layout of shared memory:
    // [0 .. TILE_SIZE-1]         : tile of data points (float2)
    // [TILE_SIZE .. + WARPS_PER_BLOCK*k-1] : neighbor indices (int) per warp
    // [.. + WARPS_PER_BLOCK*k ..]          : neighbor distances (float) per warp
    float2* sData = reinterpret_cast<float2*>(shared_raw);
    int* sNeighborIdxAll = reinterpret_cast<int*>(sData + TILE_SIZE);
    float* sNeighborDistAll = reinterpret_cast<float*>(sNeighborIdxAll + WARPS_PER_BLOCK * k);

    const int lane_id        = threadIdx.x & (WARP_SIZE - 1);   // Lane index within warp
    const int warp_id_in_blk = threadIdx.x >> 5;                // Warp index within block (0..WARPS_PER_BLOCK-1)
    const int global_warp_id = blockIdx.x * WARPS_PER_BLOCK + warp_id_in_blk; // One warp per query

    const bool warp_active = (global_warp_id < query_count);

    // Per-warp pointers into shared memory for neighbor lists
    int* warpNeighborIdx   = sNeighborIdxAll   + warp_id_in_blk * k;
    float* warpNeighborDist = sNeighborDistAll + warp_id_in_blk * k;

    // Load the query point for this warp
    float2 q;
    if (warp_active) {
        q = query[global_warp_id];
    }

    // State for streaming top-k, used only by lane 0 of active warps.
    int   neighbor_count = 0; // Number of neighbors currently stored (<= k)
    float worst_dist     = 0.0f; // Distance of the worst (largest) neighbor currently in list
    int   worst_pos      = 0;    // Position of the worst neighbor in the list

    if (warp_active && lane_id == 0) {
        neighbor_count = 0;
        // No need to initialize warpNeighborDist/warpNeighborIdx here;
        // elements are filled sequentially as candidates are accepted.
    }

    // -------------------------------------------------------------------------
    // Iterate over the data points in tiles cached in shared memory.
    // -------------------------------------------------------------------------
    for (int tile_start = 0; tile_start < data_count; tile_start += TILE_SIZE) {
        const int tile_size = (tile_start + TILE_SIZE <= data_count)
                                ? TILE_SIZE
                                : (data_count - tile_start);

        // Load tile of data points into shared memory (all threads cooperate).
        for (int i = threadIdx.x; i < tile_size; i += blockDim.x) {
            sData[i] = data[tile_start + i];
        }

        // Ensure the entire tile is loaded before any warp starts using it.
        __syncthreads();

        // Each active warp now processes the tile.
        if (warp_active) {
            const int num_warp_iters = (tile_size + WARP_SIZE - 1) / WARP_SIZE;

            for (int it = 0; it < num_warp_iters; ++it) {
                const int data_idx_in_tile = it * WARP_SIZE + lane_id;
                const int global_data_idx  = tile_start + data_idx_in_tile;

                // Compute distance for this lane's candidate, or mark invalid if out-of-range.
                float dist = 0.0f;
                int idx    = -1;

                if (data_idx_in_tile < tile_size) {
                    const float2 p = sData[data_idx_in_tile];
                    const float dx = p.x - q.x;
                    const float dy = p.y - q.y;
                    dist = dx * dx + dy * dy;  // squared L2 distance
                    idx  = global_data_idx;
                } else {
                    // No valid point for this lane in this iteration.
                    dist = 0.0f;
                    idx  = -1;
                }

                // Lane 0 gathers candidate distances and indices using warp shuffles
                // and updates the top-k neighbor list.
                const unsigned full_mask = 0xFFFFFFFFu;

                // All lanes participate in the shuffles; only lane 0 updates the list.
                for (int src_lane = 0; src_lane < WARP_SIZE; ++src_lane) {
                    const float cand_dist = __shfl_sync(full_mask, dist, src_lane);
                    const int   cand_idx  = __shfl_sync(full_mask, idx, src_lane);

                    if (lane_id == 0 && cand_idx >= 0) {
                        // Streaming top-k insertion:
                        //  - While neighbor_count < k: append candidate.
                        //  - Once neighbor_count == k: only accept if better than worst_dist,
                        //    replacing the current worst and recomputing worst_dist/worst_pos.

                        if (neighbor_count < k) {
                            // Append candidate
                            warpNeighborDist[neighbor_count] = cand_dist;
                            warpNeighborIdx[neighbor_count]  = cand_idx;
                            ++neighbor_count;

                            // If we've just filled k entries, compute the initial worst.
                            if (neighbor_count == k) {
                                worst_pos  = 0;
                                worst_dist = warpNeighborDist[0];
                                for (int i = 1; i < k; ++i) {
                                    const float d = warpNeighborDist[i];
                                    if (d > worst_dist) {
                                        worst_dist = d;
                                        worst_pos  = i;
                                    }
                                }
                            }
                        } else {
                            // neighbor_count == k
                            if (cand_dist < worst_dist) {
                                // Replace current worst with candidate
                                warpNeighborDist[worst_pos] = cand_dist;
                                warpNeighborIdx[worst_pos]  = cand_idx;

                                // Recompute new worst entry
                                worst_pos  = 0;
                                worst_dist = warpNeighborDist[0];
                                for (int i = 1; i < k; ++i) {
                                    const float d = warpNeighborDist[i];
                                    if (d > worst_dist) {
                                        worst_dist = d;
                                        worst_pos  = i;
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }

        // Ensure all warps are done using this tile before it is overwritten.
        __syncthreads();
    }

    // At this point, each active warp has exactly k neighbors in its list:
    // warpNeighborIdx[0..k-1], warpNeighborDist[0..k-1] (unsorted).

    if (warp_active) {
        // ---------------------------------------------------------------------
        // Sort the k neighbors by ascending distance using in-place bitonic sort.
        // The sort operates entirely within the warp, using shared memory for
        // storage and 32 threads cooperatively performing compare-exchange steps.
        // ---------------------------------------------------------------------
        // Bitonic sort network from CUDA samples, adapted to use only 32 threads
        // for arbitrary power-of-two k (32 <= k <= 1024).
        for (int size_stage = 2; size_stage <= k; size_stage <<= 1) {
            for (int stride = size_stage >> 1; stride > 0; stride >>= 1) {
                __syncwarp();

                for (int i = lane_id; i < k; i += WARP_SIZE) {
                    int j = i ^ stride;
                    if (j > i) {
                        const bool ascending = ((i & size_stage) == 0);

                        float di = warpNeighborDist[i];
                        float dj = warpNeighborDist[j];
                        int   ii = warpNeighborIdx[i];
                        int   ij = warpNeighborIdx[j];

                        if (ascending) {
                            if (di > dj) {
                                // Swap to enforce ascending order
                                warpNeighborDist[i] = dj;
                                warpNeighborDist[j] = di;
                                warpNeighborIdx[i]  = ij;
                                warpNeighborIdx[j]  = ii;
                            }
                        } else {
                            if (di < dj) {
                                // Swap to enforce descending order in this segment
                                warpNeighborDist[i] = dj;
                                warpNeighborDist[j] = di;
                                warpNeighborIdx[i]  = ij;
                                warpNeighborIdx[j]  = ii;
                            }
                        }
                    }
                }
            }
        }
        __syncwarp();

        // ---------------------------------------------------------------------
        // Write sorted neighbors to global memory.
        // For query q = global_warp_id, its neighbors are stored in
        // result[q * k + 0 .. q * k + (k - 1)].
        // ---------------------------------------------------------------------
        const int base_out = global_warp_id * k;
        for (int i = lane_id; i < k; i += WARP_SIZE) {
            const int out_idx = base_out + i;
            result[out_idx].first  = warpNeighborIdx[i];
            result[out_idx].second = warpNeighborDist[i];
        }
    }
}

// -----------------------------------------------------------------------------
// Host-side interface
// -----------------------------------------------------------------------------

// run_knn:
//   Launches the CUDA kernel to compute k-nearest neighbors for 2D points.
//   Inputs:
//     - query      : device pointer to query points (float2)
//     - query_count: number of queries
//     - data       : device pointer to data points (float2)
//     - data_count : number of data points
//     - result     : device pointer to result array of size query_count * k
//                    (each element is std::pair<int, float>)
//     - k          : number of neighbors (power of two, 32 <= k <= 1024)
void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    // One warp per query; each block has WARPS_PER_BLOCK warps.
    const int blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    // Shared memory size:
    //  - TILE_SIZE float2 points
    //  - WARPS_PER_BLOCK * k neighbor indices (int)
    //  - WARPS_PER_BLOCK * k neighbor distances (float)
    const size_t shared_mem_size =
        static_cast<size_t>(TILE_SIZE) * sizeof(float2) +
        static_cast<size_t>(WARPS_PER_BLOCK) * static_cast<size_t>(k) * (sizeof(int) + sizeof(float));

    knn_kernel_2d<<<blocks, THREADS_PER_BLOCK, shared_mem_size>>>(
        query,
        query_count,
        data,
        data_count,
        result,
        k
    );

    // Synchronize to ensure results are ready when function returns.
    cudaDeviceSynchronize();
}

