#include <cuda_runtime.h>
#include <utility>

// -----------------------------------------------------------------------------
// CUDA k-NN implementation for 2D points (squared Euclidean distance).
//
// - One warp (32 threads) processes one query point.
// - All warps in a block cooperatively cache tiles of the data points in shared
//   memory to minimize global memory traffic.
// - Each warp maintains its own private max-heap (in shared memory) of size k,
//   containing the currently best (smallest-distance) neighbors.
//   * The heap root is the worst (largest) distance in the current top-k.
//   * New candidates replace the heap root only if they are closer.
// - At the end of processing, each warp heap-sorts its heap to produce the k
//   nearest neighbors in ascending-distance order, and writes them to global
//   memory.
//
// This implementation is tuned for modern data-center GPUs (e.g., A100/H100).
// -----------------------------------------------------------------------------

// Number of warps per block. Each warp handles one query.
constexpr int WARPS_PER_BLOCK   = 4;
constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * 32;

// Number of data points cached per tile in shared memory.
// 1024 * sizeof(float2) = 8 KiB per block for data cache.
constexpr int TILE_SIZE         = 1024;

// Helper: push a new element into a max-heap (heapDist/heapIdx, size = heapSize).
// The parent node always has a distance >= its children.
__device__ __forceinline__
void heap_push_max(float *heapDist, int *heapIdx, int &heapSize,
                   float dist, int idx)
{
    int pos = heapSize++;
    // Sift up
    while (pos > 0) {
        int parent      = (pos - 1) >> 1;
        float parentVal = heapDist[parent];
        if (parentVal >= dist) {
            break;
        }
        // Move parent down
        heapDist[pos] = parentVal;
        heapIdx[pos]  = heapIdx[parent];
        pos           = parent;
    }
    heapDist[pos] = dist;
    heapIdx[pos]  = idx;
}

// Helper: replace the root of a max-heap with a new smaller value and sift down.
// Assumes dist < heapDist[0] and heapSize > 0.
__device__ __forceinline__
void heap_replace_root_max(float *heapDist, int *heapIdx, int heapSize,
                           float dist, int idx)
{
    int   pos       = 0;
    float valueDist = dist;
    int   valueIdx  = idx;

    // Sift down
    while (true) {
        int left = (pos << 1) + 1;
        if (left >= heapSize) {
            break;
        }
        int right       = left + 1;
        int largestPos  = left;
        float largest   = heapDist[left];

        if (right < heapSize) {
            float rightVal = heapDist[right];
            if (rightVal > largest) {
                largestPos = right;
                largest    = rightVal;
            }
        }

        if (largest <= valueDist) {
            break;
        }

        // Move child up
        heapDist[pos] = largest;
        heapIdx[pos]  = heapIdx[largestPos];
        pos           = largestPos;
    }

    heapDist[pos] = valueDist;
    heapIdx[pos]  = valueIdx;
}

// Helper: in-place heap sort of a max-heap where heapDist/heapIdx has 'size'
// elements. After this, heapDist/heapIdx are sorted in ascending order
// (smallest distance at index 0).
__device__ __forceinline__
void heap_sort_max_to_ascending(float *heapDist, int *heapIdx, int size)
{
    // Standard heapsort on a max-heap.
    for (int end = size - 1; end > 0; --end) {
        // Swap root with last element in [0, end]
        float rootDist = heapDist[0];
        float lastDist = heapDist[end];
        heapDist[0]    = lastDist;
        heapDist[end]  = rootDist;

        int rootIdx = heapIdx[0];
        int lastIdx = heapIdx[end];
        heapIdx[0]  = lastIdx;
        heapIdx[end]= rootIdx;

        // Re-heapify the reduced heap [0, end)
        int   pos       = 0;
        float valueDist = heapDist[0];
        int   valueIdx  = heapIdx[0];

        while (true) {
            int left = (pos << 1) + 1;
            if (left >= end) {
                break;
            }
            int right      = left + 1;
            int largestPos = left;
            float largest  = heapDist[left];

            if (right < end) {
                float rightVal = heapDist[right];
                if (rightVal > largest) {
                    largestPos = right;
                    largest    = rightVal;
                }
            }

            if (largest <= valueDist) {
                break;
            }

            heapDist[pos] = largest;
            heapIdx[pos]  = heapIdx[largestPos];
            pos           = largestPos;
        }

        heapDist[pos] = valueDist;
        heapIdx[pos]  = valueIdx;
    }
}

// Kernel: each warp computes k-NN for one query point.
__global__ void knn_kernel(const float2 * __restrict__ query,
                           int query_count,
                           const float2 * __restrict__ data,
                           int data_count,
                           int k,
                           std::pair<int, float> * __restrict__ result)
{
    extern __shared__ unsigned char shared_raw[];

    // Layout of shared memory:
    // [0 .. TILE_SIZE-1]              : float2 data tile
    // [TILE_SIZE .. + WARPS*k floats] : per-warp heap distances
    // [floats .. + WARPS*k ints]      : per-warp heap indices
    float2 *sData = reinterpret_cast<float2*>(shared_raw);
    float  *sHeapDists = reinterpret_cast<float*>(sData + TILE_SIZE);
    int    *sHeapIdx   = reinterpret_cast<int*>(sHeapDists + WARPS_PER_BLOCK * k);

    const unsigned FULL_MASK = 0xffffffffu;

    int laneId        = threadIdx.x & 31;     // Thread index within warp
    int warpIdInBlock = threadIdx.x >> 5;     // Warp index within block
    int warpsPerBlock = blockDim.x >> 5;      // Should equal WARPS_PER_BLOCK
    int globalWarpId  = blockIdx.x * warpsPerBlock + warpIdInBlock;

    bool warpActive = (globalWarpId < query_count);

    // Each warp has its own heap region in shared memory.
    float *heapDist = sHeapDists + warpIdInBlock * k;
    int   *heapIdx  = sHeapIdx   + warpIdInBlock * k;

    // Load query point into registers for this warp and broadcast.
    float2 q;
    if (warpActive) {
        if (laneId == 0) {
            q = query[globalWarpId];
        }
        q.x = __shfl_sync(FULL_MASK, q.x, 0);
        q.y = __shfl_sync(FULL_MASK, q.y, 0);
    }

    // Heap size is tracked only in lane 0's register;
    // other lanes never use it directly, only through lane 0.
    int heapSize = 0; // Only valid in lane 0 when warpActive.

    // Iterate over data points in tiles cached in shared memory.
    for (int tileStart = 0; tileStart < data_count; tileStart += TILE_SIZE) {

        int tileCount = data_count - tileStart;
        if (tileCount > TILE_SIZE) {
            tileCount = TILE_SIZE;
        }

        // All threads in the block cooperatively load the tile.
        for (int i = threadIdx.x; i < tileCount; i += blockDim.x) {
            sData[i] = data[tileStart + i];
        }
        __syncthreads();

        // Each active warp processes the tile for its query.
        if (warpActive) {
            // Process the tile in groups of warpSize points.
            for (int base = 0; base < tileCount; base += warpSize) {
                int idxInTile = base + laneId;

                float dist = 0.0f;
                int   idx  = -1;

                if (idxInTile < tileCount) {
                    float2 p = sData[idxInTile];
                    float dx = p.x - q.x;
                    float dy = p.y - q.y;
                    // Squared Euclidean distance (no sqrt needed).
                    dist = dx * dx + dy * dy;
                    idx  = tileStart + idxInTile;
                }

                // Number of valid candidates in this group (<= warpSize).
                int groupSize = tileCount - base;
                if (groupSize > warpSize) {
                    groupSize = warpSize;
                }

                // Sequentially feed this group's candidates to lane 0's heap.
                // All threads participate using warp shuffles.
                for (int i = 0; i < groupSize; ++i) {
                    float candDist = __shfl_sync(FULL_MASK, dist, i);
                    int   candIdx  = __shfl_sync(FULL_MASK, idx,  i);

                    if (laneId == 0) {
                        if (heapSize < k) {
                            // Heap not full yet: simply push.
                            heap_push_max(heapDist, heapIdx, heapSize, candDist, candIdx);
                        } else if (candDist < heapDist[0]) {
                            // Candidate is better (closer) than current worst in top-k.
                            heap_replace_root_max(heapDist, heapIdx, heapSize, candDist, candIdx);
                        }
                    }
                    // Ensure heap updates are visible to the warp before the
                    // next candidate is processed.
                    __syncwarp(FULL_MASK);
                }
            }
        }

        __syncthreads();
    }

    // Finalize results for this warp's query.
    if (warpActive) {
        // Heap currently contains k smallest distances in a max-heap.
        // Convert heap into ascending order.
        if (laneId == 0) {
            heap_sort_max_to_ascending(heapDist, heapIdx, heapSize);
        }
        __syncwarp(FULL_MASK);

        // Write sorted k nearest neighbors (index, distance) to global memory.
        if (laneId == 0) {
            int outBase = globalWarpId * k;
            for (int i = 0; i < k; ++i) {
                result[outBase + i].first  = heapIdx[i];
                result[outBase + i].second = heapDist[i];
            }
        }
    }
}

// Host-side interface as requested.
void run_knn(const float2 *query, int query_count,
             const float2 *data,  int data_count,
             std::pair<int, float> *result, int k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    // One warp per query.
    const int warpsPerBlock   = WARPS_PER_BLOCK;
    const int threadsPerBlock = THREADS_PER_BLOCK;

    int numWarps  = query_count;
    int numBlocks = (numWarps + warpsPerBlock - 1) / warpsPerBlock;

    // Shared memory size:
    // - TILE_SIZE float2 for the data tile
    // - WARPS_PER_BLOCK * k floats for heap distances
    // - WARPS_PER_BLOCK * k ints   for heap indices
    size_t sharedBytes =
        TILE_SIZE * sizeof(float2) +
        WARPS_PER_BLOCK * k * (sizeof(float) + sizeof(int));

    knn_kernel<<<numBlocks, threadsPerBlock, sharedBytes>>>(
        query, query_count, data, data_count, k, result);
}

#include <cuda_runtime.h>
#include <cfloat>
#include <utility>

// Simple POD type compatible in layout with std::pair<int,float>.
// We use this on device instead of std::pair, which is not guaranteed
// to be __device__-compatible.
struct PairIF {
    int   first;
    float second;
};

// Tunable parameters for the kernel. These values are suitable for
// modern data-center GPUs (e.g., A100, H100) and typical problem sizes.
constexpr int MAX_K             = 1024;           // maximum k supported
constexpr int WARPS_PER_BLOCK   = 8;              // 8 warps * 32 threads = 256 threads per block
constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * 32;
constexpr int TILE_SIZE         = 1024;           // number of data points cached per tile (multiple of 32)

// Device helpers implementing a max-heap over distances.
//
// The heap stores the current k best (smallest) distances; as a max-heap,
// the root is the largest (worst among the best). This allows maintaining
// the k nearest neighbors in O(log k) time per candidate that improves
// the current worst.

// Insert a new (dist, idx) into a max-heap of current size heapSize.
__device__ __forceinline__
void heap_push_max(float *dists, int *idxs, int &heapSize,
                   const float dist, const int idx)
{
    int pos = heapSize++;
    float d = dist;
    int i = idx;
    // Sift up.
    while (pos > 0) {
        int parent = (pos - 1) >> 1;
        float parentDist = dists[parent];
        if (d <= parentDist) break;
        dists[pos] = parentDist;
        idxs[pos]  = idxs[parent];
        pos = parent;
    }
    dists[pos] = d;
    idxs[pos]  = i;
}

// Restore max-heap property starting at index 'start' in a heap of length heapSize.
__device__ __forceinline__
void heap_sift_down_max(float *dists, int *idxs, int start, int heapSize)
{
    int pos = start;
    while (true) {
        int left = (pos << 1) + 1;
        if (left >= heapSize) break;
        int right = left + 1;
        int largest = pos;
        float largestDist = dists[pos];
        float leftDist = dists[left];
        if (leftDist > largestDist) {
            largest = left;
            largestDist = leftDist;
        }
        if (right < heapSize) {
            float rightDist = dists[right];
            if (rightDist > largestDist) {
                largest = right;
                largestDist = rightDist;
            }
        }
        if (largest == pos) break;
        float tmpDist = dists[pos];
        int   tmpIdx  = idxs[pos];
        dists[pos]    = dists[largest];
        idxs[pos]     = idxs[largest];
        dists[largest]= tmpDist;
        idxs[largest] = tmpIdx;
        pos = largest;
    }
}

// Kernel: each warp (32 threads) processes one query point.
//
// For each query:
//   - Iterate over data in shared-memory tiles.
//   - Within each tile, each thread computes distances to a subset of points.
//   - Candidates are broadcast via warp shuffles and inserted into a per-warp
//     max-heap of size k (stored in shared memory).
//   - After all data are processed, the heap is heap-sorted into ascending order
//     and written to the result array.
__global__
void knn_kernel(const float2 * __restrict__ query,
                int query_count,
                const float2 * __restrict__ data,
                int data_count,
                PairIF * __restrict__ result,
                int k)
{
    // Shared memory:
    // - s_data_tile: a tile of data points used by all warps in the block.
    // - s_best_dists / s_best_indices: per-warp heaps of current k nearest neighbors.
    __shared__ float2 s_data_tile[TILE_SIZE];
    __shared__ float  s_best_dists[WARPS_PER_BLOCK][MAX_K];
    __shared__ int    s_best_indices[WARPS_PER_BLOCK][MAX_K];

    const int tid       = threadIdx.x;
    const int lane      = tid & 31;               // thread index within warp [0,31]
    const int warp      = tid >> 5;               // warp index within block [0,WARPS_PER_BLOCK-1]
    const int warpGlobal= blockIdx.x * WARPS_PER_BLOCK + warp;

    const bool warpActive = (warpGlobal < query_count);
    const unsigned fullMask = 0xffffffffu;

    float qx = 0.0f;
    float qy = 0.0f;

    // Load query point once per warp and broadcast to all 32 threads.
    if (warpActive) {
        if (lane == 0) {
            float2 q = query[warpGlobal];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(fullMask, qx, 0);
        qy = __shfl_sync(fullMask, qy, 0);

        // Initialize per-warp best distance/index buffers (only first k entries matter).
        float *bestDists = s_best_dists[warp];
        int   *bestIdx   = s_best_indices[warp];
        for (int i = lane; i < k; i += 32) {
            bestDists[i] = FLT_MAX;
            bestIdx[i]   = -1;
        }
    }

    // Heap size is kept in a register; only lane 0 of active warps uses it.
    int heapSize = 0;

    // Iterate over data in tiles cached in shared memory.
    for (int tileStart = 0; tileStart < data_count; tileStart += TILE_SIZE) {
        int tileSize = TILE_SIZE;
        if (tileStart + tileSize > data_count)
            tileSize = data_count - tileStart;

        // Cooperative load of current tile into shared memory by all threads in the block.
        for (int i = tid; i < tileSize; i += blockDim.x) {
            s_data_tile[i] = data[tileStart + i];
        }
        __syncthreads();

        if (warpActive) {
            float *bestDists = s_best_dists[warp];
            int   *bestIdx   = s_best_indices[warp];

            // Process the tile in chunks of 32 points: each lane handles one point per chunk.
            for (int base = 0; base < tileSize; base += 32) {
                int idxInTile     = base + lane;
                int globalDataIdx = tileStart + idxInTile;

                // Each lane computes distance from its query point to one data point (if within bounds).
                float dist = FLT_MAX;
                int   idx  = -1;
                if (idxInTile < tileSize) {
                    float2 p = s_data_tile[idxInTile];
                    float dx = p.x - qx;
                    float dy = p.y - qy;
                    dist = dx * dx + dy * dy;   // squared Euclidean distance
                    idx  = globalDataIdx;
                }

                // Ensure all threads in the warp have computed their distances.
                __syncwarp(fullMask);

                // Lane 0 sequentially feeds all 32 candidates into the per-warp max-heap.
                // The heap maintains the k smallest distances seen so far.
                for (int srcLane = 0; srcLane < 32; ++srcLane) {
                    float candDist = __shfl_sync(fullMask, dist, srcLane);
                    int   candIdx  = __shfl_sync(fullMask, idx,  srcLane);

                    if (lane == 0 && candIdx >= 0) {
                        if (heapSize < k) {
                            // Heap not full yet: insert the candidate.
                            heap_push_max(bestDists, bestIdx, heapSize, candDist, candIdx);
                        } else if (candDist < bestDists[0]) {
                            // Candidate is better than the current worst in the heap:
                            // replace root and restore heap property.
                            bestDists[0] = candDist;
                            bestIdx[0]   = candIdx;
                            heap_sift_down_max(bestDists, bestIdx, 0, heapSize);
                        }
                    }
                }
            }
        }

        __syncthreads();
    }

    // After processing all tiles, each active warp has a max-heap of size k that
    // contains the k nearest neighbors (unsorted). Convert the heap into a sorted
    // array (ascending by distance) via in-place heap sort, then write results.
    if (warpActive && lane == 0) {
        float *bestDists = s_best_dists[warp];
        int   *bestIdx   = s_best_indices[warp];

        if (heapSize > k) heapSize = k;

        // In-place heap sort on the max-heap -> ascending order.
        // Complexity: O(k log k), negligible compared to distance computations.
        for (int i = heapSize - 1; i > 0; --i) {
            // Move current maximum to the end.
            float tmpDist = bestDists[0];
            bestDists[0]  = bestDists[i];
            bestDists[i]  = tmpDist;
            int tmpIdx    = bestIdx[0];
            bestIdx[0]    = bestIdx[i];
            bestIdx[i]    = tmpIdx;

            // Restore heap property on the reduced heap [0, i).
            heap_sift_down_max(bestDists, bestIdx, 0, i);
        }

        // Now bestDists[0 .. heapSize-1] are sorted in ascending order.

        PairIF *out = result + warpGlobal * k;
        int outCount = (heapSize < k) ? heapSize : k;

        // Write found neighbors.
        for (int i = 0; i < outCount; ++i) {
            out[i].first  = bestIdx[i];
            out[i].second = bestDists[i];
        }
        // If data_count < k (not expected per problem statement), fill remaining slots.
        for (int i = outCount; i < k; ++i) {
            out[i].first  = -1;
            out[i].second = FLT_MAX;
        }
    }
}

// Host-side entry point.
//
// - query, data, and result are assumed to be device pointers allocated with cudaMalloc.
// - Each query[i] is a float2 representing a 2D point.
// - Each data[j] is a float2 representing a 2D point.
// - result is an array of std::pair<int,float> with length query_count * k in device memory.
//   For query i, result[i * k + j] will contain the index (first) and squared distance (second)
//   of its j-th nearest neighbor among data[0..data_count-1].
// - k is a power of two between 32 and 1024 inclusive.
// - data_count >= k.
//
void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    // Reinterpret the result pointer as a POD type with the same layout as std::pair<int,float>.
    PairIF *result_cast = reinterpret_cast<PairIF*>(result);

    dim3 blockDim(THREADS_PER_BLOCK, 1, 1);
    int totalWarps = query_count;
    int gridX = (totalWarps + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    dim3 gridDim(gridX, 1, 1);

    knn_kernel<<<gridDim, blockDim>>>(query, query_count, data, data_count, result_cast, k);
}

#include <cuda_runtime.h>
#include <float.h>
#include <utility>

// This implementation assigns one CUDA warp (32 threads) to each query point.
// The warp cooperatively scans all data points in 2D space, keeping a private
// top-k list of nearest neighbors for its query in shared memory.
//
// Key features:
// - Warp-per-query: each warp handles one query, all 32 threads share the work.
// - Data tiling: data points are processed in tiles cached in shared memory.
// - Top-k storage per query: for each query/warp we keep an ordered list of
//   indices and distances of its k nearest neighbors in shared memory.
// - Warp-level communication: shuffles and ballots are used so only candidates
//   that beat the current worst neighbor are inserted into the top-k list.
//
// Top-k details:
// - For each query, we maintain a sorted array (ascending by distance) of size k.
//   The worst (largest) distance is always at position k - 1.
// - For a new candidate (idx, dist), we first compare dist against the current
//   worst distance. If it is not better, we skip it.
// - If it is better, we binary-search for its insertion position and shift the
//   tail of the array to make room. Because new insertions are rare compared to
//   distance computations, this remains efficient even for k up to 1024.
//
// Constraints matched from the problem:
// - Exactly one warp (32 threads) per query.
// - No extra device memory allocations; only shared memory is used.
// - k is a power of two between 32 and 1024 (inclusive).
// - Data are processed iteratively in batches cached in shared memory.

constexpr int WARP_SIZE         = 32;
constexpr int WARPS_PER_BLOCK   = 4;    // 4 warps * 32 threads = 128 threads per block
constexpr int THREADS_PER_BLOCK = WARP_SIZE * WARPS_PER_BLOCK;
constexpr int MAX_K             = 1024; // maximum supported k
constexpr int TILE_POINTS       = 1024; // number of data points cached per tile in shared memory

// Helper to insert a candidate into the warp-local top-k array.
// This is called only by lane 0 of each warp.
// top_dists: ascending sorted array of size k.
// top_idx  : corresponding indices.
// k        : actual k (<= MAX_K).
// idx/dist : new candidate.
// worst_dist (in/out): current worst distance for this warp (top_dists[k-1]).
__device__ __forceinline__
void insert_topk_lane0(float* top_dists, int* top_idx, int k,
                       int idx, float dist, float &worst_dist)
{
    // Precondition: dist < worst_dist
    // Binary search to find insertion position in ascending array.
    int left = 0;
    int right = k - 1;
    while (left < right) {
        int mid = (left + right) >> 1;
        if (dist < top_dists[mid])
            right = mid;
        else
            left = mid + 1;
    }
    int pos = left;

    // Shift elements [pos, k-2] one step to the right; drop the old worst at k-1.
    for (int t = k - 1; t > pos; --t) {
        top_dists[t] = top_dists[t - 1];
        top_idx[t]   = top_idx[t - 1];
    }

    top_dists[pos] = dist;
    top_idx[pos]   = idx;
    worst_dist     = top_dists[k - 1];
}

__global__ void knn_kernel(const float2* __restrict__ query,
                           int query_count,
                           const float2* __restrict__ data,
                           int data_count,
                           std::pair<int, float>* __restrict__ result,
                           int k)
{
    // Shared memory layout:
    // - s_data: tile of data points reused by all warps in the block.
    // - s_top_dists/s_top_indices: per-warp top-k buffers.
    __shared__ float2 s_data[TILE_POINTS];
    __shared__ float  s_top_dists[WARPS_PER_BLOCK * MAX_K];
    __shared__ int    s_top_indices[WARPS_PER_BLOCK * MAX_K];

    const int lane           = threadIdx.x & (WARP_SIZE - 1); // lane id in warp [0,31]
    const int warp_in_block  = threadIdx.x >> 5;              // warp id in block [0, WARPS_PER_BLOCK-1]
    const int global_warp_id = blockIdx.x * WARPS_PER_BLOCK + warp_in_block;

    // One warp processes exactly one query; if there are more warps than queries, excess warps return.
    if (global_warp_id >= query_count)
        return;

    // Pointers to this warp's top-k buffers in shared memory.
    float* top_dists = &s_top_dists[warp_in_block * MAX_K];
    int*   top_idx   = &s_top_indices[warp_in_block * MAX_K];

    // Initialize top-k to +inf distance and invalid index.
    // Each lane initializes a strided subset of the k entries.
    for (int i = lane; i < k; i += WARP_SIZE) {
        top_dists[i] = FLT_MAX;
        top_idx[i]   = -1;
    }
    __syncwarp();

    // Load query point and broadcast to all lanes in the warp.
    float qx = 0.0f, qy = 0.0f;
    if (lane == 0) {
        float2 q = query[global_warp_id];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(0xFFFFFFFFu, qx, 0);
    qy = __shfl_sync(0xFFFFFFFFu, qy, 0);

    // Current worst distance for this warp's top-k list.
    float worst_dist = FLT_MAX;
    worst_dist = __shfl_sync(0xFFFFFFFFu, worst_dist, 0);

    // Process the dataset in tiles cached in shared memory.
    for (int tile_start = 0; tile_start < data_count; tile_start += TILE_POINTS) {
        int remaining  = data_count - tile_start;
        int tile_size  = (remaining < TILE_POINTS) ? remaining : TILE_POINTS;

        // Block-wide load of tile into shared memory (coalesced).
        for (int idx = threadIdx.x; idx < tile_size; idx += blockDim.x) {
            s_data[idx] = data[tile_start + idx];
        }
        __syncthreads();

        // Each warp processes all points in the tile.
        // Each lane handles a strided subset of the tile's points.
        for (int j = lane; j < tile_size; j += WARP_SIZE) {
            float2 p = s_data[j];
            float dx = p.x - qx;
            float dy = p.y - qy;
            float dist = dx * dx + dy * dy;
            int   data_idx = tile_start + j;

            // Check if this candidate can possibly enter the top-k for this warp.
            float current_worst = __shfl_sync(0xFFFFFFFFu, worst_dist, 0);
            bool  is_better     = (dist < current_worst);

            // Build a mask of lanes with candidates better than current worst.
            unsigned int mask = __ballot_sync(0xFFFFFFFFu, is_better);

            // Process better candidates one by one in lane 0 using warp shuffles.
            // This avoids races on the shared top-k arrays and ensures correctness.
            while (mask) {
                int cand_lane = __ffs(mask) - 1; // index of least significant set bit [0,31]

                // Fetch candidate's distance and index from the owning lane.
                float cand_dist = __shfl_sync(0xFFFFFFFFu, dist,     cand_lane);
                int   cand_idx  = __shfl_sync(0xFFFFFFFFu, data_idx, cand_lane);

                if (lane == 0) {
                    // Re-check against the (possibly updated) worst_dist.
                    if (cand_dist < worst_dist) {
                        insert_topk_lane0(top_dists, top_idx, k, cand_idx, cand_dist, worst_dist);
                    }
                }

                // Broadcast updated worst_dist to all lanes in the warp.
                worst_dist = __shfl_sync(0xFFFFFFFFu, worst_dist, 0);

                // Clear the processed lane's bit and continue.
                mask &= (mask - 1);
            }
        }

        __syncthreads(); // Ensure all warps are done with this tile before loading the next one.
    }

    // Write out the final top-k results for this query.
    // top_dists[0..k-1] are ascending; top_idx[] hold corresponding data indices.
    // Each lane writes a strided subset of results.
    for (int i = lane; i < k; i += WARP_SIZE) {
        int out_index = global_warp_id * k + i;
        result[out_index].first  = top_idx[i];
        result[out_index].second = top_dists[i];
    }
}

// Host interface as requested.
// Assumes query, data, and result pointers are already allocated on the device
// with cudaMalloc, and that data_count >= k and k is a power of two in [32,1024].
void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0 || k > MAX_K)
        return;

    dim3 block_dim(THREADS_PER_BLOCK);
    int  num_blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    dim3 grid_dim(num_blocks);

    knn_kernel<<<grid_dim, block_dim>>>(query, query_count, data, data_count, result, k);
    // Synchronization and error checking are left to the caller if desired.
}

