#include <cuda_runtime.h>
#include <utility>

// -----------------------------------------------------------------------------
// Optimized k-NN (k-nearest neighbors) for 2D points using CUDA
// - One warp (32 threads) processes one query point.
// - All warps in a block share a tile of data points in shared memory.
// - Each warp maintains a private max-heap of size K (top-k neighbors) in shared
//   memory. Only lane 0 of the warp mutates the heap to avoid races.
// - Distances are squared Euclidean (L2^2) in 2D.
// -----------------------------------------------------------------------------

// Configuration for the target GPUs (A100/H100).
//  - 8 warps per block (256 threads).
//  - Data tile of 1024 points in shared memory.
constexpr int WARP_SIZE          = 32;
constexpr int WARPS_PER_BLOCK    = 8;
constexpr int THREADS_PER_BLOCK  = WARP_SIZE * WARPS_PER_BLOCK; // 256
constexpr int TILE_SIZE          = 1024;
constexpr int LOADS_PER_THREAD   = TILE_SIZE / THREADS_PER_BLOCK; // 4

static_assert(TILE_SIZE % THREADS_PER_BLOCK == 0,
              "TILE_SIZE must be a multiple of THREADS_PER_BLOCK");

// -----------------------------------------------------------------------------
// Device helper: max-heap operations for top-K selection
// -----------------------------------------------------------------------------

template<int K>
__device__ __forceinline__ void heap_insert_initial(float* heap_dists,
                                                    int*   heap_indices,
                                                    int&   heap_size,
                                                    float  dist,
                                                    int    idx)
{
    // Insert at the end and sift up to maintain max-heap property.
    int pos = heap_size;
    heap_size++;

    heap_dists[pos]   = dist;
    heap_indices[pos] = idx;

    // Sift up
    while (pos > 0) {
        int parent = (pos - 1) >> 1;
        if (heap_dists[parent] >= heap_dists[pos]) break;

        // Swap parent and current
        float td            = heap_dists[parent];
        heap_dists[parent]  = heap_dists[pos];
        heap_dists[pos]     = td;

        int ti              = heap_indices[parent];
        heap_indices[parent]= heap_indices[pos];
        heap_indices[pos]   = ti;

        pos = parent;
    }
}

template<int K>
__device__ __forceinline__ void heap_maybe_insert(float* heap_dists,
                                                  int*   heap_indices,
                                                  int&   heap_size,
                                                  float  dist,
                                                  int    idx)
{
    // If the heap is not yet full, perform initial inserts.
    if (heap_size < K) {
        heap_insert_initial<K>(heap_dists, heap_indices, heap_size, dist, idx);
        return;
    }

    // Heap is full. Root contains the current worst (maximum) distance.
    if (dist >= heap_dists[0]) {
        // Candidate is not better than current worst neighbor; discard.
        return;
    }

    // Replace root with the new candidate and sift down to maintain max-heap.
    heap_dists[0]   = dist;
    heap_indices[0] = idx;

    int pos = 0;
    while (true) {
        int left  = (pos << 1) + 1;
        int right = left + 1;
        if (left >= K) break;

        // Find child with larger distance
        int largest = left;
        if (right < K && heap_dists[right] > heap_dists[left]) {
            largest = right;
        }

        if (heap_dists[pos] >= heap_dists[largest]) break;

        // Swap current with child
        float td              = heap_dists[pos];
        heap_dists[pos]       = heap_dists[largest];
        heap_dists[largest]   = td;

        int ti                = heap_indices[pos];
        heap_indices[pos]     = heap_indices[largest];
        heap_indices[largest] = ti;

        pos = largest;
    }
}

// Pop the current worst (max) element from the heap and return it.
// This is used after all distances are processed to output neighbors
// in ascending order by performing a standard heap sort.
template<int K>
__device__ __forceinline__ void heap_pop_max(float* heap_dists,
                                             int*   heap_indices,
                                             int&   heap_size,
                                             float& out_dist,
                                             int&   out_idx)
{
    // Root of the max-heap is the current worst (maximum) distance.
    out_dist = heap_dists[0];
    out_idx  = heap_indices[0];

    // Move last element to root and decrease size.
    heap_size--;
    if (heap_size > 0) {
        heap_dists[0]   = heap_dists[heap_size];
        heap_indices[0] = heap_indices[heap_size];

        // Sift down from root to restore max-heap.
        int pos = 0;
        while (true) {
            int left  = (pos << 1) + 1;
            int right = left + 1;
            if (left >= heap_size) break;

            int largest = left;
            if (right < heap_size && heap_dists[right] > heap_dists[left]) {
                largest = right;
            }

            if (heap_dists[pos] >= heap_dists[largest]) break;

            float td              = heap_dists[pos];
            heap_dists[pos]       = heap_dists[largest];
            heap_dists[largest]   = td;

            int ti                = heap_indices[pos];
            heap_indices[pos]     = heap_indices[largest];
            heap_indices[largest] = ti;

            pos = largest;
        }
    }
}

// -----------------------------------------------------------------------------
// Core kernel: one warp per query, k supplied as template parameter K.
//
// For each block:
//   - Shared memory holds a TILE_SIZE chunk of data points.
//   - Each warp in the block processes a different query point.
//   - Each warp maintains a max-heap of size K in shared memory as its
//     intermediate top-K result.
// -----------------------------------------------------------------------------

template<int K>
__global__ void knn_kernel(const float2* __restrict__ query,
                           int                    query_count,
                           const float2* __restrict__ data,
                           int                    data_count,
                           std::pair<int, float>* __restrict__ result)
{
    static_assert(K >= 32 && K <= 1024 && (K & (K - 1)) == 0,
                  "K must be a power of two between 32 and 1024");

    // Shared memory:
    //  - sh_data: cache of TILE_SIZE data points.
    //  - sh_heap_dists/sh_heap_indices: per-warp max-heap for top-K.
    __shared__ float2 sh_data[TILE_SIZE];
    __shared__ float  sh_heap_dists[WARPS_PER_BLOCK][K];
    __shared__ int    sh_heap_indices[WARPS_PER_BLOCK][K];

    const unsigned full_mask = 0xffffffffu;

    // Warp and lane identifiers
    const int thread_id       = threadIdx.x;
    const int warp_id_in_block= thread_id / WARP_SIZE;
    const int lane_id         = thread_id % WARP_SIZE;

    // Global warp index: one warp corresponds to one query
    const int global_warp_id  = blockIdx.x * WARPS_PER_BLOCK + warp_id_in_block;
    const int query_idx       = global_warp_id;

    const bool warp_active    = (query_idx < query_count);

    // Load query point into registers and broadcast within the warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (warp_active && lane_id == 0) {
        float2 q = query[query_idx];
        qx = q.x;
        qy = q.y;
    }
    // Broadcast from lane 0 to all lanes in the warp.
    qx = __shfl_sync(full_mask, qx, 0);
    qy = __shfl_sync(full_mask, qy, 0);

    // Pointers to this warp's heap arrays in shared memory.
    float* heap_dists   = &sh_heap_dists[warp_id_in_block][0];
    int*   heap_indices = &sh_heap_indices[warp_id_in_block][0];

    // Per-warp heap size (number of neighbors currently stored).
    int heap_size = 0;

    // Process data in tiles of size TILE_SIZE.
    for (int tile_start = 0; tile_start < data_count; tile_start += TILE_SIZE) {
        const int tile_size = min(TILE_SIZE, data_count - tile_start);

        // ---------------------------------------------------------------------
        // Load this tile of data points into shared memory.
        // Each thread loads LOADS_PER_THREAD contiguous points (if in range).
        // ---------------------------------------------------------------------
        #pragma unroll
        for (int i = 0; i < LOADS_PER_THREAD; ++i) {
            int dst_index   = thread_id + i * blockDim.x;   // 0 .. TILE_SIZE-1
            int global_idx  = tile_start + dst_index;
            if (dst_index < tile_size) {
                sh_data[dst_index] = data[global_idx];
            }
        }

        // Synchronize so that all data in the tile is visible to all warps.
        __syncthreads();

        // ---------------------------------------------------------------------
        // Each active warp processes the shared tile for its own query:
        //   - Compute squared distances to all points in the tile.
        //   - For each distance, attempt to insert into the warp's heap.
        //
        // We process the tile in chunks of WARP_SIZE data points:
        //   - In each chunk, each lane computes the distance to one point.
        //   - Lane 0 then sequentially processes the 32 candidate distances and
        //     updates the warp's heap using heap_maybe_insert().
        //
        // This design:
        //   - Uses all 32 lanes for distance computation,
        //   - Uses only lane 0 for heap mutation (avoids races),
        //   - Still allows many warps to run concurrently across the GPU.
        // ---------------------------------------------------------------------
        if (warp_active) {
            for (int base = 0; base < tile_size; base += WARP_SIZE) {
                int j = base + lane_id;

                // Compute distance for this lane's candidate (if within tile).
                float dist = 0.0f;
                int   idx  = -1;

                if (j < tile_size) {
                    float2 p = sh_data[j];
                    float dx = qx - p.x;
                    float dy = qy - p.y;
                    dist     = dx * dx + dy * dy;
                    idx      = tile_start + j;  // Global index into data[]
                }

                // Now, cooperatively process all 32 candidates in this chunk.
                // Each candidate is broadcast via warp shuffle and inserted
                // into the shared heap by lane 0 if it is among the current
                // top-K neighbors.
                #pragma unroll
                for (int src = 0; src < WARP_SIZE; ++src) {
                    float cand_dist = __shfl_sync(full_mask, dist, src);
                    int   cand_idx  = __shfl_sync(full_mask, idx,  src);

                    if (cand_idx < 0) {
                        // This lane did not contribute a valid candidate
                        // (out-of-range index at end of tile).
                        continue;
                    }

                    if (lane_id == 0) {
                        heap_maybe_insert<K>(heap_dists,
                                             heap_indices,
                                             heap_size,
                                             cand_dist,
                                             cand_idx);
                    }
                }

                // Ensure all lanes in the warp stay in lockstep before
                // proceeding to the next chunk of candidates.
                __syncwarp(full_mask);
            }
        }

        // Synchronize before loading the next tile of data points.
        __syncthreads();
    }

    // -------------------------------------------------------------------------
    // After all data points are processed, each active warp has a max-heap of
    // size K (heap_dists/heap_indices). The heap stores the K nearest
    // neighbors, but in arbitrary (heap) order.
    //
    // We convert the heap into a sorted list (ascending distance) by repeatedly
    // popping the maximum (worst) element. This is equivalent to performing a
    // heap sort. The result is written to global memory.
    // -------------------------------------------------------------------------
    if (warp_active && lane_id == 0) {
        const int base_out = query_idx * K;

        // heap_size should be >= K here; but if data_count == K, it will be
        // exactly K. We only pop K elements.
        int local_heap_size = heap_size;

        // Output in ascending order: we pop the maximum and fill the result
        // array from the end to the beginning.
        for (int out_pos = K - 1; out_pos >= 0; --out_pos) {
            float dist;
            int   idx;
            heap_pop_max<K>(heap_dists, heap_indices, local_heap_size, dist, idx);

            result[base_out + out_pos].first  = idx;
            result[base_out + out_pos].second = dist;
        }
    }
}

// -----------------------------------------------------------------------------
// Host interface: run_knn
//
// query       : pointer to device array of float2 (size = query_count)
// query_count : number of query points
// data        : pointer to device array of float2 (size = data_count)
// data_count  : number of data points
// result      : pointer to device array of std::pair<int,float>
//               (size = query_count * k)
// k           : number of neighbors to retrieve (power of 2 between 32 and 1024)
// -----------------------------------------------------------------------------

void run_knn(const float2 *query,
             int            query_count,
             const float2 *data,
             int            data_count,
             std::pair<int, float> *result,
             int            k)
{
    if (query_count <= 0 || data_count <= 0) {
        return;
    }

    // One warp per query.
    const int warps_per_block = WARPS_PER_BLOCK;
    const dim3 block_dim(THREADS_PER_BLOCK, 1, 1);
    const int total_warps = query_count;
    const int grid_x = (total_warps + warps_per_block - 1) / warps_per_block;
    const dim3 grid_dim(grid_x, 1, 1);

    // Dispatch specialized kernel based on k (power of two in [32, 1024]).
    switch (k) {
        case 32:
            knn_kernel<32><<<grid_dim, block_dim>>>(
                query, query_count, data, data_count, result);
            break;
        case 64:
            knn_kernel<64><<<grid_dim, block_dim>>>(
                query, query_count, data, data_count, result);
            break;
        case 128:
            knn_kernel<128><<<grid_dim, block_dim>>>(
                query, query_count, data, data_count, result);
            break;
        case 256:
            knn_kernel<256><<<grid_dim, block_dim>>>(
                query, query_count, data, data_count, result);
            break;
        case 512:
            knn_kernel<512><<<grid_dim, block_dim>>>(
                query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_kernel<1024><<<grid_dim, block_dim>>>(
                query, query_count, data, data_count, result);
            break;
        default:
            // k is documented to always be a power of two between 32 and 1024.
            // If an unsupported k is provided, do nothing.
            break;
    }
}

#include <cuda_runtime.h>
#include <utility>

/*
 * Optimized CUDA implementation of k-nearest neighbors (k-NN) for 2D points.
 *
 * Design:
 * - Each query point is processed by a single warp (32 threads). We use one warp per block.
 * - The data points are processed in tiles (batches). Each tile is loaded into shared memory
 *   by all threads in the block (warp).
 * - For each query, we maintain a max-heap of current k best neighbors (indices + squared distances)
 *   in shared memory, private to that warp/query.
 * - In each iteration over a tile:
 *     * Each thread computes the distance to one candidate point and writes it into shared memory.
 *     * Thread 0 sequentially inserts the 32 candidates into the shared heap.
 * - After processing all data points, thread 0 performs heap extraction to produce the final
 *   sorted list of k nearest neighbors for that query and writes them to the result array.
 *
 * Notes:
 * - Distances are squared Euclidean (no sqrt) as requested.
 * - k is assumed to be a power of two in [32, 1024]; the implementation supports all k <= 1024.
 * - No additional device memory allocations are performed; only shared memory is used.
 */

namespace {

static constexpr int WARP_SIZE = 32;
static constexpr int MAX_K     = 1024;   // maximum supported k
static constexpr int TILE_SIZE = 4096;   // number of data points per tile

// Device-side struct layout-compatible with std::pair<int, float>.
struct DevicePair {
    int   first;
    float second;
};

// Sift an element up in a max-heap (by distance).
__device__ __forceinline__ void heap_sift_up(float *heap_dist,
                                             int   *heap_idx,
                                             int    pos)
{
    // Standard binary heap sift-up to maintain max-heap property.
    while (pos > 0) {
        int parent = (pos - 1) >> 1;
        float d_pos    = heap_dist[pos];
        float d_parent = heap_dist[parent];

        if (d_parent >= d_pos) {
            break;
        }

        // Swap parent and current
        heap_dist[pos]   = d_parent;
        heap_idx[pos]    = heap_idx[parent];
        heap_dist[parent] = d_pos;
        heap_idx[parent]  = heap_idx[pos];

        pos = parent;
    }
}

// Sift an element down in a max-heap (by distance).
__device__ __forceinline__ void heap_sift_down(float *heap_dist,
                                               int   *heap_idx,
                                               int    heap_size,
                                               int    pos)
{
    // Standard binary heap sift-down to maintain max-heap property.
    while (true) {
        int left  = (pos << 1) + 1;
        int right = left + 1;
        int largest = pos;

        if (left < heap_size && heap_dist[left] > heap_dist[largest]) {
            largest = left;
        }
        if (right < heap_size && heap_dist[right] > heap_dist[largest]) {
            largest = right;
        }
        if (largest == pos) {
            break;
        }

        float d_pos     = heap_dist[pos];
        float d_largest = heap_dist[largest];
        int   i_pos     = heap_idx[pos];
        int   i_largest = heap_idx[largest];

        heap_dist[pos]    = d_largest;
        heap_idx[pos]     = i_largest;
        heap_dist[largest] = d_pos;
        heap_idx[largest]  = i_pos;

        pos = largest;
    }
}

__global__ void knn_kernel(const float2 * __restrict__ query,
                           int                     query_count,
                           const float2 * __restrict__ data,
                           int                     data_count,
                           int                     k,
                           DevicePair * __restrict__ result)
{
    // One warp (block) per query.
    const int qid  = blockIdx.x;
    const int lane = threadIdx.x;  // 0..31, single warp per block

    if (qid >= query_count) {
        return;
    }

    // Shared memory used per block (i.e., per query).
    __shared__ float2 tile[TILE_SIZE];         // cached data points
    __shared__ float  heap_dist[MAX_K];        // distances in max-heap
    __shared__ int    heap_idx[MAX_K];         // indices in max-heap
    __shared__ int    heap_size;               // current heap size (<= k)
    __shared__ float  cand_dist[WARP_SIZE];    // candidate distances (one per thread)
    __shared__ int    cand_idx[WARP_SIZE];     // candidate indices (one per thread)

    // Load query point into registers.
    const float2 q = query[qid];

    // Initialize heap for this query.
    if (lane == 0) {
        heap_size = 0;
    }
    __syncthreads();

    int offset         = 0;
    int data_remaining = data_count;

    // Iterate over data in tiles.
    while (data_remaining > 0) {
        const int tile_len = (data_remaining > TILE_SIZE) ? TILE_SIZE : data_remaining;

        // Load current tile into shared memory cooperatively.
        for (int i = lane; i < tile_len; i += WARP_SIZE) {
            tile[i] = data[offset + i];
        }
        __syncthreads();

        // Process tile in batches of WARP_SIZE points.
        for (int base = 0; base < tile_len; base += WARP_SIZE) {
            const int local_idx = base + lane;
            const int global_idx = offset + local_idx;

            if (local_idx < tile_len) {
                const float2 p = tile[local_idx];
                const float dx = p.x - q.x;
                const float dy = p.y - q.y;
                cand_dist[lane] = dx * dx + dy * dy;  // squared Euclidean distance
                cand_idx[lane]  = global_idx;
            } else {
                // Mark invalid candidate.
                cand_idx[lane]  = -1;
                cand_dist[lane] = 0.0f;
            }
            __syncthreads();

            // Thread 0 merges candidates into the heap.
            if (lane == 0) {
                int hs = heap_size;

                #pragma unroll
                for (int i = 0; i < WARP_SIZE; ++i) {
                    const int   cidx  = cand_idx[i];
                    const float cdist = cand_dist[i];

                    if (cidx < 0) {
                        continue;  // skip invalid
                    }

                    if (hs < k) {
                        // Heap not full: insert new element and sift up.
                        int pos = hs++;
                        heap_dist[pos] = cdist;
                        heap_idx[pos]  = cidx;
                        heap_sift_up(heap_dist, heap_idx, pos);
                    } else {
                        // Heap full: only accept if candidate is better (smaller distance)
                        // than current worst (root of max-heap).
                        if (cdist >= heap_dist[0]) {
                            continue;
                        }
                        heap_dist[0] = cdist;
                        heap_idx[0]  = cidx;
                        heap_sift_down(heap_dist, heap_idx, k, 0);
                    }
                }

                heap_size = hs;
            }
            __syncthreads();
        }

        offset         += tile_len;
        data_remaining -= tile_len;
    }

    // Extract top-k neighbors from heap and store in ascending order of distance.
    if (lane == 0) {
        int hs = heap_size;  // should be >= k since data_count >= k

        // Pop from max-heap: each pop returns the current worst among the k best.
        // Store them from the end so that the final order is ascending.
        for (int pos = k - 1; pos >= 0; --pos) {
            const int   best_idx  = heap_idx[0];
            const float best_dist = heap_dist[0];

            // Move last element to root and reduce heap size.
            --hs;
            if (hs > 0) {
                heap_idx[0]  = heap_idx[hs];
                heap_dist[0] = heap_dist[hs];
                heap_sift_down(heap_dist, heap_idx, hs, 0);
            }

            const int out_offset = qid * k + pos;
            result[out_offset].first  = best_idx;
            result[out_offset].second = best_dist;
        }
    }
}

} // anonymous namespace

// Host-side entry point.
void run_knn(const float2 *query,
             int           query_count,
             const float2 *data,
             int           data_count,
             std::pair<int, float> *result,
             int           k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    // This implementation supports k up to MAX_K.
    if (k > MAX_K) {
        // For this task, k is guaranteed to be <= 1024, so we do not handle this case.
        return;
    }

    const dim3 block_dim(WARP_SIZE, 1, 1);     // one warp per block
    const dim3 grid_dim(query_count, 1, 1);    // one block per query

    // Reinterpret std::pair<int, float>* as layout-compatible DevicePair*.
    DevicePair *device_result = reinterpret_cast<DevicePair*>(result);

    knn_kernel<<<grid_dim, block_dim>>>(query,
                                        query_count,
                                        data,
                                        data_count,
                                        k,
                                        device_result);
}

#include <cuda_runtime.h>
#include <math_constants.h>
#include <utility>

/*
 * Optimized k-NN (k-nearest neighbors) for 2D points on NVIDIA GPUs.
 *
 * Design overview
 * ---------------
 * - One warp (32 threads) is responsible for computing the k nearest neighbors
 *   of a single query point.
 * - Each thread block contains WARPS_PER_BLOCK warps; thus each block processes
 *   WARPS_PER_BLOCK queries in parallel.
 * - The data set is processed in tiles. Each tile is cooperatively loaded into
 *   shared memory by all threads in the block, and then all warps in the block
 *   reuse that tile for their own query point.
 * - For each query, the warp maintains a streaming top-k structure:
 *     * The global top-k list (k distances + indices) is distributed across
 *       the 32 threads: each thread holds k/32 entries (k is guaranteed to be
 *       a power of two between 32 and 1024, so k/32 is an integer in [1, 32]).
 *     * The list is initialized with "empty" entries and filled by streaming
 *       over all data points. Once the list is full, candidates are only
 *       inserted if they are better than the current worst element.
 *     * To decide whether a candidate qualifies, the warp uses an approximate
 *       threshold (an upper bound on the current worst distance) for a fast
 *       reject, and a warp-wide reduction to find the exact worst when needed.
 * - Distances are computed in parallel:
 *     * For each tile, the warp processes points in batches of 32: each lane
 *       computes the distance to one point, then the 32 candidates are
 *       sequentially inserted into the warp's shared top-k structure using
 *       warp shuffles.
 * - After all data points are processed:
 *     * Each warp writes its distributed top-k list into a contiguous region
 *       of shared memory.
 *     * Lane 0 of each warp performs a simple selection sort on its k entries
 *       (O(k^2), but k <= 1024 and done once per query).
 *     * All lanes then write the sorted results to global memory in a
 *       coalesced manner.
 *
 * Notes
 * -----
 * - No additional device memory is allocated; only registers and shared memory
 *   are used.
 * - k must be a power of two between 32 and 1024 (inclusive) and data_count >= k.
 * - The result is sorted in ascending order of distance for each query.
 */

constexpr int WARP_SIZE         = 32;
constexpr int WARPS_PER_BLOCK   = 8;    // Number of warps (queries) per block
constexpr int BLOCK_THREADS     = WARP_SIZE * WARPS_PER_BLOCK;
constexpr int TILE_SIZE         = 1024; // Number of data points cached per tile
constexpr int MAX_K             = 1024; // Maximum supported k
constexpr int MAX_LOCAL_K       = MAX_K / WARP_SIZE; // 1024 / 32 = 32

// Warp-synchronous insertion of a candidate into the distributed top-k list.
__device__ __forceinline__
void warp_insert_candidate(
    float candidateDist,
    int   candidateIndex,
    float *best_dists,     // per-thread array of size MAX_LOCAL_K
    int   *best_indices,   // per-thread array of size MAX_LOCAL_K
    int   k,
    int   local_k_per_lane,
    int   laneId,
    unsigned int warpMask,
    int   &fillCount,
    float &approxMax)
{
    // Fast path while we have not yet filled k entries:
    // we simply fill slots sequentially without any comparisons.
    int fc = __shfl_sync(warpMask, fillCount, 0);
    if (fc < k) {
        int insertPos   = fc;                     // 0 .. k-1
        int ownerLane   = insertPos & (WARP_SIZE - 1); // insertPos % 32
        int ownerOffset = insertPos >> 5;         // insertPos / 32

        if (laneId == ownerLane) {
            best_dists[ownerOffset]   = candidateDist;
            best_indices[ownerOffset] = candidateIndex;
        }

        if (laneId == 0) {
            fillCount = fc + 1;
            // We do not set approxMax here; it will be set when we first
            // compute the exact worst element during a heavy-path insertion.
        }
        return;
    }

    // At this point, we have already inserted k elements; we maintain the top-k.
    // First, apply a fast reject using an approximate threshold.
    float am = __shfl_sync(warpMask, approxMax, 0);
    if (candidateDist >= am) {
        // Candidate cannot be better than the current worst; discard.
        return;
    }

    // Heavy path: recompute the exact worst element across the k entries.

    // Each lane scans its own local_k_per_lane entries to find its local maximum.
    float localMax       = -CUDART_INF_F;
    int   localMaxOffset = 0;

    for (int i = 0; i < local_k_per_lane; ++i) {
        float v = best_dists[i];
        if (v > localMax) {
            localMax       = v;
            localMaxOffset = i;
        }
    }

    // Encode the local maximum slot as a global slot index in [0, k-1].
    int localMaxSlot = (localMaxOffset << 5) + laneId; // offset * 32 + laneId

    float maxDist = localMax;
    int   maxSlot = localMaxSlot;

    // Warp-wide reduction to find the global maximum distance and its slot.
    for (int offset = WARP_SIZE / 2; offset > 0; offset >>= 1) {
        float otherDist = __shfl_down_sync(warpMask, maxDist, offset);
        int   otherSlot = __shfl_down_sync(warpMask, maxSlot, offset);
        if (otherDist > maxDist) {
            maxDist = otherDist;
            maxSlot = otherSlot;
        }
    }

    // Broadcast the global maximum distance and slot to all lanes.
    float globalMaxDist = __shfl_sync(warpMask, maxDist, 0);
    int   globalMaxSlot = __shfl_sync(warpMask, maxSlot, 0);

    // Update approximate threshold in lane 0; it is an upper bound on
    // the current worst distance (it may be slightly larger after replacement,
    // which is still safe for pruning).
    if (laneId == 0) {
        approxMax = globalMaxDist;
    }

    // If the candidate is not better than the exact worst, discard it.
    if (candidateDist >= globalMaxDist) {
        return;
    }

    // Replace the global worst element with the candidate.
    int ownerLane   = globalMaxSlot & (WARP_SIZE - 1);
    int ownerOffset = globalMaxSlot >> 5;

    if (laneId == ownerLane && ownerOffset < local_k_per_lane) {
        best_dists[ownerOffset]   = candidateDist;
        best_indices[ownerOffset] = candidateIndex;
    }
}

// CUDA kernel implementing k-NN for 2D points.
__global__
void knn_kernel_2d(
    const float2 *__restrict__ query,
    int                      query_count,
    const float2 *__restrict__ data,
    int                      data_count,
    int                      k,
    std::pair<int, float> *__restrict__ result)
{
    // Shared memory:
    // - sh_data:  tile of data points reused by all warps in the block.
    // - sh_top_dists / sh_top_indices: per-warp buffers for the final top-k
    //   results (used for sorting and writing out).
    __shared__ float2 sh_data[TILE_SIZE];
    __shared__ float  sh_top_dists[WARPS_PER_BLOCK * MAX_K];
    __shared__ int    sh_top_indices[WARPS_PER_BLOCK * MAX_K];

    const int tid    = threadIdx.x;
    const int laneId = tid & (WARP_SIZE - 1); // 0..31
    const int warpId = tid >> 5;             // 0..(WARPS_PER_BLOCK-1)

    const int globalWarpId = blockIdx.x * WARPS_PER_BLOCK + warpId;
    const int queryId      = globalWarpId;   // one warp per query

    // Some warps in the last block may not correspond to a valid query.
    const bool warpActive = (queryId < query_count);

    // Load the query point (or a dummy value for inactive warps).
    float2 q;
    if (warpActive) {
        q = query[queryId];
    } else {
        q.x = 0.0f;
        q.y = 0.0f;
    }

    // k is guaranteed to be a power of two between 32 and 1024; thus
    // local_k_per_lane is an integer in [1, 32].
    const int local_k_per_lane = k / WARP_SIZE;

    // Per-thread portion of the distributed top-k list.
    float best_dists[MAX_LOCAL_K];
    int   best_indices[MAX_LOCAL_K];

    // Initialize local top-k storage with "infinite" distances.
    for (int i = 0; i < MAX_LOCAL_K; ++i) {
        best_dists[i]   = CUDART_INF_F;
        best_indices[i] = -1;
    }

    // Shared warp-wide state (stored per thread, but lane 0 acts as master).
    int   fillCount = 0;           // number of entries actually filled, up to k
    float approxMax = CUDART_INF_F; // approximate upper bound on current worst

    const unsigned int warpMask = __activemask();

    // Process the data set in tiles.
    for (int tileStart = 0; tileStart < data_count; tileStart += TILE_SIZE) {
        const int remaining = data_count - tileStart;
        const int tileSize  = (remaining < TILE_SIZE) ? remaining : TILE_SIZE;

        // Cooperative load of the tile into shared memory.
        for (int i = tid; i < tileSize; i += blockDim.x) {
            sh_data[i] = data[tileStart + i];
        }
        __syncthreads();

        // Process the tile in batches of 32 points per warp.
        for (int base = 0; base < tileSize; base += WARP_SIZE) {
            const int j = base + laneId;

            float dist;
            int   dataIndex;

            if (j < tileSize && warpActive) {
                const float2 dp = sh_data[j];
                const float dx  = dp.x - q.x;
                const float dy  = dp.y - q.y;
                // Squared Euclidean distance (using FMA where possible).
                dist      = fmaf(dy, dy, dx * dx);
                dataIndex = tileStart + j;
            } else {
                // Inactive or out-of-range lanes generate dummy candidates
                // that will be ignored.
                dist      = CUDART_INF_F;
                dataIndex = -1;
            }

            // Broadcast and insert the 32 candidates of this batch one by one.
            for (int srcLane = 0; srcLane < WARP_SIZE; ++srcLane) {
                float cdist  = __shfl_sync(warpMask, dist, srcLane);
                int   cindex = __shfl_sync(warpMask, dataIndex, srcLane);

                if (cindex < 0) {
                    // Dummy candidate; skip.
                    continue;
                }

                // All threads in the warp cooperatively update the top-k list
                // with the candidate (cdist, cindex).
                warp_insert_candidate(
                    cdist,
                    cindex,
                    best_dists,
                    best_indices,
                    k,
                    local_k_per_lane,
                    laneId,
                    warpMask,
                    fillCount,
                    approxMax
                );
            }
        }

        __syncthreads();
    }

    // Each warp writes its distributed top-k list into a contiguous region
    // of shared memory, then sorts it and writes it out to global memory.

    const int warpBase = warpId * MAX_K;

    // Scatter from per-thread storage to shared, assembling k entries per warp.
    for (int offset = 0; offset < local_k_per_lane; ++offset) {
        const int globalSlot = (offset << 5) + laneId; // offset * 32 + laneId
        if (globalSlot < k) {
            sh_top_dists[warpBase + globalSlot]   = best_dists[offset];
            sh_top_indices[warpBase + globalSlot] = best_indices[offset];
        }
    }

    __syncthreads();

    // Lane 0 of each active warp performs a simple selection sort on its k
    // entries in shared memory to order neighbors by increasing distance.
    if (warpActive && laneId == 0) {
        float *dists = &sh_top_dists[warpBase];
        int   *idxs  = &sh_top_indices[warpBase];

        for (int i = 0; i < k - 1; ++i) {
            int   minPos = i;
            float minVal = dists[i];

            for (int j = i + 1; j < k; ++j) {
                float v = dists[j];
                if (v < minVal) {
                    minVal = v;
                    minPos = j;
                }
            }

            if (minPos != i) {
                float tmpd = dists[i];
                dists[i]   = dists[minPos];
                dists[minPos] = tmpd;

                int tmpi   = idxs[i];
                idxs[i]    = idxs[minPos];
                idxs[minPos] = tmpi;
            }
        }
    }

    __syncthreads();

    // All lanes of each active warp write the sorted results to global memory.
    if (warpActive) {
        float *dists = &sh_top_dists[warpBase];
        int   *idxs  = &sh_top_indices[warpBase];

        for (int j = laneId; j < k; j += WARP_SIZE) {
            const int outPos = queryId * k + j;
            result[outPos].first  = idxs[j];
            result[outPos].second = dists[j];
        }
    }
}

// Host-side interface as specified.
void run_knn(
    const float2 *query,
    int           query_count,
    const float2 *data,
    int           data_count,
    std::pair<int, float> *result,
    int           k)
{
    // Assumptions based on problem statement:
    // - data_count >= k
    // - k is a power of two between 32 and 1024 (inclusive).
    // - query, data, and result are device pointers (allocated with cudaMalloc).

    const dim3 blockDim(BLOCK_THREADS);
    const int  numWarps  = query_count; // one warp per query
    const int  gridX     = (numWarps + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    const dim3 gridDim(gridX);

    knn_kernel_2d<<<gridDim, blockDim>>>(
        query,
        query_count,
        data,
        data_count,
        k,
        result
    );
}

#include <cuda_runtime.h>
#include <utility>

/*
 * This file implements a CUDA-based k-NN (k-nearest neighbors) search for 2D points.
 *
 * Key design points:
 *  - Each query point is processed by exactly one warp (32 threads).
 *  - The dataset is processed in tiles; each tile of data points is loaded once into
 *    shared memory by the whole block, and then reused by all warps in the block.
 *  - For each query (warp), we maintain an intermediate top-k result in shared memory
 *    as a max-heap (by squared distance). This heap is private to the warp.
 *  - Distances are computed collaboratively by all 32 threads in the warp.
 *  - Candidate distances are broadcast via warp shuffles to lane 0, which updates
 *    the top-k heap (one heap per warp). This keeps the heap logic simple and
 *    branch-free for other lanes.
 *  - At the end, the heap is turned into a sorted list (ascending distance) using
 *    heap sort, and all lanes in the warp cooperatively write results to global memory.
 *
 * Assumptions:
 *  - k is a power of two between 32 and 1024 inclusive.
 *  - data_count >= k.
 *  - query, data, and result point to device memory allocated via cudaMalloc.
 *  - Each point is a float2 (x, y).
 *  - Distances are squared Euclidean distances (no square root).
 */

#ifndef KNN_WARP_SIZE
#define KNN_WARP_SIZE 32
#endif

// Tunable hyper-parameters for this implementation.
static constexpr int KNN_MAX_K             = 1024;         // maximum supported k
static constexpr int KNN_WARPS_PER_BLOCK   = 8;            // warps per block (8 * 32 = 256 threads)
static constexpr int KNN_THREADS_PER_BLOCK = KNN_WARPS_PER_BLOCK * KNN_WARP_SIZE;
static constexpr int KNN_TILE_POINTS       = 1024;         // data points per shared-memory tile

// ----------------------------------------------------------------------------
// Device-side heap helpers (max-heap on squared distances).
// ----------------------------------------------------------------------------

/*
 * Insert a (dist, index) pair into a max-heap of capacity k.
 *
 *  - heapDist: array of distances (length >= k)
 *  - heapIndex: array of indices (length >= k)
 *  - heapSize: current number of elements in the heap (modified in-place)
 *  - dist: candidate squared distance
 *  - index: candidate data-point index
 *  - k: heap capacity (= desired k)
 *
 * The heap invariant:
 *  - For heapSize > 0, heapDist[0] is the largest distance in the heap (worst neighbor).
 *  - Children of node i are at 2*i + 1 and 2*i + 2.
 *
 * Behavior:
 *  - If heapSize < k, insert always.
 *  - Else, insert only if dist < heapDist[0] (better than the current worst).
 *
 * This function is intended to be called only by lane 0 of a warp.
 */
__device__ __forceinline__
void knn_heap_insert(float *heapDist,
                     int   *heapIndex,
                     int   &heapSize,
                     float  dist,
                     int    index,
                     int    k)
{
    // If there is still room, just insert and sift up.
    if (heapSize < k) {
        int i = heapSize;
        heapSize++;

        heapDist[i]  = dist;
        heapIndex[i] = index;

        // Sift up to restore max-heap property.
        while (i > 0) {
            int parent = (i - 1) >> 1;
            float parentDist = heapDist[parent];
            float currentDist = heapDist[i];
            if (parentDist >= currentDist) {
                break;
            }
            // Swap parent and current.
            heapDist[i]  = parentDist;
            heapIndex[i] = heapIndex[parent];

            heapDist[parent]  = currentDist;
            heapIndex[parent] = index;

            i = parent;
        }
    } else {
        // Heap full: only insert if this candidate is better (smaller distance)
        // than the worst currently in the heap (root).
        float rootDist = heapDist[0];
        if (dist >= rootDist) {
            return; // candidate is not among top-k
        }

        // Replace root with new candidate and sift down.
        heapDist[0]  = dist;
        heapIndex[0] = index;

        int i = 0;
        const int size = heapSize; // == k

        while (true) {
            int left  = (i << 1) + 1;
            int right = left + 1;

            if (left >= size) {
                break; // no children
            }

            // Find child with larger distance.
            int largest = left;
            float largestDist = heapDist[left];

            if (right < size) {
                float rightDist = heapDist[right];
                if (rightDist > largestDist) {
                    largest = right;
                    largestDist = rightDist;
                }
            }

            float currentDist = heapDist[i];
            if (currentDist >= largestDist) {
                break; // heap property satisfied
            }

            // Swap current with largest child.
            heapDist[i]  = largestDist;
            heapIndex[i] = heapIndex[largest];

            heapDist[largest]  = currentDist;
            heapIndex[largest] = heapIndex[i];

            i = largest;
        }
    }
}

/*
 * Convert a max-heap (heapDist, heapIndex) of length n into an array sorted
 * ascending by distance using heap sort in-place.
 *
 * After this function:
 *  - heapDist[0] .. heapDist[n-1] are in ascending order.
 *  - heapIndex[] reordered correspondingly.
 *
 * This function is intended to be called only by lane 0 of a warp.
 */
__device__ __forceinline__
void knn_heap_sort_ascending(float *heapDist,
                             int   *heapIndex,
                             int    n)
{
    // Standard heapsort on a max-heap:
    // repeatedly move the root (largest) to the end and restore heap on prefix.
    for (int end = n - 1; end > 0; --end) {
        // Swap root with end.
        float rootDist = heapDist[0];
        int   rootIdx  = heapIndex[0];

        heapDist[0]    = heapDist[end];
        heapIndex[0]   = heapIndex[end];

        heapDist[end]  = rootDist;
        heapIndex[end] = rootIdx;

        // Sift down heapDist[0] .. heapDist[end-1].
        int i = 0;
        while (true) {
            int left  = (i << 1) + 1;
            int right = left + 1;

            if (left >= end) {
                break; // no children within heap
            }

            int largest = left;
            float largestDist = heapDist[left];

            if (right < end) {
                float rightDist = heapDist[right];
                if (rightDist > largestDist) {
                    largest = right;
                    largestDist = rightDist;
                }
            }

            float currentDist = heapDist[i];
            if (currentDist >= largestDist) {
                break;
            }

            // Swap current with largest child.
            heapDist[i]  = largestDist;
            heapIndex[i] = heapIndex[largest];

            heapDist[largest]  = currentDist;
            heapIndex[largest] = heapIndex[i];

            i = largest;
        }
    }

    // After heapsort on max-heap, the array is in ascending order.
}

// ----------------------------------------------------------------------------
// CUDA kernel
// ----------------------------------------------------------------------------

/*
 * Kernel mapping:
 *  - Each warp in the grid processes exactly one query point.
 *  - Block contains KNN_WARPS_PER_BLOCK warps; thus each block processes
 *    KNN_WARPS_PER_BLOCK queries.
 *  - Shared memory layout per block:
 *      [0, KNN_TILE_POINTS)                : float2 s_data[] (tile of data points)
 *      [KNN_TILE_POINTS, ...)              : float s_heapDist[WARPS_PER_BLOCK][KNN_MAX_K]
 *      [.. after previous .., ..)          : int   s_heapIndex[WARPS_PER_BLOCK][KNN_MAX_K]
 */
__global__
void knn_kernel_2d_2nn(const float2 * __restrict__ query,
                       int                      query_count,
                       const float2 * __restrict__ data,
                       int                      data_count,
                       std::pair<int, float> * __restrict__ result,
                       int                      k)
{
    // Thread, warp, and block indexing.
    const int tid            = threadIdx.x;
    const int warpIdInBlock  = tid / KNN_WARP_SIZE;
    const int laneId         = tid & (KNN_WARP_SIZE - 1);
    const int warpGlobalId   = blockIdx.x * KNN_WARPS_PER_BLOCK + warpIdInBlock;

    // Whether this warp corresponds to a valid query.
    const bool activeWarp    = (warpGlobalId < query_count);

    // Shared memory layout.
    extern __shared__ unsigned char shared_raw[];
    // Data tile.
    float2 *s_data = reinterpret_cast<float2*>(shared_raw);

    // Offsets for heap storage.
    const size_t dataTileBytes   = static_cast<size_t>(KNN_TILE_POINTS) * sizeof(float2);
    float *s_heapDist = reinterpret_cast<float*>(shared_raw + dataTileBytes);
    const size_t heapDistBytes   = static_cast<size_t>(KNN_WARPS_PER_BLOCK) *
                                   static_cast<size_t>(KNN_MAX_K) * sizeof(float);
    int   *s_heapIndex = reinterpret_cast<int*>(shared_raw + dataTileBytes + heapDistBytes);

    // Per-warp heap pointers in shared memory.
    float *heapDist  = s_heapDist  + static_cast<size_t>(warpIdInBlock) * KNN_MAX_K;
    int   *heapIndex = s_heapIndex + static_cast<size_t>(warpIdInBlock) * KNN_MAX_K;

    // Load query point for this warp and broadcast to all lanes.
    float qx = 0.0f;
    float qy = 0.0f;
    if (activeWarp && laneId == 0) {
        float2 q = query[warpGlobalId];
        qx = q.x;
        qy = q.y;
    }
    if (activeWarp) {
        // All threads in this warp participate, so full mask is fine.
        unsigned mask = 0xffffffffu;
        qx = __shfl_sync(mask, qx, 0);
        qy = __shfl_sync(mask, qy, 0);
    }

    // Private heap size per warp, maintained by lane 0 only.
    int heapSize = 0;

    // Process the dataset in tiles.
    for (int tileStart = 0; tileStart < data_count; tileStart += KNN_TILE_POINTS) {
        int remaining = data_count - tileStart;
        int tileSize  = (remaining < KNN_TILE_POINTS) ? remaining : KNN_TILE_POINTS;

        // Block-wide cooperative load of the tile into shared memory.
        for (int i = tid; i < tileSize; i += blockDim.x) {
            s_data[i] = data[tileStart + i];
        }

        // Ensure the entire tile is loaded before proceeding.
        __syncthreads();

        if (activeWarp) {
            // Iterate over the tile in chunks of 32, so that each lane processes
            // at most one point per chunk.
            for (int base = 0; base < tileSize; base += KNN_WARP_SIZE) {
                int jLocal = base + laneId;
                bool valid = (jLocal < tileSize);

                // Compute candidate distance for this lane's data point.
                float candDist = 0.0f;
                int   candIdx  = 0;
                if (valid) {
                    float2 p = s_data[jLocal];
                    float dx = qx - p.x;
                    float dy = qy - p.y;
                    candDist = dx * dx + dy * dy;
                    candIdx  = tileStart + jLocal;
                }

                // Now, in a warp-synchronous manner, broadcast each lane's candidate
                // to lane 0, which updates the heap.
                // This ensures exactly one heap update per data point.
                unsigned mask = 0xffffffffu;
                for (int srcLane = 0; srcLane < KNN_WARP_SIZE; ++srcLane) {
                    bool  bValid = __shfl_sync(mask, valid,     srcLane);
                    float bDist  = __shfl_sync(mask, candDist,  srcLane);
                    int   bIdx   = __shfl_sync(mask, candIdx,   srcLane);

                    if (laneId == 0 && bValid) {
                        knn_heap_insert(heapDist, heapIndex, heapSize, bDist, bIdx, k);
                    }
                }

                // Warp-synchronous section ends here. No explicit __syncwarp() is required
                // because control flow is warp-uniform, but it is harmless if added.
            }
        }

        // Ensure all warps in the block are done with the tile before overwriting it.
        __syncthreads();
    }

    // After scanning the entire dataset, each active warp's heap contains its k
    // nearest neighbors (unsorted, in a max-heap).
    if (activeWarp) {
        // Convert heap to ascending order and write results.
        if (laneId == 0) {
            // data_count >= k, so heapSize should be k. As a safety guard, clamp.
            if (heapSize > k) {
                heapSize = k;
            }

            // Ensure we have at least one neighbor; given data_count >= k >= 1, heapSize > 0.
            if (heapSize > 1) {
                knn_heap_sort_ascending(heapDist, heapIndex, heapSize);
            }
        }

        // Make sure lane 0 has finished sorting before other lanes read heap data.
        __syncwarp();

        // Write out results cooperatively: each lane writes a subset of the k neighbors.
        const int outBase = warpGlobalId * k;
        for (int j = laneId; j < k; j += KNN_WARP_SIZE) {
            std::pair<int, float> outPair;
            outPair.first  = heapIndex[j];
            outPair.second = heapDist[j];
            result[outBase + j] = outPair;
        }
    }
}

// ----------------------------------------------------------------------------
// Host interface
// ----------------------------------------------------------------------------

/*
 * Host entry point:
 *
 *  - query: pointer to device array of float2 (query_count elements)
 *  - query_count: number of query points
 *  - data: pointer to device array of float2 (data_count elements)
 *  - data_count: number of data points
 *  - result: pointer to device array of std::pair<int, float>,
 *            size query_count * k
 *  - k: number of nearest neighbors to find (power of 2, 32 <= k <= 1024)
 *
 * This function launches the CUDA kernel with an appropriate configuration.
 * It does not perform any device memory allocation.
 */
void run_knn(const float2 *query,
             int            query_count,
             const float2 *data,
             int            data_count,
             std::pair<int, float> *result,
             int            k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    // Sanity clamp for k; the problem guarantees 32 <= k <= 1024 and power of two.
    if (k > KNN_MAX_K) {
        k = KNN_MAX_K;
    }

    // Grid configuration: one warp per query.
    const int threadsPerBlock = KNN_THREADS_PER_BLOCK;       // 256 threads (8 warps)
    const int warpsPerBlock   = KNN_WARPS_PER_BLOCK;
    const int numWarps        = query_count;
    const int numBlocks       = (numWarps + warpsPerBlock - 1) / warpsPerBlock;

    // Shared memory size per block:
    //  - Tile of KNN_TILE_POINTS float2.
    //  - Per-warp heaps: KNN_WARPS_PER_BLOCK * KNN_MAX_K (float + int).
    const size_t sharedMemBytes =
        static_cast<size_t>(KNN_TILE_POINTS) * sizeof(float2) +
        static_cast<size_t>(KNN_WARPS_PER_BLOCK) * static_cast<size_t>(KNN_MAX_K) * sizeof(float) +
        static_cast<size_t>(KNN_WARPS_PER_BLOCK) * static_cast<size_t>(KNN_MAX_K) * sizeof(int);

    // Launch kernel.
    knn_kernel_2d_2nn<<<numBlocks, threadsPerBlock, sharedMemBytes>>>(
        query, query_count, data, data_count, result, k
    );

    // Optional: synchronize or check for errors here if desired.
    // cudaDeviceSynchronize();
    // cudaGetLastError();
}

#include <cuda_runtime.h>
#include <utility>
#include <cfloat>

// Simple POD equivalent of std::pair<int, float> for device use.
// The host code will reinterpret_cast between this and std::pair<int, float>.
struct KnnPair {
    int   first;
    float second;
};

// Tunable kernel configuration parameters.
constexpr int WARP_SIZE         = 32;
constexpr int WARPS_PER_BLOCK   = 4;    // 4 warps per block -> 128 threads/block
constexpr int THREADS_PER_BLOCK = WARP_SIZE * WARPS_PER_BLOCK;
constexpr int TILE_SIZE         = 1024; // Number of data points cached per block in shared memory

// Warp-wide function that finds the current worst (maximum) distance in a Top-K buffer.
// The Top-K buffer is shared among threads of the warp and stored in shared memory.
// All threads in the warp must call this function with the same arguments.
//
// topkDistances: pointer to the shared-memory array of distances for all warps in the block
// base         : starting index of this warp's Top-K buffer in topkDistances
// k            : number of neighbors to keep
// worstDist    : (output) maximum distance in the Top-K buffer
// worstPos     : (output) position of the maximum distance within this warp's Top-K buffer (0..k-1)
__device__ __forceinline__
void warp_find_worst(const float *topkDistances,
                     int base,
                     int k,
                     float &worstDist,
                     int &worstPos)
{
    const int laneId = threadIdx.x & (WARP_SIZE - 1);
    float localMaxDist = -FLT_MAX;
    int   localMaxPos  = 0;

    // Each lane scans a strided subset of the Top-K buffer.
    for (int i = laneId; i < k; i += WARP_SIZE) {
        float d = topkDistances[base + i];
        if (d > localMaxDist) {
            localMaxDist = d;
            localMaxPos  = i;
        }
    }

    // Parallel reduction across the warp to find the global maximum.
    unsigned mask = 0xffffffffu;
    for (int offset = WARP_SIZE / 2; offset > 0; offset >>= 1) {
        float otherDist = __shfl_down_sync(mask, localMaxDist, offset);
        int   otherPos  = __shfl_down_sync(mask, localMaxPos,  offset);
        if (otherDist > localMaxDist) {
            localMaxDist = otherDist;
            localMaxPos  = otherPos;
        }
    }

    // Broadcast the result from lane 0 to all lanes so every thread has the same worstDist/worstPos.
    worstDist = __shfl_sync(mask, localMaxDist, 0);
    worstPos  = __shfl_sync(mask, localMaxPos,  0);
}

// Kernel: each warp processes exactly one query point.
// The block loads data points in tiles into shared memory; each warp then reuses the tile to
// compute distances from its query to all points in the tile.
// A per-warp Top-K buffer (in shared memory) keeps the current k nearest neighbors.
__global__ void knn_kernel(const float2 * __restrict__ query,
                           int query_count,
                           const float2 * __restrict__ data,
                           int data_count,
                           KnnPair * __restrict__ result,
                           int k)
{
    extern __shared__ unsigned char smem[];

    // Shared-memory layout:
    // [0 .. TILE_SIZE-1]                  : float2 data tile
    // [TILE_SIZE .. TILE_SIZE + W* k - 1] : int   Top-K indices for all warps in block
    // [... next ...]                      : float Top-K distances for all warps in block
    float2 *sharedData     = reinterpret_cast<float2*>(smem);
    int    *topkIndices    = reinterpret_cast<int*>(sharedData + TILE_SIZE);
    float  *topkDistances  = reinterpret_cast<float*>(topkIndices + WARPS_PER_BLOCK * k);

    const int tid            = threadIdx.x;
    const int warpIdInBlock  = tid / WARP_SIZE;        // 0..WARPS_PER_BLOCK-1
    const int laneId         = tid & (WARP_SIZE - 1);  // 0..31
    const int globalWarpId   = blockIdx.x * WARPS_PER_BLOCK + warpIdInBlock;
    const bool active        = (globalWarpId < query_count);
    const int  queryIdx      = globalWarpId;

    const unsigned fullMask  = 0xffffffffu;

    // Load query point and broadcast its coordinates to all lanes in the warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (active && laneId == 0) {
        float2 q = query[queryIdx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(fullMask, qx, 0);
    qy = __shfl_sync(fullMask, qy, 0);

    // Per-warp Top-K buffer base offset in shared memory.
    const int topkBase = warpIdInBlock * k;

    // Initialize Top-K buffers for this warp: distances to +infinity, indices to -1.
    for (int i = laneId; i < k; i += WARP_SIZE) {
        topkDistances[topkBase + i] = FLT_MAX;
        topkIndices[topkBase + i]   = -1;
    }

    // Current worst (maximum) distance among the Top-K entries for this warp.
    float currentWorstDist = FLT_MAX;
    int   currentWorstPos  = 0;

    // Ensure that all Top-K buffers and the shared-memory layout are initialized before use.
    __syncthreads();

    // Process all data points in tiles of size TILE_SIZE.
    for (int tileStart = 0; tileStart < data_count; tileStart += TILE_SIZE) {
        int tileSize = data_count - tileStart;
        if (tileSize > TILE_SIZE) tileSize = TILE_SIZE;

        // Load the current tile into shared memory cooperatively using all threads in the block.
        for (int idxInTile = tid; idxInTile < tileSize; idxInTile += blockDim.x) {
            sharedData[idxInTile] = data[tileStart + idxInTile];
        }

        // Synchronize to ensure the tile is fully loaded before distance computations.
        __syncthreads();

        if (active) {
            // Process the tile in groups of WARP_SIZE points at a time.
            // Each lane computes distance to one point in the group; then the warp inserts
            // all 32 candidates sequentially into its Top-K buffer.
            for (int tileOffset = 0; tileOffset < tileSize; tileOffset += WARP_SIZE) {
                const int localIndex = tileOffset + laneId;

                // Each lane computes squared Euclidean distance for its candidate point.
                // Out-of-range lanes produce a dummy candidate with index -1.
                float candDist = FLT_MAX;
                int   candIdx  = -1;
                if (localIndex < tileSize) {
                    float2 p = sharedData[localIndex];
                    float dx = p.x - qx;
                    float dy = p.y - qy;
                    candDist = dx * dx + dy * dy;
                    candIdx  = tileStart + localIndex;  // global index in data[]
                }

                // Sequentially insert each lane's candidate into the Top-K buffer.
                // We iterate over srcLane = 0..31; at each step, all lanes see the same
                // candidate (distance, index) via warp shuffles. Only lane 0 performs
                // the actual write into Top-K; all lanes participate in recomputing
                // the new worst distance via warp_find_worst.
                for (int srcLane = 0; srcLane < WARP_SIZE; ++srcLane) {
                    float d   = __shfl_sync(fullMask, candDist, srcLane);
                    int   idx = __shfl_sync(fullMask, candIdx,  srcLane);

                    // Skip dummy candidates (out of range).
                    if (idx < 0) {
                        continue;
                    }

                    // If this candidate is better (smaller distance) than the current worst,
                    // insert it by replacing the current worst entry, then recompute worst.
                    if (d < currentWorstDist) {
                        if (laneId == 0) {
                            topkDistances[topkBase + currentWorstPos] = d;
                            topkIndices[topkBase + currentWorstPos]   = idx;
                        }

                        // Ensure the write is visible to all lanes before recomputing worst.
                        __syncwarp(fullMask);

                        // Recompute worstDist and worstPos across the warp's Top-K buffer.
                        warp_find_worst(topkDistances, topkBase, k,
                                        currentWorstDist, currentWorstPos);
                    }
                }
            }
        }

        // Synchronize before loading the next tile to avoid overwriting sharedData early.
        __syncthreads();
    }

    // After all tiles are processed, each active warp's Top-K buffer holds the k nearest
    // neighbors for its query, but in arbitrary order. Sort them by distance and write out.
    if (active && laneId == 0) {
        float *topDist = &topkDistances[topkBase];
        int   *topIdx  = &topkIndices[topkBase];

        // Simple in-place selection sort of size k in ascending order of distance.
        // This is done by lane 0 only; other lanes remain idle.
        for (int i = 0; i < k - 1; ++i) {
            int   minPos  = i;
            float minDist = topDist[i];
            for (int j = i + 1; j < k; ++j) {
                float d = topDist[j];
                if (d < minDist) {
                    minDist = d;
                    minPos  = j;
                }
            }
            if (minPos != i) {
                float tmpD   = topDist[i];
                topDist[i]   = topDist[minPos];
                topDist[minPos] = tmpD;

                int tmpI     = topIdx[i];
                topIdx[i]    = topIdx[minPos];
                topIdx[minPos] = tmpI;
            }
        }

        // Store sorted neighbors (index and distance) to the global result array.
        for (int j = 0; j < k; ++j) {
            int outPos = queryIdx * k + j;
            result[outPos].first  = topIdx[j];
            result[outPos].second = topDist[j];
        }
    }
}

// Host-side interface as specified.
// query       : device pointer to query_count float2 points
// data        : device pointer to data_count  float2 points
// result      : device pointer to query_count * k std::pair<int, float>
// k           : number of nearest neighbors per query (power of two, 32..1024)
void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    // reinterpret_cast result pointer to a simple POD type usable in device code.
    KnnPair *deviceResult = reinterpret_cast<KnnPair*>(result);

    // Kernel launch configuration.
    dim3 blockDim(THREADS_PER_BLOCK, 1, 1);
    int  numWarps  = query_count;
    int  numBlocks = (numWarps + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    dim3 gridDim(numBlocks, 1, 1);

    // Compute required dynamic shared memory size:
    // - TILE_SIZE float2 for the data tile
    // - WARPS_PER_BLOCK * k ints for indices
    // - WARPS_PER_BLOCK * k floats for distances
    size_t sharedMemBytes =
        sizeof(float2) * TILE_SIZE +
        sizeof(int)    * static_cast<size_t>(WARPS_PER_BLOCK) * static_cast<size_t>(k) +
        sizeof(float)  * static_cast<size_t>(WARPS_PER_BLOCK) * static_cast<size_t>(k);

    knn_kernel<<<gridDim, blockDim, sharedMemBytes>>>(query,
                                                      query_count,
                                                      data,
                                                      data_count,
                                                      deviceResult,
                                                      k);

    // In production code, one may want to add error checking or synchronization here.
}

