#include <cuda_runtime.h>
#include <cfloat>
#include <utility>

// ============================================================================
// Optimized k-NN CUDA implementation for 2D points (squared Euclidean distance)
// Each query is processed by a single warp (32 threads).
// Top-k neighbors per query are maintained cooperatively by the warp.
// The code is specialized for k in {32, 64, 128, 256, 512, 1024} via templates.
// ============================================================================

namespace {

/* Common constants */
constexpr int WARP_SIZE = 32;
constexpr int WARPS_PER_BLOCK = 8;                        // 8 warps -> 256 threads per block
constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * WARP_SIZE;
constexpr int TILE_SIZE = 4096;                           // Number of data points cached in shared memory per block

/* Full warp mask for sync/shuffle/ballot */
constexpr unsigned FULL_MASK = 0xFFFFFFFFu;

/**
 * Warp-wide reduction: compute maximum of 'val' across the warp.
 * Returns the maximum in lane 0; caller may broadcast if needed.
 */
__device__ __forceinline__
float warp_reduce_max(float val) {
    // Tree reduction with shfl_down
    for (int offset = WARP_SIZE / 2; offset > 0; offset >>= 1) {
        float other = __shfl_down_sync(FULL_MASK, val, offset);
        val = fmaxf(val, other);
    }
    return val;
}

/**
 * Warp-wide argmax: find lane index of maximum value.
 * Inputs:
 *   val      - local value in each lane
 * Outputs (by reference, same in all lanes after return):
 *   max_val  - maximum value
 *   max_lane - lane index (0..31) of one occurrence of maximum
 */
__device__ __forceinline__
void warp_argmax(float val, float &max_val, int &max_lane) {
    max_val  = val;
    max_lane = threadIdx.x & (WARP_SIZE - 1);

    // Parallel reduction to find maximum value and its lane index
    for (int offset = WARP_SIZE / 2; offset > 0; offset >>= 1) {
        float other_val  = __shfl_down_sync(FULL_MASK, max_val,  offset);
        int   other_lane = __shfl_down_sync(FULL_MASK, max_lane, offset);
        if (other_val > max_val) {
            max_val  = other_val;
            max_lane = other_lane;
        }
    }

    // Broadcast final result from lane 0 to all lanes
    max_val  = __shfl_sync(FULL_MASK, max_val,  0);
    max_lane = __shfl_sync(FULL_MASK, max_lane, 0);
}

/**
 * Warp-wide argmin with associated index.
 * Each lane provides (val, idx). The minimum (val, idx, lane) is selected.
 * Results are returned in all lanes via references.
 */
__device__ __forceinline__
void warp_argmin_with_index(float val, int idx, float &min_val, int &min_lane, int &min_idx) {
    int lane = threadIdx.x & (WARP_SIZE - 1);

    min_val  = val;
    min_lane = lane;
    min_idx  = idx;

    // Parallel reduction to find minimum value and its lane/index
    for (int offset = WARP_SIZE / 2; offset > 0; offset >>= 1) {
        float other_val  = __shfl_down_sync(FULL_MASK, min_val,  offset);
        int   other_lane = __shfl_down_sync(FULL_MASK, min_lane, offset);
        int   other_idx  = __shfl_down_sync(FULL_MASK, min_idx,  offset);
        if (other_val < min_val) {
            min_val  = other_val;
            min_lane = other_lane;
            min_idx  = other_idx;
        }
    }

    // Broadcast from lane 0
    min_val  = __shfl_sync(FULL_MASK, min_val,  0);
    min_lane = __shfl_sync(FULL_MASK, min_lane, 0);
    min_idx  = __shfl_sync(FULL_MASK, min_idx,  0);
}

/**
 * Insert a candidate (dist, idx) into a per-lane top-K list kept sorted in ascending order.
 * The list has fixed length K_PER_LANE. The worst (largest distance) entry is at index K_PER_LANE-1.
 * Precondition: dist < topk_dist[K_PER_LANE - 1] (so the candidate must enter the list).
 *
 * This is an insertion-by-bubbling algorithm:
 *   - We iterate from best to worst, and whenever the new distance is smaller than the current
 *     entry, we swap it in and bubble the displaced entry downwards.
 *   - After K_PER_LANE iterations, the worst entry is evicted.
 */
template <int K_PER_LANE>
__device__ __forceinline__
void insert_candidate_into_lane(float dist, int idx,
                                float (&topk_dist)[K_PER_LANE],
                                int   (&topk_idx)[K_PER_LANE]) {
    float cur_dist = dist;
    int   cur_idx  = idx;

    #pragma unroll
    for (int i = 0; i < K_PER_LANE; ++i) {
        if (cur_dist < topk_dist[i]) {
            // Swap current candidate with entry at position i
            float tmp_dist = topk_dist[i];
            int   tmp_idx  = topk_idx[i];

            topk_dist[i] = cur_dist;
            topk_idx[i]  = cur_idx;

            cur_dist = tmp_dist;
            cur_idx  = tmp_idx;
        }
    }
    // After this, the largest value among the (K_PER_LANE + 1) values
    // has been bumped off the end of the array.
}

/**
 * Kernel template for a fixed K (number of neighbors).
 * K is one of {32, 64, 128, 256, 512, 1024}.
 *
 * Each query is processed by a single warp. All warps in the block cooperatively
 * load batches of data points into shared memory. Each warp maintains its own
 * distributed top-K structure across lanes.
 */
template <int K>
__global__
void knn_kernel(const float2 * __restrict__ query,
                int query_count,
                const float2 * __restrict__ data,
                int data_count,
                std::pair<int, float> * __restrict__ result)
{
    static_assert(K % WARP_SIZE == 0, "K must be a multiple of warp size");
    constexpr int K_PER_LANE = K / WARP_SIZE;  // Each lane holds this many entries.

    // Shared memory tile caching data points for this block.
    __shared__ float2 shared_data[TILE_SIZE];

    const int lane_id  = threadIdx.x & (WARP_SIZE - 1);   // 0..31
    const int warp_id  = threadIdx.x >> 5;                // 0..WARPS_PER_BLOCK-1
    const int warp_per_block = blockDim.x / WARP_SIZE;

    const int global_warp_id = blockIdx.x * warp_per_block + warp_id;
    const bool valid_query   = (global_warp_id < query_count);

    // Per-lane top-K arrays (ascending order: best at index 0, worst at index K_PER_LANE-1)
    float topk_dist[K_PER_LANE];
    int   topk_idx [K_PER_LANE];

    // Initialize top-K with "infinite" distances.
    #pragma unroll
    for (int i = 0; i < K_PER_LANE; ++i) {
        topk_dist[i] = FLT_MAX;
        topk_idx[i]  = -1;
    }

    // Load query point into registers (lane 0) and broadcast within warp.
    float qx = 0.0f, qy = 0.0f;
    if (valid_query && lane_id == 0) {
        float2 q = query[global_warp_id];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    // Loop over data in tiles cached into shared memory.
    for (int tile_base = 0; tile_base < data_count; tile_base += TILE_SIZE) {
        const int tile_size = (tile_base + TILE_SIZE <= data_count)
                            ? TILE_SIZE
                            : (data_count - tile_base);

        // Cooperative loading of a tile of data points into shared memory.
        for (int i = threadIdx.x; i < tile_size; i += blockDim.x) {
            shared_data[i] = data[tile_base + i];
        }

        // Synchronize to ensure the tile is fully loaded.
        __syncthreads();

        // Process the tile in batches of WARP_SIZE points.
        for (int base = 0; base < tile_size; base += WARP_SIZE) {

            // Snapshot of current global worst distance for this warp's top-K.
            // Each lane contributes its local worst (largest) distance.
            float local_worst = topk_dist[K_PER_LANE - 1];
            float global_worst_snapshot = warp_reduce_max(local_worst);
            global_worst_snapshot = __shfl_sync(FULL_MASK, global_worst_snapshot, 0);

            // Compute candidate distance for this lane in the current batch.
            int   data_idx_in_tile = base + lane_id;
            float cand_dist = FLT_MAX;
            int   cand_idx  = -1;

            if (data_idx_in_tile < tile_size) {
                float2 p = shared_data[data_idx_in_tile];
                float dx = p.x - qx;
                float dy = p.y - qy;
                // Squared Euclidean distance; fmaf may map to FMA hardware.
                cand_dist = fmaf(dy, dy, dx * dx);
                cand_idx  = tile_base + data_idx_in_tile;
            }

            // Determine which lanes have potentially interesting candidates
            // (i.e., better than the current snapshot worst).
            int is_better = (cand_idx >= 0) && (cand_dist < global_worst_snapshot);
            unsigned better_mask = __ballot_sync(FULL_MASK, is_better);

            // Process all promising candidates from this batch.
            // We iterate over the set bits in better_mask. For each such lane,
            // we cooperatively insert its candidate into the warp's global top-K.
            unsigned active = better_mask;
            while (active) {
                // Extract index of the least significant set bit (lane with a candidate).
                int src_lane = __ffs(active) - 1;  // 0-based lane index

                // Broadcast that lane's candidate to all lanes.
                float cd = __shfl_sync(FULL_MASK, cand_dist, src_lane);
                int   ci = __shfl_sync(FULL_MASK, cand_idx,  src_lane);

                // Find current global worst among all per-lane worst entries.
                float lane_worst = topk_dist[K_PER_LANE - 1];
                float max_val;
                int   max_lane;
                warp_argmax(lane_worst, max_val, max_lane);

                // If this candidate is better than the current global worst, insert it.
                if (cd < max_val) {
                    if ((threadIdx.x & (WARP_SIZE - 1)) == max_lane) {
                        insert_candidate_into_lane<K_PER_LANE>(cd, ci, topk_dist, topk_idx);
                    }
                }

                // Clear this bit and move to the next candidate.
                active &= active - 1;
            }
        }

        // Synchronize before loading next tile into shared memory.
        __syncthreads();
    }

    // Final stage: for valid queries, merge the per-lane sorted lists into a single
    // globally sorted list of K neighbors using a warp-level multiway merge.
    if (!valid_query) {
        return;
    }

    const int base_out_index = global_warp_id * K;

    // Each lane maintains a pointer into its local sorted list.
    int ptr = 0;

    // Perform K-way merge: each iteration selects the smallest among lane heads.
    for (int out_pos = 0; out_pos < K; ++out_pos) {
        float candidate_val = (ptr < K_PER_LANE) ? topk_dist[ptr] : FLT_MAX;
        int   candidate_idx = (ptr < K_PER_LANE) ? topk_idx[ptr]  : -1;

        float min_val;
        int   min_lane, min_idx;
        warp_argmin_with_index(candidate_val, candidate_idx,
                               min_val, min_lane, min_idx);

        // Lane 0 writes the selected neighbor to global result array.
        if (lane_id == 0) {
            result[base_out_index + out_pos].first  = min_idx;
            result[base_out_index + out_pos].second = min_val;
        }

        // The lane that contributed the minimum advances its pointer.
        if (lane_id == min_lane) {
            ++ptr;
        }
    }
}

} // anonymous namespace

// ============================================================================
// Host interface
// ============================================================================

void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    // Compute launch configuration.
    dim3 block_dim(THREADS_PER_BLOCK, 1, 1);
    int  num_blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    dim3 grid_dim(num_blocks, 1, 1);

    // Dispatch to the appropriate kernel specialization based on k.
    switch (k) {
        case 32:
            knn_kernel<32><<<grid_dim, block_dim>>>(query, query_count, data, data_count, result);
            break;
        case 64:
            knn_kernel<64><<<grid_dim, block_dim>>>(query, query_count, data, data_count, result);
            break;
        case 128:
            knn_kernel<128><<<grid_dim, block_dim>>>(query, query_count, data, data_count, result);
            break;
        case 256:
            knn_kernel<256><<<grid_dim, block_dim>>>(query, query_count, data, data_count, result);
            break;
        case 512:
            knn_kernel<512><<<grid_dim, block_dim>>>(query, query_count, data, data_count, result);
            break;
        case 1024:
            knn_kernel<1024><<<grid_dim, block_dim>>>(query, query_count, data, data_count, result);
            break;
        default:
            // k is guaranteed (by problem statement) to be a power of 2 between 32 and 1024.
            // If this code path is reached, inputs are invalid; do nothing.
            return;
    }

    // Optionally, synchronize or check for errors here if desired by the caller.
    // cudaDeviceSynchronize();
    // cudaGetLastError();
}

#include <cuda_runtime.h>
#include <cfloat>
#include <utility>

// ================================================================
// Configuration constants
// ================================================================

static constexpr int WARP_SIZE          = 32;
static constexpr int MAX_K              = 1024;                // Maximum allowed k
static constexpr int MAX_K_PER_THREAD   = MAX_K / WARP_SIZE;   // 1024 / 32 = 32
static constexpr int WARPS_PER_BLOCK    = 4;                   // 4 warps per block
static constexpr int THREADS_PER_BLOCK  = WARPS_PER_BLOCK * WARP_SIZE;
static constexpr int BATCH_SIZE         = 1536;                // Must fit shared memory

// ================================================================
// Warp-level utilities
// ================================================================

/**
 * Warp-wide bitonic sort (ascending) over 32 lanes.
 * Each lane provides one key (distance) and associated value (index).
 * After the call, keys are sorted ascending across lanes 0..31.
 *
 * Implemented using __shfl_xor_sync with standard bitonic network.
 */
template <typename T, typename U>
__device__ __forceinline__ void warp_bitonic_sort_asc(T &key, U &val) {
    const unsigned mask = 0xFFFFFFFFu;
    int lane = threadIdx.x & (WARP_SIZE - 1);

    #pragma unroll
    for (int k = 2; k <= WARP_SIZE; k <<= 1) {
        #pragma unroll
        for (int j = k >> 1; j > 0; j >>= 1) {
            T  other_key = __shfl_xor_sync(mask, key, j);
            U  other_val = __shfl_xor_sync(mask, val, j);
            bool up = ((lane & k) == 0);
            if ((key > other_key) == up) {
                key = other_key;
                val = other_val;
            }
        }
    }
}

/**
 * Warp-wide argmax reduction.
 * All lanes provide a value; returns the maximum value and its lane index
 * in maxVal and maxLane (broadcast to all lanes).
 */
__device__ __forceinline__
void warp_argmax(float val, float &maxVal, int &maxLane) {
    const unsigned mask = 0xFFFFFFFFu;
    int lane = threadIdx.x & (WARP_SIZE - 1);

    float bestVal = val;
    int   bestLane = lane;

    #pragma unroll
    for (int offset = WARP_SIZE / 2; offset > 0; offset >>= 1) {
        float otherVal  = __shfl_down_sync(mask, bestVal,  offset);
        int   otherLane = __shfl_down_sync(mask, bestLane, offset);
        if (otherVal > bestVal) {
            bestVal  = otherVal;
            bestLane = otherLane;
        }
    }

    bestVal  = __shfl_sync(mask, bestVal,  0);
    bestLane = __shfl_sync(mask, bestLane, 0);

    maxVal  = bestVal;
    maxLane = bestLane;
}

/**
 * Bitonic sort on an array in shared memory using a single warp.
 * - dist/idx: base pointers to the warp's region in shared memory.
 * - n:        number of elements to sort (power of two, <= MAX_K).
 * - lane:     lane id in the warp (0..31).
 *
 * Uses standard block-level bitonic sort algorithm, but only 32 threads
 * cooperate to sort up to 1024 elements living in shared memory.
 */
__device__ __forceinline__
void warp_bitonic_sort_shared(float *dist, int *idx, int n, int lane) {
    // Bitonic sort for ascending order
    for (int size = 2; size <= n; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            // Each thread processes multiple indices spaced by WARP_SIZE
            for (int i = lane; i < n; i += WARP_SIZE) {
                int partner = i ^ stride;
                if (partner > i && partner < n) {
                    bool up = ((i & size) == 0); // ascending for lower half
                    float a = dist[i];
                    float b = dist[partner];
                    if ((a > b) == up) {
                        // swap distances
                        dist[i]       = b;
                        dist[partner] = a;
                        // swap indices
                        int ia   = idx[i];
                        idx[i]       = idx[partner];
                        idx[partner] = ia;
                    }
                }
            }
            __syncwarp();
        }
    }
}

// ================================================================
// k-NN kernel
// ================================================================

/**
 * Each warp processes a single query point.
 * - For each query, we maintain a distributed top-k structure:
 *   each lane holds k/32 candidates (distance/index pairs) sorted ascending.
 * - The block iterates over data in batches cached in shared memory.
 * - For each batch, all threads cooperatively load points into shared memory.
 * - Each warp then processes the batch: every iteration, each lane computes
 *   the distance of one candidate; the 32 candidates are warp-sorted and
 *   cooperatively inserted into the warp's top-k list.
 * - At the end, each warp gathers its top-k into shared memory, performs
 *   a warp-level bitonic sort over k elements, and writes the sorted k-NN
 *   to the output array.
 */
extern "C"
__global__ void knn_kernel_2d(
    const float2 * __restrict__ query,
    int query_count,
    const float2 * __restrict__ data,
    int data_count,
    std::pair<int, float> * __restrict__ result,
    int k
) {
    // Dynamic shared memory layout:
    // [ float2 sh_data[BATCH_SIZE] |
    //   float  sh_topk_dist[WARPS_PER_BLOCK * MAX_K] |
    //   int    sh_topk_idx [WARPS_PER_BLOCK * MAX_K] ]
    extern __shared__ __align__(16) unsigned char smem[];
    float2 *sh_data = reinterpret_cast<float2*>(smem);

    float *sh_topk_dist = reinterpret_cast<float*>(
        sh_data + BATCH_SIZE
    );
    int *sh_topk_idx = reinterpret_cast<int*>(
        sh_topk_dist + WARPS_PER_BLOCK * MAX_K
    );

    const unsigned FULL_MASK = 0xFFFFFFFFu;

    int tid           = threadIdx.x;
    int warpInBlock   = tid / WARP_SIZE;
    int lane          = tid & (WARP_SIZE - 1);
    int warpGlobal    = blockIdx.x * WARPS_PER_BLOCK + warpInBlock;
    bool warpActive   = (warpGlobal < query_count);

    // Each warp is assigned exactly one query index
    int q_idx = warpGlobal;

    // Load query point for active warp, broadcast to all lanes
    float qx = 0.0f;
    float qy = 0.0f;
    if (warpActive && lane == 0) {
        float2 q = query[q_idx];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    // Per-lane portion of top-k list
    int k_per_thread = k / WARP_SIZE;  // k is power of two and >= 32
    float best_dist[MAX_K_PER_THREAD];
    int   best_idx [MAX_K_PER_THREAD];

    // Initialize local top-k to +inf / -1
    #pragma unroll
    for (int i = 0; i < MAX_K_PER_THREAD; ++i) {
        best_dist[i] = FLT_MAX;
        best_idx[i]  = -1;
    }

    // Main loop: iterate over data in batches cached in shared memory
    for (int base = 0; base < data_count; base += BATCH_SIZE) {
        int batch_size = data_count - base;
        if (batch_size > BATCH_SIZE) batch_size = BATCH_SIZE;

        // Block-wide cooperative load into shared memory
        for (int i = tid; i < batch_size; i += blockDim.x) {
            sh_data[i] = data[base + i];
        }
        __syncthreads();

        // Each warp processes the cached batch
        // We traverse the batch in groups of 32 candidates so that each
        // lane produces one candidate per iteration.
        for (int jBase = 0; jBase < batch_size; jBase += WARP_SIZE) {
            int j = jBase + lane;

            float cand_dist = FLT_MAX;
            int   cand_idx  = -1;

            if (warpActive && j < batch_size) {
                float2 p = sh_data[j];
                float dx = p.x - qx;
                float dy = p.y - qy;
                cand_dist = dx * dx + dy * dy;
                cand_idx  = base + j;
            }

            // Sort the 32 candidates in the warp by distance (ascending)
            warp_bitonic_sort_asc(cand_dist, cand_idx);

            // Cooperatively insert the sorted candidates into the
            // distributed top-k structure.
            for (int r = 0; r < WARP_SIZE; ++r) {
                // Broadcast r-th smallest candidate in this group to all lanes
                float d   = __shfl_sync(FULL_MASK, cand_dist, r);
                int   idx = __shfl_sync(FULL_MASK, cand_idx,  r);

                // If candidate index is invalid, no more valid candidates
                if (idx < 0) break;

                if (!warpActive) continue;

                // Compute global worst (largest distance) among current top-k
                float localWorst = best_dist[k_per_thread - 1];
                float maxVal;
                int   maxLane;
                warp_argmax(localWorst, maxVal, maxLane);

                // If the candidate is not better than the worst, and since
                // candidates are processed in ascending order within this
                // group, no subsequent candidate in this group can improve.
                if (d >= maxVal) break;

                // The lane owning the global worst element inserts the new
                // candidate into its local sorted list (ascending order).
                if (lane == maxLane) {
                    int pos = k_per_thread - 1;
                    // Insertion into local list with removal of current worst
                    while (pos > 0 && d < best_dist[pos - 1]) {
                        best_dist[pos] = best_dist[pos - 1];
                        best_idx[pos]  = best_idx[pos - 1];
                        --pos;
                    }
                    best_dist[pos] = d;
                    best_idx[pos]  = idx;
                }
            } // candidates in this group
        } // groups of WARP_SIZE within batch

        __syncthreads();
    } // batches

    // Gather top-k from per-lane arrays into shared memory and
    // perform a warp-level bitonic sort over the k elements.
    int warpBase = warpInBlock * MAX_K;
    float *warp_dist = sh_topk_dist + warpBase;
    int   *warp_idx  = sh_topk_idx  + warpBase;

    if (warpActive) {
        // Copy each lane's local k_per_thread elements into warp-shared arrays
        #pragma unroll
        for (int i = 0; i < MAX_K_PER_THREAD; ++i) {
            if (i < k_per_thread) {
                int pos = lane * k_per_thread + i; // 0..k-1
                warp_dist[pos] = best_dist[i];
                warp_idx [pos] = best_idx[i];
            }
        }

        __syncwarp();

        // Sort first k elements in shared memory using the warp
        warp_bitonic_sort_shared(warp_dist, warp_idx, k, lane);

        __syncwarp();

        // Write sorted k-NN results to global memory
        int out_base = q_idx * k;
        for (int pos = lane; pos < k; pos += WARP_SIZE) {
            int out_idx = out_base + pos;
            result[out_idx].first  = warp_idx[pos];
            result[out_idx].second = warp_dist[pos];
        }
    }
}

// ================================================================
// Host wrapper
// ================================================================

/**
 * Host interface:
 *   query       - device pointer to query points (size query_count)
 *   query_count - number of queries
 *   data        - device pointer to data points (size data_count)
 *   data_count  - number of data points
 *   result      - device pointer to output pairs (size query_count * k)
 *   k           - number of neighbors (power of two, 32..1024)
 */
void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k
) {
    // Compute grid configuration: one warp per query
    int warps_needed = query_count;
    int blocks = (warps_needed + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    // Shared memory size per block
    size_t shmem_size =
        sizeof(float2) * BATCH_SIZE +
        WARPS_PER_BLOCK * MAX_K * (sizeof(float) + sizeof(int));

    dim3 grid(blocks);
    dim3 block(THREADS_PER_BLOCK);

    knn_kernel_2d<<<grid, block, shmem_size>>>(
        query,
        query_count,
        data,
        data_count,
        result,
        k
    );

    // Optional error checking/synchronization can be added here if desired
}

```cpp
#include <cuda_runtime.h>
#include <float.h>
#include <utility>

// -----------------------------------------------------------------------------
// CUDA k-NN for 2D points (float2) using one warp per query.
//
// Each query is processed by a single warp (32 threads).
// - The data points are processed in tiles cached in shared memory.
// - The warp maintains a max-heap of size k containing the k smallest
//   distances seen so far (squared Euclidean distances).
// - The heap is distributed across threads in the warp in a lane-strided
//   fashion to keep everything in registers.
// - Warp shuffles are used to read/modify heap entries that reside in
//   different lanes.
// - Initial k candidates are collected unsorted, then a bottom-up heap build
//   is performed. Remaining candidates are inserted using heap updates.
// - After all data is processed, an in-place heapsort generates sorted
//   neighbors (ascending distance), then results are written to global memory.
//
// Assumptions:
// - k is a power of two between 32 and 1024 inclusive (so k is a multiple of 32).
// - data_count >= k.
// - query_count and data_count are large enough to benefit from GPU parallelism.
// - All pointers passed to run_knn are allocated via cudaMalloc.
// -----------------------------------------------------------------------------

// Warp and block configuration.
static constexpr int WARP_SIZE         = 32;
static constexpr int WARPS_PER_BLOCK   = 8;      // 8 warps per block => 256 threads.
static constexpr int THREADS_PER_BLOCK = WARP_SIZE * WARPS_PER_BLOCK;

// Shared-memory tile size for data points.
// 4096 * sizeof(float2) = 32 KB per block, which is reasonable on modern GPUs.
static constexpr int TILE_SIZE = 4096;

// Maximum supported k (as per problem statement).
static constexpr int MAX_K = 1024;

// Number of heap elements per lane (lane-strided storage).
// MAX_K is 1024 and WARP_SIZE is 32, so this equals 32.
static constexpr int MAX_HEAP_ELEMS_PER_LANE = (MAX_K + WARP_SIZE - 1) / WARP_SIZE;

// Convenience macro for full warp mask.
static constexpr unsigned FULL_MASK = 0xFFFFFFFFu;


// -----------------------------------------------------------------------------
// Heap helper functions (device-side, warp-synchronous).
//
// Heap representation:
//   - Max-heap of up to 'heap_size' elements, indexes [0, heap_size-1].
//   - Logical index i is mapped to (lane, slot):
//           lane = i % WARP_SIZE
//           slot = i / WARP_SIZE
//   - Each lane owns MAX_HEAP_ELEMS_PER_LANE "slots" in registers:
//           dist_heap[slot], idx_heap[slot]
//
// All helper functions are warp-synchronous: they must be called by all threads
// in a warp with the same arguments. Communication between lanes uses
// __shfl_sync, and updates to heap entries are performed by the owning lane.
// -----------------------------------------------------------------------------

// Bubble-down (heapify-down) from a specific node index 'start_idx' in a
// max-heap. Runs entirely within one warp.
__device__ __forceinline__
void warp_heapify_down(float *dist_heap,
                       int   *idx_heap,
                       int    heap_size,
                       int    start_idx,
                       int    lane_id)
{
    int idx = start_idx;

    while (true) {
        int left  = idx * 2 + 1;
        if (left >= heap_size) {
            // No children; heap property satisfied.
            break;
        }
        int right = left + 1;

        // Map node indices to (lane, slot).
        int lane_idx  = idx   & (WARP_SIZE - 1);
        int slot_idx  = idx   >> 5; // divide by 32
        int lane_left = left  & (WARP_SIZE - 1);
        int slot_left = left  >> 5;
        int lane_right = 0;
        int slot_right = 0;

        // Gather parent and left child distances.
        float dist_idx  = __shfl_sync(FULL_MASK, dist_heap[slot_idx],  lane_idx);
        float dist_left = __shfl_sync(FULL_MASK, dist_heap[slot_left], lane_left);

        // Gather right child distance if it exists.
        float dist_right = -FLT_MAX;
        bool has_right = (right < heap_size);
        if (has_right) {
            lane_right = right & (WARP_SIZE - 1);
            slot_right = right >> 5;
            dist_right = __shfl_sync(FULL_MASK, dist_heap[slot_right], lane_right);
        }

        // Lane 0 decides which node (parent/left/right) has the largest distance.
        int  max_idx   = idx;
        float max_dist = dist_idx;
        if (dist_left > max_dist) {
            max_dist = dist_left;
            max_idx  = left;
        }
        if (has_right && dist_right > max_dist) {
            max_dist = dist_right;
            max_idx  = right;
        }

        // Broadcast max_idx from lane 0 to all lanes.
        max_idx = __shfl_sync(FULL_MASK, max_idx, 0);
        if (max_idx == idx) {
            // Heap property satisfied at this node.
            break;
        }

        // Swap node at idx with node at max_idx (their distances and indices).
        int child_idx   = max_idx;
        int lane_child  = child_idx & (WARP_SIZE - 1);
        int slot_child  = child_idx >> 5;

        float dist_node  = __shfl_sync(FULL_MASK, dist_heap[slot_idx],   lane_idx);
        int   id_node    = __shfl_sync(FULL_MASK, idx_heap[slot_idx],    lane_idx);
        float dist_child = __shfl_sync(FULL_MASK, dist_heap[slot_child], lane_child);
        int   id_child   = __shfl_sync(FULL_MASK, idx_heap[slot_child],  lane_child);

        if (lane_id == lane_idx) {
            dist_heap[slot_idx] = dist_child;
            idx_heap[slot_idx]  = id_child;
        }
        if (lane_id == lane_child) {
            dist_heap[slot_child] = dist_node;
            idx_heap[slot_child]  = id_node;
        }

        idx = child_idx; // Continue bubbling down at child's position.
    }
}


// Build a max-heap in-place from arbitrary values in [0, heap_size-1] using
// bottom-up heap construction.
__device__ __forceinline__
void warp_build_max_heap(float *dist_heap,
                         int   *idx_heap,
                         int    heap_size,
                         int    lane_id)
{
    // Start from the last parent node and heapify downwards.
    for (int i = (heap_size / 2) - 1; i >= 0; --i) {
        warp_heapify_down(dist_heap, idx_heap, heap_size, i, lane_id);
    }
}


// In-place heap sort on the max-heap, producing ascending order by distance.
// After this, the logical indices [0, heap_size-1] contain sorted neighbors
// (smallest distance at index 0).
__device__ __forceinline__
void warp_heap_sort_ascending(float *dist_heap,
                              int   *idx_heap,
                              int    heap_size,
                              int    lane_id)
{
    // Standard heapsort using a max-heap.
    for (int end = heap_size - 1; end > 0; --end) {
        // Swap root (index 0) with element at 'end'.
        int root_idx = 0;
        int lane_root = root_idx & (WARP_SIZE - 1);
        int slot_root = root_idx >> 5;
        int lane_end  = end      & (WARP_SIZE - 1);
        int slot_end  = end      >> 5;

        float dist_root = __shfl_sync(FULL_MASK, dist_heap[slot_root], lane_root);
        int   id_root   = __shfl_sync(FULL_MASK, idx_heap[slot_root],  lane_root);
        float dist_end  = __shfl_sync(FULL_MASK, dist_heap[slot_end],  lane_end);
        int   id_end    = __shfl_sync(FULL_MASK, idx_heap[slot_end],   lane_end);

        if (lane_id == lane_root) {
            dist_heap[slot_root] = dist_end;
            idx_heap[slot_root]  = id_end;
        }
        if (lane_id == lane_end) {
            dist_heap[slot_end] = dist_root;
            idx_heap[slot_end]  = id_root;
        }

        // Restore heap property for the reduced heap [0, end-1].
        warp_heapify_down(dist_heap, idx_heap, end, 0, lane_id);
    }
}


// -----------------------------------------------------------------------------
// k-NN kernel: one warp per query.
// -----------------------------------------------------------------------------
__global__
void knn_kernel(const float2 * __restrict__ query,
                int                    query_count,
                const float2 * __restrict__ data,
                int                    data_count,
                std::pair<int, float> * __restrict__ result,
                int                    k)
{
    extern __shared__ float2 shared_data[]; // Shared-memory tile of data points.

    const int thread_id      = threadIdx.x;
    const int lane_id        = thread_id & (WARP_SIZE - 1);
    const int warp_id_in_block = thread_id / WARP_SIZE;
    const int global_warp_id   = blockIdx.x * WARPS_PER_BLOCK + warp_id_in_block;

    const bool warp_active = (global_warp_id < query_count);

    // Each warp corresponds to one query index.
    const int query_idx = global_warp_id;

    // Per-lane heap storage (distributed heap for this query).
    float dist_heap[MAX_HEAP_ELEMS_PER_LANE];
    int   idx_heap [MAX_HEAP_ELEMS_PER_LANE];

    // Early exit for warps without an assigned query: they still must
    // participate in __syncthreads() but skip all query-dependent work.
    if (!warp_active) {
        // Still need to participate in shared memory loads and synchronizations.
        for (int tile_start = 0; tile_start < data_count; tile_start += TILE_SIZE) {
            int tile_len = data_count - tile_start;
            if (tile_len > TILE_SIZE) tile_len = TILE_SIZE;

            // Cooperative load of data tile into shared memory.
            for (int i = thread_id; i < tile_len; i += blockDim.x) {
                shared_data[i] = data[tile_start + i];
            }
            __syncthreads();
            __syncthreads();
        }
        return;
    }

    // Load query point for this warp.
    float2 q = query[query_idx];

    // Total number of data points processed so far for this query.
    int processed = 0;

    // Once 'processed == k', heap will be constructed from the first k entries.
    bool heap_built = false;

    // Main loop over data points in tiles.
    for (int tile_start = 0; tile_start < data_count; tile_start += TILE_SIZE) {
        int tile_len = data_count - tile_start;
        if (tile_len > TILE_SIZE) tile_len = TILE_SIZE;

        // Load this tile of data into shared memory using the whole block.
        for (int i = thread_id; i < tile_len; i += blockDim.x) {
            shared_data[i] = data[tile_start + i];
        }
        __syncthreads();

        // Each active warp processes the shared tile against its query.
        // We process tile entries in groups of WARP_SIZE. In each group,
        // each lane computes distance for one point, then candidates are
        // fed into the warp-local heap in a warp-synchronous manner.
        for (int base = 0; base < tile_len; base += WARP_SIZE) {
            int idx_in_tile = base + lane_id;
            bool valid = (idx_in_tile < tile_len);

            float cand_dist = 0.0f;
            int   cand_idx  = -1;

            if (valid) {
                float2 p = shared_data[idx_in_tile];
                float dx = p.x - q.x;
                float dy = p.y - q.y;
                cand_dist = dx * dx + dy * dy;           // squared Euclidean distance
                cand_idx  = tile_start + idx_in_tile;    // global index of data point
            }

            // Process the WARP_SIZE candidates in a deterministic order
            // (lane 0 to lane 31). Each candidate is handled by the whole warp
            // when updating the heap.
            #pragma unroll
            for (int src_lane = 0; src_lane < WARP_SIZE; ++src_lane) {
                bool src_valid = __shfl_sync(FULL_MASK, valid, src_lane);
                if (!src_valid) {
                    continue;
                }

                float dist = __shfl_sync(FULL_MASK, cand_dist, src_lane);
                int   idx  = __shfl_sync(FULL_MASK, cand_idx,  src_lane);

                if (processed < k) {
                    // Fill initial buffer of k elements (unsorted).
                    int insert_idx = processed;
                    int owner_lane = insert_idx & (WARP_SIZE - 1);
                    int owner_slot = insert_idx >> 5;

                    if (lane_id == owner_lane) {
                        dist_heap[owner_slot] = dist;
                        idx_heap[owner_slot]  = idx;
                    }

                    ++processed;

                    // Once we have k elements, build the initial max-heap.
                    if (processed == k) {
                        warp_build_max_heap(dist_heap, idx_heap, k, lane_id);
                        heap_built = true;
                    }
                } else {
                    // For remaining elements, use heap insertion:
                    // replace heap root if the new candidate is closer.
                    if (!heap_built) {
                        // Safety: in case processed starts >= k for some reason.
                        warp_build_max_heap(dist_heap, idx_heap, k, lane_id);
                        heap_built = true;
                    }

                    // Broadcast current root distance from lane 0.
                    float root_dist = __shfl_sync(FULL_MASK, dist_heap[0], 0);

                    if (dist < root_dist) {
                        // Replace root with the new, closer candidate.
                        if (lane_id == 0) {
                            dist_heap[0] = dist;
                            idx_heap[0]  = idx;
                        }
                        // Restore heap property.
                        warp_heapify_down(dist_heap, idx_heap, k, 0, lane_id);
                    }

                    ++processed;
                }
            }
        }

        __syncthreads();
    }

    // After all data points have been processed, dist_heap/idx_heap contain
    // the k nearest neighbor candidates in a max-heap (largest distance at root).
    // Convert to ascending order using heap sort.
    warp_heap_sort_ascending(dist_heap, idx_heap, k, lane_id);

    // Write sorted results to global memory.
    // Each lane writes its own lane-strided entries.
    int slots_per_lane = k / WARP_SIZE; // k is a multiple of 32 by assumption.
    for (int slot = 0; slot < slots_per_lane; ++slot) {
        int j = lane_id + slot * WARP_SIZE; // logical index in [0, k-1]
        int out_index = query_idx * k + j;

        result[out_index].first  = idx_heap[slot];
        result[out_index].second = dist_heap[slot];
    }
}


// -----------------------------------------------------------------------------
// Host wrapper: launches the k-NN kernel.
// -----------------------------------------------------------------------------
void run_knn(const float2 *query,
             int           query_count,
             const float2 *data,
             int           data_count,
             std::pair<int, float> *result,
             int           k)
{
    // Compute grid configuration: one warp per query.
    int total_warps = (query_count + 0); // 1 warp per query
    int blocks = (total_warps + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    dim3 block_dim(THREADS_PER_BLOCK, 1, 1);
    dim3 grid_dim(blocks, 1, 1);

    // Shared memory size: TILE_SIZE float2's per block.
    size_t shared_mem_bytes = static_cast<size_t>(TILE_SIZE) * sizeof(float2);

    knn_kernel<<<grid_dim, block_dim, shared_mem_bytes>>>(
        query, query_count, data, data_count, result, k
    );

    // Optionally synchronize here to ensure completion before returning.
    cudaDeviceSynchronize();
}
