#include <cuda_runtime.h>
#include <utility>

// Simple POD replacement for std::pair<int,float> on device.
// Layout matches std::pair<int,float> for typical ABI (two 4-byte fields).
struct PairIF {
    int   first;
    float second;
};

constexpr int WARP_SIZE         = 32;
constexpr int WARPS_PER_BLOCK   = 4;         // 4 warps -> 128 threads per block
constexpr int BLOCK_THREADS     = WARPS_PER_BLOCK * WARP_SIZE;
constexpr int TILE_SIZE_POINTS  = 2048;      // 2048 points * 8 bytes = 16 KB
                                             // Shared heap per block (max k=1024): 4 warps * 1024 * 8 B = 32 KB
                                             // Total shared memory per block ~ 48 KB

// ========================= Heap utilities (max-heap) =========================

// Max-heap insert for top-k maintenance.
// Only lane 0 in each warp calls these functions; they operate on shared memory.
template <int K>
__device__ __forceinline__
void heapify_up(float* __restrict__ heap_dist,
                int*   __restrict__ heap_idx,
                int pos)
{
    // Bubble up to maintain max-heap property.
    while (pos > 0) {
        int parent = (pos - 1) >> 1;
        float d_pos    = heap_dist[pos];
        float d_parent = heap_dist[parent];
        if (d_parent >= d_pos) {
            break;
        }
        // Swap parent and current.
        heap_dist[pos] = d_parent;
        heap_idx[pos]  = heap_idx[parent];
        heap_dist[parent] = d_pos;
        heap_idx[parent]  = heap_idx[pos];
        pos = parent;
    }
}

template <int K>
__device__ __forceinline__
void heapify_down(float* __restrict__ heap_dist,
                  int*   __restrict__ heap_idx,
                  int size,
                  int pos)
{
    // Bubble down to maintain max-heap property.
    while (true) {
        int left  = (pos << 1) + 1;
        int right = left + 1;
        int largest = pos;

        if (left < size && heap_dist[left] > heap_dist[largest]) {
            largest = left;
        }
        if (right < size && heap_dist[right] > heap_dist[largest]) {
            largest = right;
        }
        if (largest == pos) {
            break;
        }

        float d_pos     = heap_dist[pos];
        float d_largest = heap_dist[largest];
        int   i_pos     = heap_idx[pos];
        int   i_largest = heap_idx[largest];

        heap_dist[pos]    = d_largest;
        heap_idx[pos]     = i_largest;
        heap_dist[largest] = d_pos;
        heap_idx[largest]  = i_pos;

        pos = largest;
    }
}

// Insert candidate (dist, idx) into max-heap of size at most K.
// Keeps the smallest K distances seen so far.
// heap_size is updated accordingly (<= K).
template <int K>
__device__ __forceinline__
void heap_insert_max(float* __restrict__ heap_dist,
                     int*   __restrict__ heap_idx,
                     int&   heap_size,
                     float  dist,
                     int    idx)
{
    if (heap_size < K) {
        int pos = heap_size++;
        heap_dist[pos] = dist;
        heap_idx[pos]  = idx;
        heapify_up<K>(heap_dist, heap_idx, pos);
    } else {
        // Heap is full; only insert if this distance is better (smaller) than current worst.
        if (dist >= heap_dist[0]) {
            return;
        }
        heap_dist[0] = dist;
        heap_idx[0]  = idx;
        heapify_down<K>(heap_dist, heap_idx, heap_size, 0);
    }
}

// In-place heapsort on a max-heap of size heap_size.
// After sorting, heap_dist[0..heap_size-1] are in ascending order of distance.
template <int K>
__device__ __forceinline__
void heap_sort_max_heap(float* __restrict__ heap_dist,
                        int*   __restrict__ heap_idx,
                        int    heap_size)
{
    // Standard heapsort: repeatedly move max element (root) to the end,
    // shrink heap, and heapify down.
    for (int end = heap_size - 1; end > 0; --end) {
        // Swap root with end.
        float d_root = heap_dist[0];
        float d_end  = heap_dist[end];
        int   i_root = heap_idx[0];
        int   i_end  = heap_idx[end];

        heap_dist[0]  = d_end;
        heap_idx[0]   = i_end;
        heap_dist[end] = d_root;
        heap_idx[end]  = i_root;

        // Restore heap property on the reduced heap [0, end).
        heapify_down<K>(heap_dist, heap_idx, end, 0);
    }
}

// ========================= k-NN kernel (warp-per-query) =========================

template <int K>
__global__
void knn_kernel(const float2* __restrict__ query,
                int                        query_count,
                const float2* __restrict__ data,
                int                        data_count,
                PairIF*       __restrict__ result)
{
    extern __shared__ unsigned char shared_mem[];

    // Layout shared memory as:
    // [0 .. TILE_SIZE_POINTS-1]: tile of float2 data points
    // [next]: WARPS_PER_BLOCK * K floats for distances (heap)
    // [next]: WARPS_PER_BLOCK * K ints   for indices  (heap)
    float2* s_data = reinterpret_cast<float2*>(shared_mem);
    float*  s_heap_dist = reinterpret_cast<float*>(s_data + TILE_SIZE_POINTS);
    int*    s_heap_idx  = reinterpret_cast<int*>(s_heap_dist + WARPS_PER_BLOCK * K);

    const int tid               = threadIdx.x;
    const int lane              = tid & (WARP_SIZE - 1);
    const int warp_id_in_block  = tid >> 5; // tid / WARP_SIZE
    const int warp_global_id    = blockIdx.x * WARPS_PER_BLOCK + warp_id_in_block;
    const bool warp_has_query   = (warp_global_id < query_count);
    const unsigned full_mask    = 0xffffffffu;

    // Each warp uses a private segment of the heap arrays in shared memory.
    float* heap_dist = s_heap_dist + warp_id_in_block * K;
    int*   heap_idx  = s_heap_idx  + warp_id_in_block * K;

    float qx = 0.0f;
    float qy = 0.0f;

    int heap_size = 0;

    // Load the query point for this warp and broadcast within warp.
    if (warp_has_query) {
        if (lane == 0) {
            float2 q = query[warp_global_id];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(full_mask, qx, 0);
        qy = __shfl_sync(full_mask, qy, 0);
    }

    // Process data in tiles cached in shared memory.
    for (int tile_start = 0; tile_start < data_count; tile_start += TILE_SIZE_POINTS) {
        int tile_size = data_count - tile_start;
        if (tile_size > TILE_SIZE_POINTS) {
            tile_size = TILE_SIZE_POINTS;
        }

        // Load current tile into shared memory cooperatively by the entire block.
        for (int idx = tid; idx < tile_size; idx += BLOCK_THREADS) {
            s_data[idx] = data[tile_start + idx];
        }
        __syncthreads();

        if (warp_has_query) {
            // Each warp now computes distances from its query point to all points in the tile.
            // We process the tile in chunks of 32 so that each lane contributes one candidate per iteration.
            for (int base = 0; base < tile_size; base += WARP_SIZE) {
                int idx = base + lane;
                bool in_range = (idx < tile_size);

                float cand_dist = 0.0f;
                int   cand_idx  = -1;

                if (in_range) {
                    float2 p = s_data[idx];
                    float dx = p.x - qx;
                    float dy = p.y - qy;
                    // Squared Euclidean distance in 2D.
                    cand_dist = dx * dx + dy * dy;
                    cand_idx  = tile_start + idx;
                }

                // Collect active lanes (those that have a valid candidate).
                unsigned active_mask = __ballot_sync(full_mask, in_range);
                if (active_mask == 0) {
                    continue;
                }

                // Update the heap with all active candidates in this iteration.
                // Lane 0 performs heap updates; values are broadcast via shuffles.
                for (int src_lane = 0; src_lane < WARP_SIZE; ++src_lane) {
                    if (active_mask & (1u << src_lane)) {
                        float d_src = __shfl_sync(active_mask, cand_dist, src_lane);
                        int   i_src = __shfl_sync(active_mask, cand_idx,  src_lane);
                        if (lane == 0) {
                            heap_insert_max<K>(heap_dist, heap_idx, heap_size, d_src, i_src);
                        }
                    }
                }
                // Optional warp-wide sync to make sure all lanes observe consistent heap_size
                // before next iteration (lane 0 is the only writer).
                __syncwarp(full_mask);
            }
        }

        // Ensure all warps have finished processing this tile before reusing shared memory.
        __syncthreads();
    }

    // After all data tiles have been processed, each active warp holds a max-heap
    // of size K containing the k nearest neighbors for its query (unsorted).
    if (warp_has_query) {
        if (lane == 0) {
            // data_count >= K by problem statement, so heap_size >= K.
            if (heap_size > 0) {
                heap_sort_max_heap<K>(heap_dist, heap_idx, heap_size);
            }

            // Write out sorted results (ascending distance) for this query.
            PairIF* out = result + warp_global_id * K;
            const int out_size = (heap_size < K) ? heap_size : K;
            for (int i = 0; i < out_size; ++i) {
                out[i].first  = heap_idx[i];
                out[i].second = heap_dist[i];
            }
        }
    }
}

// ========================= Host launcher =========================

// Helper to launch the templated kernel for a specific K.
template <int K>
void launch_knn_kernel(const float2* d_query,
                       int            query_count,
                       const float2* d_data,
                       int            data_count,
                       PairIF*        d_result)
{
    if (query_count <= 0 || data_count <= 0) {
        return;
    }

    const int warps_needed = query_count; // 1 warp per query
    const int blocks = (warps_needed + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    dim3 grid(blocks);
    dim3 block(BLOCK_THREADS);

    // Shared memory size: tile of data + heaps for all warps in block.
    const size_t shared_bytes =
        TILE_SIZE_POINTS * sizeof(float2) +
        WARPS_PER_BLOCK * K * (sizeof(float) + sizeof(int));

    knn_kernel<K><<<grid, block, shared_bytes>>>(d_query,
                                                 query_count,
                                                 d_data,
                                                 data_count,
                                                 d_result);
}

// Public C++ interface.
// query, data, and result live in device memory (cudaMalloc'ed).
void run_knn(const float2* query,
             int           query_count,
             const float2* data,
             int           data_count,
             std::pair<int, float>* result,
             int           k)
{
    if (query == nullptr || data == nullptr || result == nullptr) {
        return;
    }
    if (query_count <= 0 || data_count <= 0) {
        return;
    }

    // Reinterpret result pointer as our device-compatible PairIF.
    PairIF* d_result = reinterpret_cast<PairIF*>(result);

    // k is guaranteed to be a power of two between 32 and 1024 inclusive.
    switch (k) {
        case 32:
            launch_knn_kernel<32>(query, query_count, data, data_count, d_result);
            break;
        case 64:
            launch_knn_kernel<64>(query, query_count, data, data_count, d_result);
            break;
        case 128:
            launch_knn_kernel<128>(query, query_count, data, data_count, d_result);
            break;
        case 256:
            launch_knn_kernel<256>(query, query_count, data, data_count, d_result);
            break;
        case 512:
            launch_knn_kernel<512>(query, query_count, data, data_count, d_result);
            break;
        case 1024:
            launch_knn_kernel<1024>(query, query_count, data, data_count, d_result);
            break;
        default:
            // For safety, you could handle invalid k here.
            // Problem statement guarantees k is valid, so we simply return.
            return;
    }
}

#include <cuda_runtime.h>
#include <utility>

// Simple POD type matching the memory layout of std::pair<int, float>
struct PairIF {
    int   first;
    float second;
};

// Tunable kernel parameters
constexpr int WARP_SIZE         = 32;
constexpr int WARPS_PER_BLOCK   = 4;                     // 4 warps => 128 threads per block
constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * WARP_SIZE;
constexpr int MAX_K             = 1024;                  // maximum supported k
constexpr int TILE_SIZE         = 1024;                  // number of data points cached per block in shared memory

// ---------------------------------------------------------------------------
// Heap utilities: max-heap on distances (largest distance at root).
// Used per warp to maintain the current k nearest neighbors for its query.
// Only lane 0 of each warp mutates the heap; other lanes feed candidates.
// ---------------------------------------------------------------------------

__device__ __forceinline__
void heap_insert_or_update(float dist,
                           int   idx,
                           float *heap_dist,
                           int   *heap_idx,
                           int   k,
                           int   &heap_size)
{
    // Insert into heap if there is still room.
    if (heap_size < k) {
        int pos = heap_size;
        heap_size++;

        // Bubble up to maintain max-heap on distance.
        while (pos > 0) {
            int parent = (pos - 1) >> 1;
            float parent_dist = heap_dist[parent];
            if (parent_dist >= dist) {
                break;
            }
            heap_dist[pos] = parent_dist;
            heap_idx[pos]  = heap_idx[parent];
            pos = parent;
        }
        heap_dist[pos] = dist;
        heap_idx[pos]  = idx;
    } else {
        // Heap is full: check if candidate is better (smaller distance) than current worst.
        float worst_dist = heap_dist[0];
        if (dist >= worst_dist) {
            return; // no improvement
        }

        // Replace root and bubble down.
        int pos = 0;

        while (true) {
            int left = (pos << 1) + 1;
            if (left >= k) {
                break; // no children
            }
            int right = left + 1;

            int largest = left;
            float largest_dist = heap_dist[left];
            if (right < k && heap_dist[right] > largest_dist) {
                largest = right;
                largest_dist = heap_dist[right];
            }

            // If the incoming element is larger than or equal to the largest child,
            // heap property is satisfied.
            if (dist >= largest_dist) {
                break;
            }

            // Move largest child up.
            heap_dist[pos] = largest_dist;
            heap_idx[pos]  = heap_idx[largest];
            pos = largest;
        }

        heap_dist[pos] = dist;
        heap_idx[pos]  = idx;
    }
}

// Process up to 32 candidates (one per lane) for a single warp's heap.
// All threads in the warp participate via warp-wide ballot and shuffles.
// Lane 0 performs the actual heap updates; others supply candidate values.
__device__ __forceinline__
void warp_heap_process_candidates(float dist,
                                  int   idx,
                                  float *heap_dist,
                                  int   *heap_idx,
                                  int   k,
                                  int   *heap_size_ptr,
                                  int   lane_id)
{
    const unsigned full_mask = 0xffffffffu;

    // Determine which lanes have a valid candidate this iteration.
    unsigned active = __ballot_sync(full_mask, idx >= 0);

    // Sequentially feed all candidates to lane 0 in lane-id order.
    while (active) {
        int src_lane = __ffs(active) - 1;  // index of next lane with a candidate

        float c_dist = __shfl_sync(full_mask, dist, src_lane);
        int   c_idx  = __shfl_sync(full_mask, idx,  src_lane);

        if (lane_id == 0) {
            int heap_size = *heap_size_ptr;
            heap_insert_or_update(c_dist, c_idx, heap_dist, heap_idx, k, heap_size);
            *heap_size_ptr = heap_size;
        }

        // Clear this lane's bit and synchronize warp before processing next candidate.
        active &= active - 1;
        __syncwarp(full_mask);
    }
}

// Heapsort on a max-heap (dist, idx) of size n.
// After completion, dist[0..n-1] and idx[0..n-1] are sorted in ascending order of distance.
__device__ __forceinline__
void heap_sort(float *dist, int *idx, int n)
{
    for (int i = n - 1; i > 0; --i) {
        // Swap root with element i.
        float tmp_d = dist[0];
        dist[0] = dist[i];
        dist[i] = tmp_d;

        int tmp_i = idx[0];
        idx[0] = idx[i];
        idx[i] = tmp_i;

        // Restore heap property for the reduced heap [0, i).
        int pos = 0;
        while (true) {
            int left = (pos << 1) + 1;
            if (left >= i) {
                break;
            }
            int right = left + 1;

            int largest = left;
            float largest_dist = dist[left];
            if (right < i && dist[right] > largest_dist) {
                largest = right;
                largest_dist = dist[right];
            }

            if (dist[pos] >= largest_dist) {
                break;
            }

            // Swap parent with largest child.
            float td = dist[pos];
            dist[pos] = dist[largest];
            dist[largest] = td;

            int ti = idx[pos];
            idx[pos] = idx[largest];
            idx[largest] = ti;

            pos = largest;
        }
    }
}

// ---------------------------------------------------------------------------
// KNN kernel: one warp per query.
// - Each block has WARPS_PER_BLOCK warps => WARPS_PER_BLOCK queries per block.
// - Data points are processed in tiles; each tile is cached in shared memory.
// - Warps compute distances from their query to all points in the tile.
// - Distances are fed into a per-warp max-heap of size k in shared memory.
// - Final heap is sorted and written to the result array.
// ---------------------------------------------------------------------------

__global__
void knn_kernel_2d(const float2 * __restrict__ query,
                   int                    query_count,
                   const float2 * __restrict__ data,
                   int                    data_count,
                   PairIF * __restrict__  result,
                   int                    k)
{
    // Shared memory:
    //  - s_data:   cached tile of data points (all warps use).
    //  - s_heap_dist / s_heap_idx: per-warp heaps (MAX_K entries per warp).
    //  - s_heap_size: per-warp heap sizes.
    __shared__ float2 s_data[TILE_SIZE];
    __shared__ float  s_heap_dist[WARPS_PER_BLOCK * MAX_K];
    __shared__ int    s_heap_idx [WARPS_PER_BLOCK * MAX_K];
    __shared__ int    s_heap_size[WARPS_PER_BLOCK];

    const int thread_id     = threadIdx.x;
    const int warp_local_id = thread_id / WARP_SIZE;        // warp index within block
    const int lane_id       = thread_id & (WARP_SIZE - 1);  // lane index within warp
    const int warp_global_id = blockIdx.x * WARPS_PER_BLOCK + warp_local_id;

    const bool warp_active = (warp_global_id < query_count);

    // Pointers to this warp's heap storage in shared memory.
    float *heap_dist = s_heap_dist + warp_local_id * MAX_K;
    int   *heap_idx  = s_heap_idx  + warp_local_id * MAX_K;
    int   *heap_size_ptr = &s_heap_size[warp_local_id];

    // Initialize per-warp heap size.
    if (warp_active && lane_id == 0) {
        *heap_size_ptr = 0;
    }

    // Load query point into registers for the warp, using a broadcast from lane 0.
    float qx = 0.0f;
    float qy = 0.0f;
    if (warp_active) {
        float2 q;
        if (lane_id == 0) {
            q = query[warp_global_id];
        }
        qx = __shfl_sync(0xffffffffu, q.x, 0);
        qy = __shfl_sync(0xffffffffu, q.y, 0);
    }

    // Process data in tiles.
    for (int tile_start = 0; tile_start < data_count; tile_start += TILE_SIZE) {
        int tile_size = data_count - tile_start;
        if (tile_size > TILE_SIZE) tile_size = TILE_SIZE;

        // Load tile into shared memory: all threads in the block participate.
        for (int i = thread_id; i < tile_size; i += blockDim.x) {
            s_data[i] = data[tile_start + i];
        }

        __syncthreads();  // Ensure tile is fully loaded before any warp uses it.

        if (warp_active) {
            // Each warp processes all points in the tile.
            // Within the warp, lanes stride through the tile with step WARP_SIZE.
            for (int offset = 0; offset < tile_size; offset += WARP_SIZE) {
                int idx_in_tile = offset + lane_id;

                float dist = 0.0f;
                int   data_idx = -1;  // mark invalid by default

                if (idx_in_tile < tile_size) {
                    float2 p = s_data[idx_in_tile];
                    float dx = p.x - qx;
                    float dy = p.y - qy;
                    dist = dx * dx + dy * dy;
                    data_idx = tile_start + idx_in_tile;
                }

                // Update this warp's heap with up to 32 candidates in parallel.
                warp_heap_process_candidates(dist,
                                             data_idx,
                                             heap_dist,
                                             heap_idx,
                                             k,
                                             heap_size_ptr,
                                             lane_id);
            }
        }

        __syncthreads();  // All warps must finish using this tile before it is overwritten.
    }

    // Finalize: convert heap to sorted list and write results for this query.
    if (warp_active && lane_id == 0) {
        int heap_size = *heap_size_ptr;

        // data_count is guaranteed >= k, so heap_size should be at least k.
        if (heap_size > k) {
            heap_size = k;
        }

        // Heapsort to get neighbors ordered by increasing distance.
        heap_sort(heap_dist, heap_idx, heap_size);

        // Write results to global memory.
        PairIF *out = result + warp_global_id * k;
        for (int i = 0; i < k; ++i) {
            out[i].first  = heap_idx[i];
            out[i].second = heap_dist[i];
        }
    }
}

// ---------------------------------------------------------------------------
// Host interface
// ---------------------------------------------------------------------------

void run_knn(const float2 *query,
             int           query_count,
             const float2 *data,
             int           data_count,
             std::pair<int, float> *result,
             int           k)
{
    // Assumptions:
    //  - query, data, and result are device pointers allocated by cudaMalloc.
    //  - data_count >= k.
    //  - k is a power of two between 32 and 1024 inclusive.

    dim3 block_dim(THREADS_PER_BLOCK, 1, 1);
    dim3 grid_dim((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK, 1, 1);

    // Launch kernel. Cast result pointer to PairIF* as layouts are compatible (POD with int and float).
    knn_kernel_2d<<<grid_dim, block_dim>>>(
        query,
        query_count,
        data,
        data_count,
        reinterpret_cast<PairIF*>(result),
        k
    );

    // Optional: synchronize or error-checking can be added by the caller.
}

#include <cuda_runtime.h>
#include <utility>
#include <cfloat>
#include <cassert>

/*
 * Optimized k-NN for 2D points using CUDA.
 *
 * - Each query is processed by exactly one warp (32 threads).
 * - The dataset is traversed in tiles cached in shared memory.
 * - For each query, we maintain a private top-k list (indices + distances)
 *   distributed across the 32 threads of its warp.
 * - The top-k list is updated cooperatively by the warp using warp
 *   intrinsics (__ballot_sync, __shfl_sync).
 * - Candidate distances are generated in batches of 32 per warp and
 *   integrated into the top-k list, potentially inserting multiple
 *   candidates per batch.
 * - After processing all data points, each warp writes its top-k list to
 *   global memory and sorts the k neighbors for its query.
 */

// Basic constants for this implementation.
constexpr int WARP_SIZE          = 32;
constexpr int THREADS_PER_BLOCK  = 256;                     // 8 warps per block
constexpr int WARPS_PER_BLOCK    = THREADS_PER_BLOCK / WARP_SIZE;
constexpr int MAX_K              = 1024;                    // As per problem statement
constexpr int MAX_PER_THREAD     = MAX_K / WARP_SIZE;       // 1024 / 32 = 32
constexpr int TILE_SIZE          = 4096;                    // Number of data points per shared-memory tile

// Simple POD type to use in device code instead of std::pair<int,float>.
struct KnnPair {
    int   idx;
    float dist;
};

/*
 * Recompute the current worst (largest) distance in the warp's distributed
 * top-k list.
 *
 * Layout of the distributed list:
 *   - Each thread has an array distList[0 .. perThread-1].
 *   - The global logical index of distList[j] in the warp's top-k array is:
 *         linearIdx = j * WARP_SIZE + laneId
 *     where laneId is 0..31.
 *   - Thus the global indices 0..k-1 are covered exactly once.
 *
 * This function:
 *   - Computes, in parallel, the maximum distance over all k entries.
 *   - Returns that maximum in worstDist and its global index in worstIdx.
 *   - All threads in the warp receive the same worstDist/worstIdx via
 *     warp-wide broadcast.
 */
__device__ __forceinline__
void warp_recompute_worst(int perThread,
                          float (&distList)[MAX_PER_THREAD],
                          float &worstDist,
                          int &worstIdx)
{
    const unsigned mask = 0xffffffffu;
    const int lane = threadIdx.x & (WARP_SIZE - 1);

    // Compute per-thread local maximum over its perThread entries.
    float localMax = distList[0];
    int   localPos = 0;

#pragma unroll
    for (int i = 1; i < MAX_PER_THREAD; ++i) {
        if (i < perThread) {
            float v = distList[i];
            if (v > localMax) {
                localMax = v;
                localPos = i;
            }
        }
    }

    // Map local position to global linear index in [0, k-1].
    int linearIdx = localPos * WARP_SIZE + lane;

    // Warp-wide argmax reduction on (localMax, linearIdx).
#pragma unroll
    for (int offset = WARP_SIZE / 2; offset > 0; offset >>= 1) {
        float otherMax = __shfl_down_sync(mask, localMax, offset);
        int   otherIdx = __shfl_down_sync(mask, linearIdx, offset);
        if (otherMax > localMax) {
            localMax = otherMax;
            linearIdx = otherIdx;
        }
    }

    // Lane 0 stores the final result, then broadcast to the warp.
    if (lane == 0) {
        worstDist = localMax;
        worstIdx  = linearIdx;
    }
    worstDist = __shfl_sync(mask, worstDist, 0);
    worstIdx  = __shfl_sync(mask, worstIdx, 0);
}

/*
 * Main k-NN kernel.
 *
 * Parameters:
 *   query       - array of query points (float2), length query_count
 *   query_count - number of queries
 *   data        - array of data points (float2), length data_count
 *   data_count  - number of data points
 *   k           - number of neighbors to find (power of 2 in [32, 1024])
 *   result      - output array of length query_count * k, where for query i
 *                 the entries [i*k .. i*k + k-1] contain (index, distance)
 *                 pairs for its k nearest neighbors.
 *
 * Each block:
 *   - Loads tiles of the data array into shared memory cooperatively.
 *   - Contains WARPS_PER_BLOCK warps, each assigned to one query.
 *
 * Each warp:
 *   - Maintains a private top-k list distributed across threads.
 *   - For each tile, computes squared distances to its query using the
 *     cached data in shared memory.
 *   - Updates the top-k list using warp-synchronous operations, handling
 *     multiple candidate insertions per 32-candidate batch.
 */
__global__ void knn_kernel(const float2 * __restrict__ query,
                           int query_count,
                           const float2 * __restrict__ data,
                           int data_count,
                           int k,
                           KnnPair * __restrict__ result)
{
    extern __shared__ float2 sh_data[]; // Shared tile of data points

    const unsigned fullMask = 0xffffffffu;
    const int lane          = threadIdx.x & (WARP_SIZE - 1);
    const int warpInBlock   = threadIdx.x >> 5; // threadIdx.x / WARP_SIZE
    const int warpGlobal    = blockIdx.x * WARPS_PER_BLOCK + warpInBlock;

    const bool isActiveWarp = (warpGlobal < query_count);

    // Per-thread number of entries in the distributed top-k list.
    // Assumes k is a power of two and >= 32, hence divisible by 32.
    const int perThread = k / WARP_SIZE;

    // Per-thread portion of the warp's top-k list.
    float bestDist[MAX_PER_THREAD];
    int   bestIdx [MAX_PER_THREAD];

    // Initialize the per-thread top-k list with "infinite" distances.
#pragma unroll
    for (int i = 0; i < MAX_PER_THREAD; ++i) {
        if (i < perThread) {
            bestDist[i] = FLT_MAX;
            bestIdx[i]  = -1;
        }
    }

    // Current worst distance and its global index in the distributed top-k list.
    float worstDist = FLT_MAX;
    int   worstIdx  = 0;

    // Load the warp's query point into registers and broadcast across the warp.
    float2 q;
    if (isActiveWarp) {
        if (lane == 0) {
            q = query[warpGlobal];
        }
        q.x = __shfl_sync(fullMask, q.x, 0);
        q.y = __shfl_sync(fullMask, q.y, 0);
    }

    // Process the data in tiles cached in shared memory.
    for (int tileStart = 0; tileStart < data_count; tileStart += TILE_SIZE) {
        int tileSize = data_count - tileStart;
        if (tileSize > TILE_SIZE) tileSize = TILE_SIZE;

        // Cooperative loading of the tile into shared memory by the whole block.
        for (int i = threadIdx.x; i < tileSize; i += blockDim.x) {
            sh_data[i] = data[tileStart + i];
        }
        __syncthreads();

        // Only warps that correspond to a valid query perform k-NN work.
        if (isActiveWarp) {
            // Traverse the tile in batches of 32 points per warp.
            for (int base = 0; base < tileSize; base += WARP_SIZE) {
                const int idxInTile = base + lane;
                bool valid = (idxInTile < tileSize);

                float candDist = 0.0f;
                int   candIdx  = -1;

                // Compute squared Euclidean distance for this thread's candidate.
                if (valid) {
                    const float2 p = sh_data[idxInTile];
                    const float dx = p.x - q.x;
                    const float dy = p.y - q.y;
                    candDist = dx * dx + dy * dy;
                    candIdx  = tileStart + idxInTile;
                }

                /*
                 * Update the warp's top-k list with the candidates from this batch.
                 *
                 * - Each thread holds one candidate (distance + index) in registers.
                 * - We repeatedly:
                 *     * Find which threads currently have candidates smaller than the
                 *       current worst distance in the top-k list.
                 *     * Select one such thread (the lowest lane in the mask).
                 *     * Broadcast its candidate to the warp.
                 *     * Replace the current worst entry in the top-k list with that
                 *       candidate.
                 *     * Recompute the worst entry in the updated top-k list.
                 *     * Mark the selected thread's candidate as consumed.
                 * - This loop may insert multiple candidates from the batch if
                 *   several are better than the evolving worst distance.
                 */
                while (true) {
                    const float curWorst = worstDist;

                    // Mask of threads whose candidate is valid and beats the current worst.
                    const unsigned betterMask =
                        __ballot_sync(fullMask, valid && (candDist < curWorst));

                    if (betterMask == 0u) {
                        // No more candidates in this batch can improve the top-k list.
                        break;
                    }

                    // Select one candidate lane to insert (lowest set bit in mask).
                    const int srcLane = __ffs(betterMask) - 1;

                    // Broadcast the chosen candidate to all threads in the warp.
                    const float chosenDist = __shfl_sync(fullMask, candDist, srcLane);
                    const int   chosenIdx  = __shfl_sync(fullMask, candIdx,  srcLane);

                    // Compute which thread and local slot own the current worst entry.
                    const int ownerLane   = worstIdx % WARP_SIZE;
                    const int ownerOffset = worstIdx / WARP_SIZE;

                    // The owning thread updates its local segment of the top-k list.
                    if (lane == ownerLane) {
                        bestDist[ownerOffset] = chosenDist;
                        bestIdx [ownerOffset] = chosenIdx;
                    }

                    // Recompute the worst entry in the updated top-k list cooperatively.
                    warp_recompute_worst(perThread, bestDist, worstDist, worstIdx);

                    // Consume the candidate so it won't be considered again.
                    if (lane == srcLane) {
                        valid = false;
                    }
                }
            } // end for base
        }

        // Ensure all threads are done using this tile before loading the next one.
        __syncthreads();
    } // end for tileStart

    // Only warps corresponding to valid queries write results.
    if (isActiveWarp) {
        const int baseOut = warpGlobal * k;

        /*
         * Write the warp's distributed top-k list to global memory in a
         * contiguous fashion. Given our logical layout:
         *   global index = localIdx * WARP_SIZE + lane
         * this results in fully coalesced writes.
         */
#pragma unroll
        for (int j = 0; j < MAX_PER_THREAD; ++j) {
            if (j < perThread) {
                const int linear = j * WARP_SIZE + lane;
                if (linear < k) {
                    KnnPair p;
                    p.idx  = bestIdx[j];
                    p.dist = bestDist[j];
                    result[baseOut + linear] = p;
                }
            }
        }

        /*
         * Final sort of the k neighbors for this query by ascending distance.
         *
         * We perform a simple insertion sort in-place in global memory.
         * This is executed by lane 0 only; k <= 1024, so O(k^2) comparisons
         * are acceptable overhead relative to the O(data_count) distance
         * computations per query.
         */
        if (lane == 0) {
            KnnPair *out = result + baseOut;
            for (int i = 1; i < k; ++i) {
                KnnPair key = out[i];
                float keyDist = key.dist;
                int j = i - 1;
                while (j >= 0 && out[j].dist > keyDist) {
                    out[j + 1] = out[j];
                    --j;
                }
                out[j + 1] = key;
            }
        }
    }
}

/*
 * Host interface:
 *
 *   void run_knn(const float2 *query, int query_count,
 *                const float2 *data, int data_count,
 *                std::pair<int, float> *result, int k);
 *
 * All pointers (query, data, result) refer to device memory allocated with
 * cudaMalloc. This function configures and launches the kernel.
 */
void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    // Basic validations according to the problem constraints.
    assert(k >= 32 && k <= MAX_K);
    assert((k & (k - 1)) == 0);    // k is power of two
    assert(data_count >= k);       // guaranteed by the problem statement

    const int threadsPerBlock = THREADS_PER_BLOCK;
    const int warpsPerBlock   = WARPS_PER_BLOCK;

    // One warp per query.
    const int totalWarps = query_count;
    const int numBlocks  = (totalWarps + warpsPerBlock - 1) / warpsPerBlock;

    // Shared memory for one tile of data points.
    const size_t sharedMemBytes = TILE_SIZE * sizeof(float2);

    // Reinterpret the std::pair<int,float>* as KnnPair* for device access.
    KnnPair *deviceResult = reinterpret_cast<KnnPair*>(result);

    knn_kernel<<<numBlocks, threadsPerBlock, sharedMemBytes>>>(
        query,
        query_count,
        data,
        data_count,
        k,
        deviceResult
    );

    // The caller can choose whether to synchronize or check errors.
    // cudaDeviceSynchronize(); // Optional: uncomment if needed.
}

#include <cuda_runtime.h>
#include <utility>

// Maximum k supported by this implementation (power of two, up to 1024 as per problem statement)
static constexpr int MAX_K = 1024;
static constexpr int WARPS_PER_BLOCK = 8;      // 8 warps per block -> 256 threads
static constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * 32;
static constexpr int TILE_SIZE = 1024;         // Number of data points cached in shared memory per iteration

// CUDA kernel implementing k-NN for 2D points.
// Each warp processes a single query point and maintains a private max-heap of size k
// in shared memory to store the current k nearest neighbors (distance and index).
// Data points are processed in tiles, each tile cached in shared memory for reuse.
template<int TILE_POINTS, int WARPS_PER_BLK>
__global__ void knn_kernel(
    const float2* __restrict__ query,
    int query_count,
    const float2* __restrict__ data,
    int data_count,
    std::pair<int, float>* __restrict__ result,
    int k)
{
    // Layout of dynamic shared memory:
    // [ float2 s_data[TILE_POINTS] ]
    // [ float warp_heap_dists[WARPS_PER_BLK * MAX_K] ]
    // [ int   warp_heap_idxs [WARPS_PER_BLK * MAX_K] ]
    // [ int   warp_heap_sizes[WARPS_PER_BLK] ]
    extern __shared__ unsigned char shared[];
    unsigned char* smem_ptr = shared;

    // Shared-memory tile of data points
    float2* s_data = reinterpret_cast<float2*>(smem_ptr);
    smem_ptr += TILE_POINTS * sizeof(float2);

    // Per-warp heaps: distances and indices
    float* s_heap_dists = reinterpret_cast<float*>(smem_ptr);
    smem_ptr += WARPS_PER_BLK * MAX_K * sizeof(float);

    int* s_heap_idxs = reinterpret_cast<int*>(smem_ptr);
    smem_ptr += WARPS_PER_BLK * MAX_K * sizeof(int);

    // Per-warp heap sizes
    int* s_heap_sizes = reinterpret_cast<int*>(smem_ptr);
    // smem_ptr += WARPS_PER_BLK * sizeof(int); // not needed further

    const int lane_id        = threadIdx.x & 31;          // thread index within warp [0,31]
    const int warp_in_block  = threadIdx.x >> 5;          // warp index within block
    const int warp_global_id = (blockIdx.x * blockDim.x + threadIdx.x) >> 5; // global warp index

    if (warp_global_id >= query_count)
        return; // No query to process for this warp

    // Per-warp heap pointers
    float* heap_dists = s_heap_dists + warp_in_block * MAX_K;
    int*   heap_idxs  = s_heap_idxs  + warp_in_block * MAX_K;
    int&   heap_size  = s_heap_sizes[warp_in_block];

    // Initialize per-warp heap size once
    if (lane_id == 0) {
        heap_size = 0;
    }
    __syncwarp();

    // Load the query point for this warp and broadcast to all lanes
    float2 q;
    if (lane_id == 0) {
        q = query[warp_global_id];
    }
    q.x = __shfl_sync(0xFFFFFFFFu, q.x, 0);
    q.y = __shfl_sync(0xFFFFFFFFu, q.y, 0);

    // Iterate over data points in tiles
    for (int tile_start = 0; tile_start < data_count; tile_start += TILE_POINTS) {
        int tile_size = TILE_POINTS;
        if (tile_start + tile_size > data_count) {
            tile_size = data_count - tile_start;
        }

        // Load tile into shared memory cooperatively by the whole block
        for (int i = threadIdx.x; i < tile_size; i += blockDim.x) {
            s_data[i] = data[tile_start + i];
        }
        __syncthreads(); // Ensure tile is fully cached before any warp uses it

        // Process the tile: each warp processes all points in the tile.
        // We step in batches of 32 points so that each lane handles one candidate,
        // and the warp leader (lane 0) integrates these 32 candidates into the
        // per-warp max-heap via warp shuffles.
        for (int j_base = 0; j_base < tile_size; j_base += warpSize) {
            int j = j_base + lane_id;

            float dist = CUDART_INF_F;
            int   data_idx = -1;

            if (j < tile_size) {
                float2 p = s_data[j];
                float dx = q.x - p.x;
                float dy = q.y - p.y;
                // Squared Euclidean distance
                dist = dx * dx + dy * dy;
                data_idx = tile_start + j;
            }

            // Active lanes in this batch (those with a valid candidate)
            unsigned int active_mask = __ballot_sync(0xFFFFFFFFu, j < tile_size);
            if (active_mask == 0)
                continue; // No candidates in this batch for this warp

            // Warp leader integrates all candidates in this batch into the heap.
            if (lane_id == 0) {
                int local_heap_size = heap_size;

                // Iterate over all active lanes in this batch
                while (active_mask) {
                    int src_lane = __ffs(active_mask) - 1; // index of a lane with a candidate

                    float c_dist = __shfl_sync(0xFFFFFFFFu, dist, src_lane);
                    int   c_idx  = __shfl_sync(0xFFFFFFFFu, data_idx, src_lane);

                    // Max-heap insertion / update:
                    // - While heap not full: push and sift-up.
                    // - When full: if candidate better than root, replace root and sift-down.
                    if (local_heap_size < k) {
                        // Insert new element at the end and sift-up
                        int i = local_heap_size++;
                        while (i > 0) {
                            int parent = (i - 1) >> 1;
                            float parent_val = heap_dists[parent];
                            if (parent_val >= c_dist)
                                break;
                            heap_dists[i] = parent_val;
                            heap_idxs[i]  = heap_idxs[parent];
                            i = parent;
                        }
                        heap_dists[i] = c_dist;
                        heap_idxs[i]  = c_idx;
                    } else {
                        // Heap is full; candidate must be better than current worst (root)
                        float root_dist = heap_dists[0];
                        if (c_dist < root_dist) {
                            // Replace root and sift-down
                            int i = 0;
                            int size = local_heap_size;
                            int left = 1;
                            while (left < size) {
                                int right = left + 1;
                                int largest = left;
                                float largest_val = heap_dists[left];
                                if (right < size) {
                                    float right_val = heap_dists[right];
                                    if (right_val > largest_val) {
                                        largest = right;
                                        largest_val = right_val;
                                    }
                                }
                                if (largest_val <= c_dist)
                                    break;
                                heap_dists[i] = largest_val;
                                heap_idxs[i]  = heap_idxs[largest];
                                i = largest;
                                left = (i << 1) + 1;
                            }
                            heap_dists[i] = c_dist;
                            heap_idxs[i]  = c_idx;
                        }
                    }

                    // Clear this lane from the active mask and continue with next
                    active_mask &= active_mask - 1;
                }

                heap_size = local_heap_size;
            }

            // Synchronize warp before next batch so all lanes see updated heap state
            __syncwarp();
        }

        __syncthreads(); // Ensure all warps finish using this tile before loading a new one
    }

    // At this point, heap_dists/heap_idxs contain a max-heap of size k with the k nearest neighbors
    // (max-heap: root is the worst among the k best).
    // We now convert the heap into an array sorted by ascending distance using in-place heapsort.
    __syncwarp();
    if (lane_id == 0) {
        int n = heap_size; // should be equal to k since data_count >= k
        // Heapsort on max-heap to obtain ascending order in-place
        for (int i = n - 1; i > 0; --i) {
            // Swap root (current maximum) with position i
            float tmp_dist = heap_dists[0];
            int   tmp_idx  = heap_idxs[0];
            heap_dists[0] = heap_dists[i];
            heap_idxs[0]  = heap_idxs[i];
            heap_dists[i] = tmp_dist;
            heap_idxs[i]  = tmp_idx;

            // Sift-down from root within reduced heap [0, i)
            int size = i;
            int parent = 0;
            while (true) {
                int left = (parent << 1) + 1;
                if (left >= size)
                    break;
                int right = left + 1;
                int largest = left;
                float largest_val = heap_dists[left];
                if (right < size) {
                    float right_val = heap_dists[right];
                    if (right_val > largest_val) {
                        largest = right;
                        largest_val = right_val;
                    }
                }
                if (largest_val <= heap_dists[parent])
                    break;
                float pd = heap_dists[parent];
                int   pi = heap_idxs[parent];
                heap_dists[parent] = heap_dists[largest];
                heap_idxs[parent]  = heap_idxs[largest];
                heap_dists[largest] = pd;
                heap_idxs[largest]  = pi;
                parent = largest;
            }
        }
    }
    __syncwarp();

    // Now heap_dists[0..k-1] is sorted in ascending order of distance.
    // Write out results cooperatively: each lane handles a strided subset of neighbors.
    const int base_out = warp_global_id * k;
    for (int i = lane_id; i < k; i += warpSize) {
        int   nn_idx = heap_idxs[i];
        float nn_dst = heap_dists[i];
        result[base_out + i].first  = nn_idx;
        result[base_out + i].second = nn_dst;
    }
}

// Host function interface.
// query, data, and result are assumed to be device pointers allocated with cudaMalloc.
// query_count: number of query points
// data_count : number of data points
// k          : number of nearest neighbors (power of two between 32 and 1024)
void run_knn(
    const float2* query,
    int query_count,
    const float2* data,
    int data_count,
    std::pair<int, float>* result,
    int k)
{
    // Guard against unsupported k at runtime
    if (k <= 0 || k > MAX_K) {
        // For production code, you might want to handle this case differently
        return;
    }

    const int warps_per_block = WARPS_PER_BLOCK;
    const int threads_per_block = THREADS_PER_BLOCK;

    // Each warp processes one query
    int total_warps = query_count;
    int num_blocks = (total_warps + warps_per_block - 1) / warps_per_block;

    // Dynamic shared memory size
    size_t shared_bytes =
        sizeof(float2) * TILE_SIZE +                         // s_data
        warps_per_block * MAX_K * sizeof(float) +            // s_heap_dists
        warps_per_block * MAX_K * sizeof(int)   +            // s_heap_idxs
        warps_per_block * sizeof(int);                       // s_heap_sizes

    knn_kernel<TILE_SIZE, WARPS_PER_BLOCK>
        <<<num_blocks, threads_per_block, shared_bytes>>>(query, query_count, data, data_count, result, k);
}

