#include <cuda_runtime.h>
#include <float.h>
#include <utility>

// Internal representation of a k-NN entry (index, distance).
// Layout matches std::pair<int,float> for practical purposes.
struct PairIntFloat {
    int   first;   // data point index
    float second;  // squared Euclidean distance
};

// Warp-level helper to merge the candidate buffer into the current k-NN set.
// - knn:        current k-NN array [0..k-1] in shared memory
// - candidates: candidate buffer [0..cand_count-1] in shared memory
// - k:          number of neighbors
// - cand_count: number of valid entries in candidates
// - max_dist:   (in/out) distance of the current k-th nearest neighbor
// - lane_id:    lane index within the warp (0..31)
// - mask:       active-lane mask for this warp
//
// After the merge:
// - knn[0..k-1] contain the k nearest neighbors among previous knn and candidates,
//   sorted by ascending distance (second).
// - max_dist is updated to knn[k-1].second.
// - Candidates are marked as consumed (their distances set to FLT_MAX); caller should
//   reset cand_count to 0 afterwards.
static __device__ __forceinline__ void merge_candidates(
    PairIntFloat* knn,
    PairIntFloat* candidates,
    int            k,
    int            cand_count,
    float&         max_dist,
    int            lane_id,
    unsigned       mask)
{
    // Repeatedly select the smallest element among:
    //   - knn[i] for i in [out..k-1]
    //   - candidates[j] for j in [0..cand_count-1]
    // and place it at knn[out].
    for (int out = 0; out < k; ++out) {
        float best_dist  = FLT_MAX;
        int   best_index = -1;
        int   best_from  = 0;   // 0 = from knn, 1 = from candidates
        int   best_pos   = -1;  // index within the chosen array

        // Search current knn segment [out..k-1]
        for (int i = out + lane_id; i < k; i += warpSize) {
            float d = knn[i].second;
            int   idx = knn[i].first;
            if (d < best_dist) {
                best_dist  = d;
                best_index = idx;
                best_from  = 0;
                best_pos   = i;
            }
        }

        // Search candidates [0..cand_count-1]
        for (int j = lane_id; j < cand_count; j += warpSize) {
            float d = candidates[j].second;
            int   idx = candidates[j].first;
            if (d < best_dist) {
                best_dist  = d;
                best_index = idx;
                best_from  = 1;
                best_pos   = j;
            }
        }

        // Warp-wide reduction to find the global best (smallest distance).
        for (int offset = 16; offset > 0; offset >>= 1) {
            float other_dist  = __shfl_down_sync(mask, best_dist,  offset);
            int   other_index = __shfl_down_sync(mask, best_index, offset);
            int   other_from  = __shfl_down_sync(mask, best_from,  offset);
            int   other_pos   = __shfl_down_sync(mask, best_pos,   offset);

            if (other_dist < best_dist) {
                best_dist  = other_dist;
                best_index = other_index;
                best_from  = other_from;
                best_pos   = other_pos;
            }
        }

        // Lane 0 commits the selected element and marks its source as consumed.
        if (lane_id == 0) {
            knn[out].first  = best_index;
            knn[out].second = best_dist;

            if (best_from == 0) {
                // Consumed from knn; mark its original slot as inactive.
                knn[best_pos].second = FLT_MAX;
            } else {
                // Consumed from candidates.
                candidates[best_pos].second = FLT_MAX;
            }
        }

        // Ensure all threads see updated FLT_MAX markers before next iteration.
        __syncwarp(mask);
    }

    // Update max_dist to distance of the k-th (last) nearest neighbor.
    if (lane_id == 0) {
        max_dist = knn[k - 1].second;
    }
    max_dist = __shfl_sync(mask, max_dist, 0);
}

// Kernel implementing k-NN search for 2D points with one warp per query.
// Template parameters:
// - TILE_SIZE:        number of data points cached per block in shared memory.
// - WARPS_PER_BLOCK:  number of warps (queries) processed per block.
//
// Each warp maintains:
// - a private k-element intermediate result (knn) in shared memory,
// - a k-element candidate buffer in shared memory,
// - a shared candidate counter and max_distance.
//
// The block cooperatively loads tiles of data points into shared memory.
// Each active warp processes the tile for its own query, filters by max_distance,
// appends candidates using atomicAdd, and merges when the buffer becomes full.
template <int TILE_SIZE, int WARPS_PER_BLOCK>
__global__ void knn_kernel(
    const float2* __restrict__ query,
    int                       query_count,
    const float2* __restrict__ data,
    int                       data_count,
    PairIntFloat* __restrict__ result,
    int                       k)
{
    extern __shared__ unsigned char smem[];

    // Layout of dynamic shared memory:
    // [0 .. TILE_SIZE-1] float2      : cached data points
    // next: WARPS_PER_BLOCK * 2*k    : PairIntFloat (k knn + k candidates per warp)
    // next: WARPS_PER_BLOCK          : int candidate_counts
    // next: WARPS_PER_BLOCK          : float max_dists
    float2* s_points = reinterpret_cast<float2*>(smem);

    PairIntFloat* s_pairs = reinterpret_cast<PairIntFloat*>(s_points + TILE_SIZE);
    int*          s_candidate_counts = reinterpret_cast<int*>(s_pairs + WARPS_PER_BLOCK * 2 * k);
    float*        s_max_dists        = reinterpret_cast<float*>(s_candidate_counts + WARPS_PER_BLOCK);

    const int thread_id       = threadIdx.x;
    const int lane_id         = thread_id & (warpSize - 1);      // lane index in warp
    const int warp_id_in_block = thread_id >> 5;                 // warp index in block
    const int warps_per_block = WARPS_PER_BLOCK;
    const int warp_global_id  = blockIdx.x * warps_per_block + warp_id_in_block;

    const bool warp_active = (warp_global_id < query_count);

    // Active-lane mask for this warp.
    const unsigned full_mask = __activemask();

    // Per-warp pointers into shared memory for knn and candidate buffers.
    PairIntFloat* warp_base      = s_pairs + (warp_id_in_block * 2 * k);
    PairIntFloat* warp_knn       = warp_base;           // [0 .. k-1]
    PairIntFloat* warp_candidates = warp_base + k;      // [0 .. k-1], only [0..cand_count-1] used

    int&   warp_candidate_count = s_candidate_counts[warp_id_in_block];
    float& warp_max_dist        = s_max_dists[warp_id_in_block];

    // Initialize per-warp state (only for active warps).
    if (warp_active) {
        if (lane_id == 0) {
            warp_candidate_count = 0;
            warp_max_dist        = FLT_MAX;
        }
        // Initialize intermediate k-NN result with "infinite" distances.
        for (int i = lane_id; i < k; i += warpSize) {
            warp_knn[i].first  = -1;
            warp_knn[i].second = FLT_MAX;
        }
    }

    // All threads must reach this barrier because shared memory is reused across warps.
    __syncthreads();

    float2 query_point;
    if (warp_active) {
        // Load query point once (lane 0) and broadcast within warp.
        if (lane_id == 0) {
            query_point = query[warp_global_id];
        }
        query_point.x = __shfl_sync(full_mask, query_point.x, 0);
        query_point.y = __shfl_sync(full_mask, query_point.y, 0);
    }

    // Process data points in tiles.
    for (int tile_start = 0; tile_start < data_count; tile_start += TILE_SIZE) {
        int tile_size = TILE_SIZE;
        if (tile_start + tile_size > data_count) {
            tile_size = data_count - tile_start;
        }

        // Block-wide cooperative load of the current tile into shared memory.
        for (int i = thread_id; i < tile_size; i += blockDim.x) {
            s_points[i] = data[tile_start + i];
        }

        __syncthreads();

        if (warp_active) {
            // Local copy of max distance used for filtering within this tile.
            float max_d = warp_max_dist;

            // Strided over tile points by warp lanes.
            for (int idx_in_tile = lane_id; idx_in_tile < tile_size; idx_in_tile += warpSize) {
                float2 p  = s_points[idx_in_tile];
                float dx  = p.x - query_point.x;
                float dy  = p.y - query_point.y;
                float dist = dx * dx + dy * dy;

                // Filter by current max distance.
                bool is_candidate = (dist < max_d);

                // Determine which lanes have a candidate in this iteration.
                unsigned candidate_mask = __ballot_sync(full_mask, is_candidate);
                int local_count = __popc(candidate_mask);

                if (local_count > 0) {
                    // Check if candidate buffer has enough free slots; if not, merge.
                    int need_merge = 0;
                    int base_count = 0;

                    if (lane_id == 0) {
                        base_count = warp_candidate_count;
                        if (base_count + local_count > k) {
                            need_merge = 1;
                        }
                    }

                    base_count = __shfl_sync(full_mask, base_count, 0);
                    need_merge = __shfl_sync(full_mask, need_merge, 0);

                    if (need_merge) {
                        // Merge existing candidates into knn before inserting new ones.
                        int cand_count = 0;
                        if (lane_id == 0) {
                            cand_count = warp_candidate_count;
                        }
                        cand_count = __shfl_sync(full_mask, cand_count, 0);

                        if (cand_count > 0) {
                            merge_candidates(
                                warp_knn,
                                warp_candidates,
                                k,
                                cand_count,
                                warp_max_dist,
                                lane_id,
                                full_mask);
                            // Update local max distance after merge.
                            max_d = warp_max_dist;
                        }

                        if (lane_id == 0) {
                            warp_candidate_count = 0;
                            base_count = 0;
                        }
                        base_count = __shfl_sync(full_mask, base_count, 0);
                    }

                    // Reserve slots in candidate buffer using a single atomicAdd per warp.
                    int offset = 0;
                    if (lane_id == 0) {
                        offset = atomicAdd(&warp_candidate_count, local_count);
                    }
                    offset = __shfl_sync(full_mask, offset, 0);

                    // Each lane with a candidate writes its element to the reserved range.
                    if (is_candidate) {
                        unsigned lane_mask = (lane_id == 0) ? 0u : ((1u << lane_id) - 1u);
                        int pos_in_local = __popc(candidate_mask & lane_mask);
                        int pos          = offset + pos_in_local;

                        // pos is guaranteed < k due to the capacity check above.
                        warp_candidates[pos].first  = tile_start + idx_in_tile;
                        warp_candidates[pos].second = dist;
                    }
                }
            } // end loop over tile points
        }

        __syncthreads();
    } // end loop over tiles

    // Final merge for remaining candidates after processing all tiles.
    if (warp_active) {
        int cand_count = 0;
        if (lane_id == 0) {
            cand_count = warp_candidate_count;
        }
        cand_count = __shfl_sync(full_mask, cand_count, 0);

        if (cand_count > 0) {
            merge_candidates(
                warp_knn,
                warp_candidates,
                k,
                cand_count,
                warp_max_dist,
                lane_id,
                full_mask);

            if (lane_id == 0) {
                warp_candidate_count = 0;
            }
        }

        // Write final k-NN results back to global memory.
        // Each lane handles a strided subset.
        for (int i = lane_id; i < k; i += warpSize) {
            PairIntFloat p = warp_knn[i];
            result[warp_global_id * k + i].first  = p.first;
            result[warp_global_id * k + i].second = p.second;
        }
    }
}

// Host-side C++ interface as specified.
// query, data, and result are device pointers allocated with cudaMalloc.
// - query:  query_count  float2 points
// - data:   data_count   float2 points
// - result: query_count * k std::pair<int,float> entries
extern "C" void run_knn(
    const float2*                 query,
    int                           query_count,
    const float2*                 data,
    int                           data_count,
    std::pair<int, float>*        result,
    int                           k)
{
    // Configuration parameters:
    // - TILE_SIZE: number of data points cached per block
    // - WARPS_PER_BLOCK: number of queries processed per block
    // For k up to 1024 and TILE_SIZE = 1024, WARPS_PER_BLOCK = 2 keeps shared memory
    // usage per block within ~41 KB, which is safe on modern data center GPUs.
    constexpr int TILE_SIZE        = 1024;
    constexpr int WARPS_PER_BLOCK  = 2;
    constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * 32;

    // One warp per query.
    int total_warps  = query_count;
    int num_blocks   = (total_warps + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    // Shared memory size calculation:
    // TILE_SIZE * sizeof(float2) for cached data points +
    // WARPS_PER_BLOCK * 2 * k * sizeof(PairIntFloat) for knn and candidates +
    // WARPS_PER_BLOCK * sizeof(int) for candidate counts +
    // WARPS_PER_BLOCK * sizeof(float) for max distances.
    size_t shared_bytes =
        static_cast<size_t>(TILE_SIZE) * sizeof(float2) +
        static_cast<size_t>(WARPS_PER_BLOCK) * 2 * static_cast<size_t>(k) * sizeof(PairIntFloat) +
        static_cast<size_t>(WARPS_PER_BLOCK) * sizeof(int) +
        static_cast<size_t>(WARPS_PER_BLOCK) * sizeof(float);

    // Launch kernel. Cast result pointer to internal PairIntFloat layout.
    PairIntFloat* result_internal = reinterpret_cast<PairIntFloat*>(result);

    knn_kernel<TILE_SIZE, WARPS_PER_BLOCK>
        <<<num_blocks, THREADS_PER_BLOCK, shared_bytes>>>(
            query, query_count,
            data,  data_count,
            result_internal,
            k);

    // Synchronize to ensure completion before the caller uses the results.
    cudaDeviceSynchronize();
}

#include <cuda_runtime.h>
#include <utility>
#include <cfloat>
#include <cstdint>

// This implementation assigns one warp (32 threads) to each query point.
// The data points are processed in tiles that are cached in shared memory.
// For each query (warp), we keep:
//   - An intermediate result: k best distances + indices (top-k neighbors).
//   - A candidate buffer in shared memory that stores up to k candidates.
//   - A shared integer counter that tracks candidate buffer size.
// When the candidate buffer is full, we merge it with the intermediate
// result using a warp-wide bitonic sort on the union of size 2*k and keep
// the k smallest distances.
//
// The kernel uses atomicAdd on a shared counter to assign positions in the
// per-warp candidate buffer. Distance filtering uses a max_distance
// variable equal to the current k-th (worst) distance in the intermediate
// result. Threads communicate within a warp using __shfl_sync and
// __syncwarp. Data tiling uses __syncthreads across the block.

using Pair = std::pair<int, float>;

constexpr int WARP_SIZE        = 32;
constexpr int WARPS_PER_BLOCK  = 4;   // 4 warps -> 128 threads per block
constexpr int BLOCK_SIZE       = WARP_SIZE * WARPS_PER_BLOCK;
constexpr int TILE_POINTS      = 2048; // number of data points cached per tile

// Warp-wide merge of candidate buffer into intermediate top-k using bitonic sort.
// Each warp operates only on its own regions in shared memory.
__device__ __forceinline__
void warp_merge_topk(
    int lane,                 // thread's lane ID within the warp (0..31)
    int k,                    // number of neighbors
    int *cand_count_ptr,      // pointer to shared candidate count for this warp
    int *best_indices,        // shared array [k] of current best indices
    float *best_dists,        // shared array [k] of current best distances
    int *cand_indices,        // shared array [k] of candidate indices
    float *cand_dists,        // shared array [k] of candidate distances
    int *merge_indices,       // shared array [2*k] scratch indices
    float *merge_dists        // shared array [2*k] scratch distances
) {
    const unsigned FULL_MASK = 0xFFFFFFFFu;

    int cand_count = 0;
    if (lane == 0) {
        cand_count = *cand_count_ptr;
    }
    cand_count = __shfl_sync(FULL_MASK, cand_count, 0);

    if (cand_count == 0) {
        // Nothing to merge.
        return;
    }

    // Build union of current top-k and candidates into merge_* arrays.
    // First [0..k-1] = current best, then [k..k+cand_count-1] = candidates,
    // remaining slots up to 2*k are padded with FLT_MAX so they end up at
    // the end of the sorted sequence.
    for (int i = lane; i < k; i += WARP_SIZE) {
        merge_dists[i]   = best_dists[i];
        merge_indices[i] = best_indices[i];
    }

    for (int i = lane; i < cand_count; i += WARP_SIZE) {
        merge_dists[k + i]   = cand_dists[i];
        merge_indices[k + i] = cand_indices[i];
    }

    for (int i = lane + k + cand_count; i < 2 * k; i += WARP_SIZE) {
        merge_dists[i]   = FLT_MAX;
        merge_indices[i] = -1;
    }

    __syncwarp();

    // Bitonic sort on 2*k elements in ascending order of distance.
    const int N = 2 * k;
    for (int size = 2; size <= N; size <<= 1) {
        int halfSize = size >> 1;
        for (int stride = halfSize; stride > 0; stride >>= 1) {
            for (int i = lane; i < N; i += WARP_SIZE) {
                int partner = i ^ stride;
                if (partner > i) {
                    float dist_i = merge_dists[i];
                    float dist_j = merge_dists[partner];
                    int idx_i    = merge_indices[i];
                    int idx_j    = merge_indices[partner];

                    // Determine sorting direction for this subsequence.
                    bool ascending = ((i & size) == 0);
                    bool do_swap   = (dist_i > dist_j) == ascending;

                    if (do_swap) {
                        // Swap distances
                        merge_dists[i]       = dist_j;
                        merge_dists[partner] = dist_i;
                        // Swap indices
                        merge_indices[i]       = idx_j;
                        merge_indices[partner] = idx_i;
                    }
                }
            }
            __syncwarp();
        }
    }

    // First k entries now hold the smallest distances; copy back to best_*.
    for (int i = lane; i < k; i += WARP_SIZE) {
        best_dists[i]   = merge_dists[i];
        best_indices[i] = merge_indices[i];
    }

    if (lane == 0) {
        *cand_count_ptr = 0;
    }
    __syncwarp();
}

__global__
void knn_kernel(
    const float2 * __restrict__ query,
    int query_count,
    const float2 * __restrict__ data,
    int data_count,
    Pair * __restrict__ result,
    int k
) {
    extern __shared__ unsigned char smem[];

    // Layout dynamic shared memory:
    // [0]                    float2 sh_data[TILE_POINTS]
    // [aligned]              int   candidate_counts[WARPS_PER_BLOCK]
    // [next]                 int   best_indices[WARPS_PER_BLOCK][k]
    // [next]                 float best_dists  [WARPS_PER_BLOCK][k]
    // [next]                 int   cand_indices[WARPS_PER_BLOCK][k]
    // [next]                 float cand_dists  [WARPS_PER_BLOCK][k]
    // [next]                 int   merge_indices[WARPS_PER_BLOCK][2*k]
    // [next]                 float merge_dists  [WARPS_PER_BLOCK][2*k]

    unsigned char *ptr = smem;

    // Shared tile of data points.
    float2 *sh_data = reinterpret_cast<float2*>(ptr);
    ptr += TILE_POINTS * sizeof(float2);

    // Align to 16 bytes for the remaining arrays.
    uintptr_t iptr = reinterpret_cast<uintptr_t>(ptr);
    iptr = (iptr + 15u) & ~uintptr_t(15u);
    ptr = reinterpret_cast<unsigned char*>(iptr);

    int *candidate_counts = reinterpret_cast<int*>(ptr);
    ptr += WARPS_PER_BLOCK * sizeof(int);

    int *best_indices = reinterpret_cast<int*>(ptr);
    ptr += WARPS_PER_BLOCK * k * sizeof(int);

    float *best_dists = reinterpret_cast<float*>(ptr);
    ptr += WARPS_PER_BLOCK * k * sizeof(float);

    int *cand_indices = reinterpret_cast<int*>(ptr);
    ptr += WARPS_PER_BLOCK * k * sizeof(int);

    float *cand_dists = reinterpret_cast<float*>(ptr);
    ptr += WARPS_PER_BLOCK * k * sizeof(float);

    int *merge_indices = reinterpret_cast<int*>(ptr);
    ptr += WARPS_PER_BLOCK * 2 * k * sizeof(int);

    float *merge_dists = reinterpret_cast<float*>(ptr);
    // ptr += WARPS_PER_BLOCK * 2 * k * sizeof(float); // not needed further

    const int tid   = threadIdx.x;
    const int lane  = tid & (WARP_SIZE - 1);
    const int warp  = tid / WARP_SIZE; // warp index within block

    const int global_warp = blockIdx.x * WARPS_PER_BLOCK + warp;
    const bool active     = (global_warp < query_count);
    const unsigned FULL_MASK = 0xFFFFFFFFu;

    // Per-warp views into shared arrays.
    int   *warp_cand_count  = &candidate_counts[warp];
    int   *warp_best_indices = best_indices   + warp * k;
    float *warp_best_dists   = best_dists     + warp * k;
    int   *warp_cand_indices = cand_indices   + warp * k;
    float *warp_cand_dists   = cand_dists     + warp * k;
    int   *warp_merge_indices = merge_indices + warp * 2 * k;
    float *warp_merge_dists   = merge_dists   + warp * 2 * k;

    // Initialize per-warp intermediate result and candidate count.
    if (active) {
        // Initialize best distances to +inf and indices to -1.
        for (int i = lane; i < k; i += WARP_SIZE) {
            warp_best_dists[i]   = FLT_MAX;
            warp_best_indices[i] = -1;
        }
        if (lane == 0) {
            *warp_cand_count = 0;
        }
    }

    // Ensure all shared memory initialization is visible before using sh_data.
    __syncthreads();

    // Load query point for this warp.
    float2 q;
    if (active) {
        q = query[global_warp];
    }

    // Iterate over data in tiles.
    for (int data_start = 0; data_start < data_count; data_start += TILE_POINTS) {
        int remaining = data_count - data_start;
        int tile_size = remaining < TILE_POINTS ? remaining : TILE_POINTS;

        // Load tile into shared memory cooperatively by the whole block.
        for (int idx = tid; idx < tile_size; idx += blockDim.x) {
            sh_data[idx] = data[data_start + idx];
        }

        __syncthreads();

        if (active) {
            // Each warp processes the tile in groups of 32 points (one per lane).
            for (int base = 0; base < tile_size; base += WARP_SIZE) {
                int idx_in_tile = base + lane;
                bool in_range   = (idx_in_tile < tile_size);

                float dist      = 0.0f;
                int data_index  = -1;

                if (in_range) {
                    float2 p = sh_data[idx_in_tile];
                    float dx = p.x - q.x;
                    float dy = p.y - q.y;
                    dist = dx * dx + dy * dy;
                    data_index = data_start + idx_in_tile;
                }

                // max_distance: distance of current k-th nearest neighbor
                // (k-th = worst in sorted top-k array).
                float max_distance = warp_best_dists[k - 1];

                // Determine which lanes have candidates closer than max_distance.
                unsigned int candidate_mask =
                    __ballot_sync(FULL_MASK, in_range && dist < max_distance);
                int num_new = __popc(candidate_mask);

                if (num_new > 0) {
                    // Ensure that adding num_new candidates does not overflow
                    // the candidate buffer. If it would, flush and merge first.
                    while (true) {
                        int cur_count = 0;
                        if (lane == 0) {
                            cur_count = *warp_cand_count;
                        }
                        cur_count = __shfl_sync(FULL_MASK, cur_count, 0);

                        if (cur_count + num_new <= k) {
                            // Enough space for all new candidates.
                            break;
                        }

                        // Candidate buffer full: merge it with the intermediate result.
                        warp_merge_topk(
                            lane,
                            k,
                            warp_cand_count,
                            warp_best_indices,
                            warp_best_dists,
                            warp_cand_indices,
                            warp_cand_dists,
                            warp_merge_indices,
                            warp_merge_dists
                        );

                        // Update max_distance and recompute candidate mask with
                        // the new threshold, since it may have decreased.
                        max_distance = warp_best_dists[k - 1];
                        candidate_mask =
                            __ballot_sync(FULL_MASK, in_range && dist < max_distance);
                        num_new = __popc(candidate_mask);

                        if (num_new == 0) {
                            break;
                        }
                    }

                    if (num_new > 0) {
                        // Reserve a contiguous block in the candidate buffer using atomicAdd.
                        int base_pos = 0;
                        if (lane == 0) {
                            base_pos = atomicAdd(warp_cand_count, num_new);
                        }
                        base_pos = __shfl_sync(FULL_MASK, base_pos, 0);

                        // Compute per-lane offset among the new candidates.
                        unsigned int mask_before =
                            candidate_mask & ((1u << lane) - 1u);
                        int rank = __popc(mask_before);

                        if (in_range && dist < max_distance) {
                            int pos = base_pos + rank;
                            warp_cand_indices[pos] = data_index;
                            warp_cand_dists[pos]   = dist;
                        }
                    }
                }
            }
        }

        __syncthreads();
    }

    if (active) {
        // Final merge for any remaining candidates in the buffer.
        int cand_count = 0;
        if (lane == 0) {
            cand_count = *warp_cand_count;
        }
        cand_count = __shfl_sync(FULL_MASK, cand_count, 0);

        if (cand_count > 0) {
            warp_merge_topk(
                lane,
                k,
                warp_cand_count,
                warp_best_indices,
                warp_best_dists,
                warp_cand_indices,
                warp_cand_dists,
                warp_merge_indices,
                warp_merge_dists
            );
        }

        // After all merges, warp_best_dists/indices contain the final k-NN
        // for this query in ascending order of distance.
        for (int i = lane; i < k; i += WARP_SIZE) {
            int   idx  = warp_best_indices[i];
            float dist = warp_best_dists[i];

            Pair &out = result[global_warp * k + i];
            out.first  = idx;
            out.second = dist;
        }
    }
}

// Host interface as requested.
void run_knn(
    const float2 *query,   // device pointer
    int query_count,
    const float2 *data,    // device pointer
    int data_count,
    Pair *result,          // device pointer
    int k
) {
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    dim3 block(BLOCK_SIZE);
    dim3 grid((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    // Compute required dynamic shared memory size.
    size_t shmem_size = 0;

    shmem_size += TILE_POINTS * sizeof(float2);

    // Align to 16 bytes.
    const size_t align = 16;
    shmem_size = (shmem_size + align - 1) / align * align;

    shmem_size += WARPS_PER_BLOCK * sizeof(int);            // candidate_counts
    shmem_size += WARPS_PER_BLOCK * k * sizeof(int);        // best_indices
    shmem_size += WARPS_PER_BLOCK * k * sizeof(float);      // best_dists
    shmem_size += WARPS_PER_BLOCK * k * sizeof(int);        // cand_indices
    shmem_size += WARPS_PER_BLOCK * k * sizeof(float);      // cand_dists
    shmem_size += WARPS_PER_BLOCK * 2 * k * sizeof(int);    // merge_indices
    shmem_size += WARPS_PER_BLOCK * 2 * k * sizeof(float);  // merge_dists

    // Ensure the kernel can use the requested dynamic shared memory size
    // on modern GPUs (A100/H100 support up to 164 KB per block).
    cudaFuncSetAttribute(
        knn_kernel,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        (int)shmem_size
    );

    knn_kernel<<<grid, block, shmem_size>>>(
        query,
        query_count,
        data,
        data_count,
        result,
        k
    );

    cudaDeviceSynchronize();
}

