#include <cuda_runtime.h>
#include <float.h>
#include <utility>

// Constants for kernel configuration.
// One warp (32 threads) processes one query.
constexpr int WARP_SIZE          = 32;
constexpr int WARPS_PER_BLOCK    = 4;      // 4 warps per block -> 128 threads per block
constexpr int THREADS_PER_BLOCK  = WARP_SIZE * WARPS_PER_BLOCK;
constexpr int TILE_SIZE          = 1024;   // Number of data points cached per block in shared memory

using PairIF = std::pair<int, float>;

// ---------------------------------------------------------------------------
// Bitonic sort on (distance, index) pairs, in-place, serial on a single thread.
// Input size n must be a power of two (k is guaranteed to be).
// ---------------------------------------------------------------------------
__device__ __forceinline__
void bitonic_sort_pairs(float *dist, int *idx, int n)
{
    for (int k = 2; k <= n; k <<= 1)
    {
        for (int j = k >> 1; j > 0; j >>= 1)
        {
            for (int i = 0; i < n; ++i)
            {
                int l = i ^ j;
                if (l > i)
                {
                    bool ascending = ((i & k) == 0);
                    float di = dist[i];
                    float dl = dist[l];
                    bool do_swap = (ascending && di > dl) || (!ascending && di < dl);
                    if (do_swap)
                    {
                        dist[i] = dl;
                        dist[l] = di;
                        int ti = idx[i];
                        idx[i] = idx[l];
                        idx[l] = ti;
                    }
                }
            }
        }
    }
}

// ---------------------------------------------------------------------------
// Flush one warp's candidate buffer into its intermediate top-k result.
// This implements the specified three-step procedure:
//
// 0. Invariant: intermediate result is sorted ascending.
// 1. Sort the buffer (size k) using Bitonic Sort (ascending).
// 2. Merge buffer and intermediate into a bitonic sequence of size k by
//    taking, for each position i, the minimum of buffer[i] and
//    intermediate[k - i - 1].
// 3. Sort the merged result (size k) using Bitonic Sort (ascending) to
//    obtain the updated intermediate result.
//
// The candidate buffer is stored in `candDist` / `candIdx` and is
// overwritten with the merged, sorted result.
// The intermediate result is stored in `intermDist` / `intermIdx` and is
// updated in-place at the end.
// The per-warp candidate count is reset to 0, and maxDist[warp] is set to
// the distance of the k-th nearest neighbor.
// ---------------------------------------------------------------------------
__device__ __forceinline__
void flush_candidates_for_warp(
    int warpId,
    int k,
    float *candDistBase,
    int   *candIdxBase,
    float *intermDistBase,
    int   *intermIdxBase,
    int   *candCountArr,
    float *maxDistArr)
{
    int count = candCountArr[warpId];
    if (count == 0)
        return; // Nothing to flush.

    float *candDist   = candDistBase   + warpId * k;
    int   *candIdx    = candIdxBase    + warpId * k;
    float *intermDist = intermDistBase + warpId * k;
    int   *intermIdx  = intermIdxBase  + warpId * k;

    // Pad the buffer with "infinite" distances so its length is k.
    for (int i = count; i < k; ++i)
    {
        candDist[i] = FLT_MAX;
        candIdx[i]  = -1;
    }

    // Step 1: sort the buffer.
    bitonic_sort_pairs(candDist, candIdx, k);

    // Step 2: merge buffer and intermediate into a bitonic sequence.
    // The merged result is written back into the candidate arrays.
    for (int i = 0; i < k; ++i)
    {
        float dBuf = candDist[i];
        int   iBuf = candIdx[i];

        float dInt = intermDist[k - 1 - i];
        int   iInt = intermIdx[k - 1 - i];

        if (dBuf <= dInt)
        {
            candDist[i] = dBuf;
            candIdx[i]  = iBuf;
        }
        else
        {
            candDist[i] = dInt;
            candIdx[i]  = iInt;
        }
    }

    // Step 3: sort merged result (now in candDist/candIdx) and store into intermediate.
    bitonic_sort_pairs(candDist, candIdx, k);

    for (int i = 0; i < k; ++i)
    {
        intermDist[i] = candDist[i];
        intermIdx[i]  = candIdx[i];
    }

    // Update maxDist and reset candidate count.
    candCountArr[warpId] = 0;
    maxDistArr[warpId]   = intermDist[k - 1];
}

// ---------------------------------------------------------------------------
// CUDA kernel implementing k-NN with one warp per query.
// Each block caches TILE_SIZE data points into shared memory, and each warp
// in that block processes a different query point. For each query, a
// per-warp candidate buffer of size k is maintained in shared memory.
// ---------------------------------------------------------------------------
__global__
void knn_kernel(
    const float2 * __restrict__ query,
    int                    query_count,
    const float2 * __restrict__ data,
    int                    data_count,
    PairIF                * __restrict__ result,
    int                    k)
{
    extern __shared__ unsigned char shared_raw[];

    // Shared memory layout:
    // [0]                          : float2 dataTile[TILE_SIZE]
    // [1]                          : int   candIdx[WARPS_PER_BLOCK * k]
    // [2]                          : float candDist[WARPS_PER_BLOCK * k]
    // [3]                          : int   intermIdx[WARPS_PER_BLOCK * k]
    // [4]                          : float intermDist[WARPS_PER_BLOCK * k]
    // [5]                          : int   candCount[WARPS_PER_BLOCK]
    // [6]                          : float maxDist[WARPS_PER_BLOCK]

    size_t offset = 0;

    float2 *dataTile = reinterpret_cast<float2 *>(shared_raw + offset);
    offset += TILE_SIZE * sizeof(float2);

    int *candIdxBase = reinterpret_cast<int *>(shared_raw + offset);
    offset += WARPS_PER_BLOCK * static_cast<size_t>(k) * sizeof(int);

    float *candDistBase = reinterpret_cast<float *>(shared_raw + offset);
    offset += WARPS_PER_BLOCK * static_cast<size_t>(k) * sizeof(float);

    int *intermIdxBase = reinterpret_cast<int *>(shared_raw + offset);
    offset += WARPS_PER_BLOCK * static_cast<size_t>(k) * sizeof(int);

    float *intermDistBase = reinterpret_cast<float *>(shared_raw + offset);
    offset += WARPS_PER_BLOCK * static_cast<size_t>(k) * sizeof(float);

    int *candCountArr = reinterpret_cast<int *>(shared_raw + offset);
    offset += WARPS_PER_BLOCK * sizeof(int);

    float *maxDistArr = reinterpret_cast<float *>(shared_raw + offset);
    // offset += WARPS_PER_BLOCK * sizeof(float); // No further use of offset.

    const int threadId = threadIdx.x;
    const int warpId   = threadId / WARP_SIZE;
    const int laneId   = threadId % WARP_SIZE;

    const int globalWarpId = blockIdx.x * WARPS_PER_BLOCK + warpId;
    const int queryId      = globalWarpId;

    const bool hasQuery = (queryId < query_count);

    // Load query point for this warp and broadcast within warp.
    float qx = 0.0f;
    float qy = 0.0f;
    if (hasQuery && laneId == 0)
    {
        float2 q = query[queryId];
        qx = q.x;
        qy = q.y;
    }
    qx = __shfl_sync(0xFFFFFFFFu, qx, 0);
    qy = __shfl_sync(0xFFFFFFFFu, qy, 0);

    // Initialize per-warp intermediate result and candidate state.
    if (hasQuery && laneId == 0)
    {
        candCountArr[warpId] = 0;
        maxDistArr[warpId]   = FLT_MAX;

        float *intermDist = intermDistBase + warpId * k;
        int   *intermIdx  = intermIdxBase  + warpId * k;

        // Intermediate result starts as "all infinities" (no neighbors yet).
        for (int i = 0; i < k; ++i)
        {
            intermDist[i] = FLT_MAX;
            intermIdx[i]  = -1;
        }
    }

    __syncthreads();

    // Sweep over data points in tiles.
    for (int dataStart = 0; dataStart < data_count; dataStart += TILE_SIZE)
    {
        const int tileSize = min(TILE_SIZE, data_count - dataStart);

        // Load tile into shared memory cooperatively by all threads in block.
        for (int i = threadId; i < tileSize; i += blockDim.x)
        {
            dataTile[i] = data[dataStart + i];
        }

        __syncthreads();

        // Process the tile: each warp handles its query.
        if (hasQuery)
        {
            float *candDistWarp = candDistBase + warpId * k;
            int   *candIdxWarp  = candIdxBase  + warpId * k;

            // Each iteration processes up to WARP_SIZE points from the tile.
            for (int jBase = 0; jBase < tileSize; jBase += WARP_SIZE)
            {
                int j = jBase + laneId;
                bool hasPoint = (j < tileSize);

                float dist       = 0.0f;
                bool isCandidate = false;

                if (hasPoint)
                {
                    float2 p = dataTile[j];
                    float dx = p.x - qx;
                    float dy = p.y - qy;
                    dist = dx * dx + dy * dy;

                    float curMax = maxDistArr[warpId];
                    isCandidate  = (dist < curMax);
                }

                unsigned int mask = __ballot_sync(0xFFFFFFFFu, isCandidate);
                int numCandidates  = __popc(mask);

                if (numCandidates > 0)
                {
                    bool needFlush = false;

                    // Check if buffer has enough room for these candidates; if not, flush first.
                    if (laneId == 0)
                    {
                        int curCount = candCountArr[warpId];
                        if (curCount + numCandidates > k)
                        {
                            flush_candidates_for_warp(
                                warpId,
                                k,
                                candDistBase,
                                candIdxBase,
                                intermDistBase,
                                intermIdxBase,
                                candCountArr,
                                maxDistArr);

                            needFlush = true;
                        }
                    }

                    needFlush = __shfl_sync(0xFFFFFFFFu, needFlush, 0);

                    if (needFlush)
                    {
                        // After flushing, maxDist may have decreased, so re-evaluate candidates.
                        if (hasPoint)
                        {
                            float curMax2 = maxDistArr[warpId];
                            isCandidate   = (dist < curMax2);
                        }
                        else
                        {
                            isCandidate = false;
                        }

                        mask          = __ballot_sync(0xFFFFFFFFu, isCandidate);
                        numCandidates = __popc(mask);

                        if (numCandidates == 0)
                        {
                            // No candidates remain for this wave after threshold tightening.
                            continue;
                        }
                    }

                    // Insert candidates: lane 0 reserves a block of positions with atomicAdd.
                    int base = 0;
                    if (laneId == 0)
                    {
                        base = atomicAdd(&candCountArr[warpId], numCandidates);
                    }
                    base = __shfl_sync(0xFFFFFFFFu, base, 0);

                    if (isCandidate)
                    {
                        // Compute per-lane offset within this wave using prefix of the mask bits.
                        unsigned int laneMask = mask & ((1u << laneId) - 1u);
                        int offset            = __popc(laneMask);
                        int pos               = base + offset;

                        candDistWarp[pos] = dist;
                        candIdxWarp[pos]  = dataStart + j;
                    }
                }
            }
        }

        __syncthreads();
    }

    // After processing all tiles, flush remaining candidates and write results.
    if (hasQuery && laneId == 0)
    {
        if (candCountArr[warpId] > 0)
        {
            flush_candidates_for_warp(
                warpId,
                k,
                candDistBase,
                candIdxBase,
                intermDistBase,
                intermIdxBase,
                candCountArr,
                maxDistArr);
        }

        float *intermDist = intermDistBase + warpId * k;
        int   *intermIdx  = intermIdxBase  + warpId * k;

        // Write final k nearest neighbors for this query, sorted ascending by distance.
        for (int i = 0; i < k; ++i)
        {
            int outPos = queryId * k + i;
            result[outPos].first  = intermIdx[i];
            result[outPos].second = intermDist[i];
        }
    }
}

// ---------------------------------------------------------------------------
// Host interface: launches the CUDA kernel.
// Assumes `query`, `data`, and `result` are device pointers allocated by
// cudaMalloc, and that data_count >= k, with k being a power of two between
// 32 and 1024 (inclusive).
// ---------------------------------------------------------------------------
void run_knn(
    const float2 *query,
    int           query_count,
    const float2 *data,
    int           data_count,
    PairIF       *result,
    int           k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0)
        return;

    // Grid configuration: one warp per query.
    int numWarps   = (query_count + 0) / 1; // one query per warp
    int numBlocks  = (numWarps + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    dim3 blockDim(THREADS_PER_BLOCK, 1, 1);
    dim3 gridDim(numBlocks, 1, 1);

    // Compute dynamic shared memory size.
    size_t shared_bytes = 0;
    shared_bytes += TILE_SIZE * sizeof(float2);                    // dataTile
    shared_bytes += WARPS_PER_BLOCK * static_cast<size_t>(k) * sizeof(int);   // candIdx
    shared_bytes += WARPS_PER_BLOCK * static_cast<size_t>(k) * sizeof(float); // candDist
    shared_bytes += WARPS_PER_BLOCK * static_cast<size_t>(k) * sizeof(int);   // intermIdx
    shared_bytes += WARPS_PER_BLOCK * static_cast<size_t>(k) * sizeof(float); // intermDist
    shared_bytes += WARPS_PER_BLOCK * sizeof(int);                            // candCount
    shared_bytes += WARPS_PER_BLOCK * sizeof(float);                          // maxDist

    // Allow kernel to use the requested dynamic shared memory size (for GPUs that require opt-in).
    cudaFuncSetAttribute(
        knn_kernel,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(shared_bytes));

    knn_kernel<<<gridDim, blockDim, shared_bytes>>>(
        query,
        query_count,
        data,
        data_count,
        result,
        k);

    // Caller can synchronize or check errors as needed.
}

#include <cuda_runtime.h>
#include <utility>
#include <cfloat>

// -----------------------------------------------------------------------------
// Optimized CUDA k-NN (2D, squared Euclidean) implementation.
//
// Key design points:
//   * One warp (32 threads) computes k-NN for a single query point.
//   * Block size: 8 warps (256 threads).
//   * All data points are processed in tiles cached in shared memory.
//   * For each query/warp we maintain:
//       - A sorted "intermediate" result of size k in shared memory.
//       - A candidate buffer of size k in shared memory.
//       - A shared candidate counter updated with atomicAdd.
//       - A max_distance (distance of k-th neighbor) used for filtering.
//   * When candidate buffer is full (or at the end), we:
//       0. (Invariant) Intermediate array is sorted ascending.
//       1. Sort the candidate buffer with a bitonic sort (ascending).
//       2. Merge candidate and intermediate into a bitonic array by
//          taking min(intermediate[i], candidate[k-1-i]) element-wise.
//       3. Bitonic-sort the merged array to restore sorted intermediate.
//   * Bitonic sort and merge per query are done within a warp,
//     using shared memory and warp-synchronous programming.
// -----------------------------------------------------------------------------

// Tunable constants.
constexpr int WARP_SIZE         = 32;
constexpr int WARPS_PER_BLOCK   = 8;
constexpr int THREADS_PER_BLOCK = WARP_SIZE * WARPS_PER_BLOCK;
constexpr int MAX_K             = 1024;   // per problem statement
constexpr int DATA_TILE_SIZE    = 1024;   // number of data points cached per block in shared memory

// Struct for internal neighbor representation (distance + index).
struct Neighbor {
    float dist;
    int   idx;
};

// Shared memory:
//   * dataTile: cached data points for the block
//   * inter[warp][k]: per-warp (per-query) intermediate result (sorted)
//   * cand[warp][k]:  per-warp (per-query) candidate buffer
//   * candCount[warp]: number of used entries in cand[warp]
__shared__ float2   s_dataTile[DATA_TILE_SIZE];
__shared__ Neighbor s_intermediate[WARPS_PER_BLOCK][MAX_K];
__shared__ Neighbor s_candidates [WARPS_PER_BLOCK][MAX_K];
__shared__ int      s_candidateCount[WARPS_PER_BLOCK];

// -----------------------------------------------------------------------------
// Warp-level bitonic sort for Neighbor arrays, ascending by dist.
// n must be a power of two and <= MAX_K.
//
// Parallelization:
//   * Each thread in the warp processes indices i = laneId, i += WARP_SIZE.
//   * __syncwarp is used to synchronize threads between compare-exchange steps.
// -----------------------------------------------------------------------------
__device__ __forceinline__
void bitonicSortWarp(Neighbor *arr, int n, unsigned laneId)
{
    // Standard bitonic sort network translated to CUDA and parallelized over a warp.
    for (int k = 2; k <= n; k <<= 1) {
        for (int j = k >> 1; j > 0; j >>= 1) {
            for (int i = laneId; i < n; i += WARP_SIZE) {
                int ixj = i ^ j;
                if (ixj > i) {
                    bool ascending = ((i & k) == 0);
                    Neighbor a = arr[i];
                    Neighbor b = arr[ixj];
                    bool shouldSwap = (ascending ? (a.dist > b.dist) : (a.dist < b.dist));
                    if (shouldSwap) {
                        arr[i]  = b;
                        arr[ixj] = a;
                    }
                }
            }
            __syncwarp();
        }
    }
}

// -----------------------------------------------------------------------------
// Flush candidate buffer into intermediate result for a single warp/query.
//
// Steps:
//   0. (Assumption) s_intermediate[warp] is sorted ascending (invariant).
//   1. Pad candidate buffer [candCount..k-1] with (INF, -1) if not full.
//   2. Bitonic sort candidate buffer ascending.
//   3. Merge candidate and intermediate:
//        merged[i] = min( intermediate[i], candidates[k-1-i] )
//      producing a bitonic sequence stored back into intermediate.
//   4. Bitonic sort intermediate to restore ascending order.
//
// Parameters:
//   inter     - pointer to this warp's intermediate array (size MAX_K)
//   cand      - pointer to this warp's candidate array (size MAX_K)
//   k         - actual k (<= MAX_K, power of two)
//   candCount - number of valid candidates currently stored (<= k)
//   laneId    - lane index within warp
// -----------------------------------------------------------------------------
__device__ __forceinline__
void flushCandidateBuffer(Neighbor *inter, Neighbor *cand,
                          int k, int candCount, unsigned laneId)
{
    // 1. Pad candidate buffer with "infinite" distances if not full.
    for (int i = laneId + candCount; i < k; i += WARP_SIZE) {
        cand[i].dist = FLT_MAX;
        cand[i].idx  = -1;
    }
    __syncwarp();

    // 2. Sort candidate buffer ascending by distance.
    bitonicSortWarp(cand, k, laneId);
    __syncwarp();

    // 3. Merge candidate and intermediate into a bitonic sequence in 'inter'.
    //    merged[i] = min( inter[i], cand[k-1-i] )
    for (int i = laneId; i < k; i += WARP_SIZE) {
        Neighbor a = inter[i];
        Neighbor b = cand[k - 1 - i];
        inter[i] = (a.dist <= b.dist) ? a : b;
    }
    __syncwarp();

    // 4. Sort merged result (in inter) in ascending order.
    bitonicSortWarp(inter, k, laneId);
    __syncwarp();
}

// -----------------------------------------------------------------------------
// Core k-NN kernel.
//
// Each warp handles a single query point:
//   - Loads query point into registers.
//   - Iterates over data points in tiles cached in shared memory.
//   - For each tile, each thread computes distances for multiple data points,
//     applying a warp-cooperative insertion into the candidate buffer.
//   - When candidate buffer is full, flushCandidateBuffer is called.
//   - After processing all tiles, if candidate buffer is non-empty, it is
//     flushed one last time.
//   - Final intermediate result is written to the global 'result' array.
// -----------------------------------------------------------------------------
__global__
void knn_kernel(const float2 * __restrict__ query,
                int query_count,
                const float2 * __restrict__ data,
                int data_count,
                std::pair<int, float> * __restrict__ result,
                int k)
{
    const unsigned laneId       = threadIdx.x & (WARP_SIZE - 1);
    const unsigned warpIdInBlock = threadIdx.x / WARP_SIZE;
    const unsigned globalWarpId  = blockIdx.x * WARPS_PER_BLOCK + warpIdInBlock;

    if (globalWarpId >= static_cast<unsigned>(query_count)) {
        return;
    }

    Neighbor *inter = s_intermediate[warpIdInBlock];
    Neighbor *cand  = s_candidates[warpIdInBlock];
    int      &candCount = s_candidateCount[warpIdInBlock];

    // Initialize intermediate result for this query:
    //   distances = INF, indices = -1; sorted ascending by construction.
    for (int i = laneId; i < k; i += WARP_SIZE) {
        inter[i].dist = FLT_MAX;
        inter[i].idx  = -1;
    }
    if (laneId == 0) {
        candCount = 0;
    }
    __syncwarp();

    // Initial max_distance (distance of k-th nearest neighbor in intermediate).
    // Since all are INF, initial max_distance is INF.
    float maxDist = FLT_MAX;

    // Load query point for this warp into registers.
    float2 q = query[globalWarpId];

    // Process data points in tiles.
    for (int tileStart = 0; tileStart < data_count; tileStart += DATA_TILE_SIZE) {
        int tileCount = data_count - tileStart;
        if (tileCount > DATA_TILE_SIZE) {
            tileCount = DATA_TILE_SIZE;
        }

        // Load current tile of data points into shared memory.
        // All threads in block cooperate.
        for (int i = threadIdx.x; i < tileCount; i += blockDim.x) {
            s_dataTile[i] = data[tileStart + i];
        }
        __syncthreads();

        // Each warp processes all data points in this tile.
        // We iterate over tile in chunks of WARP_SIZE so that each thread
        // handles a unique data point in each iteration.
        const unsigned FULL_MASK = 0xFFFFFFFFu;

        for (int base = 0; base < tileCount; base += WARP_SIZE) {
            int idxInTile = base + laneId;
            bool valid    = (idxInTile < tileCount);

            float dist  = 0.0f;
            int   index = tileStart + idxInTile;

            if (valid) {
                float2 p = s_dataTile[idxInTile];
                float dx = p.x - q.x;
                float dy = p.y - q.y;
                // Squared Euclidean distance.
                dist = dx * dx + dy * dy;
            }

            // Candidate if valid and closer than current maxDist.
            bool isCandidate = valid && (dist < maxDist);
            bool pending     = isCandidate;

            // Warp-cooperative insertion into candidate buffer, with capacity k.
            while (true) {
                unsigned mask = __ballot_sync(FULL_MASK, pending);
                if (mask == 0) {
                    break; // no pending candidates left in this warp for this group
                }

                int pendingCount = __popc(mask);

                // Load current candidate count from shared memory and broadcast.
                int candCountCur = 0;
                if (laneId == 0) {
                    candCountCur = candCount;
                }
                candCountCur = __shfl_sync(FULL_MASK, candCountCur, 0);
                int avail = k - candCountCur;

                if (avail == 0) {
                    // Candidate buffer full: flush into intermediate.
                    flushCandidateBuffer(inter, cand, k, candCountCur, laneId);

                    // Reset candidate count and update maxDist = k-th neighbor distance.
                    if (laneId == 0) {
                        candCount = 0;
                    }
                    float newMaxDist = 0.0f;
                    if (laneId == 0) {
                        newMaxDist = inter[k - 1].dist;
                    }
                    newMaxDist = __shfl_sync(FULL_MASK, newMaxDist, 0);
                    maxDist = newMaxDist;

                    // Try again with same pending candidates and new buffer state.
                    continue;
                }

                int numInsert = (pendingCount < avail) ? pendingCount : avail;

                int basePos = 0;
                if (laneId == 0) {
                    // Use atomicAdd (as required) to reserve positions in candidate buffer.
                    basePos = atomicAdd(&candCount, numInsert);
                }
                basePos  = __shfl_sync(FULL_MASK, basePos, 0);
                numInsert = __shfl_sync(FULL_MASK, numInsert, 0);

                // Rank of this lane within the pending mask.
                int rank = __popc(mask & ((1u << laneId) - 1u));

                bool willInsert = pending && (rank < numInsert);
                if (willInsert) {
                    cand[basePos + rank].dist = dist;
                    cand[basePos + rank].idx  = index;
                    pending = false;
                }

                // If we filled the buffer exactly, flush it immediately.
                if (numInsert == avail) {
                    // After insertion, candCountCur + numInsert == k.
                    flushCandidateBuffer(inter, cand, k, candCountCur + numInsert, laneId);

                    if (laneId == 0) {
                        candCount = 0;
                    }
                    float newMaxDist = 0.0f;
                    if (laneId == 0) {
                        newMaxDist = inter[k - 1].dist;
                    }
                    newMaxDist = __shfl_sync(FULL_MASK, newMaxDist, 0);
                    maxDist = newMaxDist;
                }
                // Loop continues if any lanes still have pending candidates.
            }
        }

        __syncthreads(); // ensure all warps done before loading next tile
    }

    // After last tile: if candidate buffer is not empty, flush it.
    int finalCandCount = 0;
    if (laneId == 0) {
        finalCandCount = candCount;
    }
    finalCandCount = __shfl_sync(0xFFFFFFFFu, finalCandCount, 0);

    if (finalCandCount > 0) {
        flushCandidateBuffer(inter, cand, k, finalCandCount, laneId);
        if (laneId == 0) {
            candCount = 0;
        }
    }
    __syncwarp();

    // Write final k nearest neighbors for this query to global memory.
    // inter[0..k-1] is sorted ascending by distance.
    for (int i = laneId; i < k; i += WARP_SIZE) {
        int outIdx = globalWarpId * k + i;
        result[outIdx].first  = inter[i].idx;
        result[outIdx].second = inter[i].dist;
    }
}

// -----------------------------------------------------------------------------
// Host interface as requested.
//
// query       - device pointer to query points (float2), size query_count
// query_count - number of query points
// data        - device pointer to data points (float2), size data_count
// data_count  - number of data points
// result      - device pointer to output array of size query_count * k
// k           - number of nearest neighbors (power of two, 32..1024)
// -----------------------------------------------------------------------------
void run_knn(const float2 *query, int query_count,
             const float2 *data,  int data_count,
             std::pair<int, float> *result, int k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0 || k > MAX_K) {
        return;
    }

    dim3 blockDim(THREADS_PER_BLOCK);
    int warpsPerBlock = WARPS_PER_BLOCK;
    int numBlocks = (query_count + warpsPerBlock - 1) / warpsPerBlock;
    dim3 gridDim(numBlocks);

    knn_kernel<<<gridDim, blockDim>>>(query, query_count, data, data_count, result, k);

    // In production code, it is good practice to check for errors, e.g.:
    // cudaDeviceSynchronize();
    // cudaGetLastError();
}

