#include <cuda_runtime.h>
#include <cfloat>
#include <utility>

constexpr int WARP_SIZE         = 32;
constexpr int WARPS_PER_BLOCK   = 4;    // 4 warps per block => 128 threads
constexpr int THREADS_PER_BLOCK = WARP_SIZE * WARPS_PER_BLOCK;
constexpr int MAX_K             = 1024; // maximum supported k
constexpr int BATCH_SIZE        = 2048; // number of data points cached per block in shared memory

// Simple POD pair type with the same layout as std::pair<int, float>
struct PairIntFloat {
    int   first;
    float second;
};

static_assert(sizeof(PairIntFloat) == sizeof(std::pair<int, float>),
              "PairIntFloat must match std::pair<int,float> layout");

// Bitonic sort of an array of length n (power of two, 32 <= n <= MAX_K).
// The array is stored in shared memory and cooperatively sorted by a single warp.
static __device__ __forceinline__
void bitonic_sort_shared(float *dist, int *idx, int n)
{
    const unsigned mask = 0xFFFFFFFFu;
    const int lane = threadIdx.x & (WARP_SIZE - 1);

    for (int size = 2; size <= n; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            for (int i = lane; i < n; i += WARP_SIZE) {
                int l = i ^ stride;
                if (l > i && l < n) {
                    bool ascending = ((i & size) == 0);
                    float di = dist[i];
                    float dl = dist[l];
                    int   ii = idx[i];
                    int   il = idx[l];
                    bool doSwap = (ascending && di > dl) || (!ascending && di < dl);
                    if (doSwap) {
                        dist[i] = dl;
                        dist[l] = di;
                        idx[i]  = il;
                        idx[l]  = ii;
                    }
                }
            }
            __syncwarp(mask);
        }
    }
}

// Merge a full (or partially filled) candidate buffer with the current intermediate
// k-NN result for a query. The intermediate result is kept sorted in ascending order.
// The candidate buffer is sorted, merged, and the merged result is sorted again using
// bitonic sort. The candidate buffer is then reset to empty.
// Returns the updated maxDist (distance of the k-th nearest neighbor).
static __device__ __forceinline__
float merge_buffer_with_intermediate(float *interDist, int *interIdx,
                                     float *bufDist,   int *bufIdx,
                                     int k,
                                     int *bufCount,
                                     float currentMaxDist)
{
    const unsigned mask = 0xFFFFFFFFu;
    const int lane = threadIdx.x & (WARP_SIZE - 1);

    // 1. Sort the candidate buffer (size k) in ascending order
    bitonic_sort_shared(bufDist, bufIdx, k);
    __syncwarp(mask);

    // 2. Merge buffer and intermediate result into a bitonic sequence
    // merged[i] = min(inter[i], buf[k-1-i])
    for (int i = lane; i < k; i += WARP_SIZE) {
        int j = k - 1 - i;
        float di = interDist[i];
        float db = bufDist[j];
        if (db < di) {
            interDist[i] = db;
            interIdx[i]  = bufIdx[j];
        }
    }
    __syncwarp(mask);

    // 3. Sort the merged sequence (stored in interDist/interIdx) in ascending order
    bitonic_sort_shared(interDist, interIdx, k);
    __syncwarp(mask);

    // Update maxDist to distance of k-th nearest neighbor
    float newMaxDist = currentMaxDist;
    if (lane == 0) {
        newMaxDist = interDist[k - 1];
        *bufCount  = 0;
    }
    newMaxDist = __shfl_sync(mask, newMaxDist, 0);

    // Reset candidate buffer contents (optional but keeps invariants simple)
    const float INF = FLT_MAX;
    for (int i = lane; i < k; i += WARP_SIZE) {
        bufDist[i] = INF;
        bufIdx[i]  = -1;
    }
    __syncwarp(mask);

    return newMaxDist;
}

// Each warp processes one query point and finds its k nearest neighbors among all data points.
__global__ void knn_kernel(const float2 * __restrict__ query,
                           int query_count,
                           const float2 * __restrict__ data,
                           int data_count,
                           int k,
                           PairIntFloat * __restrict__ result)
{
    extern __shared__ unsigned char shared_raw[];
    unsigned char *ptr = shared_raw;

    // Shared memory layout:
    // [0] float2 sData[BATCH_SIZE];
    // [1] float interDist[WARPS_PER_BLOCK][MAX_K];
    // [2] int   interIdx [WARPS_PER_BLOCK][MAX_K];
    // [3] float bufDist  [WARPS_PER_BLOCK][MAX_K];
    // [4] int   bufIdx   [WARPS_PER_BLOCK][MAX_K];
    // [5] int   bufCount [WARPS_PER_BLOCK];

    float2 *sData = reinterpret_cast<float2*>(ptr);
    ptr += BATCH_SIZE * sizeof(float2);

    float *interDistAll = reinterpret_cast<float*>(ptr);
    ptr += WARPS_PER_BLOCK * MAX_K * sizeof(float);

    int *interIdxAll = reinterpret_cast<int*>(ptr);
    ptr += WARPS_PER_BLOCK * MAX_K * sizeof(int);

    float *bufDistAll = reinterpret_cast<float*>(ptr);
    ptr += WARPS_PER_BLOCK * MAX_K * sizeof(float);

    int *bufIdxAll = reinterpret_cast<int*>(ptr);
    ptr += WARPS_PER_BLOCK * MAX_K * sizeof(int);

    int *bufCountAll = reinterpret_cast<int*>(ptr);
    // ptr += WARPS_PER_BLOCK * sizeof(int); // no further use

    const int tid    = threadIdx.x;
    const int warpId = tid / WARP_SIZE;
    const int lane   = tid & (WARP_SIZE - 1);
    const int warpsPerBlock = blockDim.x / WARP_SIZE;
    const int globalWarpId  = blockIdx.x * warpsPerBlock + warpId;
    const bool warpActive   = (globalWarpId < query_count);

    // Per-warp views into shared memory
    float *interDist = interDistAll + warpId * MAX_K;
    int   *interIdx  = interIdxAll  + warpId * MAX_K;
    float *bufDist   = bufDistAll   + warpId * MAX_K;
    int   *bufIdx    = bufIdxAll    + warpId * MAX_K;
    int   *bufCount  = bufCountAll  + warpId;

    const unsigned fullMask = 0xFFFFFFFFu;

    // Initialize per-warp intermediate result and candidate buffer
    if (warpActive) {
        const float INF = FLT_MAX;
        for (int i = lane; i < k; i += WARP_SIZE) {
            interDist[i] = INF;
            interIdx[i]  = -1;
            bufDist[i]   = INF;
            bufIdx[i]    = -1;
        }
        if (lane == 0) {
            *bufCount = 0;
        }
    }
    __syncthreads();

    float maxDist = FLT_MAX;

    // Load query point for this warp and broadcast within the warp
    float qx = 0.0f, qy = 0.0f;
    if (warpActive) {
        float2 q;
        if (lane == 0) {
            q = query[globalWarpId];
        }
        qx = __shfl_sync(fullMask, q.x, 0);
        qy = __shfl_sync(fullMask, q.y, 0);
    }

    // Process the data points in batches cached in shared memory
    for (int batchStart = 0; batchStart < data_count; batchStart += BATCH_SIZE) {
        int remainingGlobal = data_count - batchStart;
        int batchSize = remainingGlobal < BATCH_SIZE ? remainingGlobal : BATCH_SIZE;

        // Cooperative load of this batch into shared memory
        for (int i = tid; i < batchSize; i += blockDim.x) {
            sData[i] = data[batchStart + i];
        }
        __syncthreads();

        if (warpActive) {
            int localPos = 0;
            while (localPos < batchSize) {
                // If the candidate buffer is full, merge it with the intermediate result
                int bufCountVal = 0;
                if (lane == 0) {
                    bufCountVal = *bufCount;
                }
                bufCountVal = __shfl_sync(fullMask, bufCountVal, 0);

                if (bufCountVal >= k) {
                    maxDist = merge_buffer_with_intermediate(interDist, interIdx,
                                                             bufDist, bufIdx,
                                                             k, bufCount,
                                                             maxDist);
                    continue;
                }

                int remainingPoints = batchSize - localPos;
                if (remainingPoints <= 0) {
                    break;
                }

                int capacity    = k - bufCountVal;
                int activeLanes = capacity < WARP_SIZE ? capacity : WARP_SIZE;
                if (activeLanes > remainingPoints) {
                    activeLanes = remainingPoints;
                }
                if (activeLanes <= 0) {
                    // No capacity or no points; buffer-full case is handled above
                    break;
                }

                bool laneActive = (lane < activeLanes);
                int idxLocal    = localPos + lane;
                float d         = 0.0f;
                int dataIndex   = -1;
                bool isCandidate = false;

                if (laneActive) {
                    float2 p = sData[idxLocal];
                    float dx = qx - p.x;
                    float dy = qy - p.y;
                    d = dx * dx + dy * dy;
                    dataIndex = batchStart + idxLocal;
                    if (d < maxDist) {
                        isCandidate = true;
                    }
                }

                unsigned int candidateMask = __ballot_sync(fullMask, laneActive && isCandidate);
                int numCandidates = __popc(candidateMask);

                if (numCandidates > 0) {
                    int basePos = 0;
                    if (lane == 0) {
                        basePos = atomicAdd(bufCount, numCandidates);
                    }
                    basePos = __shfl_sync(fullMask, basePos, 0);

                    if (laneActive && isCandidate) {
                        unsigned int maskBefore = candidateMask & ((1u << lane) - 1);
                        int offset = __popc(maskBefore);
                        int pos = basePos + offset;
                        // pos is guaranteed to be < k (numCandidates <= capacity)
                        bufDist[pos] = d;
                        bufIdx[pos]  = dataIndex;
                    }
                }

                localPos += activeLanes;
            } // while localPos
        }

        __syncthreads();
    } // for batchStart

    // After processing all batches, merge any remaining candidates
    if (warpActive) {
        int bufCountVal = 0;
        if (lane == 0) {
            bufCountVal = *bufCount;
        }
        bufCountVal = __shfl_sync(fullMask, bufCountVal, 0);

        if (bufCountVal > 0) {
            maxDist = merge_buffer_with_intermediate(interDist, interIdx,
                                                     bufDist, bufIdx,
                                                     k, bufCount,
                                                     maxDist);
        }

        // Write the final k nearest neighbors for this query
        for (int i = lane; i < k; i += WARP_SIZE) {
            int outIdx = globalWarpId * k + i;
            result[outIdx].first  = interIdx[i];
            result[outIdx].second = interDist[i];
        }
    }
}

// Host interface as specified.
void run_knn(const float2 *query, int query_count,
             const float2 *data,  int data_count,
             std::pair<int, float> *result, int k)
{
    // Basic validation; assumes inputs are otherwise valid as per problem statement.
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }
    if (k > MAX_K) {
        // Clamp to MAX_K for safety; in production code you might handle this differently.
        k = MAX_K;
    }

    dim3 blockDim(THREADS_PER_BLOCK);
    int warpsPerBlock = WARPS_PER_BLOCK;
    int totalWarps    = (query_count + warpsPerBlock - 1) / warpsPerBlock;
    dim3 gridDim(totalWarps);

    // Compute required dynamic shared memory size
    size_t sharedMemBytes = 0;
    sharedMemBytes += BATCH_SIZE * sizeof(float2);              // sData
    sharedMemBytes += WARPS_PER_BLOCK * MAX_K * sizeof(float);  // interDist
    sharedMemBytes += WARPS_PER_BLOCK * MAX_K * sizeof(int);    // interIdx
    sharedMemBytes += WARPS_PER_BLOCK * MAX_K * sizeof(float);  // bufDist
    sharedMemBytes += WARPS_PER_BLOCK * MAX_K * sizeof(int);    // bufIdx
    sharedMemBytes += WARPS_PER_BLOCK * sizeof(int);            // bufCount

    // Ensure enough dynamic shared memory is available (for A100/H100 this is supported)
    cudaFuncSetAttribute(knn_kernel,
                         cudaFuncAttributeMaxDynamicSharedMemorySize,
                         static_cast<int>(sharedMemBytes));

    PairIntFloat *resultRaw = reinterpret_cast<PairIntFloat*>(result);

    knn_kernel<<<gridDim, blockDim, sharedMemBytes>>>(query, query_count,
                                                      data,  data_count,
                                                      k, resultRaw);
    cudaDeviceSynchronize();
}

#include <cuda_runtime.h>
#include <utility>
#include <cfloat>

// ---------------------------------------------------------------------------
// Optimized k-NN kernel for 2D points.
// 
// Design highlights:
//
// * Each query is processed by exactly one warp (32 threads).
// * A thread block contains WARPS_PER_BLOCK warps and processes that many
//   queries concurrently.
// * The data points are processed in tiles and cached in shared memory.
//   All threads in the block cooperatively load each tile.
// * Each warp keeps:
//      - A private "intermediate result" (top-k neighbors) in the global
//        result[] array assigned to that query. This array is always kept
//        sorted in ascending order of distance.
//      - A private candidate buffer of size k in shared memory
//        (distances + indices) plus a shared candidate counter, updated via
//        atomicAdd as specified.
// * For each tile, each warp computes distances from its query to all data
//   points in that tile, filters them by a per-query max_distance (distance
//   of the current k-th neighbor), and inserts qualifying points into the
//   candidate buffer.
// * If the candidate buffer is full and new candidates need to be inserted,
//   the buffer is merged with the intermediate result:
//      0) Invariant: intermediate result is sorted ascending.
//      1) Sort candidate buffer ascending with a serial Bitonic Sort.
//      2) Merge buffer and intermediate result into a bitonic sequence:
//           merged[i] = min( intermediate[i], buffer[k-1-i] ).
//      3) Sort merged sequence ascending via Bitonic Sort, obtaining an
//         updated intermediate result (still of size k).
//   The k-th neighbor distance is then stored into max_distance.
// * Warp-level cooperation:
//      - Warp shuffles (__shfl_sync) are used to broadcast scalars (e.g. the
//        query coordinates, candidate buffer base index, candidate_count,
//        max_distance) from lane 0 to the rest of the warp.
//      - Warp barriers (__syncwarp) are used inside the per-warp merge
//        routine to guarantee consistent views of shared state.
// * Candidate insertion uses a warp-wide ballot/prefix scheme so that only
//   one atomicAdd per warp is required per "insertion round", yet every lane
//   capable of inserting a candidate gets its own slot in the shared buffer.
// * The Bitonic Sort used here is a straightforward serial reference
//   implementation, as allowed by the problem statement. It runs in O(k log^2 k)
//   time and is executed only by lane 0 of each warp, which is acceptable
//   because k <= 1024 and merges are relatively infrequent.
//
// Assumptions:
// * data_count >= k.
// * k is a power of two in [32, 1024].
// * query, data, and result are all device pointers allocated with cudaMalloc.
// * Typical usage has many queries and millions of data points.
// ---------------------------------------------------------------------------

constexpr int WARP_SIZE        = 32;
constexpr int MAX_K            = 1024;   // maximum allowed k
constexpr int WARPS_PER_BLOCK  = 8;      // one query per warp
constexpr int THREADS_PER_BLOCK = WARP_SIZE * WARPS_PER_BLOCK;
constexpr int TILE_SIZE        = THREADS_PER_BLOCK; // number of data points per tile

using Pair = std::pair<int, float>;

// ---------------------------------------------------------------------------
// Serial Bitonic Sort on arrays 'dist' (keys) and 'idx' (payload).
// The length n must be a power of two (here n == k).
// This implementation is executed by a single thread (lane 0).
// ---------------------------------------------------------------------------
__device__ __forceinline__
void bitonic_sort_inplace(float* dist, int* idx, int n)
{
    // Reference-like implementation as per pseudocode in the problem statement.
    for (int k = 2; k <= n; k <<= 1)
    {
        for (int j = k >> 1; j > 0; j >>= 1)
        {
            for (int i = 0; i < n; ++i)
            {
                int l = i ^ j;
                if (l > i)
                {
                    bool ascending  = ((i & k) == 0);
                    bool shouldSwap = (dist[i] > dist[l]);
                    if (!ascending)
                    {
                        // Reverse comparison when sorting descending.
                        shouldSwap = !shouldSwap;
                    }
                    if (shouldSwap)
                    {
                        float td = dist[i];
                        dist[i]  = dist[l];
                        dist[l]  = td;

                        int ti = idx[i];
                        idx[i] = idx[l];
                        idx[l] = ti;
                    }
                }
            }
        }
    }
}

// ---------------------------------------------------------------------------
// Flush and merge a warp's candidate buffer with its intermediate result.
//
// candDist/candIdx : shared-memory arrays of size at least k for this warp.
// candCount        : shared-memory counter for this warp's candidate buffer.
// k                : number of neighbors.
// result           : global array of pairs; result[queryIndex * k .. +k-1]
//                    is the intermediate result for this query, sorted
//                    ascending by distance.
// queryIndex       : index of the current query handled by this warp.
// max_distance     : per-warp max_distance (distance of the k-th neighbor).
// warpMask         : active mask for this warp (here always 0xffffffff).
//
// Steps:
//  1) Pad the candidate buffer (if partially filled) with FLT_MAX distances
//     so that Bitonic Sort can work on exactly k elements.
//  2) Sort buffer ascending via Bitonic Sort.
//  3) Merge buffer and intermediate result into a length-k bitonic sequence:
//         merged[i] = min( best[i], buffer[k-1-i] ), by distance.
//     The merged sequence is kept in candDist/candIdx.
//  4) Sort this merged sequence ascending via Bitonic Sort.
//  5) Write the merged, sorted result back to result[] for this query.
//  6) Update max_distance to the distance of the k-th neighbor.
//  7) Reset the candidate counter to 0.
// ---------------------------------------------------------------------------
__device__ __forceinline__
void flush_and_merge(float* candDist,
                     int*   candIdx,
                     int*   candCount,
                     int    k,
                     Pair*  result,
                     int    queryIndex,
                     float& max_distance,
                     unsigned warpMask)
{
    int lane = threadIdx.x & (WARP_SIZE - 1);

    // Only lane 0 performs the serial work; all lanes then synchronize.
    if (lane == 0)
    {
        int count = *candCount;

        if (count > 0)
        {
            // Pad unused slots with "infinite" distance so that we always sort k elements.
            for (int i = count; i < k; ++i)
            {
                candDist[i] = FLT_MAX;
                candIdx[i]  = -1;
            }

            // 1) Sort candidate buffer ascending.
            bitonic_sort_inplace(candDist, candIdx, k);

            // 2) Merge buffer and existing intermediate result into a bitonic sequence.
            int base = queryIndex * k;
            for (int i = 0; i < k; ++i)
            {
                float bestDist = result[base + i].second;
                int   bestIdx  = result[base + i].first;

                float bufDist  = candDist[k - 1 - i];
                int   bufIdx   = candIdx[k - 1 - i];

                if (bestDist <= bufDist)
                {
                    // Take from intermediate result.
                    candDist[i] = bestDist;
                    candIdx[i]  = bestIdx;
                }
                else
                {
                    // Take from buffer.
                    candDist[i] = bufDist;
                    candIdx[i]  = bufIdx;
                }
            }

            // 3) Sort merged bitonic sequence ascending.
            bitonic_sort_inplace(candDist, candIdx, k);

            // 4) Write merged top-k back to intermediate result.
            for (int i = 0; i < k; ++i)
            {
                result[base + i].first  = candIdx[i];
                result[base + i].second = candDist[i];
            }

            // 5) Update max_distance to the distance of the k-th nearest neighbor.
            max_distance = candDist[k - 1];

            // 6) Reset candidate counter.
            *candCount = 0;
        }
    }

    // Broadcast updated max_distance from lane 0 to the entire warp.
    max_distance = __shfl_sync(warpMask, max_distance, 0);

    // Ensure all lanes see the updated candidate_count and buffer state.
    __syncwarp(warpMask);
}

// ---------------------------------------------------------------------------
// GPU kernel: each warp processes one query and computes its k nearest
// neighbors among all data points.
// ---------------------------------------------------------------------------
__global__
void knn_kernel(const float2* __restrict__ query,
                int                           query_count,
                const float2* __restrict__ data,
                int                           data_count,
                Pair* __restrict__            result,
                int                           k)
{
    // Dynamic shared memory layout:
    //   [0                              .. TILE_SIZE * sizeof(float2)                  ) : data tile (float2)
    //   [TILE_SIZE * sizeof(float2)     .. + WARPS_PER_BLOCK*MAX_K*sizeof(float)       ) : candidate distances
    //   [prev + WARPS_PER_BLOCK*MAX_K*sizeof(float) .. + WARPS_PER_BLOCK*MAX_K*sizeof(int)) : candidate indices
    //   [prev + WARPS_PER_BLOCK*MAX_K*sizeof(int)   .. + WARPS_PER_BLOCK*sizeof(int)   ) : candidate counts
    extern __shared__ unsigned char smem[];

    unsigned char* ptr = smem;

    // Data tile shared by entire block.
    float2* sData = reinterpret_cast<float2*>(ptr);
    ptr += TILE_SIZE * sizeof(float2);

    // Candidate buffers per warp (distances then indices).
    float* sCandDistBase = reinterpret_cast<float*>(ptr);
    ptr += WARPS_PER_BLOCK * MAX_K * sizeof(float);

    int* sCandIdxBase = reinterpret_cast<int*>(ptr);
    ptr += WARPS_PER_BLOCK * MAX_K * sizeof(int);

    // Candidate counts per warp.
    int* sCandCount = reinterpret_cast<int*>(ptr);

    const int tid       = threadIdx.x;
    const int lane      = tid & (WARP_SIZE - 1);
    const int warpLocal = tid / WARP_SIZE;
    const int warpGlobal = blockIdx.x * WARPS_PER_BLOCK + warpLocal;
    const unsigned warpMask = 0xFFFFFFFFu;

    // Pointers to this warp's candidate buffer and counter.
    float* candDist = sCandDistBase + warpLocal * MAX_K;
    int*   candIdx  = sCandIdxBase  + warpLocal * MAX_K;
    int*   candCount = sCandCount   + warpLocal;

    // Initialize candidate count for all warps.
    if (lane == 0)
    {
        *candCount = 0;
    }

    // Determine if this warp is assigned a valid query.
    const bool warpValid = (warpGlobal < query_count);

    // Per-warp max_distance: distance of the current k-th nearest neighbor.
    // Initialize to infinity so that all points are initially considered.
    float max_distance = FLT_MAX;

    // Initialize intermediate result (result[warpGlobal * k .. +k-1]) for valid warps.
    if (warpValid && lane == 0)
    {
        const int base = warpGlobal * k;
        for (int i = 0; i < k; ++i)
        {
            result[base + i].first  = -1;
            result[base + i].second = FLT_MAX;
        }
    }
    __syncwarp(warpMask);

    // Load query coordinates into registers and broadcast within warp.
    float2 q;
    if (warpValid)
    {
        if (lane == 0)
        {
            q = query[warpGlobal];
        }
        q.x = __shfl_sync(warpMask, q.x, 0);
        q.y = __shfl_sync(warpMask, q.y, 0);
    }

    // Process all data points in tiles.
    for (int tileStart = 0; tileStart < data_count; tileStart += TILE_SIZE)
    {
        int tileSize = TILE_SIZE;
        if (tileStart + tileSize > data_count)
        {
            tileSize = data_count - tileStart;
        }

        // Load tile of data points into shared memory.
        if (tid < tileSize)
        {
            sData[tid] = data[tileStart + tid];
        }

        __syncthreads(); // ensure tile is fully loaded

        // Every warp processes all points in the current tile.
        const int numIters = (tileSize + WARP_SIZE - 1) / WARP_SIZE;

        for (int it = 0; it < numIters; ++it)
        {
            const int localIndex = it * WARP_SIZE + lane;

            float dist     = 0.0f;
            int   data_idx = -1;
            bool  pending  = false;

            // Compute distance for this lane's data point, if any and if warp is valid.
            if (warpValid && localIndex < tileSize)
            {
                const float2 p = sData[localIndex];
                const float dx = p.x - q.x;
                const float dy = p.y - q.y;
                dist           = dx * dx + dy * dy;
                data_idx       = tileStart + localIndex;

                // Filter by current k-th neighbor distance.
                pending = (dist < max_distance);
            }

            // Warp-synchronous candidate insertion loop.
            // This loop may call flush_and_merge() when the candidate buffer fills up,
            // and will retry insertion for any still-pending candidates afterward.
            while (__any_sync(warpMask, pending))
            {
                // Mask of lanes that still have a pending candidate.
                unsigned pendingMask = __ballot_sync(warpMask, pending);
                if (pendingMask == 0u)
                {
                    break;
                }

                // Current number of candidates in buffer.
                int curCount = 0;
                if (lane == 0)
                {
                    curCount = *candCount;
                }
                curCount = __shfl_sync(warpMask, curCount, 0);

                const int freeSlots = k - curCount;

                if (freeSlots == 0)
                {
                    // Buffer is full; merge candidates with the intermediate result.
                    // Only meaningful for valid warps; for invalid warps, pending is always false.
                    if (warpValid)
                    {
                        flush_and_merge(candDist,
                                        candIdx,
                                        candCount,
                                        k,
                                        result,
                                        warpGlobal,
                                        max_distance,
                                        warpMask);
                    }

                    // Re-evaluate this candidate's eligibility with updated max_distance.
                    if (pending)
                    {
                        pending = (dist < max_distance);
                    }

                    continue;
                }

                // Number of lanes currently pending in this round.
                const int totalPending = __popc(pendingMask);
                int allowed = totalPending;

                // Only 'allowed' pending candidates can be inserted in this round.
                if (lane == 0 && allowed > freeSlots)
                {
                    allowed = freeSlots;
                }
                allowed = __shfl_sync(warpMask, allowed, 0);

                // Compute rank of this lane among pending lanes (0-based).
                const int myRank =
                    __popc(pendingMask & ((1u << lane) - 1));

                if (pending && myRank < allowed)
                {
                    // This lane will insert its candidate in this round.
                    int base = 0;
                    if (lane == 0)
                    {
                        // Atomic add to determine starting index for this batch.
                        base = atomicAdd(candCount, allowed);
                    }
                    base = __shfl_sync(warpMask, base, 0);

                    const int pos = base + myRank;
                    candDist[pos] = dist;
                    candIdx[pos]  = data_idx;

                    // Candidate successfully inserted.
                    pending = false;
                }

                // Lanes that are still 'pending' (myRank >= allowed) will loop again.
            }
        }

        __syncthreads(); // ensure all warps finished with this tile before loading next
    }

    // After processing all data points, flush any remaining candidates.
    if (warpValid)
    {
        flush_and_merge(candDist,
                        candIdx,
                        candCount,
                        k,
                        result,
                        warpGlobal,
                        max_distance,
                        warpMask);
    }
}

// ---------------------------------------------------------------------------
// Host interface.
// 
// query       : device pointer to query_count float2 points.
// data        : device pointer to data_count float2 points.
// result      : device pointer to query_count * k pairs (index, distance).
// query_count : number of query points.
// data_count  : number of data points.
// k           : number of neighbors (power of two, 32 <= k <= 1024).
//
// This function launches the knn_kernel with a configuration chosen for
// modern data center GPUs (such as A100/H100) and uses dynamic shared memory
// sized for the maximum supported k (MAX_K).
// ---------------------------------------------------------------------------
void run_knn(const float2* query,
             int           query_count,
             const float2* data,
             int           data_count,
             Pair*         result,
             int           k)
{
    // Guard against degenerate cases; nothing to do.
    if (query_count <= 0 || data_count <= 0 || k <= 0)
    {
        return;
    }

    // Clamp k to MAX_K for safety (problem guarantees k <= MAX_K).
    if (k > MAX_K)
    {
        k = MAX_K;
    }

    const dim3 blockDim(THREADS_PER_BLOCK);
    const int  warpsPerBlock = WARPS_PER_BLOCK;
    const dim3 gridDim( (query_count + warpsPerBlock - 1) / warpsPerBlock );

    // Dynamic shared memory size (in bytes), sized for MAX_K.
    const size_t sharedBytes =
        TILE_SIZE * sizeof(float2) +                 // sData
        WARPS_PER_BLOCK * MAX_K * sizeof(float) +    // sCandDistBase
        WARPS_PER_BLOCK * MAX_K * sizeof(int) +      // sCandIdxBase
        WARPS_PER_BLOCK * sizeof(int);               // sCandCount

    knn_kernel<<<gridDim, blockDim, sharedBytes>>>(query,
                                                   query_count,
                                                   data,
                                                   data_count,
                                                   result,
                                                   k);

    // Synchronize to ensure completion before the caller uses 'result'.
    cudaDeviceSynchronize();
}

#include <cuda_runtime.h>
#include <math_constants.h>
#include <utility>

// Simple struct to hold neighbor data (distance and index) in shared memory.
// The layout is (float, int), but this is independent of std::pair<int,float>.
struct Neighbor {
    float dist;   // squared distance
    int   index;  // index of the data point
};

static constexpr int WARP_SIZE         = 32;
static constexpr int WARPS_PER_BLOCK   = 4;
static constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * WARP_SIZE;
static constexpr int BATCH_SIZE        = 2048;

// Warp-wide Bitonic Sort for Neighbor arrays in shared memory.
// - arr: pointer to the first element of the array to sort.
// - n:   number of elements, must be a power of two, n <= 1024.
// Sorting key is 'dist' in ascending order.
__device__ __forceinline__
void bitonic_sort_warp(Neighbor *arr, int n)
{
    const unsigned FULL_MASK = 0xffffffffu;
    const int laneId = threadIdx.x & (WARP_SIZE - 1);

    // Implementation based on the standard bitonic sorting network.
    for (int k = 2; k <= n; k <<= 1) {
        for (int j = k >> 1; j > 0; j >>= 1) {
            for (int i = laneId; i < n; i += WARP_SIZE) {
                int ixj = i ^ j;
                if (ixj > i) {
                    Neighbor a = arr[i];
                    Neighbor b = arr[ixj];
                    bool up = ((i & k) == 0);
                    bool comp = (a.dist > b.dist);
                    if ((up && comp) || (!up && !comp)) {
                        arr[i]  = b;
                        arr[ixj] = a;
                    }
                }
            }
            __syncwarp(FULL_MASK);
        }
    }
}

// Merge the candidate buffer with the current intermediate k-NN result for one warp.
// Preconditions:
//  - 'knn' holds the current intermediate result, sorted ascending by distance.
//  - 'cand[0..cand_count-1]' holds newly found candidates; cand_count <= k.
//  - k is a power of two between 32 and 1024.
// Steps performed:
//  0. Pad the candidate buffer up to k elements with +INF distances.
//  1. Sort the candidate buffer using Bitonic Sort (ascending).
//  2. Merge 'cand' and 'knn' by taking for each i the minimum of knn[i] and cand[k-1-i],
//     storing the result back into knn[i]. This yields a bitonic sequence in 'knn'.
//  3. Sort 'knn' using Bitonic Sort (ascending) to restore the invariant.
//  4. Update max_distance and reset candidate count for this warp.
__device__ __forceinline__
void merge_buffer(
    Neighbor *knn,
    Neighbor *cand,
    int k,
    int cand_count,
    float *sh_max_dists,
    int *sh_cand_counts,
    int warpId)
{
    const unsigned FULL_MASK = 0xffffffffu;
    const int laneId = threadIdx.x & (WARP_SIZE - 1);

    // Pad remaining candidate slots with infinite distance so that
    // we can always sort 'k' elements.
    for (int i = laneId + cand_count; i < k; i += WARP_SIZE) {
        cand[i].dist  = CUDART_INF_F;
        cand[i].index = -1;
    }
    __syncwarp(FULL_MASK);

    // (1) Sort the candidate buffer.
    bitonic_sort_warp(cand, k);

    // (2) Merge 'cand' and 'knn' into a bitonic sequence stored in 'knn'.
    for (int i = laneId; i < k; i += WARP_SIZE) {
        Neighbor a = knn[i];
        Neighbor b = cand[k - 1 - i];
        if (b.dist < a.dist) {
            knn[i] = b;
        }
    }
    __syncwarp(FULL_MASK);

    // (3) Sort the merged result to restore ascending order.
    bitonic_sort_warp(knn, k);

    // (4) Update max_distance (distance of the k-th nearest neighbor)
    //     and reset candidate count for this warp.
    if (laneId == 0) {
        sh_max_dists[warpId]   = knn[k - 1].dist;
        sh_cand_counts[warpId] = 0;
    }
    __syncwarp(FULL_MASK);
}

// CUDA kernel: each warp processes one query point and computes its k nearest neighbors.
__global__ void knn_kernel(
    const float2 * __restrict__ query,
    int query_count,
    const float2 * __restrict__ data,
    int data_count,
    std::pair<int, float> * __restrict__ result,
    int k)
{
    const int warpId         = threadIdx.x / WARP_SIZE;         // Warp index in block
    const int laneId         = threadIdx.x & (WARP_SIZE - 1);   // Lane index within warp
    const int warpsPerBlock  = blockDim.x / WARP_SIZE;
    const int globalWarpId   = blockIdx.x * warpsPerBlock + warpId;
    const bool active        = (globalWarpId < query_count);
    const unsigned FULL_MASK = 0xffffffffu;

    // Dynamic shared memory layout:
    // [0]  float2 sh_points[BATCH_SIZE]
    // [1]  int    sh_cand_counts[warpsPerBlock]
    // [2]  float  sh_max_dists[warpsPerBlock]
    // [3]  Neighbor sh_knn_all[warpsPerBlock * k]
    // [4]  Neighbor sh_cand_all[warpsPerBlock * k]
    extern __shared__ unsigned char shared_mem[];
    size_t offset = 0;

    // Shared buffer of data points for the current batch (shared by all warps in the block).
    float2 *sh_points = reinterpret_cast<float2*>(shared_mem + offset);
    offset += sizeof(float2) * BATCH_SIZE;

    // Per-warp candidate counts.
    int *sh_cand_counts = reinterpret_cast<int*>(shared_mem + offset);
    offset += sizeof(int) * warpsPerBlock;

    // Per-warp max_distance (distance of current k-th nearest neighbor).
    float *sh_max_dists = reinterpret_cast<float*>(shared_mem + offset);
    offset += sizeof(float) * warpsPerBlock;

    // Per-warp intermediate k-NN results.
    Neighbor *sh_knn_all = reinterpret_cast<Neighbor*>(shared_mem + offset);
    offset += sizeof(Neighbor) * warpsPerBlock * k;

    // Per-warp candidate buffers.
    Neighbor *sh_cand_all = reinterpret_cast<Neighbor*>(shared_mem + offset);
    // offset += sizeof(Neighbor) * warpsPerBlock * k; // Not needed further

    Neighbor *warp_knn  = sh_knn_all  + warpId * k;
    Neighbor *warp_cand = sh_cand_all + warpId * k;

    // Initialize per-warp shared state.
    if (laneId == 0) {
        if (warpId < warpsPerBlock) {
            sh_cand_counts[warpId] = 0;
            sh_max_dists[warpId]   = CUDART_INF_F;
        }
    }

    // Initialize the intermediate k-NN result for active warps.
    if (active) {
        for (int i = laneId; i < k; i += WARP_SIZE) {
            warp_knn[i].dist  = CUDART_INF_F;
            warp_knn[i].index = -1;
        }
    }
    __syncthreads();

    // Load the query point for this warp and broadcast to all lanes.
    float2 q;
    q.x = 0.0f;
    q.y = 0.0f;
    if (active && laneId == 0) {
        q = query[globalWarpId];
    }
    q.x = __shfl_sync(FULL_MASK, q.x, 0);
    q.y = __shfl_sync(FULL_MASK, q.y, 0);

    // Process all data points in batches cached in shared memory.
    for (int dataStart = 0; dataStart < data_count; dataStart += BATCH_SIZE) {
        int batchSize = data_count - dataStart;
        if (batchSize > BATCH_SIZE) batchSize = BATCH_SIZE;

        // Load the batch of data points into shared memory using the whole block.
        for (int idx = threadIdx.x; idx < batchSize; idx += blockDim.x) {
            sh_points[idx] = data[dataStart + idx];
        }
        __syncthreads();

        if (!active) {
            __syncthreads();
            continue;
        }

        // Each warp processes all points in the current batch for its query.
        for (int base = 0; base < batchSize; base += WARP_SIZE) {
            int idx_in_batch = base + laneId;
            bool valid = (idx_in_batch < batchSize);

            float dist        = 0.0f;
            int   point_index = -1;
            bool  is_candidate = false;

            float max_dist = sh_max_dists[warpId];

            if (valid) {
                float2 p = sh_points[idx_in_batch];
                float dx = q.x - p.x;
                float dy = q.y - p.y;
                dist = dx * dx + dy * dy;

                // Filter by current max_distance threshold.
                if (dist < max_dist) {
                    is_candidate = true;
                    point_index  = dataStart + idx_in_batch;
                }
            }

            // Identify candidate lanes within the warp.
            unsigned int cand_mask = __ballot_sync(FULL_MASK, is_candidate);

            // Process candidates one by one; lane 0 manages the shared buffer.
            while (cand_mask) {
                int srcLane = __ffs(cand_mask) - 1;

                float cdist  = __shfl_sync(FULL_MASK, dist, srcLane);
                int   cindex = __shfl_sync(FULL_MASK, point_index, srcLane);

                bool trigger_merge = false;
                int cand_count_after = 0;

                if (laneId == 0) {
                    int pos = atomicAdd(&sh_cand_counts[warpId], 1);
                    warp_cand[pos].dist  = cdist;
                    warp_cand[pos].index = cindex;
                    cand_count_after = pos + 1;
                    trigger_merge = (cand_count_after >= k);
                }

                // Broadcast the decision to merge and the candidate count after insertion.
                trigger_merge    = __shfl_sync(FULL_MASK, trigger_merge, 0);
                cand_count_after = __shfl_sync(FULL_MASK, cand_count_after, 0);

                if (trigger_merge) {
                    merge_buffer(
                        warp_knn,
                        warp_cand,
                        k,
                        cand_count_after,
                        sh_max_dists,
                        sh_cand_counts,
                        warpId);
                }

                // Remove the processed lane from the mask.
                cand_mask &= cand_mask - 1;
                __syncwarp(FULL_MASK);
            }
        }

        __syncthreads();
    }

    // After processing all batches, merge any remaining candidates for active warps.
    if (active) {
        int final_count = 0;
        if (laneId == 0) {
            final_count = sh_cand_counts[warpId];
        }
        final_count = __shfl_sync(FULL_MASK, final_count, 0);

        if (final_count > 0) {
            merge_buffer(
                warp_knn,
                warp_cand,
                k,
                final_count,
                sh_max_dists,
                sh_cand_counts,
                warpId);
        }

        // Write the final k nearest neighbors for this query to the global result array.
        for (int i = laneId; i < k; i += WARP_SIZE) {
            int out_idx = globalWarpId * k + i;
            result[out_idx].first  = warp_knn[i].index;
            result[out_idx].second = warp_knn[i].dist;
        }
    }
}

// Host function that launches the CUDA kernel.
// - query:  device pointer to query points (float2[query_count]).
// - data:   device pointer to data points  (float2[data_count]).
// - result: device pointer to result pairs (pair<int,float>[query_count * k]).
void run_knn(
    const float2 *query,
    int query_count,
    const float2 *data,
    int data_count,
    std::pair<int, float> *result,
    int k)
{
    // One warp per query.
    const int warpsPerBlock   = WARPS_PER_BLOCK;
    const int threadsPerBlock = THREADS_PER_BLOCK;

    int numBlocks = (query_count + warpsPerBlock - 1) / warpsPerBlock;

    // Dynamic shared memory size:
    //  - BATCH_SIZE float2 elements for cached data points.
    //  - For each warp:
    //      * 1 int    candidate count.
    //      * 1 float  max_distance.
    //      * k Neighbor elements for intermediate results.
    //      * k Neighbor elements for candidate buffer.
    size_t sharedBytes =
        sizeof(float2) * BATCH_SIZE +
        warpsPerBlock * (sizeof(int) + sizeof(float) + 2 * k * sizeof(Neighbor));

    dim3 grid(numBlocks);
    dim3 block(threadsPerBlock);

    knn_kernel<<<grid, block, sharedBytes>>>(
        query,
        query_count,
        data,
        data_count,
        result,
        k);
}

#include <cuda_runtime.h>
#include <cfloat>
#include <utility>

// ----------------------------------------------------------------------------------
// Basic configuration constants
// ----------------------------------------------------------------------------------

#ifndef WARP_SIZE
#define WARP_SIZE 32
#endif

// Maximum supported k and per-thread element count
static constexpr int MAX_K  = 1024;
static constexpr int MAX_R  = MAX_K / WARP_SIZE;

// Number of warps per block. Each warp processes one query.
static constexpr int WARPS_PER_BLOCK = 4;

// Number of data points cached per block in shared memory.
static constexpr int TILE_POINTS = 1536;

// ----------------------------------------------------------------------------------
// Device-side helper structures and functions
// ----------------------------------------------------------------------------------

struct Candidate
{
    float dist;
    int   idx;
};

// Initialize the per-thread portion of the intermediate top-k result.
__device__ __forceinline__
void init_topk(float (&bestDist)[MAX_R], int (&bestIdx)[MAX_R], int R)
{
    for (int i = 0; i < R; ++i)
    {
        bestDist[i] = FLT_MAX;
        bestIdx[i]  = -1;
    }
}

// Warp-wide bitonic sort over k elements distributed across the 32 threads.
// Each thread holds R = k / 32 consecutive elements in its registers.
// The arrays bestDist / bestIdx are per-thread and contain R elements.
// The global index of element (thread lane, local position p) is:
//     i = lane * R + p, 0 <= i < k.
// For stride >= R, comparators operate across threads using shuffles,
// and for stride < R, comparators operate within the registers of a single thread.
__device__ __forceinline__
void warp_bitonic_sort(float (&dist)[MAX_R], int (&idx)[MAX_R], int n, int R)
{
    const unsigned FULL_MASK = 0xffffffffu;
    int lane = threadIdx.x & (WARP_SIZE - 1);

    // Bitonic sort network
    for (int size = 2; size <= n; size <<= 1)
    {
        // size: length of subsequences to be sorted in this stage
        for (int stride = size >> 1; stride > 0; stride >>= 1)
        {
            __syncwarp(FULL_MASK);

            if (stride >= R)
            {
                // Cross-thread comparators: same local index in different threads.
                // laneMask is the XOR distance in lane IDs.
                int laneMask = stride / R;

                for (int p = 0; p < R; ++p)
                {
                    int i = lane * R + p;
                    bool up = ((i & size) == 0);

                    float selfVal = dist[p];
                    int   selfIdx = idx[p];

                    float otherVal = __shfl_xor_sync(FULL_MASK, selfVal, laneMask);
                    int   otherIdx = __shfl_xor_sync(FULL_MASK, selfIdx, laneMask);

                    bool cond = (selfVal > otherVal);
                    if ((up && cond) || (!up && !cond))
                    {
                        selfVal = otherVal;
                        selfIdx = otherIdx;
                    }

                    dist[p] = selfVal;
                    idx[p]  = selfIdx;
                }
            }
            else
            {
                // Intra-thread comparators: swap register values inside a single thread.
                int stridePos = stride; // stride < R

                for (int p = 0; p < R; ++p)
                {
                    int partner_pos = p ^ stridePos;
                    if (partner_pos > p)
                    {
                        int i = lane * R + p;
                        bool up = ((i & size) == 0);

                        float valA = dist[p];
                        int   idxA = idx[p];
                        float valB = dist[partner_pos];
                        int   idxB = idx[partner_pos];

                        bool cond = (valA > valB);
                        if ((up && cond) || (!up && !cond))
                        {
                            // Swap values
                            float tmpV = valA; valA = valB; valB = tmpV;
                            int   tmpI = idxA; idxA = idxB; idxB = tmpI;
                        }

                        dist[p]          = valA;
                        idx[p]           = idxA;
                        dist[partner_pos] = valB;
                        idx[partner_pos]  = idxB;
                    }
                }
            }
        }
    }
}

// Merge a full candidate buffer (k elements) into the current intermediate result.
// Preconditions:
//   - bestDist / bestIdx contain the current intermediate result, sorted in ascending order.
//   - candBuf[0..k-1] contains a full buffer of candidate elements (unsorted).
// Steps (per specification):
//   0. Intermediate result in registers is sorted.
//   1. Swap content of registers and buffer so that the buffer is in registers.
//   2. Sort the buffer (now in registers) using bitonic sort.
//   3. Merge the buffer and the intermediate result (now in shared memory) into registers:
//        merged[i] = min( buffer[i], intermediate[k-1-i] ), for i in [0, k-1].
//      The merged sequence is bitonic and contains the best k elements of the union.
//   4. Sort the merged sequence again using bitonic sort to restore ascending order.
//   5. Update maxDist to be the distance of the k-th nearest neighbor.
__device__ __forceinline__
void warp_merge_full_buffer(
    float (&bestDist)[MAX_R],
    int   (&bestIdx)[MAX_R],
    float &maxDist,
    Candidate *candBuf, // per-warp candidate buffer in shared memory
    int k,
    int R)
{
    const unsigned FULL_MASK = 0xffffffffu;
    int lane = threadIdx.x & (WARP_SIZE - 1);

    // Step 1: swap content of buffer and intermediate result.
    for (int p = 0; p < R; ++p)
    {
        int i = lane * R + p;

        float bufDist = candBuf[i].dist;
        int   bufIdx  = candBuf[i].idx;

        candBuf[i].dist = bestDist[p];
        candBuf[i].idx  = bestIdx[p];

        bestDist[p] = bufDist;
        bestIdx[p]  = bufIdx;
    }

    // Step 2: sort the buffer (now in registers).
    warp_bitonic_sort(bestDist, bestIdx, k, R);

    // Step 3: merge buffer (registers, sorted) and intermediate result (shared, sorted).
    // For each global position i, take the minimum of:
    //   - buffer[i]   (registers)
    //   - intermediate[k - 1 - i] (shared memory)
    for (int p = 0; p < R; ++p)
    {
        int i = lane * R + p;

        float regDist = bestDist[p];
        int   regIdx  = bestIdx[p];

        Candidate other = candBuf[k - 1 - i];

        if (other.dist < regDist)
        {
            regDist = other.dist;
            regIdx  = other.idx;
        }

        bestDist[p] = regDist;
        bestIdx[p]  = regIdx;
    }

    // Step 4: sort merged result (still in registers) in ascending order.
    warp_bitonic_sort(bestDist, bestIdx, k, R);

    // Step 5: update maxDist = distance of the k-th nearest neighbor.
    // After sorting ascending, the k-th (largest) element is at index k-1,
    // which is stored in the last register of lane (WARP_SIZE - 1).
    float kth = bestDist[R - 1];
    kth = __shfl_sync(FULL_MASK, kth, WARP_SIZE - 1);
    maxDist = kth;
}

// ----------------------------------------------------------------------------------
// k-NN CUDA kernel
// Each warp processes a single query point.
// Each thread in the warp holds k / 32 consecutive nearest neighbors in registers.
// ----------------------------------------------------------------------------------

__global__
void knn_kernel(
    const float2 * __restrict__ query,
    int query_count,
    const float2 * __restrict__ data,
    int data_count,
    std::pair<int, float> * __restrict__ result,
    int k)
{
    const unsigned FULL_MASK = 0xffffffffu;

    int lane              = threadIdx.x & (WARP_SIZE - 1);
    int warp_id_in_block  = threadIdx.x >> 5; // threadIdx.x / 32
    int warp_global_id    = blockIdx.x * WARPS_PER_BLOCK + warp_id_in_block;
    bool warp_active      = (warp_global_id < query_count);

    // Per-thread number of neighbors kept in registers.
    int R = k / WARP_SIZE;

    // Shared memory layout (dynamic):
    // [0 .. TILE_POINTS-1]        : cached data points for the block
    // [TILE_POINTS .. ]           : WARPS_PER_BLOCK * k Candidate entries
    // [after Candidate array]     : WARPS_PER_BLOCK ints (candidate counts)
    extern __shared__ unsigned char shared_mem[];
    float2  *tilePoints    = reinterpret_cast<float2*>(shared_mem);
    Candidate *allCandBuf  = reinterpret_cast<Candidate*>(tilePoints + TILE_POINTS);
    int     *candCounts    = reinterpret_cast<int*>(allCandBuf + WARPS_PER_BLOCK * k);

    // Per-warp candidate buffer and counter in shared memory.
    Candidate *candBuf = allCandBuf + warp_id_in_block * k;
    int       *candCountPtr = candCounts + warp_id_in_block;

    // Per-thread intermediate top-k result stored in registers.
    float bestDist[MAX_R];
    int   bestIdx[MAX_R];

    float qx = 0.0f;
    float qy = 0.0f;

    if (warp_active)
    {
        // Initialize per-thread top-k.
        init_topk(bestDist, bestIdx, R);

        // Load the query point for this warp.
        float2 q = query[warp_global_id];
        qx = q.x;
        qy = q.y;

        // Initialize candidate count for this warp.
        if (lane == 0)
        {
            *candCountPtr = 0;
        }
    }

    // maxDist: distance of current k-th nearest neighbor (per warp).
    float maxDist = FLT_MAX;

    __syncthreads(); // Ensure shared memory initialization visibility.

    // Process data points in batches cached into shared memory.
    for (int base = 0; base < data_count; base += TILE_POINTS)
    {
        int tileCount = data_count - base;
        if (tileCount > TILE_POINTS)
            tileCount = TILE_POINTS;

        // Load a tile of data points into shared memory cooperatively.
        for (int t = threadIdx.x; t < tileCount; t += blockDim.x)
        {
            tilePoints[t] = data[base + t];
        }

        __syncthreads();

        if (warp_active)
        {
            // Iterate over the points in the tile, one batch of 32 points per iteration.
            for (int t = lane; t < tileCount; t += WARP_SIZE)
            {
                float2 dp = tilePoints[t];
                float dx = dp.x - qx;
                float dy = dp.y - qy;
                float dist = dx * dx + dy * dy;
                int   data_idx = base + t;

                // Determine which threads have a candidate closer than current maxDist.
                bool is_candidate = (dist < maxDist);
                unsigned int mask = __ballot_sync(FULL_MASK, is_candidate);
                int n = __popc(mask);

                if (n == 0)
                {
                    continue;
                }

                // Retrieve the current candidate count from shared memory.
                int candCount = 0;
                if (lane == 0)
                {
                    candCount = *candCountPtr;
                }
                candCount = __shfl_sync(FULL_MASK, candCount, 0);

                int leftover = k - candCount; // remaining capacity in buffer

                // rank: position among new candidates in this iteration.
                int rank = __popc(mask & ((1u << lane) - 1u));

                if (n <= leftover)
                {
                    // All new candidates fit into the current buffer.

                    if (lane == 0)
                    {
                        *candCountPtr = candCount + n;
                    }

                    if (is_candidate)
                    {
                        int dst = candCount + rank;
                        candBuf[dst].dist = dist;
                        candBuf[dst].idx  = data_idx;
                    }

                    // If buffer is exactly full (candCount+n == k), merge it.
                    bool doMerge = false;
                    if (lane == 0)
                    {
                        doMerge = (*candCountPtr == k);
                    }
                    doMerge = __shfl_sync(FULL_MASK, doMerge, 0);

                    if (doMerge)
                    {
                        __syncwarp(FULL_MASK);

                        // Merge full buffer with intermediate result.
                        warp_merge_full_buffer(bestDist, bestIdx, maxDist, candBuf, k, R);

                        if (lane == 0)
                        {
                            *candCountPtr = 0;
                        }
                    }
                }
                else
                {
                    // Not all new candidates fit into the current buffer.
                    // First fill the remaining capacity, then merge, then handle leftovers.

                    // First chunk: candidates with rank < leftover.
                    if (is_candidate && (rank < leftover))
                    {
                        int dst = candCount + rank;
                        candBuf[dst].dist = dist;
                        candBuf[dst].idx  = data_idx;
                    }

                    if (lane == 0)
                    {
                        *candCountPtr = k;
                    }

                    __syncwarp(FULL_MASK);

                    // Merge full buffer with intermediate result.
                    warp_merge_full_buffer(bestDist, bestIdx, maxDist, candBuf, k, R);

                    if (lane == 0)
                    {
                        *candCountPtr = 0;
                    }

                    __syncwarp(FULL_MASK);

                    // Second chunk: remaining candidates (rank >= leftover), re-filtered
                    // against the updated maxDist.
                    bool is_candidate2 = is_candidate && (rank >= leftover) && (dist < maxDist);
                    unsigned int mask2 = __ballot_sync(FULL_MASK, is_candidate2);
                    int n2 = __popc(mask2);

                    if (n2 > 0)
                    {
                        int rank2 = __popc(mask2 & ((1u << lane) - 1u));

                        if (lane == 0)
                        {
                            *candCountPtr = n2;
                        }

                        if (is_candidate2)
                        {
                            int dst = rank2;
                            candBuf[dst].dist = dist;
                            candBuf[dst].idx  = data_idx;
                        }
                    }
                }
            }
        }

        __syncthreads();
    }

    if (warp_active)
    {
        // After processing all tiles, merge remaining candidates (if any).
        int candCount = 0;
        if (lane == 0)
        {
            candCount = *candCountPtr;
        }
        candCount = __shfl_sync(FULL_MASK, candCount, 0);

        if (candCount > 0)
        {
            // Fill the rest of the buffer with sentinel values so that it has k elements.
            // Sentinel distance is maxDist; they will not improve the top-k set.
            int fillCount = k - candCount;
            for (int offset = lane; offset < fillCount; offset += WARP_SIZE)
            {
                int dst = candCount + offset;
                candBuf[dst].dist = maxDist;
                candBuf[dst].idx  = -1;
            }

            if (lane == 0)
            {
                *candCountPtr = k;
            }

            __syncwarp(FULL_MASK);

            // Merge full buffer with intermediate result.
            warp_merge_full_buffer(bestDist, bestIdx, maxDist, candBuf, k, R);

            if (lane == 0)
            {
                *candCountPtr = 0;
            }
        }

        // Write final top-k for this query to global memory.
        int baseOut = warp_global_id * k;
        for (int p = 0; p < R; ++p)
        {
            int globalPos = (lane * R) + p;
            int outIdx = baseOut + globalPos;

            result[outIdx].first  = bestIdx[p];
            result[outIdx].second = bestDist[p];
        }
    }
}

// ----------------------------------------------------------------------------------
// Host-side interface
// ----------------------------------------------------------------------------------

void run_knn(
    const float2 *query, int query_count,
    const float2 *data,  int data_count,
    std::pair<int, float> *result,
    int k)
{
    // Each warp processes one query.
    int totalWarps = query_count;
    int threadsPerBlock = WARPS_PER_BLOCK * WARP_SIZE;
    int blocks = (totalWarps + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    // Shared memory size:
    //   TILE_POINTS * sizeof(float2)                         : cached data points
    // + WARPS_PER_BLOCK * k * sizeof(Candidate)              : candidate buffers
    // + WARPS_PER_BLOCK * sizeof(int)                        : candidate counts
    size_t sharedMemBytes =
        TILE_POINTS * sizeof(float2) +
        static_cast<size_t>(WARPS_PER_BLOCK) * static_cast<size_t>(k) * sizeof(Candidate) +
        WARPS_PER_BLOCK * sizeof(int);

    knn_kernel<<<blocks, threadsPerBlock, sharedMemBytes>>>(
        query, query_count, data, data_count, result, k);

    // Ensure completion before returning.
    cudaDeviceSynchronize();
}

#include <cuda_runtime.h>
#include <cfloat>
#include <utility>

// ----------------------------------------------------------------------------------
// k-NN implementation for 2D points (float2) using CUDA.
// - One warp (32 threads) processes one query point.
// - Each warp maintains its k nearest neighbors in registers.
// - Candidates are accumulated in a per-warp buffer in shared memory.
// - When the buffer fills (or at the end), the buffer is merged with the
//   intermediate result using a warp-wide bitonic sort + merge scheme.
// ----------------------------------------------------------------------------------

// Simple POD type matching the layout (int, float) for device-side access.
// We rely on the host providing a std::pair<int,float> array with identical layout.
struct PairIF {
    int   first;
    float second;
};

// Internal neighbor representation.
struct Neighbor {
    float dist;
    int   idx;
};

// Warp utilities.
__device__ __forceinline__ int lane_id()
{
    return threadIdx.x & 31;
}

__device__ __forceinline__ int warp_id_in_block()
{
    return threadIdx.x >> 5;
}

// Forward declarations of device helpers.
__device__ __forceinline__ void warp_bitonic_sort(
    float *dist, int *idx,
    int k, int k_per_thread,
    int lane, unsigned full_mask);

__device__ __forceinline__ void flush_candidate_buffer(
    Neighbor *warp_buf,
    int k, int k_per_thread,
    float *best_dist, int *best_idx,
    int &cand_count,
    float &max_dist,
    int lane, unsigned full_mask);

// ----------------------------------------------------------------------------------
// Warp-wide bitonic sort for k elements distributed over a warp.
// - k is a power of two, and k is a multiple of 32: k = 32 * k_per_thread.
// - Each thread holds k_per_thread elements in registers.
// - Global index mapping:
//   global_index = offset * 32 + lane (offset in [0, k_per_thread-1]).
// ----------------------------------------------------------------------------------
__device__ __forceinline__ void warp_bitonic_sort(
    float *dist, int *idx,
    int k, int k_per_thread,
    int lane, unsigned full_mask)
{
    const int WARP_SIZE = 32;

    // Outer loop: size of the subsequences being merged (Batcher's bitonic).
    for (int size = 2; size <= k; size <<= 1) {

        // Inner loop: distance between compared elements.
        for (int stride = size >> 1; stride > 0; stride >>= 1) {

            if (stride >= WARP_SIZE) {
                // --------------------------------------------------------------
                // Comparisons within a thread (same lane, different offsets).
                // Each pair (offset, partner_offset) is processed only once.
                // --------------------------------------------------------------
                int stride_off = stride >> 5;  // stride / 32

                for (int o = 0; o < k_per_thread; ++o) {
                    int partner_o = o ^ stride_off;
                    // Process each pair only once (partner_o > o).
                    if (partner_o > o && partner_o < k_per_thread) {

                        int gi = (o << 5) | lane;  // global index of element at offset o
                        bool up = ((gi & size) == 0);

                        float v_i = dist[o];
                        float v_p = dist[partner_o];
                        int   i_i = idx[o];
                        int   i_p = idx[partner_o];

                        bool cond = (v_i > v_p);
                        // If up == true: keep smaller at gi, larger at partner.
                        // If up == false: keep larger at gi, smaller at partner.
                        if ((cond && up) || (!cond && !up)) {
                            float tmpd = v_i; v_i = v_p; v_p = tmpd;
                            int   tmpi = i_i; i_i = i_p; i_p = tmpi;
                        }

                        dist[o]          = v_i;
                        idx[o]           = i_i;
                        dist[partner_o]  = v_p;
                        idx[partner_o]   = i_p;
                    }
                }
            } else {
                // --------------------------------------------------------------
                // Comparisons across threads (different lanes, same offset).
                // Implemented with warp shuffles; each comparator is realized
                // symmetrically at both ends.
                // --------------------------------------------------------------
                for (int o = 0; o < k_per_thread; ++o) {
                    int gi = (o << 5) | lane;  // global index of this element

                    float self_dist = dist[o];
                    int   self_idx  = idx[o];

                    float other_dist = __shfl_xor_sync(full_mask, self_dist, stride);
                    int   other_idx  = __shfl_xor_sync(full_mask, self_idx,  stride);

                    bool up = ((gi & size) == 0);

                    // If up == true: keep min; if up == false: keep max.
                    bool swap = ((self_dist > other_dist) == up);
                    if (swap) {
                        self_dist = other_dist;
                        self_idx  = other_idx;
                    }

                    dist[o] = self_dist;
                    idx[o]  = self_idx;
                }
            }
        }
    }
}

// ----------------------------------------------------------------------------------
// Merge the per-warp candidate buffer (in shared memory) with the intermediate
// k-NN result (in registers).
//
// - best_dist / best_idx : current top-k in ascending order (registers).
// - warp_buf             : shared memory buffer [0..k-1] for candidate points.
// - cand_count           : number of valid candidates stored in warp_buf.
// - max_dist             : distance of the current k-th neighbor.
// ----------------------------------------------------------------------------------
__device__ __forceinline__ void flush_candidate_buffer(
    Neighbor *warp_buf,
    int k, int k_per_thread,
    float *best_dist, int *best_idx,
    int &cand_count,
    float &max_dist,
    int lane, unsigned full_mask)
{
    if (cand_count == 0) {
        return;
    }

    const int WARP_SIZE = 32;

    // If the candidate buffer is not completely filled, pad the remainder
    // with max_dist so that we can treat it like a full buffer.
    if (cand_count < k) {
        for (int i = cand_count + lane; i < k; i += WARP_SIZE) {
            warp_buf[i].dist = max_dist;
            warp_buf[i].idx  = -1;
        }
        __syncwarp(full_mask);
    }

    // -------------------------------------------------------------------------
    // Step 1: Swap the contents of the buffer (shared) and the intermediate
    // result (registers) so that the buffer becomes resident in registers.
    // After this step:
    // - warp_buf[...]     contains the old intermediate result.
    // - best_dist/best_idx contain the previous candidate buffer contents.
    // -------------------------------------------------------------------------
    for (int o = 0; o < k_per_thread; ++o) {
        int gi = (o << 5) | lane;  // global index for this register element

        // Old intermediate result (from registers).
        Neighbor tmp;
        tmp.dist = best_dist[o];
        tmp.idx  = best_idx[o];

        // Current candidate from shared buffer.
        Neighbor buf_val = warp_buf[gi];

        // Swap: write old intermediate result to shared memory.
        warp_buf[gi] = tmp;

        // Store candidates into registers.
        best_dist[o] = buf_val.dist;
        best_idx[o]  = buf_val.idx;
    }
    __syncwarp(full_mask);

    // -------------------------------------------------------------------------
    // Step 2: Sort the buffer (now in registers) in ascending order using
    // warp-wide bitonic sort.
    // -------------------------------------------------------------------------
    warp_bitonic_sort(best_dist, best_idx, k, k_per_thread, lane, full_mask);

    // -------------------------------------------------------------------------
    // Step 3: Merge the sorted buffer (registers) and intermediate result
    // (shared) into a bitonic sequence:
    //
    // For each global index i:
    //   merged[i] = min( buffer[i], intermediate[k - 1 - i] )
    //
    // In terms of our data layout:
    // - buffer[i] is in registers (best_dist/best_idx).
    // - intermediate[k - 1 - i] is in warp_buf[ mirrored_index ].
    // -------------------------------------------------------------------------
    for (int o = 0; o < k_per_thread; ++o) {
        int gi      = (o << 5) | lane;   // index in buffer (registers)
        int gi_rev  = k - 1 - gi;        // mirrored index in shared

        Neighbor r = warp_buf[gi_rev];
        float rd   = r.dist;
        int   ri   = r.idx;

        float bd   = best_dist[o];
        int   bi   = best_idx[o];

        // Keep the closer of the two.
        if (rd < bd) {
            best_dist[o] = rd;
            best_idx[o]  = ri;
        }
    }
    __syncwarp(full_mask);

    // -------------------------------------------------------------------------
    // Step 4: Sort the merged result (still in registers) in ascending order.
    // This yields the updated intermediate result.
    // -------------------------------------------------------------------------
    warp_bitonic_sort(best_dist, best_idx, k, k_per_thread, lane, full_mask);

    // Update max_dist to the distance of the k-th nearest neighbor (last element).
    int last_index  = k - 1;
    int last_offset = last_index >> 5;   // which offset within a thread
    int last_lane   = last_index & 31;   // which lane owns it

    float last_val = best_dist[last_offset];
    max_dist = __shfl_sync(full_mask, last_val, last_lane);

    // Candidate buffer is now conceptually empty.
    cand_count = 0;
}

// ----------------------------------------------------------------------------------
// CUDA kernel: each warp processes one query point.
// - query_count   : number of query points.
// - data_count    : number of data points.
// - query         : [query_count] array of float2.
// - data          : [data_count] array of float2.
// - result        : [query_count * k] array of PairIF (index, distance).
// - k             : number of nearest neighbors (power of two, 32 <= k <= 1024).
// ----------------------------------------------------------------------------------
template<int WARPS_PER_BLOCK, int TILE_SIZE>
__global__ void knn_kernel(
    const float2 * __restrict__ query,
    int query_count,
    const float2 * __restrict__ data,
    int data_count,
    PairIF * __restrict__ result,
    int k)
{
    const int WARP_SIZE  = 32;
    const int lane       = lane_id();
    const int warp_in_blk= warp_id_in_block();
    const int warp_global= blockIdx.x * WARPS_PER_BLOCK + warp_in_blk;
    const unsigned FULL_MASK = 0xFFFFFFFFu;

    // Per-thread local storage for top-k neighbors.
    // k is in [32, 1024], so k_per_thread in [1, 32].
    const int k_per_thread = k / WARP_SIZE;

    // Shared memory layout:
    // [0 .. TILE_SIZE-1] : float2 data tile
    // [TILE_SIZE .. ]    : per-warp candidate buffers (Neighbor[WARPS_PER_BLOCK][k])
    extern __shared__ unsigned char smem[];
    float2 *s_data = reinterpret_cast<float2*>(smem);
    Neighbor *s_candidates_base = reinterpret_cast<Neighbor*>(s_data + TILE_SIZE);

    // Pointer to this warp's candidate buffer in shared memory.
    Neighbor *warp_buf = s_candidates_base + warp_in_blk * k;

    // Determine whether this warp corresponds to a valid query.
    bool active = (warp_global < query_count);

    // Load query point once per warp and broadcast.
    float2 q;
    if (active) {
        if (lane == 0) {
            q = query[warp_global];
        }
        q.x = __shfl_sync(FULL_MASK, q.x, 0);
        q.y = __shfl_sync(FULL_MASK, q.y, 0);
    }

    // Initialize intermediate result in registers: distances set to +inf, indices to -1.
    float best_dist[32];
    int   best_idx[32];
    for (int o = 0; o < k_per_thread; ++o) {
        best_dist[o] = FLT_MAX;
        best_idx[o]  = -1;
    }

    // Candidate buffer state (replicated across threads in the warp).
    int   cand_count = 0;
    float max_dist   = FLT_MAX;  // distance of current k-th neighbor

    // Process the data points in tiles loaded into shared memory.
    for (int base = 0; base < data_count; base += TILE_SIZE) {
        int tile_count = data_count - base;
        if (tile_count > TILE_SIZE) tile_count = TILE_SIZE;

        // Load tile into shared memory by the entire block.
        for (int i = threadIdx.x; i < tile_count; i += blockDim.x) {
            s_data[i] = data[base + i];
        }
        __syncthreads();

        // Each active warp processes the tile for its query.
        if (active) {
            for (int t = 0; t < tile_count; t += WARP_SIZE) {
                int idx_in_tile = t + lane;
                bool valid = (idx_in_tile < tile_count);

                float dist  = FLT_MAX;
                int   d_idx = -1;

                if (valid) {
                    float2 p = s_data[idx_in_tile];
                    float dx = p.x - q.x;
                    float dy = p.y - q.y;
                    dist  = dx * dx + dy * dy;     // squared Euclidean distance
                    d_idx = base + idx_in_tile;    // global data index
                }

                // Filter by max_dist and add to candidate buffer using warp ballot.
                bool is_candidate = valid && (dist < max_dist);

                unsigned mask      = __ballot_sync(FULL_MASK, is_candidate);
                int      n_in_warp = __popc(mask);

                if (n_in_warp > 0) {
                    // If adding these candidates would overflow the buffer, flush first.
                    if (cand_count + n_in_warp > k) {
                        flush_candidate_buffer(
                            warp_buf, k, k_per_thread,
                            best_dist, best_idx,
                            cand_count, max_dist,
                            lane, FULL_MASK);

                        // max_dist has been updated; recompute candidacy.
                        is_candidate = valid && (dist < max_dist);
                        mask         = __ballot_sync(FULL_MASK, is_candidate);
                        n_in_warp    = __popc(mask);

                        if (n_in_warp == 0) {
                            continue;
                        }
                    }

                    // Compute position in the buffer for this thread's candidate.
                    int prefix = __popc(mask & ((1u << lane) - 1));

                    if (is_candidate) {
                        int pos = cand_count + prefix;
                        warp_buf[pos].dist = dist;
                        warp_buf[pos].idx  = d_idx;
                    }

                    // Update candidate count (warp-uniform).
                    cand_count += n_in_warp;
                }
            }
        }

        __syncthreads();
    }

    // After all tiles are processed, flush any remaining candidates.
    if (active && cand_count > 0) {
        flush_candidate_buffer(
            warp_buf, k, k_per_thread,
            best_dist, best_idx,
            cand_count, max_dist,
            lane, FULL_MASK);
    }

    // Write final top-k results to global memory.
    if (active) {
        int base_out = warp_global * k;

        // Global index mapping: g = offset * 32 + lane.
        for (int o = 0; o < k_per_thread; ++o) {
            int g = (o << 5) | lane;  // position in [0, k-1]
            PairIF out;
            out.first  = best_idx[o];
            out.second = best_dist[o];
            result[base_out + g] = out;
        }
    }
}

// ----------------------------------------------------------------------------------
// Host entry point: launches the CUDA kernel.
// Assumptions (per problem statement):
// - query, data, result are device pointers allocated with cudaMalloc.
// - data_count >= k.
// - k is a power of two, 32 <= k <= 1024.
// ----------------------------------------------------------------------------------
void run_knn(
    const float2 *query, int query_count,
    const float2 *data,  int data_count,
    std::pair<int, float> *result,
    int k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    // Configuration parameters:
    // - WARPS_PER_BLOCK: number of queries processed per block.
    // - TILE_SIZE: number of data points cached per block in shared memory.
    constexpr int WARPS_PER_BLOCK = 4;
    constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * 32;
    constexpr int TILE_SIZE = 1024;

    dim3 block_dim(THREADS_PER_BLOCK);
    dim3 grid_dim((query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK);

    // Shared memory size:
    //   TILE_SIZE * sizeof(float2) for the data tile
    // + WARPS_PER_BLOCK * k * sizeof(Neighbor) for per-warp candidate buffers.
    size_t shared_bytes =
        TILE_SIZE * sizeof(float2) +
        static_cast<size_t>(WARPS_PER_BLOCK) * static_cast<size_t>(k) * sizeof(Neighbor);

    PairIF *raw_result = reinterpret_cast<PairIF*>(result);

    knn_kernel<WARPS_PER_BLOCK, TILE_SIZE>
        <<<grid_dim, block_dim, shared_bytes>>>(
            query, query_count,
            data,  data_count,
            raw_result, k);

    // For simplicity, synchronize here. In a larger application, the caller
    // might prefer to manage stream synchronization externally.
    cudaDeviceSynchronize();
}

```cpp
// CUDA implementation of k-NN for 2D points with one warp (32 threads) per query.
// The algorithm uses a per-warp intermediate result stored in registers and
// a per-warp candidate buffer in shared memory. Candidates are accumulated and
// periodically merged into the intermediate result using bitonic sort and a
// bitonic merge operation implemented with warp shuffle intrinsics.

#include <cuda_runtime.h>
#include <float.h>
#include <stdint.h>
#include <utility>

// Constants tuned for modern data-center GPUs (A100/H100-like).
// These can be adjusted if necessary.
static constexpr int WARP_SIZE            = 32;
static constexpr int MAX_K                = 1024;                 // Maximum supported k
static constexpr int MAX_ELEMS_PER_THREAD = MAX_K / WARP_SIZE;    // 32
static constexpr int THREADS_PER_BLOCK    = 256;                  // 8 warps per block
static constexpr int BATCH_SIZE           = 2048;                 // Number of data points per shared-memory batch

// Internal representation for results on device, assumed to be layout-compatible
// with std::pair<int,float> for the given platform (two 32-bit values).
struct ResultPairDevice {
    int   first;
    float second;
};

// Warp-level bitonic sort of k elements distributed across a warp.
//
// - Each thread stores elemsPerThread = k / WARP_SIZE consecutive elements
//   in arrays dist[0..elemsPerThread-1] and idx[0..elemsPerThread-1].
// - The global index of element (lane, e) is i = lane * elemsPerThread + e.
// - k is a power of two between 32 and 1024 (inclusive), so elemsPerThread is
//   a power of two between 1 and 32.
//
// The implementation follows the classical bitonic sort network:
//   for (size = 2; size <= k; size <<= 1)
//     for (stride = size >> 1; stride > 0; stride >>= 1)
//       for each i in parallel:
//         partner = i ^ stride
//         dir = ((i & size) == 0)
//         if ((dist[i] > dist[partner]) == dir) swap(dist[i], dist[partner])
//
// We adapt this to a distributed layout and use warp shuffles for exchanges
// that occur between different lanes. For exchanges within the same lane,
// we swap registers directly. Thanks to the structure of the network,
// exchanges between lanes always involve elements with the same local index
// within each thread.
__device__ __forceinline__
void warpBitonicSort(float (&dist)[MAX_ELEMS_PER_THREAD],
                     int   (&idx)[MAX_ELEMS_PER_THREAD],
                     int k)
{
    const unsigned fullMask = 0xFFFFFFFFu;
    const int lane = threadIdx.x & (WARP_SIZE - 1);
    const int elemsPerThread = k / WARP_SIZE;

    // Bitonic sort over k elements.
    for (int size = 2; size <= k; size <<= 1) {
        // size is the size of the bitonic subsequences being merged.
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            // stride controls the distance between compared elements.

            if (stride >= elemsPerThread) {
                // Cross-lane comparisons: partner is in another lane, but with the
                // same local index. Because k and elemsPerThread are powers of two
                // and stride is also a power of two, stride / elemsPerThread is an
                // integer power of two that can be used as the XOR mask for lanes.
                const int laneMask = stride / elemsPerThread;

                #pragma unroll
                for (int e = 0; e < MAX_ELEMS_PER_THREAD; ++e) {
                    if (e >= elemsPerThread) break;

                    const int globalIdx = lane * elemsPerThread + e;
                    const bool up = ((globalIdx & size) == 0); // sort direction for this element

                    float selfVal = dist[e];
                    int   selfIdx = idx[e];

                    float otherVal = __shfl_xor_sync(fullMask, selfVal, laneMask, WARP_SIZE);
                    int   otherIdx = __shfl_xor_sync(fullMask, selfIdx, laneMask, WARP_SIZE);

                    const bool swap = (selfVal > otherVal) == up;
                    if (swap) {
                        selfVal = otherVal;
                        selfIdx = otherIdx;
                    }

                    dist[e] = selfVal;
                    idx[e]  = selfIdx;
                }
            } else {
                // Intra-lane comparisons: partner is in the same lane, with a
                // different local index. We swap registers directly.
                const int strideLocal = stride;

                #pragma unroll
                for (int e = 0; e < MAX_ELEMS_PER_THREAD; ++e) {
                    if (e >= elemsPerThread) break;

                    const int globalIdx = lane * elemsPerThread + e;
                    const bool up = ((globalIdx & size) == 0);

                    const int partner = e ^ strideLocal; // partner in same lane

                    float selfVal = dist[e];
                    int   selfIdx = idx[e];

                    float otherVal = dist[partner];
                    int   otherIdx = idx[partner];

                    const bool swap = (selfVal > otherVal) == up;
                    if (swap) {
                        dist[e] = otherVal;
                        idx[e]  = otherIdx;
                    }
                }
            }
        }
    }
}

// Merge the candidate buffer in shared memory with the current intermediate
// result stored in registers for a single warp.
//
// Inputs:
//   regDist, regIdx: current intermediate result in registers, sorted ascending.
//   sharedBufDist, sharedBufIdx: shared-memory buffer for this warp, containing
//       candCount candidate entries in positions [0 .. candCount-1] (unsorted).
//   k: total number of neighbors to keep per query (power of two in [32,1024]).
//   candCount: number of valid candidates currently stored in shared buffer.
//   maxDist: reference to current max_distance (distance of k-th neighbor).
//
// Procedure (per specification):
//   0. Intermediate result in registers is sorted ascending (invariant).
//   1. Pad buffer with +INF up to k elements, then swap contents of buffer
//      and intermediate result so that the buffer is in registers.
//   2. Sort the buffer in registers using bitonic sort (ascending).
//   3. Merge the sorted buffer (in registers) and the former intermediate
//      result (now in shared memory) by taking, for each i, the minimum of
//      buffer[i] and intermediate[k-1-i]; this yields a bitonic sequence of
//      length k in registers containing the k smallest elements overall.
//   4. Sort the merged bitonic sequence in registers using bitonic sort.
//   5. Update maxDist to the last element (k-th neighbor) of the sorted result.
__device__ __forceinline__
void warpMergeWithBuffer(float (&regDist)[MAX_ELEMS_PER_THREAD],
                         int   (&regIdx)[MAX_ELEMS_PER_THREAD],
                         float *sharedBufDist,
                         int   *sharedBufIdx,
                         int k,
                         int candCount,
                         float &maxDist)
{
    const int lane = threadIdx.x & (WARP_SIZE - 1);
    const unsigned fullMask = 0xFFFFFFFFu;
    const int elemsPerThread = k / WARP_SIZE;

    // Step 0: pad the candidate buffer with +INF and dummy indices so that
    // it conceptually contains exactly k elements.
    #pragma unroll
    for (int e = 0; e < MAX_ELEMS_PER_THREAD; ++e) {
        if (e >= elemsPerThread) break;

        int globalIdx = lane * elemsPerThread + e;
        if (globalIdx >= candCount && globalIdx < k) {
            sharedBufDist[globalIdx] = FLT_MAX;
            sharedBufIdx[globalIdx]  = -1;
        }
    }
    __syncwarp();

    // Step 1: swap contents of buffer (shared memory) and intermediate result
    // (registers), so that the buffer is now in registers and the old
    // intermediate result resides in shared memory.
    #pragma unroll
    for (int e = 0; e < MAX_ELEMS_PER_THREAD; ++e) {
        if (e >= elemsPerThread) break;

        int globalIdx = lane * elemsPerThread + e;
        if (globalIdx < k) {
            float tmpDist = sharedBufDist[globalIdx];
            int   tmpIdx  = sharedBufIdx[globalIdx];

            sharedBufDist[globalIdx] = regDist[e];
            sharedBufIdx[globalIdx]  = regIdx[e];

            regDist[e] = tmpDist;
            regIdx[e]  = tmpIdx;
        }
    }
    __syncwarp();

    // Step 2: sort the buffer (now in registers) in ascending order.
    warpBitonicSort(regDist, regIdx, k);

    // Step 3: merge the sorted buffer (in registers) with the previous
    // intermediate result (now in shared memory). For each position i in [0,k),
    // we compare buffer[i] with intermediate[k-1-i] and keep the minimum.
    // The resulting sequence in registers is bitonic and contains the k
    // smallest elements from both sequences.
    #pragma unroll
    for (int e = 0; e < MAX_ELEMS_PER_THREAD; ++e) {
        if (e >= elemsPerThread) break;

        int i = lane * elemsPerThread + e;
        if (i < k) {
            int j = k - 1 - i;

            float aDist = regDist[e];
            int   aIdx  = regIdx[e];

            float bDist = sharedBufDist[j];
            int   bIdx  = sharedBufIdx[j];

            if (bDist < aDist) {
                regDist[e] = bDist;
                regIdx[e]  = bIdx;
            }
        }
    }
    __syncwarp();

    // Step 4: sort the resulting bitonic sequence in registers.
    warpBitonicSort(regDist, regIdx, k);

    // Step 5: update maxDist to the distance of the k-th nearest neighbor,
    // which is the last element in the sorted sequence.
    float kthDist = 0.0f;
    if (lane == WARP_SIZE - 1) {
        // Each thread holds elemsPerThread consecutive elements; the last element
        // in the sequence is in lane (WARP_SIZE-1) at index (elemsPerThread-1).
        kthDist = regDist[elemsPerThread - 1];
    }
    kthDist = __shfl_sync(fullMask, kthDist, WARP_SIZE - 1);
    maxDist = kthDist;
}

// Kernel: one warp processes one query point.
// Each warp maintains:
//   - A register-resident sorted array of k nearest neighbors (indices & distances).
//   - A shared-memory candidate buffer of up to k (index, distance) pairs.
//
// The data points are processed in batches. Each batch is loaded into shared memory
// by the entire block. Then, each warp computes distances from its query point to
// the cached data points, filters them using maxDist, and inserts the qualifying
// candidates into its shared buffer using warp-wide ballot and prefix sums.
// When the buffer is "close" to full (more than k - WARP_SIZE elements), it is
// merged into the intermediate result using the warpMergeWithBuffer() routine.
__global__
void knn_kernel(const float2 * __restrict__ query,
                int query_count,
                const float2 * __restrict__ data,
                int data_count,
                ResultPairDevice * __restrict__ result,
                int k)
{
    const int threadId      = threadIdx.x;
    const int lane          = threadId & (WARP_SIZE - 1);
    const int warpId        = threadId >> 5;
    const int warpsPerBlock = blockDim.x >> 5;

    const int queryId = blockIdx.x * warpsPerBlock + warpId;
    const bool warpActive = (queryId < query_count);

    const int elemsPerThread = k / WARP_SIZE;

    // Shared memory layout:
    // [0 .. BATCH_SIZE-1]      : float2 sharedData[BATCH_SIZE]
    // [next ..]                : float candDist[warpsPerBlock * k]
    // [next .. end]            : int   candIdx [warpsPerBlock * k]
    extern __shared__ unsigned char sharedRaw[];
    unsigned char *ptr = sharedRaw;

    float2 *sharedData = reinterpret_cast<float2*>(ptr);
    ptr += BATCH_SIZE * sizeof(float2);

    float *candDistAll = reinterpret_cast<float*>(ptr);
    ptr += warpsPerBlock * k * sizeof(float);

    int *candIdxAll = reinterpret_cast<int*>(ptr);
    // ptr += warpsPerBlock * k * sizeof(int); // Not needed further

    // Per-warp pointers into candidate buffers.
    float *warpCandDist = candDistAll + warpId * k;
    int   *warpCandIdx  = candIdxAll  + warpId * k;

    // Load the query point for this warp.
    float2 q;
    if (warpActive) {
        if (lane == 0) {
            q = query[queryId];
        }
        const unsigned fullMask = 0xFFFFFFFFu;
        q.x = __shfl_sync(fullMask, q.x, 0);
        q.y = __shfl_sync(fullMask, q.y, 0);
    }

    // Intermediate k-NN result in registers: each thread holds elemsPerThread
    // consecutive elements. Initially, all distances are +INF and indices are -1.
    float regDist[MAX_ELEMS_PER_THREAD];
    int   regIdx [MAX_ELEMS_PER_THREAD];

    #pragma unroll
    for (int e = 0; e < MAX_ELEMS_PER_THREAD; ++e) {
        if (e >= elemsPerThread) break;
        regDist[e] = FLT_MAX;
        regIdx[e]  = -1;
    }

    float maxDist = FLT_MAX;    // Distance of the current k-th nearest neighbor.
    int   candCount = 0;        // Number of candidates stored in this warp's buffer.

    const unsigned fullMask = 0xFFFFFFFFu;

    // Process data in batches.
    for (int base = 0; base < data_count; base += BATCH_SIZE) {
        int batchSize = data_count - base;
        if (batchSize > BATCH_SIZE) batchSize = BATCH_SIZE;

        // Load this batch of data points into shared memory cooperatively.
        for (int i = threadId; i < batchSize; i += blockDim.x) {
            sharedData[i] = data[base + i];
        }

        __syncthreads();

        if (warpActive) {
            // Number of iterations required so that each warp thread processes
            // all elements of the batch. Each iteration handles WARP_SIZE points.
            const int warpIters = (batchSize + WARP_SIZE - 1) / WARP_SIZE;

            for (int it = 0; it < warpIters; ++it) {
                // Ensure there is enough room in the candidate buffer for up to
                // WARP_SIZE new candidates. If not, merge the current buffer into
                // the intermediate result first.
                if (candCount > k - WARP_SIZE && candCount > 0) {
                    warpMergeWithBuffer(regDist, regIdx,
                                        warpCandDist, warpCandIdx,
                                        k, candCount, maxDist);
                    candCount = 0;
                }

                const int dIdx = it * WARP_SIZE + lane;
                const bool valid = (dIdx < batchSize);

                float dist = 0.0f;
                bool  isCandidate = false;
                int   globalDataIndex = -1;

                if (valid) {
                    const float2 p = sharedData[dIdx];
                    const float dx = p.x - q.x;
                    const float dy = p.y - q.y;
                    // Squared Euclidean distance.
                    dist = fmaf(dx, dx, dy * dy);
                    globalDataIndex = base + dIdx;
                    isCandidate = (dist < maxDist);
                }

                // Use warp-wide ballot to determine which threads found candidates.
                unsigned int mask = __ballot_sync(fullMask, isCandidate);
                int newCount = __popc(mask);

                // Append new candidates into this warp's shared buffer.
                int baseOffset = candCount;
                candCount += newCount;

                if (isCandidate) {
                    // Offset of this thread's candidate within the new segment.
                    unsigned int laneMask = (1u << lane) - 1u;
                    int offset = __popc(mask & laneMask);
                    int outPos = baseOffset + offset;

                    warpCandDist[outPos] = dist;
                    warpCandIdx[outPos]  = globalDataIndex;
                }
            }
        }

        __syncthreads();
    }

    // After processing all batches, merge the remaining candidates (if any)
    // into the intermediate result.
    if (warpActive && candCount > 0) {
        warpMergeWithBuffer(regDist, regIdx,
                            warpCandDist, warpCandIdx,
                            k, candCount, maxDist);
        candCount = 0;
    }

    // Write the final k nearest neighbors for this query to global memory.
    if (warpActive) {
        const int outBase = queryId * k;

        #pragma unroll
        for (int e = 0; e < MAX_ELEMS_PER_THREAD; ++e) {
            if (e >= elemsPerThread) break;

            int globalIdx = lane * elemsPerThread + e;
            int outIdx    = outBase + globalIdx;

            result[outIdx].first  = regIdx[e];
            result[outIdx].second = regDist[e];
        }
    }
}

// Host interface as requested.
//
// query:       device pointer to array of query_count float2 points.
// data:        device pointer to array of data_count float2 points.
// result:      device pointer to array of query_count * k std::pair<int,float>.
// k:           power-of-two between 32 and 1024, inclusive.
//
// The function launches the CUDA kernel with one warp per query and uses
// dynamic shared memory for batches and candidate buffers.
void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    if (query_count <= 0 || data_count <= 0) {
        return;
    }

    // Assumptions: k is a power of two between 32 and 1024, inclusive.
    // (As specified in the problem statement.)
    const int warpsPerBlock = THREADS_PER_BLOCK / WARP_SIZE;
    const int numBlocks = (query_count + warpsPerBlock - 1) / warpsPerBlock;

    // Dynamic shared memory size:
    //  - BATCH_SIZE float2s for cached data points.
    //  - warpsPerBlock * k floats and ints for candidate buffers.
    size_t sharedMemSize =
        static_cast<size_t>(BATCH_SIZE) * sizeof(float2) +
        static_cast<size_t>(warpsPerBlock) * static_cast<size_t>(k) *
            (sizeof(float) + sizeof(int));

    // Reinterpret result pointer for device use; ResultPairDevice is layout-compatible
    // with std::pair<int,float> for the purposes of this implementation.
    ResultPairDevice *resultDevice =
        reinterpret_cast<ResultPairDevice*>(result);

    knn_kernel<<<numBlocks, THREADS_PER_BLOCK, sharedMemSize>>>(
        query,
        query_count,
        data,
        data_count,
        resultDevice,
        k
    );

    // Optional synchronization; can be removed if the caller handles it.
    cudaDeviceSynchronize();
}
