#include <cuda_runtime.h>
#include <cfloat>
#include <utility>

/*
 * Optimized CUDA implementation of k-NN for 2D points.
 *
 * Design overview (high level, see detailed comments in code body):
 *
 * - Each query is processed by a single warp (32 threads).
 * - For each query, we maintain the current k nearest neighbors (NNs)
 *   in registers, distributed across the warp:
 *        k is a power of two in [32, 1024].
 *        Each thread stores k/32 consecutive elements
 *        (indices and distances) in its registers.
 * - For each query/warp we also maintain a candidate buffer of size k
 *   in shared memory (indices + distances), plus a candidate counter.
 * - We process the data points in tiles. Each tile is cooperatively
 *   loaded into shared memory by the entire block. Then each warp
 *   computes distances from its query point to all points in the tile.
 * - For each batch of 32 distances (one per thread in the warp),
 *   we use a warp ballot to determine which of them are closer
 *   than the current max_distance (the distance of the k-th NN).
 *   Those that pass the filter are appended to the candidate buffer
 *   using warp-aggregated indexing.
 * - Whenever the candidate buffer reaches capacity k, or when it is
 *   non-empty after all data points have been processed, we merge it
 *   with the current register-resident NN list:
 *
 *   Merge procedure:
 *     0. Invariant: the register-resident NN list is sorted ascending.
 *     1. Swap the contents of the candidate buffer (shared) and the
 *        register-resident NN list so that candidates move into
 *        registers and the previous NN list moves into shared memory.
 *     2. Sort the candidate list in registers using a bitonic sort
 *        over k elements distributed across the warp.
 *     3. Merge the sorted candidate list (in registers) and the
 *        previous NN list (in shared memory) by forming a bitonic
 *        sequence: for each position i in [0, k-1], we take the
 *        minimum of candidate[i] and prev[k-1-i]. This yields a
 *        bitonic sequence containing the best k elements of the
 *        2k-element union.
 *     4. Bitonic-sort the bitonic sequence (in registers) again to
 *        restore a sorted list of length k in registers, and update
 *        max_distance to the last element.
 *
 * - Bitonic sort implementation:
 *     * k is a power of two (<= 1024).
 *     * Warp size is 32, so each thread stores k/32 elements.
 *     * Because k/32 is also a power of two, the global indices
 *       of elements (0..k-1) can be mapped to (lane, local_index)
 *       with:
 *           global = lane * elems_per_thread + local_index
 *       where elems_per_thread = k/32.
 *     * In the bitonic network, for each stage parameter j:
 *           partner = global ^ j
 *       If j < elems_per_thread, the partner lies in the same thread
 *       but at a different local_index.
 *       If j >= elems_per_thread, j is a multiple of elems_per_thread
 *       and the partner lies in a different thread but at the same
 *       local_index. In that case, we exchange values via warp
 *       shuffle (__shfl_xor_sync).
 *     * Intra-thread exchanges are implemented with simple register
 *       swaps. Inter-thread exchanges use shuffles, and both threads
 *       update their own registers in a symmetric fashion (standard
 *       warp-synchronous bitonic sort pattern).
 *
 * - The final sorted k NNs for each query are written back to the
 *   result array, which is laid out as:
 *       result[query_index * k + j] = { index_of_data, distance }.
 */

static constexpr int WARP_SIZE          = 32;
static constexpr int MAX_K              = 1024;
static constexpr int MAX_K_PER_THREAD   = MAX_K / WARP_SIZE;  // 32
static constexpr int WARPS_PER_BLOCK    = 4;                  // 4 warps -> 128 threads
static constexpr int BLOCK_SIZE         = WARPS_PER_BLOCK * WARP_SIZE;
static constexpr int TILE_SIZE          = 512;                // data points per tile

// Device-side bitonic sort over k elements distributed across a warp.
// Each thread holds elems_per_thread = k / WARP_SIZE consecutive elements
// in dist[] / idx[], which are stored in registers.
//
// - dist[0..elems_per_thread-1], idx[0..elems_per_thread-1] contain
//   the data for this thread.
// - n == k is the total number of elements in the warp.
// - elems_per_thread must be a power of two, and n a power of two.
//
// Cross-thread exchanges always swap elements with the same local index
// in different threads, allowing us to use warp shuffles on scalars.
__device__ __forceinline__
void bitonic_sort_warp(float dist[MAX_K_PER_THREAD],
                       int   idx [MAX_K_PER_THREAD],
                       int   n,
                       int   elems_per_thread)
{
    const int lane      = threadIdx.x & (WARP_SIZE - 1);
    const unsigned mask = 0xffffffffu;

    // Outer loop over the bitonic network parameter 'size' (k in pseudocode).
    for (int size = 2; size <= n; size <<= 1) {
        // Inner loop over 'j' (distance between partners).
        for (int j = size >> 1; j > 0; j >>= 1) {

            if (j < elems_per_thread) {
                // Intra-thread compare-exchange:
                // All pairs (i, i^j) lie within the same thread.
                #pragma unroll
                for (int r = 0; r < MAX_K_PER_THREAD; ++r) {
                    if (r >= elems_per_thread) break;

                    int partner_r = r ^ j;
                    // Only process each pair once; choose the one with smaller local index.
                    if (partner_r > r && partner_r < elems_per_thread) {
                        int global_i = lane * elems_per_thread + r;
                        bool up = ((global_i & size) == 0);

                        float a = dist[r];
                        float b = dist[partner_r];
                        bool do_swap = ((a > b) == up);

                        if (do_swap) {
                            dist[r]          = b;
                            dist[partner_r]  = a;
                            int ia           = idx[r];
                            int ib           = idx[partner_r];
                            idx[r]          = ib;
                            idx[partner_r]  = ia;
                        }
                    }
                }
            } else {
                // Inter-thread compare-exchange:
                // j >= elems_per_thread => j is a multiple of elems_per_thread,
                // so the partner lies in a different thread but at the same
                // local index r.
                int delta_lane = j / elems_per_thread;

                #pragma unroll
                for (int r = 0; r < MAX_K_PER_THREAD; ++r) {
                    if (r >= elems_per_thread) break;

                    int global_i = lane * elems_per_thread + r;
                    bool up = ((global_i & size) == 0);

                    float my_d   = dist[r];
                    int   my_idx = idx[r];

                    float other_d = __shfl_xor_sync(mask, my_d,   delta_lane);
                    int   other_i = __shfl_xor_sync(mask, my_idx, delta_lane);

                    bool do_swap = ((my_d > other_d) == up);
                    if (do_swap) {
                        dist[r] = other_d;
                        idx[r]  = other_i;
                    }
                }
            }

            // Ensure all threads in the warp complete this j-stage
            // before moving to the next j or size.
            __syncwarp(mask);
        }
    }
}

// Merge the per-warp candidate buffer (in shared memory) into the current
// intermediate result (in registers).
//
// Parameters:
//   best_dist, best_idx    : per-thread register arrays holding the current
//                            (sorted) k nearest neighbors for this query.
//   elems_per_thread       : k / WARP_SIZE.
//   warp_id                : warp index within the block (0..WARPS_PER_BLOCK-1).
//   k                      : number of nearest neighbors (power of two).
//   valid_candidates       : number of valid entries currently stored in
//                            the candidate buffer (0 < valid_candidates <= k).
//   cand_dist_array, cand_idx_array : shared-memory 2D arrays holding the
//                            candidate buffers for all warps in the block.
//   max_distance           : (reference) distance of the current k-th neighbor;
//                            updated at the end of the merge.
//
__device__ __forceinline__
void merge_buffer_with_result(float best_dist[MAX_K_PER_THREAD],
                              int   best_idx [MAX_K_PER_THREAD],
                              int   elems_per_thread,
                              int   warp_id,
                              int   k,
                              int   valid_candidates,
                              float cand_dist_array[WARPS_PER_BLOCK][MAX_K],
                              int   cand_idx_array [WARPS_PER_BLOCK][MAX_K],
                              float &max_distance)
{
    const int lane      = threadIdx.x & (WARP_SIZE - 1);
    const unsigned mask = 0xffffffffu;

    float *buf_dist = cand_dist_array[warp_id];
    int   *buf_idx  = cand_idx_array [warp_id];

    // If the buffer is not full, pad remaining entries with +INF and dummy
    // indices so that bitonic sort / merge can operate on exactly k elements.
    if (valid_candidates < k) {
        for (int i = valid_candidates + lane; i < k; i += WARP_SIZE) {
            buf_dist[i] = FLT_MAX;
            buf_idx[i]  = -1;
        }
    }
    __syncwarp(mask);

    // Step 1: swap content of buffer (shared) and intermediate result (registers).
    // After this, registers contain the k candidates, and shared memory holds
    // the previous NN list.
    #pragma unroll
    for (int r = 0; r < MAX_K_PER_THREAD; ++r) {
        if (r >= elems_per_thread) break;

        int   g        = lane * elems_per_thread + r;
        float tmp_d    = best_dist[r];
        int   tmp_i    = best_idx [r];
        float cand_d   = buf_dist[g];
        int   cand_i   = buf_idx [g];
        best_dist[r]   = cand_d;
        best_idx [r]   = cand_i;
        buf_dist[g]    = tmp_d;
        buf_idx [g]    = tmp_i;
    }
    __syncwarp(mask);

    // Step 2: sort the buffer (now in registers) in ascending order.
    bitonic_sort_warp(best_dist, best_idx, k, elems_per_thread);

    // Step 3: merge buffer (sorted in registers) with previous intermediate
    // result (sorted in shared memory) into a bitonic sequence of length k.
    // For each position g in [0, k-1], we take the minimum of:
    //   buffer[g] and prev[k - 1 - g].
    #pragma unroll
    for (int r = 0; r < MAX_K_PER_THREAD; ++r) {
        if (r >= elems_per_thread) break;

        int   g        = lane * elems_per_thread + r;
        int   partner  = k - 1 - g;
        float prev_d   = buf_dist[partner];
        int   prev_i   = buf_idx [partner];
        float cand_d   = best_dist[r];
        int   cand_i   = best_idx [r];

        if (prev_d < cand_d) {
            best_dist[r] = prev_d;
            best_idx [r] = prev_i;
        }
    }
    __syncwarp(mask);

    // Step 4: sort the resulting bitonic sequence in ascending order
    // to produce the updated intermediate result.
    bitonic_sort_warp(best_dist, best_idx, k, elems_per_thread);

    // Update max_distance (the distance of the k-th nearest neighbor).
    // The k-th element is the last one in the sorted sequence, which is
    // stored in lane WARP_SIZE-1 at local index elems_per_thread - 1.
    float kth = 0.0f;
    if (lane == WARP_SIZE - 1) {
        kth = best_dist[elems_per_thread - 1];
    }
    kth = __shfl_sync(mask, kth, WARP_SIZE - 1);
    max_distance = kth;
}

// CUDA kernel implementing k-NN for multiple queries.
// Each warp handles one query.
__global__ void knn_kernel(const float2 * __restrict__ query,
                           int                     query_count,
                           const float2 * __restrict__ data,
                           int                     data_count,
                           std::pair<int, float> * __restrict__ result,
                           int                     k)
{
    // Shared memory:
    // - s_data: tile of data points.
    // - s_cand_dist / s_cand_idx: candidate buffers for each warp in block.
    __shared__ float2 s_data[TILE_SIZE];
    __shared__ float  s_cand_dist[WARPS_PER_BLOCK][MAX_K];
    __shared__ int    s_cand_idx [WARPS_PER_BLOCK][MAX_K];

    const int thread_id       = threadIdx.x;
    const int warp_id_in_block= thread_id / WARP_SIZE;
    const int lane            = thread_id & (WARP_SIZE - 1);
    const int warp_global_id  = blockIdx.x * WARPS_PER_BLOCK + warp_id_in_block;

    if (warp_global_id >= query_count)
        return;  // Entire warp is inactive for this block.

    const unsigned full_mask = 0xffffffffu;

    // Each warp owns one row of the candidate buffers.
    float *cand_dist = s_cand_dist[warp_id_in_block];
    int   *cand_idx  = s_cand_idx [warp_id_in_block];

    // Number of elements stored per thread in the intermediate result.
    const int elems_per_thread = k / WARP_SIZE;

    // Register-resident intermediate result: k-best neighbors per query.
    float best_dist[MAX_K_PER_THREAD];
    int   best_idx [MAX_K_PER_THREAD];

    // Initialize intermediate result with +INF distances and dummy indices.
    #pragma unroll
    for (int i = 0; i < MAX_K_PER_THREAD; ++i) {
        if (i < elems_per_thread) {
            best_dist[i] = FLT_MAX;
            best_idx [i] = -1;
        }
    }

    // Load query point for this warp and broadcast to all lanes.
    float2 q;
    if (lane == 0) {
        q = query[warp_global_id];
    }
    q.x = __shfl_sync(full_mask, q.x, 0);
    q.y = __shfl_sync(full_mask, q.y, 0);

    // Current max distance (distance of the k-th nearest neighbor).
    float max_distance = FLT_MAX;

    // Candidate buffer size for this warp (kept in registers, synchronized
    // among lanes via shuffles).
    int cand_count = 0;

    // Process data points in tiles.
    for (int tile_start = 0; tile_start < data_count; tile_start += TILE_SIZE) {
        int tile_size = data_count - tile_start;
        if (tile_size > TILE_SIZE) tile_size = TILE_SIZE;

        // Load tile into shared memory cooperatively.
        for (int i = thread_id; i < tile_size; i += blockDim.x) {
            s_data[i] = data[tile_start + i];
        }
        __syncthreads();

        // Each warp processes all points in the tile.
        for (int idx_in_tile = lane; idx_in_tile < tile_size; idx_in_tile += WARP_SIZE) {

            // Preemptive merge to avoid candidate buffer overflow.
            // In one iteration we can add at most WARP_SIZE candidates.
            // If k > WARP_SIZE and cand_count > k - WARP_SIZE, we merge now.
            if (k > WARP_SIZE && cand_count > k - WARP_SIZE) {
                if (cand_count > 0) {
                    merge_buffer_with_result(best_dist, best_idx,
                                             elems_per_thread,
                                             warp_id_in_block,
                                             k,
                                             cand_count,
                                             s_cand_dist,
                                             s_cand_idx,
                                             max_distance);
                }
                cand_count = 0;
            }

            // Load data point from shared memory and compute squared L2 distance.
            float2 p = s_data[idx_in_tile];
            float dx = p.x - q.x;
            float dy = p.y - q.y;
            float dist = dx * dx + dy * dy;

            float current_max = max_distance;
            bool is_candidate = (dist < current_max);

            // Warp-wide ballot to identify candidates.
            unsigned cand_mask = __ballot_sync(full_mask, is_candidate);
            int votes = __popc(cand_mask);

            if (votes > 0) {
                // Reserve [warp_offset, warp_offset + votes) slots in the
                // candidate buffer for this warp.
                int warp_offset = 0;
                if (lane == 0) {
                    warp_offset = cand_count;
                    cand_count += votes;
                }
                warp_offset = __shfl_sync(full_mask, warp_offset, 0);
                cand_count  = __shfl_sync(full_mask, cand_count, 0);

                // Each candidate thread computes its offset within the
                // new block of 'votes' elements.
                if (is_candidate) {
                    unsigned mask_before = cand_mask & ((1u << lane) - 1);
                    int local_pos        = __popc(mask_before);
                    int pos              = warp_offset + local_pos;
                    // By construction, cand_count <= k, so pos < k.
                    cand_dist[pos] = dist;
                    cand_idx [pos] = tile_start + idx_in_tile;
                }
            }

            // If the candidate buffer is exactly full, merge it with
            // the intermediate result.
            if (cand_count == k) {
                merge_buffer_with_result(best_dist, best_idx,
                                         elems_per_thread,
                                         warp_id_in_block,
                                         k,
                                         cand_count,
                                         s_cand_dist,
                                         s_cand_idx,
                                         max_distance);
                cand_count = 0;
            }
        }

        // Ensure all warps are done with this tile before reusing s_data.
        __syncthreads();
    }

    // After processing all tiles, if there are remaining candidates in the
    // buffer, merge them as well.
    if (cand_count > 0) {
        merge_buffer_with_result(best_dist, best_idx,
                                 elems_per_thread,
                                 warp_id_in_block,
                                 k,
                                 cand_count,
                                 s_cand_dist,
                                 s_cand_idx,
                                 max_distance);
        cand_count = 0;
    }

    // Write final k nearest neighbors for this query to global memory.
    // The intermediate result is sorted ascending by distance and
    // distributed across the warp as k/32 consecutive elements per thread.
    int base_out = warp_global_id * k;
    #pragma unroll
    for (int i = 0; i < MAX_K_PER_THREAD; ++i) {
        if (i >= elems_per_thread) break;

        int global_pos = lane * elems_per_thread + i;
        std::pair<int, float> &out = result[base_out + global_pos];
        out.first  = best_idx [i];
        out.second = best_dist[i];
    }
}

// Host interface: runs the k-NN CUDA kernel.
//
// query       : pointer to device array of float2 (queries), length query_count.
// data        : pointer to device array of float2 (data points), length data_count.
// result      : pointer to device array of std::pair<int,float>, length query_count * k.
// k           : number of nearest neighbors to find (power of two, in [32, 1024]).
void run_knn(const float2 *query, int query_count,
             const float2 *data,  int data_count,
             std::pair<int, float> *result, int k)
{
    // One warp per query.
    dim3 block(BLOCK_SIZE);
    int num_warps = (query_count + 0); // each warp handles exactly one query
    int grid_x    = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    dim3 grid(grid_x);

    knn_kernel<<<grid, block>>>(query, query_count,
                                data,  data_count,
                                result, k);
}

#include <cuda_runtime.h>
#include <float.h>
#include <utility>

// Simple POD type with the same layout as std::pair<int, float>.
struct PairIF {
    int   first;
    float second;
};

static_assert(sizeof(PairIF) == sizeof(std::pair<int, float>), "PairIF must match std::pair<int,float> size");

// Constants for warp- and block-level configuration.
constexpr int WARP_SIZE            = 32;
constexpr int MAX_K                = 1024;
constexpr int MAX_ITEMS_PER_THREAD = MAX_K / WARP_SIZE; // 32
constexpr int THREADS_PER_BLOCK    = 256;                // 8 warps per block
constexpr int WARPS_PER_BLOCK      = THREADS_PER_BLOCK / WARP_SIZE;
constexpr int TILE_POINTS          = 1024;               // data points per tile loaded into shared memory

// Warp-level bitonic sort for a distributed array of length k.
// The array is stored across the warp as:
//   global_index = local_index * WARP_SIZE + lane
// Each thread holds 'itemsPerThread = k / WARP_SIZE' elements in registers
// at positions [0 .. itemsPerThread-1].
__device__ __forceinline__ void warp_bitonic_sort(float *dist, int *idx, int k) {
    const unsigned full_mask     = 0xffffffffu;
    const int      lane          = threadIdx.x & (WARP_SIZE - 1);
    const int      itemsPerThread = k / WARP_SIZE;

    // Standard bitonic sort network on k elements.
    for (int size = 2; size <= k; size <<= 1) {
        for (int stride = size >> 1; stride > 0; stride >>= 1) {

            __syncwarp(full_mask);

            if (stride >= WARP_SIZE) {
                // Comparisons within the same thread (no cross-lane communication).
                for (int local = 0; local < itemsPerThread; ++local) {
                    int i        = local * WARP_SIZE + lane;
                    int partner  = i ^ stride;
                    int p_local  = partner >> 5;   // divide by 32

                    // Handle each pair only once.
                    if (p_local <= local) continue;

                    bool up = ((i & size) == 0);

                    float a  = dist[local];
                    int   ai = idx[local];
                    float b  = dist[p_local];
                    int   bi = idx[p_local];

                    bool do_swap = ((a > b) == up); // (up && a>b) || (!up && a<b)

                    if (do_swap) {
                        dist[local]  = b;
                        idx[local]   = bi;
                        dist[p_local] = a;
                        idx[p_local]  = ai;
                    }
                }
            } else {
                // Cross-lane comparisons using warp shuffles.
                int xorMask = stride;

                for (int local = 0; local < itemsPerThread; ++local) {
                    int i  = local * WARP_SIZE + lane;
                    bool up = ((i & size) == 0);

                    float val = dist[local];
                    int   id  = idx[local];

                    // Exchange values with the partner lane (same local index).
                    float partnerVal = __shfl_xor_sync(full_mask, val, xorMask, WARP_SIZE);
                    int   partnerId  = __shfl_xor_sync(full_mask, id,  xorMask, WARP_SIZE);

                    int  partner = i ^ stride;
                    bool smaller = (i < partner);

                    float minv = val;
                    int   mini = id;
                    float maxv = partnerVal;
                    int   maxi = partnerId;
                    if (partnerVal < val) {
                        minv = partnerVal; mini = partnerId;
                        maxv = val;        maxi = id;
                    }

                    // For ascending ('up' == true), the smaller index keeps the min;
                    // for descending, the smaller index keeps the max.
                    bool keepMin = (smaller == up);

                    dist[local] = keepMin ? minv : maxv;
                    idx[local]  = keepMin ? mini : maxi;
                }
            }
        }
    }

    __syncwarp(full_mask);
}

// Merge the candidate buffer in shared memory with the current intermediate
// result in registers using the procedure described in the prompt.
//
// Arguments:
//   bestDist / bestIdx   : current intermediate result in registers (sorted ascending)
//   bufDist  / bufIdx    : temporary registers for the candidate buffer
//   sharedCandDist/Idx   : per-warp candidate buffer in shared memory (size >= k)
//   k                    : k for this run (power of two, 32..1024)
//   bufferCount          : number of valid candidate entries currently in sharedCand*
__device__ __forceinline__
void warp_merge_buffer(float       *bestDist,
                       int         *bestIdx,
                       float       *bufDist,
                       int         *bufIdx,
                       float       *sharedCandDist,
                       int         *sharedCandIdx,
                       int          k,
                       int          bufferCount)
{
    const unsigned full_mask      = 0xffffffffu;
    const int      lane           = threadIdx.x & (WARP_SIZE - 1);
    const int      itemsPerThread = k / WARP_SIZE;
    const float    INF            = FLT_MAX;

    if (bufferCount == 0) {
        return;
    }

    // Pad unused positions in the candidate buffer with +INF so that
    // we always work with exactly k candidates.
    for (int local = 0; local < itemsPerThread; ++local) {
        int g = local * WARP_SIZE + lane; // global index in [0, k)
        if (g >= bufferCount && g < k) {
            sharedCandDist[g] = INF;
            sharedCandIdx[g]  = -1;
        }
    }

    __syncwarp(full_mask);

    // Step 1: Swap content between the candidate buffer in shared memory
    //         and the intermediate result in registers so that the buffer
    //         resides in registers and the intermediate result in shared memory.
    for (int local = 0; local < itemsPerThread; ++local) {
        int g   = local * WARP_SIZE + lane;
        float cd = sharedCandDist[g];
        int   ci = sharedCandIdx[g];

        sharedCandDist[g] = bestDist[local];
        sharedCandIdx[g]  = bestIdx[local];

        bufDist[local] = cd;
        bufIdx[local]  = ci;
    }

    __syncwarp(full_mask);

    // Step 2: Sort the buffer in registers in ascending order.
    warp_bitonic_sort(bufDist, bufIdx, k);

    // At this point:
    //   - bufDist/Idx (registers) hold the sorted candidate buffer B[0..k-1]
    //   - sharedCandDist/Idx hold the previous intermediate result A[0..k-1] (sorted)

    // Step 3: Merge buffer and intermediate into a bitonic sequence.
    // The merged sequence C[0..k-1] is:
    //   C[i] = min( B[i], A[k-1-i] )
    for (int local = 0; local < itemsPerThread; ++local) {
        int i = local * WARP_SIZE + lane;   // index into B
        int j = k - 1 - i;                  // corresponding index into reversed A

        float aDist = sharedCandDist[j];
        int   aIdx  = sharedCandIdx[j];
        float bDist = bufDist[local];
        int   bIdx  = bufIdx[local];

        if (bDist < aDist) {
            bestDist[local] = bDist;
            bestIdx[local]  = bIdx;
        } else {
            bestDist[local] = aDist;
            bestIdx[local]  = aIdx;
        }
    }

    __syncwarp(full_mask);

    // Step 4: Sort the merged bitonic sequence in registers in ascending order.
    warp_bitonic_sort(bestDist, bestIdx, k);
}

// Main CUDA kernel: each warp processes one query point.
__global__ void knn_kernel(const float2 * __restrict__ query,
                           int                    query_count,
                           const float2 * __restrict__ data,
                           int                    data_count,
                           PairIF * __restrict__  result,
                           int                    k)
{
    extern __shared__ unsigned char smem[];
    unsigned char *ptr = smem;

    // Shared data tile: TILE_POINTS float2 points.
    float2 *tilePoints = reinterpret_cast<float2*>(ptr);
    ptr += TILE_POINTS * sizeof(float2);

    // Per-warp candidate buffers in shared memory:
    //   WARPS_PER_BLOCK * k integers and distances.
    int   *sharedCandIdx  = reinterpret_cast<int*>(ptr);
    ptr += WARPS_PER_BLOCK * k * sizeof(int);

    float *sharedCandDist = reinterpret_cast<float*>(ptr);
    ptr += WARPS_PER_BLOCK * k * sizeof(float);

    // Per-warp candidate counts.
    int   *sharedBufCount = reinterpret_cast<int*>(ptr);
    // ptr += WARPS_PER_BLOCK * sizeof(int); // not needed further

    const int lane            = threadIdx.x & (WARP_SIZE - 1);
    const int warpInBlock     = threadIdx.x >> 5; // / WARP_SIZE
    const int warpGlobal      = blockIdx.x * WARPS_PER_BLOCK + warpInBlock;
    const bool warpActive     = (warpGlobal < query_count);
    const unsigned full_mask  = 0xffffffffu;

    const int itemsPerThread  = k / WARP_SIZE;

    // Each warp's region in the shared candidate buffers.
    float *warpCandDist = sharedCandDist + warpInBlock * k;
    int   *warpCandIdx  = sharedCandIdx  + warpInBlock * k;

    // Initialize per-warp candidate count.
    if (lane == 0) {
        sharedBufCount[warpInBlock] = 0;
    }

    // Registers for intermediate k-NN result (sorted ascending).
    float bestDist[MAX_ITEMS_PER_THREAD];
    int   bestIdx [MAX_ITEMS_PER_THREAD];

    // Temporary registers used when merging candidate buffer.
    float bufDist [MAX_ITEMS_PER_THREAD];
    int   bufIdx  [MAX_ITEMS_PER_THREAD];

    // Initialize intermediate result with +INF distances and invalid indices.
    for (int i = 0; i < MAX_ITEMS_PER_THREAD; ++i) {
        bestDist[i] = FLT_MAX;
        bestIdx[i]  = -1;
    }

    float2 queryPoint;
    if (warpActive) {
        queryPoint = query[warpGlobal];
    }

    float max_distance = FLT_MAX;

    // Process the data set in tiles.
    for (int tileBase = 0; tileBase < data_count; tileBase += TILE_POINTS) {
        int tileCount = data_count - tileBase;
        if (tileCount > TILE_POINTS) tileCount = TILE_POINTS;

        // Load tile into shared memory cooperatively by the whole block.
        for (int i = threadIdx.x; i < tileCount; i += blockDim.x) {
            tilePoints[i] = data[tileBase + i];
        }

        __syncthreads();

        if (warpActive) {
            // Iterate over points in the tile in groups of WARP_SIZE.
            for (int tBase = 0; tBase < tileCount; tBase += WARP_SIZE) {
                int idxInTile = tBase + lane;
                bool valid    = (idxInTile < tileCount);

                float dist = 0.0f;
                int   dataIndex = tileBase + idxInTile;

                if (valid) {
                    float2 p = tilePoints[idxInTile];
                    float dx = p.x - queryPoint.x;
                    float dy = p.y - queryPoint.y;
                    dist = dx * dx + dy * dy;
                } else {
                    dataIndex = -1;
                }

                // Filter by current max_distance.
                bool isCandidate = valid && (dist < max_distance);

                unsigned mask = __ballot_sync(full_mask, isCandidate);
                int numCand   = __popc(mask);

                if (numCand == 0) {
                    continue;
                }

                int bufferCount = sharedBufCount[warpInBlock];

                // If adding these candidates would overflow the buffer,
                // merge the existing buffer first.
                if (bufferCount + numCand > k) {
                    if (bufferCount > 0) {
                        warp_merge_buffer(bestDist, bestIdx,
                                          bufDist,  bufIdx,
                                          warpCandDist, warpCandIdx,
                                          k, bufferCount);

                        if (lane == 0) {
                            sharedBufCount[warpInBlock] = 0;
                        }
                        __syncwarp(full_mask);

                        // Update max_distance (distance of k-th nearest neighbor).
                        max_distance = __shfl_sync(full_mask,
                                                   bestDist[itemsPerThread - 1],
                                                   WARP_SIZE - 1);
                    }

                    bufferCount = 0;

                    // Recompute candidate flag with updated max_distance.
                    isCandidate = valid && (dist < max_distance);
                    mask        = __ballot_sync(full_mask, isCandidate);
                    numCand     = __popc(mask);
                    if (numCand == 0) {
                        continue;
                    }
                }

                // Now we know bufferCount + numCand <= k.
                int offset = __popc(mask & ((1u << lane) - 1));

                if (lane == 0) {
                    sharedBufCount[warpInBlock] = bufferCount + numCand;
                }

                if (isCandidate) {
                    int dest = bufferCount + offset;
                    warpCandIdx [dest] = dataIndex;
                    warpCandDist[dest] = dist;
                }

                int newBufferCount = bufferCount + numCand;

                // If the buffer just became full, merge it immediately.
                if (newBufferCount == k) {
                    warp_merge_buffer(bestDist, bestIdx,
                                      bufDist,  bufIdx,
                                      warpCandDist, warpCandIdx,
                                      k, newBufferCount);

                    if (lane == 0) {
                        sharedBufCount[warpInBlock] = 0;
                    }
                    __syncwarp(full_mask);

                    max_distance = __shfl_sync(full_mask,
                                               bestDist[itemsPerThread - 1],
                                               WARP_SIZE - 1);
                }
            }
        }

        __syncthreads();
    }

    if (warpActive) {
        // After processing all tiles, merge any remaining candidates.
        int bufferCount = sharedBufCount[warpInBlock];
        if (bufferCount > 0) {
            warp_merge_buffer(bestDist, bestIdx,
                              bufDist,  bufIdx,
                              warpCandDist, warpCandIdx,
                              k, bufferCount);
        }

        // Write the final k nearest neighbors for this query to global memory.
        for (int local = 0; local < itemsPerThread; ++local) {
            int g = local * WARP_SIZE + lane; // global neighbor index in [0, k)
            PairIF out;
            out.first  = bestIdx[local];
            out.second = bestDist[local];
            result[static_cast<size_t>(warpGlobal) * k + g] = out;
        }
    }
}

// Host interface as specified.
void run_knn(const float2 *query,
             int           query_count,
             const float2 *data,
             int           data_count,
             std::pair<int, float> *result,
             int           k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    // Reinterpret std::pair<int,float>* as a POD with the same layout.
    PairIF *result_cast = reinterpret_cast<PairIF*>(result);

    // Grid configuration: one warp per query.
    const int warpsPerBlock = WARPS_PER_BLOCK;
    int numWarps  = (query_count + warpsPerBlock - 1) / warpsPerBlock;
    int numBlocks = numWarps;

    // Dynamic shared memory size per block.
    size_t sharedBytes =
        TILE_POINTS * sizeof(float2) +
        static_cast<size_t>(WARPS_PER_BLOCK) * k * (sizeof(int) + sizeof(float)) +
        WARPS_PER_BLOCK * sizeof(int);

    knn_kernel<<<numBlocks, THREADS_PER_BLOCK, sharedBytes>>>(
        query, query_count,
        data,  data_count,
        result_cast,
        k
    );

    // The caller may choose to synchronize or check errors outside this function.
}

#include <cuda_runtime.h>
#include <utility>
#include <float.h>

// This implementation computes k-NN for 2D points on the GPU.
// Each query is processed by a single warp (32 threads).
// For each query, the warp maintains:
//   - A sorted intermediate result of k nearest neighbors in registers.
//   - A candidate buffer of up to k elements in shared memory.
//
// The intermediate result is distributed so that each thread stores
// k/32 consecutive elements in its registers. The full k-element array
// is laid out as:
//   arr[0 .. k-1], where element at global position g is stored in
//   thread (lane) t = g / localK and local register index e = g % localK,
//   with localK = k / 32.
//
// The candidate buffer is shared per-warp and uses the same layout
// (contiguous in global index g).
//
// When the buffer is full or needs to be merged, we:
//   1. Pad the buffer to k elements with +inf distances.
//   2. Swap buffer and intermediate result so buffer becomes register-resident.
//   3. Bitonic-sort the buffer.
//   4. Merge buffer and previous result into a bitonic sequence in registers
//      by taking minima of pairs (buffer[i], result[k-1-i]).
//   5. Bitonic-sort the merged sequence to restore global ascending order.
//   6. Update max_distance to the distance of the k-th nearest neighbor.
//
// Distances are squared Euclidean (L2) distances.

constexpr int WARP_SIZE          = 32;
constexpr int MAX_K              = 1024;                       // maximum supported k
constexpr int MAX_K_PER_THREAD   = MAX_K / WARP_SIZE;          // 32 when MAX_K=1024
constexpr int WARPS_PER_BLOCK    = 4;                          // 4 warps => 128 threads per block
constexpr int THREADS_PER_BLOCK  = WARPS_PER_BLOCK * WARP_SIZE;
constexpr int DATA_TILE          = 2048;                       // number of data points cached per block

// Warp-cooperative bitonic sort for k elements distributed across 32 threads.
// Each thread stores localK consecutive elements in its registers:
//   global index g = lane * localK + e, where e in [0, localK).
// k is a power of two in [32, 1024]. localK = k / 32 is thus a power of two in [1, 32].
// The arrays 'dist' and 'idx' contain the localK elements for this thread.
__device__ __forceinline__
void bitonic_sort_k(float dist[MAX_K_PER_THREAD],
                    int   idx [MAX_K_PER_THREAD],
                    int localK,
                    int k)
{
    const unsigned FULL_MASK = 0xffffffffu;
    const int lane = threadIdx.x & (WARP_SIZE - 1);

    // Outer loop over bitonic sequence sizes.
    for (int size = 2; size <= k; size <<= 1) {
        // Inner loop over compare distances within the current size.
        for (int stride = size >> 1; stride > 0; stride >>= 1) {

            if (stride < localK) {
                // Intra-thread comparisons: partner index within the same thread.
                // For stride < localK, XOR toggles only the low bits within [0, localK),
                // so both indices reside in the same thread and have different local indices.
                for (int e = 0; e < localK; ++e) {
                    int partner = e ^ stride;
                    // process each pair only once
                    if (partner > e) {
                        int g = lane * localK + e;
                        bool up = ((g & size) == 0);  // true => ascending, false => descending

                        float a  = dist[e];
                        float b  = dist[partner];
                        int   ia = idx[e];
                        int   ib = idx[partner];

                        bool comp = (a > b);
                        if (comp == up) {
                            // swap
                            dist[e]       = b;
                            idx[e]        = ib;
                            dist[partner] = a;
                            idx[partner]  = ia;
                        }
                    }
                }
            } else {
                // Inter-thread comparisons: partner index resides in another lane.
                // For stride >= localK, stride is a multiple of localK (both are powers of two).
                // XOR affects only the higher bits that encode the lane index, leaving
                // the intra-thread index e unchanged.
                int warpDelta = stride / localK;  // lane XOR distance in [1,16]
                for (int e = 0; e < localK; ++e) {
                    int g = lane * localK + e;
                    float v  = dist[e];
                    int   id = idx[e];

                    float otherV  = __shfl_xor_sync(FULL_MASK, v,  warpDelta);
                    int   otherId = __shfl_xor_sync(FULL_MASK, id, warpDelta);

                    bool up   = ((g & size) == 0);
                    bool comp = (v > otherV);
                    if (comp == up) {
                        v  = otherV;
                        id = otherId;
                    }

                    dist[e] = v;
                    idx[e]  = id;
                }
            }

            __syncwarp();
        }
    }
}

// Merge the per-warp candidate buffer (in shared memory) with the current
// intermediate result (in registers). The steps are:
//
//   1. Swap buffer (shared) and intermediate (registers), so that the buffer
//      becomes register-resident in regBufDist/regBufIdx and the previous
//      intermediate result is moved to shared memory.
//   2. Bitonic-sort the buffer (regBuf*).
//   3. For each global index i, compute:
//           merged[i] = min( buffer[i], intermediate[k-1-i] ),
//      producing a bitonic sequence in bestDist/bestIdx.
//   4. Bitonic-sort the merged sequence to restore ascending order.
//   5. Update maxDistance from the k-th element.
__device__ __forceinline__
void merge_buffer_with_intermediate(
    float regBufDist[MAX_K_PER_THREAD],
    int   regBufIdx [MAX_K_PER_THREAD],
    float bestDist  [MAX_K_PER_THREAD],
    int   bestIdx   [MAX_K_PER_THREAD],
    float *warpCandDist,
    int   *warpCandIdx,
    int k,
    int localK,
    float &maxDistance)
{
    const unsigned FULL_MASK = 0xffffffffu;
    const int lane = threadIdx.x & (WARP_SIZE - 1);

    // Step 1: swap buffer (shared) and intermediate result (registers)
    for (int e = 0; e < localK; ++e) {
        int g = lane * localK + e;
        if (g < k) {
            float tmpD = warpCandDist[g];
            int   tmpI = warpCandIdx[g];

            warpCandDist[g] = bestDist[e];
            warpCandIdx[g]  = bestIdx[e];

            regBufDist[e] = tmpD;
            regBufIdx[e]  = tmpI;
        }
    }
    __syncwarp();

    // Step 2: sort the buffer in registers
    bitonic_sort_k(regBufDist, regBufIdx, localK, k);

    // Step 3: merge into a bitonic sequence using minima of (buffer[i], intermediate[k-1-i])
    for (int e = 0; e < localK; ++e) {
        int g = lane * localK + e;
        if (g < k) {
            int j = k - 1 - g;

            float valB = regBufDist[e];
            int   idB  = regBufIdx[e];

            float valI = warpCandDist[j];
            int   idI  = warpCandIdx[j];

            if (valI < valB) {
                valB = valI;
                idB  = idI;
            }

            bestDist[e] = valB;
            bestIdx[e]  = idB;
        }
    }
    __syncwarp();

    // Step 4: sort merged result in registers (ascending)
    bitonic_sort_k(bestDist, bestIdx, localK, k);
    __syncwarp();

    // Step 5: update maxDistance from global position k-1, which is stored at
    // lane = WARP_SIZE-1, local index = localK-1.
    float last = bestDist[localK - 1];
    maxDistance = __shfl_sync(FULL_MASK, last, WARP_SIZE - 1);
    __syncwarp();
}

// Flush the per-warp candidate buffer into the intermediate result.
// The buffer currently contains sCandCount[warpId] entries at the
// beginning; we pad the remainder up to k with +inf before merging.
//
// This function is warp-synchronous and must be called by all threads
// in the warp that owns warpId.
__device__ __forceinline__
void flush_candidate_buffer(
    int warpId,
    float bestDist[MAX_K_PER_THREAD],
    int   bestIdx [MAX_K_PER_THREAD],
    float regBufDist[MAX_K_PER_THREAD],
    int   regBufIdx [MAX_K_PER_THREAD],
    float (*sCandDist)[MAX_K],
    int   (*sCandIdx )[MAX_K],
    int *sCandCount,
    int k,
    int localK,
    float &maxDistance)
{
    const int lane = threadIdx.x & (WARP_SIZE - 1);
    int candCount = sCandCount[warpId];
    if (candCount == 0) {
        return;
    }

    float *warpCandDist = sCandDist[warpId];
    int   *warpCandIdx  = sCandIdx[warpId];

    // Pad unused entries with +inf so that the buffer has exactly k elements.
    if (lane == 0) {
        for (int i = candCount; i < k; ++i) {
            warpCandDist[i] = CUDART_INF_F;
            warpCandIdx[i]  = -1;
        }
    }
    __syncwarp();

    // Merge candidate buffer with current intermediate result.
    merge_buffer_with_intermediate(regBufDist, regBufIdx,
                                   bestDist, bestIdx,
                                   warpCandDist, warpCandIdx,
                                   k, localK, maxDistance);

    if (lane == 0) {
        sCandCount[warpId] = 0;
    }
    __syncwarp();
}

// Kernel: each warp processes one query point.
__global__ void knn_kernel_2d(
    const float2 *__restrict__ query,
    int query_count,
    const float2 *__restrict__ data,
    int data_count,
    std::pair<int, float> *__restrict__ result,
    int k)
{
    // Shared memory layout:
    //   - sData:  tile of DATA_TILE points cached for all warps in the block.
    //   - sCandDist/sCandIdx: WARPS_PER_BLOCK candidate buffers.
    //   - sCandCount: per-warp candidate counts.
    __shared__ float2 sData[DATA_TILE];
    __shared__ float  sCandDist[WARPS_PER_BLOCK][MAX_K];
    __shared__ int    sCandIdx [WARPS_PER_BLOCK][MAX_K];
    __shared__ int    sCandCount[WARPS_PER_BLOCK];

    const int lane         = threadIdx.x & (WARP_SIZE - 1);
    const int warpId       = threadIdx.x / WARP_SIZE;
    const int warpGlobalId = blockIdx.x * WARPS_PER_BLOCK + warpId;
    const bool warpActive  = (warpGlobalId < query_count);
    const unsigned FULL_MASK = 0xffffffffu;

    const int localK = k / WARP_SIZE;

    // Per-thread registers: intermediate result and temporary buffer for merging.
    float bestDist [MAX_K_PER_THREAD];
    int   bestIdx  [MAX_K_PER_THREAD];
    float bufRegDist[MAX_K_PER_THREAD];
    int   bufRegIdx [MAX_K_PER_THREAD];

    float qx = 0.0f;
    float qy = 0.0f;
    float maxDistance = CUDART_INF_F;

    if (warpActive) {
        // Initialize intermediate result with +inf distances.
        for (int i = 0; i < localK; ++i) {
            bestDist[i] = CUDART_INF_F;
            bestIdx[i]  = -1;
        }

        // Initialize candidate count for this warp.
        if (lane == 0) {
            sCandCount[warpId] = 0;
        }

        // Load and broadcast query point.
        if (lane == 0) {
            float2 q = query[warpGlobalId];
            qx = q.x;
            qy = q.y;
        }
        qx = __shfl_sync(FULL_MASK, qx, 0);
        qy = __shfl_sync(FULL_MASK, qy, 0);

        maxDistance = CUDART_INF_F;
    }

    __syncthreads();

    // Process data points in tiles cached in shared memory.
    for (int base = 0; base < data_count; base += DATA_TILE) {
        int tileSize = data_count - base;
        if (tileSize > DATA_TILE) tileSize = DATA_TILE;

        // Load tile cooperatively.
        for (int idx = threadIdx.x; idx < tileSize; idx += blockDim.x) {
            sData[idx] = data[base + idx];
        }
        __syncthreads();

        if (warpActive) {
            // Each warp scans all points in the tile.
            for (int i = lane; i < tileSize; i += WARP_SIZE) {
                float2 p = sData[i];
                float dx = p.x - qx;
                float dy = p.y - qy;
                float distSq = dx * dx + dy * dy;

                bool isCandidate = distSq < maxDistance;

                unsigned mask = __ballot_sync(FULL_MASK, isCandidate);
                int warpNew = __popc(mask);
                if (warpNew == 0) {
                    continue;
                }

                int oldCount = sCandCount[warpId];

                // If buffer would overflow, flush it first and recompute candidacy
                // with the updated maxDistance.
                if (oldCount + warpNew > k) {
                    flush_candidate_buffer(warpId,
                                           bestDist, bestIdx,
                                           bufRegDist, bufRegIdx,
                                           sCandDist, sCandIdx,
                                           sCandCount,
                                           k, localK, maxDistance);

                    oldCount = sCandCount[warpId];

                    isCandidate = distSq < maxDistance;
                    mask = __ballot_sync(FULL_MASK, isCandidate);
                    warpNew = __popc(mask);
                    if (warpNew == 0) {
                        continue;
                    }
                }

                // Re-read candidate count after possible flush.
                oldCount = sCandCount[warpId];
                int baseOffset = oldCount;

                // Update candidate count for this warp.
                if (lane == 0) {
                    sCandCount[warpId] = oldCount + warpNew;
                }
                __syncwarp();

                // Each candidate thread reserves a unique slot in the buffer
                // based on the prefix count of candidate lanes before it.
                if (isCandidate) {
                    unsigned laneMask = mask & ((1u << lane) - 1u);
                    int offset = __popc(laneMask);
                    int pos = baseOffset + offset;
                    sCandDist[warpId][pos] = distSq;
                    sCandIdx [warpId][pos] = base + i;  // global data index
                }
                __syncwarp();
            }
        }

        __syncthreads();
    }

    if (warpActive) {
        // Flush remaining candidates after processing all tiles.
        flush_candidate_buffer(warpId,
                               bestDist, bestIdx,
                               bufRegDist, bufRegIdx,
                               sCandDist, sCandIdx,
                               sCandCount,
                               k, localK, maxDistance);

        // Write final k nearest neighbors for this query to global memory.
        const int queryIdx = warpGlobalId;
        for (int e = 0; e < localK; ++e) {
            int g = (lane * localK) + e;  // global neighbor rank in [0, k)
            int outIndex = queryIdx * k + g;
            result[outIndex].first  = bestIdx[e];
            result[outIndex].second = bestDist[e];
        }
    }
}

// Host-side wrapper. Assumes that 'query', 'data', and 'result' are device
// pointers allocated with cudaMalloc, and that k is a power of two between
// 32 and 1024 (inclusive) with data_count >= k.
void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    if (query_count <= 0 || data_count <= 0 || k <= 0) {
        return;
    }

    // Simple grid configuration: one warp per query.
    const int blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    dim3 grid(blocks);
    dim3 block(THREADS_PER_BLOCK);

    knn_kernel_2d<<<grid, block>>>(query, query_count, data, data_count, result, k);

    // Synchronize to ensure completion before returning.
    cudaDeviceSynchronize();
}

