#include <cuda_runtime.h>
#include <utility>

/*
 * Optimized k-NN kernel (squared Euclidean distance in 2D) for modern NVIDIA GPUs.
 *
 * Requirements implemented:
 *  - Each query is processed by a single warp (32 threads).
 *  - Intermediate k-NN result is kept in registers, distributed so that
 *    each thread stores k/32 consecutive neighbors.
 *  - For each query/warp, a candidate buffer of size k (indices + distances)
 *    is stored in shared memory, plus a per-warp candidate counter.
 *  - Input data points are processed in batches cached into shared memory.
 *  - For each batch, each warp computes distances to its query, filters by
 *    current max_distance, and adds closer points to its candidate buffer.
 *    Warp ballot is used to count and position new candidates.
 *  - When the candidate buffer becomes full (k elements), it is merged with
 *    the intermediate result using the specified sequence:
 *      0. Intermediate result is always sorted ascending (invariant).
 *      1. Swap content of buffer and intermediate such that buffer is in
 *         registers (and intermediate is in shared memory).
 *      2. Sort the buffer in registers using Bitonic Sort (ascending).
 *      3. Merge buffer and intermediate into a bitonic sequence by taking
 *         element-wise minima of buffer[i] and intermediate[k - 1 - i].
 *      4. Sort this bitonic sequence with Bitonic Sort to obtain an updated
 *         sorted intermediate result.
 *  - After all data is processed, any non-empty candidate buffer is merged
 *    once more with the intermediate result (with padding).
 *  - Bitonic Sort uses warp shuffle instructions for cross-thread exchanges.
 *    Since each thread stores consecutive elements, exchanged elements always
 *    have the same index within each thread's register array. Within-thread
 *    exchanges are simple register swaps.
 */

static constexpr int WARPS_PER_BLOCK        = 8;    // 8 warps (256 threads) per block
static constexpr int THREADS_PER_BLOCK      = WARPS_PER_BLOCK * 32;
static constexpr int MAX_K                  = 1024; // max k (power of two, 32..1024)
static constexpr int MAX_ITEMS_PER_THREAD   = MAX_K / 32; // max k/32 = 32
static constexpr int DATA_TILE_SIZE         = 1024; // number of data points cached per block

// Convenience alias for the result type.
using PairIF = std::pair<int, float>;

// Full warp mask.
#ifndef FULL_MASK
#define FULL_MASK 0xffffffffu
#endif

// Warp-wide function to obtain the k-th element (index k-1) from a distributed array.
// The array is stored so that each lane holds itemsPerThread consecutive elements.
template <int MAX_ITEMS_PER_THREAD>
__device__ inline float warpGetKthValue(const float (&values)[MAX_ITEMS_PER_THREAD],
                                        int itemsPerThread, int k)
{
    int laneId   = threadIdx.x & 31;
    int index    = k - 1;                     // global index of k-th nearest neighbor
    int ownerLane = index / itemsPerThread;   // lane holding that element
    int localSlot = index % itemsPerThread;   // index within that lane's register array
    float v = values[localSlot];
    // Broadcast from ownerLane to all lanes.
    return __shfl_sync(FULL_MASK, v, ownerLane);
}

/*
 * Warp-level Bitonic Sort for k elements distributed across the warp.
 *
 * Layout:
 *  - k is a power of two in [32, MAX_K].
 *  - Each warp has 32 lanes; each lane stores itemsPerThread = k / 32
 *    consecutive elements in its register arrays 'values' and 'indices'.
 *
 * Algorithm:
 *  - Follows the classical bitonic sorting network for k elements.
 *  - For strides smaller than itemsPerThread, comparators operate within
 *    each thread (intra-thread), using register swaps.
 *  - For strides greater or equal to itemsPerThread, comparators operate
 *    across threads (inter-thread). In this case the partner index differs
 *    only in the more significant bits (lane id), while the localSlot
 *    (element index within the thread) is identical. This allows us to
 *    use __shfl_xor_sync on the per-slot values.
 */
template <int MAX_ITEMS_PER_THREAD, int MAX_K>
__device__ inline void warpBitonicSort(float (&values)[MAX_ITEMS_PER_THREAD],
                                       int   (&indices)[MAX_ITEMS_PER_THREAD],
                                       int k,
                                       unsigned int activeMask)
{
    int laneId         = threadIdx.x & 31;
    int itemsPerThread = k >> 5; // k / 32, guaranteed power-of-two
    // log2(itemsPerThread), itemsPerThread >= 1
    int shift = __ffs(itemsPerThread) - 1;

    // Outer loops over bitonic sequence size (size) and comparison stride (stride).
    for (int size = 2; size <= k; size <<= 1)
    {
        for (int stride = size >> 1; stride > 0; stride >>= 1)
        {
            if (stride < itemsPerThread)
            {
                // Intra-thread comparators: indices differ only in localSlot.
                // We process each pair once (p > s) and update both entries.
                for (int s = 0; s < itemsPerThread; ++s)
                {
                    int p = s ^ stride;
                    if (p <= s) continue; // each pair only once

                    int i0 = laneId * itemsPerThread + s;
                    // i1 = i0 ^ stride, but we don't need it explicitly.
                    bool ascending = ((i0 & size) == 0);

                    float v0 = values[s];
                    float v1 = values[p];
                    int   id0 = indices[s];
                    int   id1 = indices[p];

                    float minV, maxV;
                    int   minId, maxId;
                    if (v0 < v1) {
                        minV = v0; minId = id0;
                        maxV = v1; maxId = id1;
                    } else {
                        minV = v1; minId = id1;
                        maxV = v0; maxId = id0;
                    }

                    if (ascending) {
                        // Put smaller at lower index, larger at higher index.
                        values[s] = minV; indices[s] = minId;
                        values[p] = maxV; indices[p] = maxId;
                    } else {
                        // Descending sequence.
                        values[s] = maxV; indices[s] = maxId;
                        values[p] = minV; indices[p] = minId;
                    }
                }
            }
            else
            {
                // Inter-thread comparators: indices differ in lane bits only.
                // For a given localSlot s, the partner lane is:
                //   partnerLane = laneId ^ (stride / itemsPerThread)
                // and both lanes work on the same localSlot s.
                int partnerMask = stride >> shift; // power-of-two (>=1)

                for (int s = 0; s < itemsPerThread; ++s)
                {
                    int i      = laneId * itemsPerThread + s;
                    int partner = i ^ stride;

                    // Both indices in a pair share the same 'size' bit,
                    // hence the same direction (ascending/descending).
                    bool ascending = ((i & size) == 0);
                    bool isLow     = ((i & stride) == 0); // "lower" index in the pair

                    float v   = values[s];
                    int   id  = indices[s];

                    // Partner's value and index from the lane with id laneId ^ partnerMask.
                    float ov  = __shfl_xor_sync(activeMask, v,  partnerMask, 32);
                    int   oid = __shfl_xor_sync(activeMask, id, partnerMask, 32);

                    float minV, maxV;
                    int   minId, maxId;
                    if (v < ov) {
                        minV = v;   minId = id;
                        maxV = ov;  maxId = oid;
                    } else {
                        minV = ov;  minId = oid;
                        maxV = v;   maxId = id;
                    }

                    if (ascending) {
                        // Ascending sequence: lower index gets min, higher gets max.
                        if (isLow) {
                            values[s] = minV; indices[s] = minId;
                        } else {
                            values[s] = maxV; indices[s] = maxId;
                        }
                    } else {
                        // Descending sequence: lower index gets max, higher gets min.
                        if (isLow) {
                            values[s] = maxV; indices[s] = maxId;
                        } else {
                            values[s] = minV; indices[s] = minId;
                        }
                    }
                }
            }

            __syncwarp(activeMask);
        }
    }
}

/*
 * Merge a full candidate buffer (k elements) with the current intermediate
 * result for one warp/query.
 *
 * Parameters:
 *  - warpIdInBlock: warp index within the block.
 *  - bestDist/bestIdx: intermediate k-NN result stored in registers, sorted ascending.
 *  - maxDistance: reference to the current max_distance variable (updated here).
 *  - sharedCandDist/sharedCandIdx: per-warp candidate buffer in shared memory.
 *  - k: total number of neighbors (power of two between 32 and MAX_K).
 *  - itemsPerThread: k / 32, number of elements per lane.
 *
 * Steps implemented:
 *  1. Swap contents of buffer and intermediate result so that the buffer
 *     (candidates) is in registers (bufDist/bufIdx) and the intermediate
 *     result is in shared memory.
 *  2. Sort the buffer (bufDist/bufIdx) with bitonic sort (ascending).
 *  3. Merge buffer and intermediate by taking, for each global index i,
 *     min(buffer[i], intermediate[k-1-i]) into bestDist/bestIdx. The result
 *     is a bitonic sequence containing the best k elements of both.
 *  4. Sort bestDist/bestIdx (bitonic sequence) ascending with bitonic sort.
 *     Update maxDistance to the last element (k-th nearest).
 */
template <int WARPS_PER_BLOCK_T, int MAX_ITEMS_PER_THREAD_T, int MAX_K_T>
__device__ inline void merge_full_buffer(int warpIdInBlock,
                                         float (&bestDist)[MAX_ITEMS_PER_THREAD_T],
                                         int   (&bestIdx)[MAX_ITEMS_PER_THREAD_T],
                                         float &maxDistance,
                                         float sharedCandDist[WARPS_PER_BLOCK_T][MAX_K_T],
                                         int   sharedCandIdx [WARPS_PER_BLOCK_T][MAX_K_T],
                                         int   k,
                                         int   itemsPerThread)
{
    int laneId = threadIdx.x & 31;

    float bufDist[MAX_ITEMS_PER_THREAD_T];
    int   bufIdx [MAX_ITEMS_PER_THREAD_T];

    int base = laneId * itemsPerThread;

    // Step 1: swap buffer (shared) and intermediate (registers).
    #pragma unroll
    for (int i = 0; i < MAX_ITEMS_PER_THREAD_T; ++i)
    {
        if (i < itemsPerThread)
        {
            int idx = base + i;
            bufDist[i] = sharedCandDist[warpIdInBlock][idx];
            bufIdx[i]  = sharedCandIdx [warpIdInBlock][idx];

            sharedCandDist[warpIdInBlock][idx] = bestDist[i];
            sharedCandIdx [warpIdInBlock][idx] = bestIdx[i];
        }
    }

    __syncwarp(FULL_MASK);

    // Step 2: sort buffer in registers (ascending).
    warpBitonicSort<MAX_ITEMS_PER_THREAD_T, MAX_K_T>(bufDist, bufIdx, k, FULL_MASK);

    __syncwarp(FULL_MASK);

    // Step 3: merge buffer and intermediate into a bitonic sequence.
    #pragma unroll
    for (int i = 0; i < MAX_ITEMS_PER_THREAD_T; ++i)
    {
        if (i < itemsPerThread)
        {
            int idx1 = base + i;
            int idx2 = k - 1 - idx1; // mirrored index

            float candD = bufDist[i];
            int   candI = bufIdx[i];

            float intermD = sharedCandDist[warpIdInBlock][idx2];
            int   intermI = sharedCandIdx [warpIdInBlock][idx2];

            if (candD <= intermD) {
                bestDist[i] = candD;
                bestIdx[i]  = candI;
            } else {
                bestDist[i] = intermD;
                bestIdx[i]  = intermI;
            }
        }
    }

    __syncwarp(FULL_MASK);

    // Step 4: sort the merged bitonic sequence (ascending).
    warpBitonicSort<MAX_ITEMS_PER_THREAD_T, MAX_K_T>(bestDist, bestIdx, k, FULL_MASK);

    __syncwarp(FULL_MASK);

    // Update maxDistance to distance of k-th nearest neighbor.
    maxDistance = warpGetKthValue<MAX_ITEMS_PER_THREAD_T>(bestDist, itemsPerThread, k);
}

/*
 * Main k-NN kernel.
 *
 * Each warp processes exactly one query point.
 *  - The warp index (within the grid) identifies the query index.
 *  - The block cooperatively loads batches of data points into shared memory.
 *  - Each warp computes squared distances from its query to all data points,
 *    filters by maxDistance, and fills its candidate buffer.
 *  - When the candidate buffer is full, it is merged with the intermediate
 *    result using merge_full_buffer().
 */
__global__ void knn_kernel(const float2 * __restrict__ query,
                           int query_count,
                           const float2 * __restrict__ data,
                           int data_count,
                           PairIF * __restrict__ result,
                           int k)
{
    // Shared memory: cached data tile and per-warp candidate buffers.
    __shared__ float2 s_data[DATA_TILE_SIZE];
    __shared__ int    s_candIdx [WARPS_PER_BLOCK][MAX_K];
    __shared__ float  s_candDist[WARPS_PER_BLOCK][MAX_K];

    const int warpIdInBlock = threadIdx.x >> 5;  // warp index inside block
    const int laneId        = threadIdx.x & 31;  // lane index in warp
    const int globalWarpId  = blockIdx.x * WARPS_PER_BLOCK + warpIdInBlock;
    const int queryIdx      = globalWarpId;

    const bool activeWarp   = (queryIdx < query_count);
    const int  itemsPerThread = k >> 5; // k / 32; guaranteed power-of-two

    // Per-warp intermediate result: stored in registers, k/32 elements per lane.
    float bestDist[MAX_ITEMS_PER_THREAD];
    int   bestIdx [MAX_ITEMS_PER_THREAD];

    float maxDistance = CUDART_INF_F; // distance of k-th nearest neighbor
    int   bufCount    = 0;            // number of candidates currently in buffer

    float qx = 0.0f, qy = 0.0f;

    if (activeWarp)
    {
        // Initialize intermediate result with +inf and invalid indices.
        #pragma unroll
        for (int i = 0; i < MAX_ITEMS_PER_THREAD; ++i)
        {
            if (i < itemsPerThread)
            {
                bestDist[i] = CUDART_INF_F;
                bestIdx[i]  = -1;
            }
        }

        // Load this warp's query point and broadcast its coordinates.
        if (laneId == 0)
        {
            float2 q = query[queryIdx];
            qx = q.x;
            qy = q.y;
        }
    }

    qx = __shfl_sync(FULL_MASK, qx, 0);
    qy = __shfl_sync(FULL_MASK, qy, 0);

    // Process data in tiles.
    for (int base = 0; base < data_count; base += DATA_TILE_SIZE)
    {
        int tileSize = data_count - base;
        if (tileSize > DATA_TILE_SIZE) tileSize = DATA_TILE_SIZE;

        // Load data tile into shared memory cooperatively.
        for (int idx = threadIdx.x; idx < tileSize; idx += blockDim.x)
        {
            s_data[idx] = data[base + idx];
        }

        __syncthreads();

        if (activeWarp)
        {
            // Each lane processes a subset of the tile. The union of all lanes'
            // subsets covers the whole tile.
            for (int tIdx = laneId; tIdx < tileSize; tIdx += 32)
            {
                float2 p = s_data[tIdx];
                float dx = qx - p.x;
                float dy = qy - p.y;
                float dist2 = dx * dx + dy * dy;

                // Filter using current maxDistance (distance of k-th neighbor).
                bool isCandidate = (dist2 < maxDistance);

                unsigned int mask = __ballot_sync(FULL_MASK, isCandidate);

                // Process all candidate lanes for this data point, possibly in
                // multiple iterations if the buffer is almost full.
                while (mask)
                {
                    int freeSpace = k - bufCount;

                    if (freeSpace == 0)
                    {
                        // Candidate buffer is full: merge with intermediate result.
                        merge_full_buffer<WARPS_PER_BLOCK, MAX_ITEMS_PER_THREAD, MAX_K>(
                            warpIdInBlock,
                            bestDist,
                            bestIdx,
                            maxDistance,
                            s_candDist,
                            s_candIdx,
                            k,
                            itemsPerThread);

                        bufCount = 0;
                        freeSpace = k;
                    }

                    int totalPending = __popc(mask);
                    int insertCount  = (totalPending < freeSpace) ? totalPending : freeSpace;

                    if (insertCount == 0)
                        break;

                    bool pending = ((mask >> laneId) & 1u);
                    unsigned int prefixMask = mask & ((1u << laneId) - 1u);
                    int rank = __popc(prefixMask);

                    // Insert first 'insertCount' candidates from this mask into
                    // the candidate buffer, contiguously.
                    if (pending && rank < insertCount)
                    {
                        int indexInBuffer = bufCount + rank;
                        if (indexInBuffer < k)
                        {
                            s_candDist[warpIdInBlock][indexInBuffer] = dist2;
                            s_candIdx [warpIdInBlock][indexInBuffer] = base + tIdx;
                        }
                    }

                    // Update buffer count (warp-synchronous).
                    if (laneId == 0)
                    {
                        bufCount += insertCount;
                    }
                    bufCount = __shfl_sync(FULL_MASK, bufCount, 0);

                    // Remove inserted lanes from the mask.
                    unsigned int insertedMask = __ballot_sync(FULL_MASK, pending && (rank < insertCount));
                    mask &= ~insertedMask;
                }

                // If the buffer has become full exactly after processing this
                // data point, merge it immediately.
                if (bufCount == k)
                {
                    merge_full_buffer<WARPS_PER_BLOCK, MAX_ITEMS_PER_THREAD, MAX_K>(
                        warpIdInBlock,
                        bestDist,
                        bestIdx,
                        maxDistance,
                        s_candDist,
                        s_candIdx,
                        k,
                        itemsPerThread);

                    bufCount = 0;
                }
            }
        }

        __syncthreads();
    }

    if (activeWarp)
    {
        // After all data is processed, merge any remaining candidates in the
        // buffer (if bufCount > 0) with the intermediate result.
        if (bufCount > 0)
        {
            // Pad unused buffer entries with +inf so that the buffer logically
            // contains exactly k elements. These padded entries will not affect
            // the final k nearest neighbors.
            for (int idx = laneId; idx < k; idx += 32)
            {
                if (idx >= bufCount)
                {
                    s_candDist[warpIdInBlock][idx] = CUDART_INF_F;
                    s_candIdx [warpIdInBlock][idx] = -1;
                }
            }
            __syncwarp(FULL_MASK);

            merge_full_buffer<WARPS_PER_BLOCK, MAX_ITEMS_PER_THREAD, MAX_K>(
                warpIdInBlock,
                bestDist,
                bestIdx,
                maxDistance,
                s_candDist,
                s_candIdx,
                k,
                itemsPerThread);
        }

        // Write final k nearest neighbors for this query to global memory.
        int baseOut = queryIdx * k + laneId * itemsPerThread;
        #pragma unroll
        for (int i = 0; i < MAX_ITEMS_PER_THREAD; ++i)
        {
            if (i < itemsPerThread)
            {
                int outIdx = baseOut + i;
                result[outIdx].first  = bestIdx[i];
                result[outIdx].second = bestDist[i];
            }
        }
    }
}

/*
 * Host interface.
 *
 * The input pointers (query, data, result) must be device pointers allocated
 * with cudaMalloc. This function launches the k-NN kernel. No additional
 * device memory is allocated here or in the kernel.
 *
 * Parameters:
 *  - query       : device pointer to array of float2, size query_count.
 *  - query_count : number of query points.
 *  - data        : device pointer to array of float2, size data_count.
 *  - data_count  : number of data points.
 *  - result      : device pointer to array of PairIF, size query_count * k.
 *  - k           : number of nearest neighbors per query (power of two,
 *                  32 <= k <= 1024).
 */
void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             PairIF *result,
             int k)
{
    dim3 blockDim(THREADS_PER_BLOCK);
    int numBlocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;
    dim3 gridDim(numBlocks > 0 ? numBlocks : 1);

    knn_kernel<<<gridDim, blockDim>>>(query, query_count, data, data_count, result, k);
}

#include <cuda_runtime.h>
#include <cfloat>
#include <utility>

// ----------------------------------------------------------------------------
// Configuration constants tuned for modern data-center NVIDIA GPUs (A100/H100).
// ----------------------------------------------------------------------------
constexpr int WARP_SIZE          = 32;
constexpr int MAX_K              = 1024;               // upper bound from problem statement
constexpr int MAX_K_PER_THREAD   = MAX_K / WARP_SIZE;  // 32
constexpr int BLOCK_THREADS      = 256;                // 8 warps per block
constexpr int WARPS_PER_BLOCK    = BLOCK_THREADS / WARP_SIZE;
constexpr int TILE_SIZE          = 4096;               // number of data points cached per block

// ----------------------------------------------------------------------------
// Helper struct for distance/index pairs used in shared memory.
// ----------------------------------------------------------------------------
struct IdxDist {
    float dist;
    int   idx;
};

// ----------------------------------------------------------------------------
// Bitonic sort of k elements distributed across one warp.
//
// Layout:
//   - Logical array A[0..k-1] is distributed across the warp.
//   - Mapping: global index i -> (lane, local_slot):
//         lane       = i % WARP_SIZE
//         local_slot = i / WARP_SIZE
//   - Each thread stores k_per_thread = k / WARP_SIZE consecutive elements
//     in registers at indices local_slot = 0..k_per_thread-1.
//
// The implementation follows the serial bitonic sort pseudocode, but uses
// warp shuffles for cross-lane exchanges (stride < WARP_SIZE) and in-thread
// swaps for strides >= WARP_SIZE.
// ----------------------------------------------------------------------------
template<int MAX_KPT>
__device__ __forceinline__
void bitonic_sort_warp(float * __restrict__ dist,
                       int   * __restrict__ idx,
                       int k,
                       int k_per_thread,
                       int lane,
                       unsigned warpMask)
{
    // size: current bitonic subsequence length (2,4,...,k)
    for (int size = 2; size <= k; size <<= 1) {
        // stride: distance between elements being compared/swapped
        for (int stride = size >> 1; stride > 0; stride >>= 1) {
            if (stride >= WARP_SIZE) {
                // Comparisons are between elements stored in the same thread
                // (different local indices).
                int strideLocal = stride >> 5; // stride / WARP_SIZE (since WARP_SIZE == 32)
                for (int r = 0; r < k_per_thread; ++r) {
                    int partnerR = r ^ strideLocal;
                    if (partnerR > r && partnerR < k_per_thread) {
                        int i   = (r << 5) | lane;      // global index
                        bool up = ((i & size) == 0);    // sort direction for this index
                        float a  = dist[r];
                        float b  = dist[partnerR];
                        int   ia = idx[r];
                        int   ib = idx[partnerR];
                        bool doSwap = ((a > b) == up);
                        if (doSwap) {
                            dist[r]        = b;
                            dist[partnerR] = a;
                            idx[r]         = ib;
                            idx[partnerR]  = ia;
                        }
                    }
                }
            } else {
                // Comparisons are across threads in the warp (same local index).
                for (int r = 0; r < k_per_thread; ++r) {
                    int i   = (r << 5) | lane;      // global index
                    bool up = ((i & size) == 0);    // sort direction

                    float selfVal = dist[r];
                    int   selfIdx = idx[r];

                    float otherVal = __shfl_xor_sync(warpMask, selfVal, stride);
                    int   otherIdx = __shfl_xor_sync(warpMask, selfIdx, stride);

                    bool doSwap = ((selfVal > otherVal) == up);
                    if (doSwap) {
                        dist[r] = otherVal;
                        idx[r]  = otherIdx;
                    }
                }
            }
        }
    }
}

// ----------------------------------------------------------------------------
// Merge candidate buffer (in shared memory) with intermediate result
// (in registers) for one warp.
//
// The candidate buffer has up to 'candidateCount' valid entries at the
// beginning (0..candidateCount-1). The rest of the k buffer slots are
// filled with +INF so they don't affect the result.
//
// Steps (per problem statement):
//   0. Intermediates in interDist/interIdx are sorted ascending (invariant).
//   1. Swap contents so that the candidate buffer becomes resident in
//      registers (bufDist/bufIdx), and the old intermediate result is moved
//      into shared memory.
//   2. Sort the buffer in registers with bitonic sort (ascending).
//   3. Merge buffer and intermediate into interDist/interIdx in registers:
//      merged[i] = min( buffer[i], intermediate[k-1-i] ).
//      This yields a bitonic sequence of length k.
//   4. Sort this merged sequence again with bitonic sort to restore ascending
//      order. The k smallest distances are now in interDist/interIdx.
//
// Returns the updated maxDistance (distance of the k-th nearest neighbor).
// ----------------------------------------------------------------------------
template<int MAX_KPT>
__device__ __forceinline__
float merge_candidate_buffer(float * __restrict__ interDist,
                             int   * __restrict__ interIdx,
                             float * __restrict__ bufDist,
                             int   * __restrict__ bufIdx,
                             IdxDist * __restrict__ warpBuf,
                             int candidateCount,
                             int k,
                             int k_per_thread,
                             int lane,
                             unsigned warpMask)
{
    const float INF = FLT_MAX;

    // Fill unused candidate slots with INF so they don't influence the merge.
    for (int r = 0; r < k_per_thread; ++r) {
        int iGlobal = (r << 5) | lane;  // r * WARP_SIZE + lane
        if (iGlobal >= candidateCount && iGlobal < k) {
            warpBuf[iGlobal].dist = INF;
            warpBuf[iGlobal].idx  = -1;
        }
    }

    // Step 1: swap buffer (shared) with intermediate result (registers).
    for (int r = 0; r < k_per_thread; ++r) {
        int iGlobal = (r << 5) | lane;
        IdxDist tmp = warpBuf[iGlobal];  // candidate or INF
        warpBuf[iGlobal].dist = interDist[r];
        warpBuf[iGlobal].idx  = interIdx[r];
        bufDist[r]            = tmp.dist;
        bufIdx[r]             = tmp.idx;
    }

    // Step 2: sort candidate buffer in registers (ascending).
    bitonic_sort_warp<MAX_KPT>(bufDist, bufIdx, k, k_per_thread, lane, warpMask);

    // Step 3: merge sorted buffer and previous intermediate result into
    // interDist/interIdx registers via mirrored index comparison.
    for (int r = 0; r < k_per_thread; ++r) {
        int iGlobal = (r << 5) | lane;
        int jGlobal = k - 1 - iGlobal;  // mirrored index in the other sequence

        IdxDist bufVal;
        bufVal.dist = bufDist[r];
        bufVal.idx  = bufIdx[r];

        IdxDist intVal = warpBuf[jGlobal];  // previous intermediate result

        if (bufVal.dist <= intVal.dist) {
            interDist[r] = bufVal.dist;
            interIdx[r]  = bufVal.idx;
        } else {
            interDist[r] = intVal.dist;
            interIdx[r]  = intVal.idx;
        }
    }

    // Step 4: sort the merged bitonic sequence (ascending).
    bitonic_sort_warp<MAX_KPT>(interDist, interIdx, k, k_per_thread, lane, warpMask);

    // Compute and broadcast new maxDistance (distance of k-th neighbor).
    float maxDistLane = 0.0f;
    if (lane == WARP_SIZE - 1) {
        maxDistLane = interDist[k_per_thread - 1];
    }
    float maxDist = __shfl_sync(warpMask, maxDistLane, WARP_SIZE - 1);
    return maxDist;
}

// ----------------------------------------------------------------------------
// Main CUDA kernel: each warp processes exactly one query point.
// ----------------------------------------------------------------------------
__global__
void knn_kernel(const float2 * __restrict__ query,
                int query_count,
                const float2 * __restrict__ data,
                int data_count,
                int k,
                std::pair<int,float> * __restrict__ result)
{
    extern __shared__ unsigned char shared_raw[];

    // Layout of dynamic shared memory:
    // [TILE_SIZE float2] [WARPS_PER_BLOCK * k IdxDist] [WARPS_PER_BLOCK int]
    float2 *tilePoints = reinterpret_cast<float2*>(shared_raw);

    const int warpsPerBlock = blockDim.x / WARP_SIZE;
    size_t offset = TILE_SIZE * sizeof(float2);

    IdxDist *warpBuffers = reinterpret_cast<IdxDist*>(shared_raw + offset);
    offset += static_cast<size_t>(warpsPerBlock) * static_cast<size_t>(k) * sizeof(IdxDist);

    int *warpCounts = reinterpret_cast<int*>(shared_raw + offset);

    int lane           = threadIdx.x & (WARP_SIZE - 1);
    int warpIdInBlock  = threadIdx.x / WARP_SIZE;
    int globalWarpId   = blockIdx.x * warpsPerBlock + warpIdInBlock;
    bool validWarp     = (globalWarpId < query_count);

    unsigned warpMask  = 0xffffffffu;

    // Initialize candidate count for each warp.
    if (lane == 0) {
        warpCounts[warpIdInBlock] = 0;
    }

    // Per-thread registers for this warp's intermediate result and temp buffer.
    float interDist[MAX_K_PER_THREAD];
    int   interIdx[MAX_K_PER_THREAD];
    float bufDist[MAX_K_PER_THREAD];
    int   bufIdx[MAX_K_PER_THREAD];

    float2 q;
    int    k_per_thread = 0;
    float  maxDist      = FLT_MAX;

    if (validWarp) {
        q = query[globalWarpId];
        k_per_thread = k / WARP_SIZE;

        // Initialize intermediate result to "empty": INF distances and invalid indices.
        for (int r = 0; r < k_per_thread; ++r) {
            interDist[r] = FLT_MAX;
            interIdx[r]  = -1;
        }
        maxDist = FLT_MAX;
    }

    // Process data points in batches cached in shared memory.
    for (int base = 0; base < data_count; base += TILE_SIZE) {
        int remaining = data_count - base;
        int tileSize  = (remaining < TILE_SIZE) ? remaining : TILE_SIZE;

        // All threads in the block cooperatively load the tile into shared memory.
        for (int i = threadIdx.x; i < tileSize; i += blockDim.x) {
            tilePoints[i] = data[base + i];
        }

        __syncthreads();

        if (validWarp) {
            IdxDist *warpBuf = warpBuffers + warpIdInBlock * k;

            // Each warp walks over the tile, striding by WARP_SIZE.
            for (int idxInTile = lane; idxInTile < tileSize; idxInTile += WARP_SIZE) {
                float2 p = tilePoints[idxInTile];
                float dx = p.x - q.x;
                float dy = p.y - q.y;
                float dist = dx * dx + dy * dy;  // squared Euclidean distance

                // Filter by current maxDist to reduce candidate insertions.
                bool isCandidate = (dist < maxDist);

                // Warp-wide ballot to count candidates for this data point.
                unsigned candMask = __ballot_sync(warpMask, isCandidate);
                int numNew = __popc(candMask);

                if (numNew > 0) {
                    int candCountOld;
                    if (lane == 0) {
                        candCountOld = warpCounts[warpIdInBlock];
                    }
                    candCountOld = __shfl_sync(warpMask, candCountOld, 0);

                    // If buffer would overflow, merge current buffer with the
                    // intermediate result first, then re-evaluate this candidate.
                    if (candCountOld + numNew > k) {
                        maxDist = merge_candidate_buffer<MAX_K_PER_THREAD>(
                            interDist, interIdx,
                            bufDist, bufIdx,
                            warpBuf,
                            candCountOld,
                            k,
                            k_per_thread,
                            lane,
                            warpMask);

                        if (lane == 0) {
                            warpCounts[warpIdInBlock] = 0;
                        }
                        candCountOld = 0;

                        // Re-evaluate candidate predicate with updated maxDist.
                        isCandidate = (dist < maxDist);
                        candMask = __ballot_sync(warpMask, isCandidate);
                        numNew   = __popc(candMask);
                    }

                    if (numNew > 0) {
                        // Compute per-thread offset among new candidates
                        // using prefix popcount of the ballot mask.
                        unsigned maskBefore = candMask & ((1u << lane) - 1u);
                        int offsetLocal = __popc(maskBefore);

                        if (isCandidate) {
                            int pos = candCountOld + offsetLocal;
                            warpBuf[pos].dist = dist;
                            warpBuf[pos].idx  = base + idxInTile;
                        }

                        if (lane == 0) {
                            warpCounts[warpIdInBlock] = candCountOld + numNew;
                        }
                    }
                }
            }
        }

        __syncthreads();
    }

    if (validWarp) {
        IdxDist *warpBuf = warpBuffers + warpIdInBlock * k;

        // Final merge for any remaining candidates in the buffer.
        int candCountFinal;
        if (lane == 0) {
            candCountFinal = warpCounts[warpIdInBlock];
        }
        candCountFinal = __shfl_sync(warpMask, candCountFinal, 0);

        if (candCountFinal > 0) {
            maxDist = merge_candidate_buffer<MAX_K_PER_THREAD>(
                interDist, interIdx,
                bufDist, bufIdx,
                warpBuf,
                candCountFinal,
                k,
                k_per_thread,
                lane,
                warpMask);

            if (lane == 0) {
                warpCounts[warpIdInBlock] = 0;
            }
        }

        // Write the final k nearest neighbors for this query to global memory.
        for (int r = 0; r < k_per_thread; ++r) {
            int iGlobal   = (r << 5) | lane;  // r * WARP_SIZE + lane
            int outIndex  = globalWarpId * k + iGlobal;
            result[outIndex].first  = interIdx[r];
            result[outIndex].second = interDist[r];
        }
    }
}

// ----------------------------------------------------------------------------
// Public host entry point.
// Assumes 'query', 'data', and 'result' are device pointers (cudaMalloc'ed).
// No additional device allocations are performed here.
// ----------------------------------------------------------------------------
void run_knn(const float2 *query,
             int query_count,
             const float2 *data,
             int data_count,
             std::pair<int, float> *result,
             int k)
{
    // Assumptions from problem statement:
    //   - 32 <= k <= 1024
    //   - k is a power of two, and thus divisible by WARP_SIZE (32).
    // No explicit checks here; behavior is undefined if violated.

    constexpr int blockThreads   = BLOCK_THREADS;
    constexpr int warpsPerBlock  = WARPS_PER_BLOCK;

    int numBlocks = (query_count + warpsPerBlock - 1) / warpsPerBlock;
    if (numBlocks == 0) {
        return; // nothing to do
    }

    dim3 grid(numBlocks);
    dim3 block(blockThreads);

    // Dynamic shared memory size per block:
    //   [TILE_SIZE float2] + [warpsPerBlock * k IdxDist] + [warpsPerBlock int]
    size_t sharedBytes =
        TILE_SIZE * sizeof(float2) +
        static_cast<size_t>(warpsPerBlock) * static_cast<size_t>(k) * sizeof(IdxDist) +
        static_cast<size_t>(warpsPerBlock) * sizeof(int);

    // Allow the kernel to use the required dynamic shared memory size.
    // On modern GPUs (A100/H100), this limit can exceed 48KB.
    cudaFuncSetAttribute(
        knn_kernel,
        cudaFuncAttributeMaxDynamicSharedMemorySize,
        static_cast<int>(sharedBytes));

    knn_kernel<<<grid, block, sharedBytes>>>(query, query_count, data, data_count, k, result);
}

#include <cuda_runtime.h>
#include <cfloat>
#include <utility>

// Simple POD type with the same layout as std::pair<int,float>
struct PairIF {
    int   first;
    float second;
};

/**
 * Warp-wide bitonic sort of K elements, where each thread in the warp owns
 * ITEMS_PER_THREAD = K / 32 consecutive elements in registers.
 *
 * The global logical index of an element is:
 *   i = lane * ITEMS_PER_THREAD + local
 *
 * For a given bitonic (k, j) stage, comparisons may be:
 *   - Within a single thread (when j < ITEMS_PER_THREAD)
 *   - Across threads (when j >= ITEMS_PER_THREAD), but always between
 *     elements with the same local index in each thread.
 */
template <int K>
__device__ __forceinline__
void bitonic_sort_k(float (&dist)[K / 32], int (&idx)[K / 32]) {
    constexpr unsigned int FULL_MASK       = 0xffffffffu;
    constexpr int          WARP_SIZE       = 32;
    constexpr int          ITEMS_PER_THREAD = K / WARP_SIZE;

    const int lane = threadIdx.x & (WARP_SIZE - 1);

    // Standard bitonic sort network over K = WARP_SIZE * ITEMS_PER_THREAD elements
    #pragma unroll
    for (int seqLen = 2; seqLen <= K; seqLen <<= 1) {
        #pragma unroll
        for (int j = seqLen >> 1; j > 0; j >>= 1) {
            if (j < ITEMS_PER_THREAD) {
                // All comparisons for this (seqLen, j) step are within a thread
                #pragma unroll
                for (int local = 0; local < ITEMS_PER_THREAD; ++local) {
                    int i            = lane * ITEMS_PER_THREAD + local;
                    int partnerLocal = local ^ j;

                    // Only process each pair once
                    if (partnerLocal > local && partnerLocal < ITEMS_PER_THREAD) {
                        int l = lane * ITEMS_PER_THREAD + partnerLocal;

                        bool up           = ((i & seqLen) == 0);
                        bool smallerIndex = ((i & j)     == 0);

                        float a    = dist[local];
                        float b    = dist[partnerLocal];
                        int   ia   = idx[local];
                        int   ib   = idx[partnerLocal];

                        float minVal, maxVal;
                        int   minIdx, maxIdx;
                        if (a <= b) {
                            minVal = a; maxVal = b;
                            minIdx = ia; maxIdx = ib;
                        } else {
                            minVal = b; maxVal = a;
                            minIdx = ib; maxIdx = ia;
                        }

                        // If (smallerIndex == up) we keep the min at i, max at l; otherwise swapped
                        if (smallerIndex == up) {
                            dist[local]        = minVal;
                            idx[local]         = minIdx;
                            dist[partnerLocal] = maxVal;
                            idx[partnerLocal]  = maxIdx;
                        } else {
                            dist[local]        = maxVal;
                            idx[local]         = maxIdx;
                            dist[partnerLocal] = minVal;
                            idx[partnerLocal]  = minIdx;
                        }
                    }
                }
            } else {
                // Comparisons across threads. For j >= ITEMS_PER_THREAD,
                // j is a multiple of ITEMS_PER_THREAD. The partner lane offset is:
                int partnerOffset = j / ITEMS_PER_THREAD;

                #pragma unroll
                for (int local = 0; local < ITEMS_PER_THREAD; ++local) {
                    int   i       = lane * ITEMS_PER_THREAD + local;
                    float selfVal = dist[local];
                    int   selfIdx = idx[local];

                    // Fetch the partner element at the same local index in a different lane
                    float otherVal = __shfl_xor_sync(FULL_MASK, selfVal, partnerOffset);
                    int   otherIdx = __shfl_xor_sync(FULL_MASK, selfIdx, partnerOffset);

                    bool up           = ((i & seqLen) == 0);
                    bool smallerIndex = ((i & j)      == 0);

                    float minVal, maxVal;
                    int   minIdx, maxIdx;
                    if (selfVal <= otherVal) {
                        minVal = selfVal; maxVal = otherVal;
                        minIdx = selfIdx; maxIdx = otherIdx;
                    } else {
                        minVal = otherVal; maxVal = selfVal;
                        minIdx = otherIdx; maxIdx = selfIdx;
                    }

                    // Compute the new value for index i only; index (i^j) is handled in its own thread
                    if (smallerIndex == up) {
                        dist[local] = minVal;
                        idx[local]  = minIdx;
                    } else {
                        dist[local] = maxVal;
                        idx[local]  = maxIdx;
                    }
                }
            }
            __syncwarp(FULL_MASK);
        }
    }
    __syncwarp(FULL_MASK);
}

/**
 * Merge the current intermediate result (stored in registers across the warp)
 * with the per-warp candidate buffer in shared memory.
 *
 * Steps (per the specification):
 *  0. The intermediate result in registers is sorted ascending.
 *  1. Swap the contents of the buffer and the intermediate result so that
 *     the buffer is now in registers.
 *  2. Sort the buffer (now in registers) in ascending order using bitonic sort.
 *  3. Merge the buffer and the intermediate result in shared memory into the
 *     registers: for each global position i, take the minimum of
 *        buffer[i] and intermediate[K - 1 - i].
 *     This produces a bitonic sequence of length K in registers.
 *  4. Sort the merged sequence in ascending order using bitonic sort.
 *     The result is the updated intermediate result.
 *
 * The candidate buffer may contain fewer than K elements; the remaining
 * positions are filled with values >= current max_distance so that they
 * cannot influence the top-K result.
 */
template <int K>
__device__ __forceinline__
void merge_buffer_with_intermediate(float (&dist_reg)[K / 32],
                                    int   (&idx_reg)[K / 32],
                                    float *cand_dist,
                                    int   *cand_idx,
                                    int    cand_count,
                                    float &max_distance) {
    constexpr unsigned int FULL_MASK        = 0xffffffffu;
    constexpr int          WARP_SIZE        = 32;
    constexpr int          ITEMS_PER_THREAD = K / WARP_SIZE;

    const int lane = threadIdx.x & (WARP_SIZE - 1);

    // Fill unused slots in the candidate buffer with distances >= current max_distance
    // so that they cannot enter the top-K after merging.
    if (cand_count < K) {
        int num_to_fill = K - cand_count;
        for (int t = lane; t < num_to_fill; t += WARP_SIZE) {
            cand_dist[cand_count + t] = max_distance;
            cand_idx[cand_count + t]  = -1;
        }
    }
    __syncwarp(FULL_MASK);

    // Swap the K elements between registers (intermediate result) and shared memory (buffer)
    #pragma unroll
    for (int local = 0; local < ITEMS_PER_THREAD; ++local) {
        int   global_index = lane * ITEMS_PER_THREAD + local;
        float tmp_dist     = dist_reg[local];
        int   tmp_idx      = idx_reg[local];

        float buf_dist     = cand_dist[global_index];
        int   buf_idx      = cand_idx[global_index];

        dist_reg[local]    = buf_dist;
        idx_reg[local]     = buf_idx;

        cand_dist[global_index] = tmp_dist;
        cand_idx[global_index]  = tmp_idx;
    }
    __syncwarp(FULL_MASK);

    // Sort the buffer now stored in registers
    bitonic_sort_k<K>(dist_reg, idx_reg);
    __syncwarp(FULL_MASK);

    // Merge: for each position i, keep the minimum of
    //   buffer[i] (in registers) and intermediate[K - 1 - i] (in shared memory)
    #pragma unroll
    for (int local = 0; local < ITEMS_PER_THREAD; ++local) {
        int   global_index = lane * ITEMS_PER_THREAD + local;
        int   mirror_index = K - 1 - global_index;

        float a_dist = dist_reg[local];
        int   a_idx  = idx_reg[local];

        float b_dist = cand_dist[mirror_index];
        int   b_idx  = cand_idx[mirror_index];

        if (b_dist < a_dist) {
            dist_reg[local] = b_dist;
            idx_reg[local]  = b_idx;
        }
    }
    __syncwarp(FULL_MASK);

    // The registers now contain a bitonic sequence of length K; sort it
    bitonic_sort_k<K>(dist_reg, idx_reg);
    __syncwarp(FULL_MASK);

    // Update max_distance as the k-th (last) element of the sorted intermediate result
    float kth = dist_reg[ITEMS_PER_THREAD - 1];
    kth       = __shfl_sync(FULL_MASK, kth, WARP_SIZE - 1);
    max_distance = kth;
}

/**
 * Main k-NN kernel: one warp processes one query point.
 * Each warp maintains a distributed top-K list in registers, and a
 * per-warp candidate buffer of size K in shared memory.
 */
template <int K>
__global__
void knn_kernel(const float2 *__restrict__ query,
                int                         query_count,
                const float2 *__restrict__ data,
                int                         data_count,
                PairIF      *__restrict__  result) {
    constexpr unsigned int FULL_MASK        = 0xffffffffu;
    constexpr int          WARP_SIZE        = 32;
    constexpr int          WARPS_PER_BLOCK  = 4;
    constexpr int          THREADS_PER_BLOCK = WARPS_PER_BLOCK * WARP_SIZE;
    constexpr int          ITEMS_PER_THREAD = K / WARP_SIZE;
    // Size of data tile loaded into shared memory per block
    constexpr int          DATA_TILE_SIZE   = 4096;

    // Shared memory:
    //  - sh_data:   cached data points for the current tile
    //  - sh_cand_*: per-warp candidate buffers of size K
    __shared__ float2 sh_data[DATA_TILE_SIZE];
    __shared__ int    sh_cand_idx[WARPS_PER_BLOCK * K];
    __shared__ float  sh_cand_dist[WARPS_PER_BLOCK * K];

    const int thread_id   = threadIdx.x;
    const int warp_id     = thread_id / WARP_SIZE;      // warp index within block
    const int lane        = thread_id & (WARP_SIZE - 1);
    const int global_warp = blockIdx.x * WARPS_PER_BLOCK + warp_id;

    const bool warp_active = (global_warp < query_count);

    // Per-warp views into shared candidate buffers
    int   *cand_idx  = sh_cand_idx  + warp_id * K;
    float *cand_dist = sh_cand_dist + warp_id * K;

    // Per-thread top-K intermediate result stored in registers
    float dist_reg[ITEMS_PER_THREAD];
    int   idx_reg[ITEMS_PER_THREAD];

    // Initialize intermediate result with "infinite" distances
    #pragma unroll
    for (int i = 0; i < ITEMS_PER_THREAD; ++i) {
        dist_reg[i] = FLT_MAX;
        idx_reg[i]  = -1;
    }

    // Current distance threshold: distance of the k-th nearest neighbor
    float max_distance = FLT_MAX;

    // Number of candidates currently stored in this warp's shared buffer
    int cand_count = 0;

    // Query point for this warp
    float2 q;
    if (warp_active) {
        q = query[global_warp];
    }

    // Iterate over data points in tiles cached in shared memory
    for (int tile_start = 0; tile_start < data_count; tile_start += DATA_TILE_SIZE) {
        int tile_size = data_count - tile_start;
        if (tile_size > DATA_TILE_SIZE) tile_size = DATA_TILE_SIZE;

        // Load tile into shared memory cooperatively by the whole block
        for (int idx = thread_id; idx < tile_size; idx += THREADS_PER_BLOCK) {
            sh_data[idx] = data[tile_start + idx];
        }
        __syncthreads();

        if (warp_active) {
            // Each warp processes all points in the tile for its own query
            for (int j = lane; j < tile_size; j += WARP_SIZE) {
                float2 p = sh_data[j];
                float dx = q.x - p.x;
                float dy = q.y - p.y;
                float dist = dx * dx + dy * dy;

                // Filter by current max_distance
                bool is_candidate = (dist < max_distance);
                unsigned int mask = __ballot_sync(FULL_MASK, is_candidate);
                int num_new       = __popc(mask);

                if (num_new > 0) {
                    int old_count = cand_count;
                    int new_total = old_count + num_new;

                    // If the buffer would overflow, merge existing candidates first,
                    // then re-evaluate the current distance against the updated max_distance.
                    if (new_total > K) {
                        if (old_count > 0) {
                            merge_buffer_with_intermediate<K>(
                                dist_reg, idx_reg,
                                cand_dist, cand_idx,
                                old_count, max_distance);
                        }
                        cand_count = 0;

                        // Recheck with updated max_distance
                        is_candidate = (dist < max_distance);
                        mask         = __ballot_sync(FULL_MASK, is_candidate);
                        num_new      = __popc(mask);

                        if (num_new == 0) {
                            continue;
                        }

                        old_count = 0;
                        new_total = num_new;
                    }

                    int warp_offset = old_count;

                    // Reserve positions [warp_offset, warp_offset + num_new)
                    if (is_candidate) {
                        unsigned int lane_mask = mask & ((1u << lane) - 1u);
                        int prefix = __popc(lane_mask);
                        int pos    = warp_offset + prefix;

                        cand_idx[pos]  = tile_start + j; // global index of data point
                        cand_dist[pos] = dist;
                    }

                    cand_count = new_total;

                    // If the buffer is now full, merge it with the intermediate result
                    if (cand_count == K) {
                        merge_buffer_with_intermediate<K>(
                            dist_reg, idx_reg,
                            cand_dist, cand_idx,
                            cand_count, max_distance);
                        cand_count = 0;
                    }
                }
            }
        }

        __syncthreads();
    }

    // After processing all tiles, merge any remaining candidates
    if (warp_active && cand_count > 0) {
        merge_buffer_with_intermediate<K>(
            dist_reg, idx_reg,
            cand_dist, cand_idx,
            cand_count, max_distance);
        cand_count = 0;
    }

    // Write out the K nearest neighbors for this query
    if (warp_active) {
        #pragma unroll
        for (int local = 0; local < ITEMS_PER_THREAD; ++local) {
            int global_k_index = lane * ITEMS_PER_THREAD + local;
            int out_index      = global_warp * K + global_k_index;

            PairIF out;
            out.first  = idx_reg[local];
            out.second = dist_reg[local];

            result[out_index] = out;
        }
    }
}

/**
 * Host-side dispatcher. Launches a specialized kernel for each supported K.
 */
void run_knn(const float2 *query,
             int           query_count,
             const float2 *data,
             int           data_count,
             std::pair<int, float> *result,
             int           k) {
    constexpr int WARP_SIZE        = 32;
    constexpr int WARPS_PER_BLOCK  = 4;
    constexpr int THREADS_PER_BLOCK = WARP_SIZE * WARPS_PER_BLOCK;

    // reinterpret std::pair<int,float>* as PairIF* (same memory layout)
    PairIF *result_cast = reinterpret_cast<PairIF *>(result);

    int num_blocks = (query_count + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK;

    dim3 block_dim(THREADS_PER_BLOCK, 1, 1);
    dim3 grid_dim(num_blocks, 1, 1);

    switch (k) {
        case 32:
            knn_kernel<32><<<grid_dim, block_dim>>>(
                query, query_count, data, data_count, result_cast);
            break;
        case 64:
            knn_kernel<64><<<grid_dim, block_dim>>>(
                query, query_count, data, data_count, result_cast);
            break;
        case 128:
            knn_kernel<128><<<grid_dim, block_dim>>>(
                query, query_count, data, data_count, result_cast);
            break;
        case 256:
            knn_kernel<256><<<grid_dim, block_dim>>>(
                query, query_count, data, data_count, result_cast);
            break;
        case 512:
            knn_kernel<512><<<grid_dim, block_dim>>>(
                query, query_count, data, data_count, result_cast);
            break;
        case 1024:
            knn_kernel<1024><<<grid_dim, block_dim>>>(
                query, query_count, data, data_count, result_cast);
            break;
        default:
            // Unsupported k (should not happen given the problem constraints)
            return;
    }

    // Synchronize to ensure completion before returning
    cudaDeviceSynchronize();
}
